-- Poems batch 418
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-736','驻马听・望眼巴巴，春陌香尘迷去马。梦魂飒飒，晓窗初日闹啼鸦。千声','童童学士','元','元曲','yuanqu','','[]','作念凑嗟呀，一丝情景留牵挂。',30,'元曲/yuanqu.json','["作念凑嗟呀，一丝情景留牵挂。", "许归期全是假，秀才每说谎天来大。"]'),
('yuanqu-737','乔牌儿・绣双飞线脚差，描并宿笔尖怕。牡丹亭闲却秋千架，好春光谁共','童童学士','元','元曲','yuanqu','','[]','耍？。',3,'元曲/yuanqu.json','["耍？。"]'),
('yuanqu-738','落梅风・肌消玉，脸褪霞，怎打熬九秋三夏？被薄赚的孤又寡，辜负了小','童童学士','元','元曲','yuanqu','','[]','乔初嫁。',4,'元曲/yuanqu.json','["乔初嫁。"]'),
('yuanqu-740','得胜令・身似井中蛙，命似釜中虾。难把猿心锁，空将鹃泪洒。情杂，下','童童学士','元','元曲','yuanqu','','[]','不的题着他名儿骂。',22,'元曲/yuanqu.json','["不的题着他名儿骂。", "性猾，恨不的揪住他身子打。"]'),
('yuanqu-741','甜水令・马上墙头，月底星前，窗间帘下，容易得欢洽。案举齐眉，带绾','童童学士','元','元曲','yuanqu','','[]','同心，钗留结发，那曾有一点儿亵狎。',17,'元曲/yuanqu.json','["同心，钗留结发，那曾有一点儿亵狎。"]'),
('yuanqu-742','折桂令・好姻缘两意相答，你本是秋水无尘，我本是美玉无瑕。十字为媒，','童童学士','元','元曲','yuanqu','','[]','又不图红定黄茶。',50,'元曲/yuanqu.json','["又不图红定黄茶。", "我不学普救寺幽期调发，你怎犯海神祠负意折罚？生也因他，死也因他，恩爱人儿，欢喜冤家。"]'),
('yuanqu-743','锦上花・想着他锦绣充肠，诸余俊雅。山海填胸，所事撑达。花下低头，','童童学士','元','元曲','yuanqu','','[]','风吹帽纱。',57,'元曲/yuanqu.json','["风吹帽纱。", "月底潜踪，露湿罗袜。", "朱弦续有时，宝剑配无价。", "求似神仙，信心菩萨。", "才得相逢，扑絮纳瓜。", "恰早分离，瓶沉珠撒。"]'),
('yuanqu-744','清江引・一声去也没乱杀，少几句叮咛话。说归甚日归？待罢何时罢？梦','童童学士','元','元曲','yuanqu','','[]','儿中见他刚半霎。',8,'元曲/yuanqu.json','["儿中见他刚半霎。"]'),
('yuanqu-745','离亭宴歇指煞・狂风飘散鸳鸯瓦，严霜冷透鸾凰榻，好教我如痴似哑。佳','童童学士','元','元曲','yuanqu','','[]','期绝往来，后约无凭准，前语皆欺诈。',93,'元曲/yuanqu.json','["期绝往来，后约无凭准，前语皆欺诈。", "空传红叶诗，枉卜金钱卦，凄凉日加。", "燕惊飞张氏楼，犬吠断韩生宅，虎拦住萧郎驾。", "闷随秋夜长，情逐春冰化。", "待他见咱，算他那狠罪过有千桩，害的我这瘦骨头没一把。"]'),
('yuanqu-746','临江驿潇湘秋夜雨・仙吕/端正好','杨显之','元','元曲','yuanqu','','[]','我恰才沉没这急流中，挣的到河滩上。',63,'元曲/yuanqu.json','["我恰才沉没这急流中，挣的到河滩上。", "只看我这湿渌渌上下衣裳。", "若不是渔翁肯把咱恩养，(带云)天那！(唱)这泼性命休承望。", "(同下)。"]'),
('yuanqu-747','临江驿潇湘秋夜雨・仙吕/点绛唇','杨显之','元','元曲','yuanqu','','[]','举目生愁，父亲别后难根究。',29,'元曲/yuanqu.json','["举目生愁，父亲别后难根究。", "这一片悠悠，可也还留得残生否？。"]'),
('yuanqu-748','临江驿潇湘秋夜雨・昆江龙','杨显之','元','元曲','yuanqu','','[]','若不是渔翁搭救，险些儿趁一江春水向东流。',86,'元曲/yuanqu.json','["若不是渔翁搭救，险些儿趁一江春水向东流。", "我如今偷挨岁月，爹爹呵，知他在何处沉浮？则我这一寸心怀千古恨，两条眉锁十分忧。", "多谢的那老父恩临厚，不将我似世人看待，直做个亲女收留。"]'),
('yuanqu-749','临江驿潇湘秋夜雨・油葫芦','杨显之','元','元曲','yuanqu','','[]','则见他抄定攀蟾折桂手。',162,'元曲/yuanqu.json','["则见他抄定攀蟾折桂手。", "(崔甸士云)妹子，恕生面少拜识。", "(正旦唱)待趋前还褪后，我则索慌忙施礼半含羞。", "(崔甸士云)妹子，小生有缘得此一见。", "(正旦唱)则见他身儿俊俏庞儿秀。", "(崔甸士云)妹子，小生此后又不知何时重会哩。", "(正旦唱)则见他性儿温润情儿厚。", "且休夸潘安貌欠十分，子建才非八斗。", "单只是白凉衫稳缀着鸳鸯扣，上下无半点儿不风流。"]'),
('yuanqu-750','临江驿潇湘秋夜雨・天下乐','杨显之','元','元曲','yuanqu','','[]','则愿的早夺词场第一筹，文优福亦优，宴琼林是你男儿得志秋。',54,'元曲/yuanqu.json','["则愿的早夺词场第一筹，文优福亦优，宴琼林是你男儿得志秋。", "标题的名姓又香，打扮的体态又作，准备着插宫花饮御酒。"]'),
('yuanqu-751','临江驿潇湘秋夜雨・醉中天','杨显之','元','元曲','yuanqu','','[]','才救出淮河口，又送上楚峰头。',217,'元曲/yuanqu.json','["才救出淮河口，又送上楚峰头。", "(做背哭科，云)俺那父亲呵，(唱)生死茫茫未可水，怎便待通媒媾……(孛老云)我儿，你怎么不答应我一句儿？姻缘姻缘，事非偶然。", "我也须不误了你。", "(正旦唱)虽然道姻缘不偶，我可一言难就，有多少雨泣云愁。", "(孛老云)我儿，这个是喜事，怎么倒哭起来？快不要这等。", "我看的那侄儿满腹文章，一定是做官的。", "故此将你许配了他。", "常言道：女大不中留。", "你见那家女孩儿养老在家里的？你只依着我，就今日两边行一个礼，承认了罢。", "(正旦唱)。"]'),
('yuanqu-752','临江驿潇湘秋夜雨・金盏儿','杨显之','元','元曲','yuanqu','','[]','元来他敬儒流，意绸缪。',224,'元曲/yuanqu.json','["元来他敬儒流，意绸缪。", "可甚么是非只为多开口，倒道我女大不中留。", "他分明亲许出，着我怎抬头？虽然俺心下有，我须是脸儿羞。", "(孛老扯旦、末行礼科，云)则今日好日辰，成合了这门亲事。", "侄儿，你与我便上朝求官应举去，得一官半职，回来改换家门．则是休忘了我的思念。", "(正旦云)多谢父亲。", "则怕崔秀才此一去，久后负了人也。", "(崔甸士云)小生若负了你呵，天不盖，地不载，日月不照临。", "(正旦云)秀才也，你去则去，频频的稍个书信回来。", "(崔甸士云)小生知道，你放心者。", "(正旦唱)。"]'),
('yuanqu-753','临江驿潇湘秋夜雨・赚煞','杨显之','元','元曲','yuanqu','','[]','则他这胸臆卷江淮，宝剑辉星斗。',117,'元曲/yuanqu.json','["则他这胸臆卷江淮，宝剑辉星斗。", "是俺那父亲匹配下鸾交凤友。", "想着你千里关山独自个走，则今宵有梦难投。", "你若到至公楼，占了鳌头，则怕你金榜无名誓不休。", "莫便要心不应口，早做了背亲忘旧。", "(带云)崔秀才也，(唱)休着我倚柴门，凝望断不归舟。", "(下)。"]'),
('yuanqu-754','临江驿潇湘秋夜雨・梁州','杨显之','元','元曲','yuanqu','','[]','我则见舞旋旋飘空的这败叶，恰便似红溜溜血染胭脂。',365,'元曲/yuanqu.json','["我则见舞旋旋飘空的这败叶，恰便似红溜溜血染胭脂。", "冷飕飕西风了却黄花事。", "看了些林梢掩映，山势参差。", "走的我口干舌苦，眼晕头疵。", "我可也把不住抹泪揉眵，行不上软弱腰肢。", "我、我、我，款款的兜定这鞋儿，是、是、是，慢慢的按下这笠儿，呀、呀、呀，我可便轻轻的拽起这裙儿。", "我想起亏心的那厮，你为官消不得人伏侍。", "你忙杀呵，写不得那半张纸？我也须有个日头儿见你时，好着我仔细寻思。", "(云)可早来到秦川县了也。", "我问人咱。", "(做向古门问科，云)敢问哥哥，那里是崔甸士的私宅？(内云)则前面那个八字墙门便是。", "(正旦云)哥哥，我寄着这包袱儿在这里，我认了亲眷呵便采取也。", "(内云)放在这里不妨事，你自去。", "(正旦云)门上有人么？你报复去，道有夫人在于门首。", "(祗从云)兀那娘子，你敢差走了。", "俺相公自有夫人哩。", "(正旦云)你道甚么？(祗从云)俺相公自有夫人哩。", "(正旦唱)。"]'),
('yuanqu-755','临江驿潇湘秋夜雨・牧羊关','杨显之','元','元曲','yuanqu','','[]','兀的是闲言浯，甚意思？他怎肯道节外生枝。',88,'元曲/yuanqu.json','["兀的是闲言浯，甚意思？他怎肯道节外生枝。", "我和他离别了三年，我怎肯半星儿失志？我则道他不肯弃糟糠妇，他原来别寻了个女娇姿。", "只待要打灭了这穷妻子，呀、呀、呀，你畅好是负心的崔甸土。"]'),
('yuanqu-756','临江驿潇湘秋夜雨・隔尾','杨显之','元','元曲','yuanqu','','[]','我则待妇随夫唱和你调琴瑟。',141,'元曲/yuanqu.json','["我则待妇随夫唱和你调琴瑟。", "谁知你再娶停婚先有个泼贱儿。", "(搽旦怒云)你这天杀的，他倒骂我哩。", "(崔甸士云)左右，还不扯下去打呀？(正旦唱)倒将我横拖竖拽离阶址。", "(带云)崔甸士，(唱)你须记的，那时亲设下誓词。", "(崔甸士云)胡说，我有甚么誓词。", "(正旦唱)你说道：不亏心，不亏心，把天地来指。"]'),
('yuanqu-757','临江驿潇湘秋夜雨・哭皇天','杨显之','元','元曲','yuanqu','','[]','则我这脊梁上如刀刺，打得来青间紫。',101,'元曲/yuanqu.json','["则我这脊梁上如刀刺，打得来青间紫。", "飕飕的雨点下，烘烘的疼半时。", "怎当他无情无情的棍子，打得来连皮彻骨，夹脑通心，肉飞筋断，血溅魂消，直着我一疼来，一疼来一个死。", "我只问你个亏心甸上，怎揣与我这无名的罪儿？。"]'),
('yuanqu-758','临江驿潇湘秋夜雨・乌夜啼','杨显之','元','元曲','yuanqu','','[]','你这短命贼怎将我来胡雕刺？迭配去别处官司，世不曾见这等跷蹊事。',95,'元曲/yuanqu.json','["你这短命贼怎将我来胡雕刺？迭配去别处官司，世不曾见这等跷蹊事。", "哭的我气噎声丝，诉不出一肚嗟咨。", "想天公难道不悲慈？只愿得你嫡亲伯父登时至，两下里质对个如何是？看你那能牙利齿，说我甚过犯公私？。"]'),
('yuanqu-759','临江驿潇湘秋夜雨・黄钟煞','杨显之','元','元曲','yuanqu','','[]','休、休、休，劝君莫把机谋使，现、现、现，东岳新添-个速报司。',419,'元曲/yuanqu.json','["休、休、休，劝君莫把机谋使，现、现、现，东岳新添-个速报司。", "你、你、你，负心人，信有之，咱、咱、咱，薄命妾，自不是。", "快、快、快，就今日，逐离此。", "行、行、行，可怜见，只独自。", "细、细、细心儿里，暗忖思，苦、苦、苦业身躯怎动止？管、管、管少不的在路上停尸。", "(做悲科唱)哎哟，天那？但不知那塌儿里把我来磨勒死？(同解子下)(搽旦云)相公，莫非是你的前妻，敢不中么？不如留他在家，做个使用丫头，也省的人谈论。", "(崔甸士云)夫人不要多心。", "我那里有前妻来？(搽旦云)他适才说，等你嫡亲伯父来，要和你面对。", "这怎么说？(崔甸士云)是我有个亲伯父，叫做崔文远。", "这原是我伯父家丫头，卖与我的。", "你看他模样倒也看的过。", "只是手脚不好要做贼。", "我前日到处寻不着他，今日自来寻我，怎么饶的他过？如今这一去，遇秋天阴雨，棒疮发呵，他也无那活的人也。", "咱和你后堂中饮酒去来。", "(诗云)幸今朝捉住逃奴，迭配去必死中途。", "(搽旦诗云)他若果然是前时妻小，倒不如你也去一搭里当夫。", "(同下)。"]'),
('yuanqu-760','临江驿潇湘秋夜雨・喜迁莺','杨显之','元','元曲','yuanqu','','[]','淋的我走投无路，知他这沙门岛是何处酆都？长吁气成云雾。',67,'元曲/yuanqu.json','["淋的我走投无路，知他这沙门岛是何处酆都？长吁气成云雾。", "行行里着车辙把腿陷住，可又早闪了胯骨。", "怎当这头直上急簌簌雨打，脚底下滑擦擦泥淤。"]'),
('yuanqu-761','临江驿潇湘秋夜雨・出队子','杨显之','元','元曲','yuanqu','','[]','好着我急难移步。',50,'元曲/yuanqu.json','["好着我急难移步。", "淋的来无是处。", "我吃饭时晒干了旧衣服，上路时又淋湿我这布里肚，吃交时掉下了一个枣木梳。"]'),
('yuanqu-762','临江驿潇湘秋夜雨・幺篇','杨显之','元','元曲','yuanqu','','[]','我心中忧虑，有三桩事我命卒。',114,'元曲/yuanqu.json','["我心中忧虑，有三桩事我命卒。", "(解子云)可是那三桩事？你说我听。", "(正旦唱)这云呵，他可便遮天映日闭了郊墟，这风呵，恰便似走石吹沙拔了树木，这雨可，他似箭竿悬麻妆助我十分苦。", "(解子云)你走便走，不走我打你也。", "(正旦云)哥哥。", "(唱)。"]'),
('yuanqu-763','临江驿潇湘秋夜雨・山坡羊','杨显之','元','元曲','yuanqu','','[]','则愿你停嗔息怒，百凡照觑，怎便精唇泼口骂到有三十句。',126,'元曲/yuanqu.json','["则愿你停嗔息怒，百凡照觑，怎便精唇泼口骂到有三十句。", "这路崎岖，水萦纡，急的我战钦钦不敢望前去，况是棒疮发怎支吾？刚挪得半步。", "(带云)哥哥，你便打杀我呵，(唱)你可也没甚福。", "(解子云)你休要多嘴多舌。", "如今秋雨淋漓，一日难走一日。", "快与我行动些。", "(正旦唱)。"]'),
('yuanqu-764','临江驿潇湘秋夜雨・刮地风','杨显之','元','元曲','yuanqu','','[]','则见他努眼撑睛大叫呼，不邓邓气夯胸脯。',140,'元曲/yuanqu.json','["则见他努眼撑睛大叫呼，不邓邓气夯胸脯。", "我湿淋淋只待要巴前路，哎，行不动我这打损的身躯。", "(解子喝科，云)还不走哩。", "(正旦唱)我捱一步又一步何曾停住，这壁厢那壁厢有似江湖。", "则儿那恶风波，他将我紧当处。", "问行人踪迹消疏，似这等白茫茫野水连天暮，(带云)哥哥也。", "(唱)你着我女孩儿怎过去？。"]'),
('yuanqu-765','临江驿潇湘秋夜雨・四门子','杨显之','元','元曲','yuanqu','','[]','告哥哥一一言分诉，那官人是我的丈大。',98,'元曲/yuanqu.json','["告哥哥一一言分诉，那官人是我的丈大。", "我可也说的是实又不是虚。", "寻着他指望成眷属，他别娶了妻道我是奴。", "我委实的衔冤负屈。", "(解子云)这等说起来，是俺那做官的不是？如今我也饶不得你。", "快行动些。", "(正旦唱)。"]'),
('yuanqu-766','临江驿潇湘秋夜雨・古水仙子','杨显之','元','元曲','yuanqu','','[]','他、他、他，忒很毒，敢、敢、敢，昧己瞒心将我图，你、你、你，恶狠狠公隶监束，我、我、我，软揣揣罪人的苦楚。',136,'元曲/yuanqu.json','["他、他、他，忒很毒，敢、敢、敢，昧己瞒心将我图，你、你、你，恶狠狠公隶监束，我、我、我，软揣揣罪人的苦楚。", "痛、痛、痛，嫩皮肤上棍棒数，冷、冷、冷，铁锁在项上拴住，可、可、可，干支剌送的人活地狱，屈、屈、屈，这烦恼待向谁行诉？(带云)哥哥，(唱)来、来、来，你是我的护身符。"]'),
('yuanqu-767','临江驿潇湘秋夜雨・随尾','杨显之','元','元曲','yuanqu','','[]','天与人心紧相助，只我这啼痕向脸儿边厢聚。',53,'元曲/yuanqu.json','["天与人心紧相助，只我这啼痕向脸儿边厢聚。", "(带云)天那天那，(唱)眼见的泪点儿更多，如他那秋夜雨。", "(同下)。"]'),
('yuanqu-768','临江驿潇湘秋夜雨・正宫/端正好','杨显之','元','元曲','yuanqu','','[]','雨如倾，敢则是风如扇。',36,'元曲/yuanqu.json','["雨如倾，敢则是风如扇。", "半空里风雨相缠，雨般儿不顾行人怨，偏打着我头和面。"]'),
('yuanqu-769','临江驿潇湘秋夜雨・伴读书','杨显之','元','元曲','yuanqu','','[]','我这里告解子且消遣，我肚里饥难分辩。',62,'元曲/yuanqu.json','["我这里告解子且消遣，我肚里饥难分辩。", "只他这风风雨雨强将程途来践，走的我筋舒力尽浑身战，一身疼痛十分倦，我、我、我，立盹行眠。"]'),
('yuanqu-770','临江驿潇湘秋夜雨・笑和尚','杨显之','元','元曲','yuanqu','','[]','我、我、我，捱一夜似一年，我、我、我，埋怨天。',81,'元曲/yuanqu.json','["我、我、我，捱一夜似一年，我、我、我，埋怨天。", "我、我、我，敢前生罚尽了凄凉愿？我、我、我，哭干了泪眼，我、我、我，叫破了喉咽。", "来、来、来，哥哥我怎把这烧饼来咽？。"]'),
('yuanqu-771','临江驿潇湘秋夜雨・快活三','杨显之','元','元曲','yuanqu','','[]','我揪将来似死狗牵，兀的不夫乃妇之天？任凭你心能机变口能言，(带云)去来，(唱)到俺老相公行说方便。',49,'元曲/yuanqu.json','["我揪将来似死狗牵，兀的不夫乃妇之天？任凭你心能机变口能言，(带云)去来，(唱)到俺老相公行说方便。"]'),
('yuanqu-772','临江驿潇湘秋夜雨・醉太平','杨显之','元','元曲','yuanqu','','[]','我道你是聪明的卓氏，我道你是俊俏西施，怎肯便手零脚碎窃金赀？这都是崔通来妄指。',140,'元曲/yuanqu.json','["我道你是聪明的卓氏，我道你是俊俏西施，怎肯便手零脚碎窃金赀？这都是崔通来妄指。", "(正旦云)左右，与我快锁了者。", "(搽旦云)阿哟，我戴凤冠霞帔的夫人是好锁的？待我来。", "(除凤冠科，唱)解下了这金花八宝凤冠儿，(脱霞帔科唱)解下这云霞五彩帔肩儿，都送与张家小姐妆台次，我甘心倒做了梅香听使。"]'),
('yuanqu-773','临江驿潇湘秋夜雨・鲍老儿','杨显之','元','元曲','yuanqu','','[]','他是我今世仇家宿世里冤，恨不的生把头来献(崔甸士云)伯父，你与我劝一劝波。',118,'元曲/yuanqu.json','["他是我今世仇家宿世里冤，恨不的生把头来献(崔甸士云)伯父，你与我劝一劝波。", "我如今情愿休了那媳妇，和小姐重做夫妻也。", "(孛老云)小姐，你只饶了他者。", "(正旦唱)我和他有甚恩情相顾恋？待不沙又怕背了这恩人面。", "只落的嗔嗔忿忿，伤心切齿，怒气冲天。"]'),
('yuanqu-774','临江驿潇湘秋夜雨・货郎儿','杨显之','元','元曲','yuanqu','','[]','想着淮河渡翻船的这灾变，也是俺那时乖运蹇，定道是-家大小丧黄泉。',68,'元曲/yuanqu.json','["想着淮河渡翻船的这灾变，也是俺那时乖运蹇，定道是-家大小丧黄泉。", "排岸司救了咱性命，崔老的与我配了姻缘，今日可，谁承望父子和夫妻两事儿全。"]'),
('yuanqu-775','临江驿潇湘秋夜雨・醉太平','杨显之','元','元曲','yuanqu','','[]','不争你亏心的解元，又打着我薄命的婵娟。',90,'元曲/yuanqu.json','["不争你亏心的解元，又打着我薄命的婵娟。", "险些儿做乐昌镜破不重圆，干受了这场罪谴。", "爹爹呵，另巍巍稳掌着森罗殿，崔通呵，喜孜孜还归去秦川县，我翠鸾呵，生刺刺硬踹入武陵源。", "也都是苍天可怜。"]'),
('yuanqu-776','临江驿潇湘秋夜雨・尾煞','杨显之','元','元曲','yuanqu','','[]','从今后鸣琴鼓瑟开欢宴，再休题冒雨汤风苦万千。',101,'元曲/yuanqu.json','["从今后鸣琴鼓瑟开欢宴，再休题冒雨汤风苦万千。", "抵多少待得鸾胶续断弦，把背飞鸟纽回成交颈鸳，隔墙花攀将做并蒂莲。", "你若肯不负文君头白篇，我情愿举案齐眉共百年。", "也非俺只记欢娱不记冤，到底是女孩儿的心肠十分样软。"]'),
('yuanqu-777','四丞相高会丽春堂・仙吕/点绛唇','王实甫','元','元曲','yuanqu','','[]','破虏平戎，灭辽取宋，中原统。',28,'元曲/yuanqu.json','["破虏平戎，灭辽取宋，中原统。", "建四十里金镛，率万国来朝贡。"]'),
('yuanqu-778','四丞相高会丽春堂・油葫芦','王实甫','元','元曲','yuanqu','','[]','则见贝阙蓬壶一望中，从地涌。',82,'元曲/yuanqu.json','["则见贝阙蓬壶一望中，从地涌。", "看了这五云楼阁日华东，恰似那访天台误入桃源洞。", "端的便往扬州移得琼花种。", "胜太子独秀岩，冠神龙万寿峰。", "则他这云间一派箫韶动，不弱似天蕊珠宫。"]'),
('yuanqu-779','四丞相高会丽春堂・天下乐','王实甫','元','元曲','yuanqu','','[]','可正是气压山河百二雄，元也波戎，将军校统。',513,'元曲/yuanqu.json','["可正是气压山河百二雄，元也波戎，将军校统。", "宰臣每为头儿又尽忠，文官每守正直，武将每建大功，到今日可也乐升平，好受用。", "(云)令人报复去，道某家来了也。", "(祗从报科，云)有四丞相来了也。", "(押宴官云)道有请。", "(见科)(押宴官云)老丞相，今奉圣人的命，教俺文武官员今日赴射柳会。", "左右那里，都摆布下了也未？(祗从云)都摆布了也。", "(净扮李圭上，诗云)幼年习兵器，都夸咱武艺，也会做院本，也会唱杂剧。", "要饱一只羊，好酒十瓶醉，听的去厮杀，躲在帐房睡。", "某普察人氏，姓李名圭，见为右副统军使。", "我这官不为那武艺上得的，为我唱得好，弹得好，舞的好。", "今日是蕤宾节令，圣人的命着俺大小官员赴射柳会。", "到那里我便射不着呵，也有我的赏赐。", "可早来到也，令人报复去，道我李监军来了也。", "(祗从报科)(押宴官云)着过来。", "(李圭见科，云)老大人，小子李圭来了也。", "(押宴官云)李监军，你来了也。", "我奉圣人的命，在此押宴。", "左右那里，将这圣人赐来的锦袍玉带。", "若射着的，将这锦袍玉带赏与他。", "先饮酒．射不着的，则饮酒，无赏。", "(祗从云)理会得。", "(押宴官云)老丞相，圣人前日分付操练的军马如何？(正末云)大人，数日前分付老夫操练的军马，都有了也。", "(押宴官云)如今有那几员上将？(正末唱)。"]'),
('yuanqu-780','四丞相高会丽春堂・那吒令','王实甫','元','元曲','yuanqu','','[]','掩如今要取讨呵，有普察副统，要辨真呵，有得满具中，要做准呵，有完颜内奉：非是咱卖蕴藉，夸强勇，端的结束威风。',54,'元曲/yuanqu.json','["掩如今要取讨呵，有普察副统，要辨真呵，有得满具中，要做准呵，有完颜内奉：非是咱卖蕴藉，夸强勇，端的结束威风。"]'),
('yuanqu-781','四丞相高会丽春堂・鹊踏枝','王实甫','元','元曲','yuanqu','','[]','衲袄子绣搀绒，兔鹘碾玉玲珑。',51,'元曲/yuanqu.json','["衲袄子绣搀绒，兔鹘碾玉玲珑。", "一个个跃马扬鞭，插箭弯弓。", "他每那祖宗足斑斓的大虫，料想俺将门下无犬迹狐踪。"]'),
('yuanqu-782','四丞相高会丽春堂・赏花时','王实甫','元','元曲','yuanqu','','[]','万草千花御苑东，簌翠偎红彩绣巾，满地绿茸茸。',38,'元曲/yuanqu.json','["万草千花御苑东，簌翠偎红彩绣巾，满地绿茸茸。", "更打着军兵簇拥，可兀的似锦胡同。"]'),
('yuanqu-783','四丞相高会丽春堂・胜葫芦','王实甫','元','元曲','yuanqu','','[]','不剌刺引马儿先将箭道通，伸猿臂揽银鬃，靶内先知箭有功。',53,'元曲/yuanqu.json','["不剌刺引马儿先将箭道通，伸猿臂揽银鬃，靶内先知箭有功。", "忽的呵弓开秋月，扑的呵箭明飞金电，脱的呵马过似飞熊。"]'),
('yuanqu-784','四丞相高会丽春堂・幺篇','王实甫','元','元曲','yuanqu','','[]','俺只见一缕垂杨落晓风。',93,'元曲/yuanqu.json','["俺只见一缕垂杨落晓风。", "(押宴官云)老丞相射中三箭也。", "将过那锦袍玉带来。", "送与老丞相。", "令人将酒来，老水相满饮-杯。", "(正末唱)人列绣芙蓉，翠袖殷勤捧玉钟。", "赢的这千花锦段，万金玉带，拚却醉颜红。"]'),
('yuanqu-785','四丞相高会丽春堂・中吕/粉蝶儿','王实甫','元','元曲','yuanqu','','[]','山势崔巍，倚晴岚数层金碧，照皇都一片琉璃。',57,'元曲/yuanqu.json','["山势崔巍，倚晴岚数层金碧，照皇都一片琉璃。", "端的个路盘桓，山掩映，堆蓝叠翠。", "俺这里伫立丹梯，则见那广寒宫在五云乡内。"]'),
('yuanqu-786','四丞相高会丽春堂・醉春风','王实甫','元','元曲','yuanqu','','[]','堪写在画图中，又添入诗句里。',54,'元曲/yuanqu.json','["堪写在画图中，又添入诗句里。", "则我这紫藤兜轿趁着浓阴，直等凉些儿个起、起。", "受用足万壑清风，半阶凉影，一襟爽气。"]'),
('yuanqu-787','四丞相高会丽春堂・迎仙客','王实甫','元','元曲','yuanqu','','[]','不知几时节离御苑，多早晚出庭闱，不记得是谁人扶下这白玉梯。',89,'元曲/yuanqu.json','["不知几时节离御苑，多早晚出庭闱，不记得是谁人扶下这白玉梯。", "(押宴宫云)老丞相昨日也不曾饮甚么酒。", "(正末唱)怎当他酬酢处两三巡，揭席时五六杯。", "醉的我将宫锦淋漓，莫不我触犯着尊严罪。"]'),
('yuanqu-788','四丞相高会丽春堂・红绣鞋','王实甫','元','元曲','yuanqu','','[]','金彩凤玲珑翡翠，绣蟠龙璎珞珠玑，他怎生下工夫达着俺那大人机？则俺那仁慈的明圣主，掌-统锦华夷，可则是平安了十万里。',57,'元曲/yuanqu.json','["金彩凤玲珑翡翠，绣蟠龙璎珞珠玑，他怎生下工夫达着俺那大人机？则俺那仁慈的明圣主，掌-统锦华夷，可则是平安了十万里。"]'),
('yuanqu-789','四丞相高会丽春堂・上小楼','王实甫','元','元曲','yuanqu','','[]','且休说白虹贯日，青龙藏地，这剑比那太阿无光，镆铘无神，巨阙无威。',54,'元曲/yuanqu.json','["且休说白虹贯日，青龙藏地，这剑比那太阿无光，镆铘无神，巨阙无威。", "你可你将他小觑的轻微不贵，端的个有吹毛风力。"]'),
('yuanqu-790','四丞相高会丽春堂・幺篇','王实甫','元','元曲','yuanqu','','[]','你的是无价宝，则我的也不是无名器，是祖宗遗留，兄弟相传，辈辈承袭。',94,'元曲/yuanqu.json','["你的是无价宝，则我的也不是无名器，是祖宗遗留，兄弟相传，辈辈承袭。", "(李圭云)老丞相，则怕我如今一回双陆，赢了你这剑可怎了？(正末唱)饶你便会泛迟，快打疾。", "能那能递，怎赢的俺这三辈儿齐天福。"]'),
('yuanqu-791','四丞相高会丽春堂・满道芳','王实甫','元','元曲','yuanqu','','[]','这都是托赖着大人的虎势，赢的他急难措手，打的他马不停蹄，做色数唤点儿皆随意。',368,'元曲/yuanqu.json','["这都是托赖着大人的虎势，赢的他急难措手，打的他马不停蹄，做色数唤点儿皆随意。", "(李圭云)我可生悔气，这色儿不顺，(正末云)你昨日也说马眼叉哩。", "(唱)不比你射柳处也推着马眼迷奚。", "(押宴官云)李监军，你输了这翡翠珠衣也。", "老丞相你饶他一掷波。", "(正末唱)我不觑大人而皮，直赢的他与我跟随。", "(李圭云)你说这大话，赢的我跟随，我和你如今别赌些利物，看那个赢那个输。", "(正末云)我如今再和你打。", "饶你一掷。", "(唱)饶先递。", "(李圭云)我怎么要你饶？(正末唱)则你那赤瓦不刺强嘴，兀白说兵机。", "(押宴官云)你两个便再打一会。", "(李圭云)恰才我翡翠珠衣输与他了，我如今再打一会。", "若输了的，扶一个黑脸，(正末云)我待不和你打，你输了你忍不的这口气，料着我便输了呵，他便怎敢抹我个黑脸？我再和你打。", "(李圭云)也罢，我若赢了呵，搽他小黑脸，也出了这场气。", "咱打来。", "(正末唱)。"]'),
('yuanqu-792','四丞相高会丽春堂・石榴花','王实甫','元','元曲','yuanqu','','[]','紫云堆里月如眉，几点晓星稀，岸滑霜冷玉尘飞。',178,'元曲/yuanqu.json','["紫云堆里月如眉，几点晓星稀，岸滑霜冷玉尘飞。", "已抛下二掷，似啄木寻食。", "从来那捻无凝滞，疾局到底便宜。", "(李圭云)这一盘是我赢了(正末唱)我见他那头盘里打一个无粱意。", "(李圭云)你这马不得到家，可不输了。", "(正末云)则我要一个幺六。", "(做喝科)(李圭云)他喝幺六就是幺六，这骰子是你的骨头做的？(正末唱)口喝着个幺六是赢的。", "(李圭云)可知叫不出，是你输了。", "(正未唱)。"]'),
('yuanqu-793','四丞相高会丽春堂・斗鹌鹑','王实甫','元','元曲','yuanqu','','[]','这本是贱骨无知，怎肯便应声也那做美？不争我连胜连赢。',71,'元曲/yuanqu.json','["这本是贱骨无知，怎肯便应声也那做美？不争我连胜连赢。", "却教你越羞越耻。", "也是我不合单行强出了底。", "便输呵怕甚的。", "虽然是作耍难当，怎敢失了尊卑道理？。"]'),
('yuanqu-794','四丞相高会丽春堂・耍孩儿','王实甫','元','元曲','yuanqu','','[]','这泼徒怎敢将人戏，你托赖着谁人气力，(李圭云)难道我托赖你的气力？(正末唱)睁开你那驴眼可便觑着阿谁？我更歹杀者波是将相的苗裔。',280,'元曲/yuanqu.json','["这泼徒怎敢将人戏，你托赖着谁人气力，(李圭云)难道我托赖你的气力？(正末唱)睁开你那驴眼可便觑着阿谁？我更歹杀者波是将相的苗裔。", "大人呵。", "尚兀自高擎着玉液来酬我，你待浓蘸着霜毫敢抹耻？这厮也个称你那戎职。", "(李圭云)甚么这厮那笋，只管骂谁？(正末云)我不敢骂你，敢打你。", "(做打科，唱)我则待一拳两脚，打的他似土如泥。", "(李圭云)好也，打下我两个门牙来也。", "(押宴官云)你两个不得无礼。", "你既是大臣，怎敢不尊上命！(李圭云)大人可怜见，昨日射柳是他赢了锦袍玉带，今日打双陆，又赢了我翡辈珠衣，我恰才赢了他。", "他就不许我抹黑脸，咱须是赌赛哩。", "(押宴官云)你都回去。", "(正末唱)。"]'),
('yuanqu-795','四丞相高会丽春堂・尾声','王实甫','元','元曲','yuanqu','','[]','我与那左丞相是兄弟，我和你须叔侄。',50,'元曲/yuanqu.json','["我与那左丞相是兄弟，我和你须叔侄。", "若不为圣人言怕搅了香山会，我不打你这泼无徒，可也放不过你。", "(下)。"]'),
('yuanqu-796','四丞相高会丽春堂・越调/斗鹌鹑','王实甫','元','元曲','yuanqu','','[]','闲对着绿树青山，消遣我烦心倦目，潜入那水国渔乡，早跳出龙潭虎窟。',69,'元曲/yuanqu.json','["闲对着绿树青山，消遣我烦心倦目，潜入那水国渔乡，早跳出龙潭虎窟。", "披着领箬笠蓑衣。", "堤防他斜风细雨。", "长则是琴一张，酒-壶，自饮自斟，自歌门舞。"]'),
('yuanqu-797','四丞相高会丽春堂・紫花儿序','王实甫','元','元曲','yuanqu','','[]','也不学刘伶荷锸，也不学屈子投江，且做个范蠡归湖，绕一滩红蓼，过两岸青蒲。',74,'元曲/yuanqu.json','["也不学刘伶荷锸，也不学屈子投江，且做个范蠡归湖，绕一滩红蓼，过两岸青蒲。", "渔夫，将我这小小船儿棹将过去，惊起那几行鸥鹭。", "似这等乐以忘忧，胡必少归欤？。"]'),
('yuanqu-798','四丞相高会丽春堂・小桃红','王实甫','元','元曲','yuanqu','','[]','水声山色两模糊，闲看云来去，则我怨结愁肠对谁诉。',56,'元曲/yuanqu.json','["水声山色两模糊，闲看云来去，则我怨结愁肠对谁诉。", "自踌躇，想这场烦恼都也由咱取。", "感今怀古，旧荣新辱，都装入酒葫芦。"]'),
('yuanqu-799','四丞相高会丽春堂・金蕉叶','王实甫','元','元曲','yuanqu','','[]','撑到这芦花密处，款款将船儿缆住。',35,'元曲/yuanqu.json','["撑到这芦花密处，款款将船儿缆住。", "见垂柳风摇翠缕，荡的这几朵儿荷花似舞。"]'),
('yuanqu-800','四丞相高会丽春堂・调笑令','王实甫','元','元曲','yuanqu','','[]','我向这浅处，扭定身躯。',142,'元曲/yuanqu.json','["我向这浅处，扭定身躯。", "呀，慢慢的将钓儿我便垂将下去，银丝界破波文绿，可怎生浮蝣儿不动纤须？(旦儿云)老爷好快活也。", "(正末做回头科，唱)我这里回头猛然觑艳姝，可知道落雁沉鱼。", "(孤云)小可闻知老丞相在此，特来与老丞相脱闷。", "将酒来，琼英，你唱一曲者。", "(旦儿云)理会的。", "(做唱科)(正末唱)。"]'),
('yuanqu-801','四丞相高会丽春堂・秃厮儿','王实甫','元','元曲','yuanqu','','[]','可人意清歌妙舞，酬吾志美酒鲜鱼。',38,'元曲/yuanqu.json','["可人意清歌妙舞，酬吾志美酒鲜鱼。", "则这春风一枝花解语，似出塞美人图，可便妆梳。"]'),
('yuanqu-802','四丞相高会丽春堂・圣药王','王实甫','元','元曲','yuanqu','','[]','乐有余，饮未足，樽前无酒无衣沽。',46,'元曲/yuanqu.json','["乐有余，饮未足，樽前无酒无衣沽。", "倒玉壶，听〔金缕〕，直吃的满身花影情人扶，我可也不让楚三闾。"]'),
('yuanqu-803','四丞相高会丽春堂・麻郎儿','王实甫','元','元曲','yuanqu','','[]','昨日个深居华屋，今日个流窜荒墟，冷落了歌儿舞女，空闲了宝马香车。',32,'元曲/yuanqu.json','["昨日个深居华屋，今日个流窜荒墟，冷落了歌儿舞女，空闲了宝马香车。"]'),
('yuanqu-804','四丞相高会丽春堂・幺篇','王实甫','元','元曲','yuanqu','','[]','知他是断与甚处外府，则落的绕青山十里平湖。',92,'元曲/yuanqu.json','["知他是断与甚处外府，则落的绕青山十里平湖。", "驾一叶扁舟睡足，抖擞着绿蓑归去。", "(孤云)老丞相也则一时间在此闲居，久后圣人还有任用。", "(正末云)府尹，你不知，老夫为官，不如在此闲居也。", "(唱)。"]'),
('yuanqu-805','四丞相高会丽春堂・东原乐','王实甫','元','元曲','yuanqu','','[]','纵得山林趣，惯将礼法疏，顿忘了马上燕南旧来路。',47,'元曲/yuanqu.json','["纵得山林趣，惯将礼法疏，顿忘了马上燕南旧来路。", "如今拣溪山好处居，为甚么懒归去，被一片野云留住。"]'),
('yuanqu-806','四丞相高会丽春堂・绵搭絮','王实甫','元','元曲','yuanqu','','[]','也无那采薪的樵子，耕种的农夫，往来的商贾，谈笑的鸿儒，做伴的茶药琴棋笔砚书。',63,'元曲/yuanqu.json','["也无那采薪的樵子，耕种的农夫，往来的商贾，谈笑的鸿儒，做伴的茶药琴棋笔砚书。", "秋草人情即惭疏。", "出落的满地江湖，我可也钓贤不钓愚。"]'),
('yuanqu-807','四丞相高会丽春堂・络丝娘','王实甫','元','元曲','yuanqu','','[]','到今日身无所如，想天公也有安排我处。',456,'元曲/yuanqu.json','["到今日身无所如，想天公也有安排我处。", "可不道吕望、严陵自千古，这便算的我春风一度。", "(孤云)老丞相，再饮一杯。", "(旦儿云)妾与老丞相把一杯咱。", "(做递酒科)(使命上，云)小官天朝使命。", "为四丞相贬在济南府歇马，如今草寇作乱，奉圣人的命，着小官直往济南府取他回朝。", "今日到此处，说他在河边钓鱼，不在家中，一径寻来，兀的不是四丞相？左右，接了马者。", "四丞相听圣人的命。", "(孤云)老丞相，天朝使命至也。", "(正末做跪科)(使命云)圣人的命，将你前项罪尽皆饶免。", "今因草寇作乱，着你星夜还朝，将你那在先手下操练过的头目每选拣几个，收捕草寇。", "若收伏了时，依旧着你为右丞相之职。", "望阙谢恩者。", "(正末拜谢科)(使命云)老丞相，恭喜贺喜。", "(正末云)官人每鞍马上驱驰，辛苦了也。", "(使命云)小官索回圣人话去。", "老相不必延迟，早早建功，以慰圣意。", "(正末云)官人稳登前途。", "(使命云)左右的将马来，则今日便回京师去也。", "(下)(孤云)小官说是么，今日果来宣取老丞相，复还旧职也。", "(正末云)我去呵，我则放不过李圭那匹夫。", "(孤云)老丞相，量那李圭，何足道哉。", "(正末唱)。"]'),
('yuanqu-808','四丞相高会丽春堂・拙鲁速','王实甫','元','元曲','yuanqu','','[]','我今日赴京都，见銮舆，也不是我倚仗着功劳，敢喝金吾，其实的瞒不过这近御。',76,'元曲/yuanqu.json','["我今日赴京都，见銮舆，也不是我倚仗着功劳，敢喝金吾，其实的瞒不过这近御。", "我去处便去，那一个闲人敢言语。", "那无徒甚的是通晓兵书，他怎敢我跟前、我跟前无怕惧。"]'),
('yuanqu-809','四丞相高会丽春堂・幺篇','王实甫','元','元曲','yuanqu','','[]','我如今上路途，你听我再嘱付。',70,'元曲/yuanqu.json','["我如今上路途，你听我再嘱付。", "则要你抚恤军卒，爱惜军户，兄弟和睦，伴当宾伏。", "从今一上，有的文书，申到区区，再也不用支吾，你跟前、你跟前敢做主。"]'),
('yuanqu-810','四丞相高会丽春堂・收尾','王实甫','元','元曲','yuanqu','','[]','则我这好山好水难将去，待写入丹青画图。',145,'元曲/yuanqu.json','["则我这好山好水难将去，待写入丹青画图。", "白日里对酒赏无休，到晚来挑灯看不足。", "(下)(孤云)不想天朝使命来，还取的四丞相往京师去了。", "琼英，(旦儿云)有。", "(孤云)我与你将酒肴整备，再到十里长亭，与丞相送行，走一遭去。", "(诗云)香山设宴逞粗豪，久矣闲居更入朝。", "不知此去成功后，李圭头上可能饶。", "(下)。"]'),
('yuanqu-811','四丞相高会丽春堂・乔木查','王实甫','元','元曲','yuanqu','','[]','自别来间阔，幸得俱无恙。',44,'元曲/yuanqu.json','["自别来间阔，幸得俱无恙。", "这里是土长根生父母邦，怎将咱流窜在济南天一方？这些时怎不凄凉？。"]'),
('yuanqu-812','四丞相高会丽春堂・一锭银','王实甫','元','元曲','yuanqu','','[]','玉管轻吹引凤凰，余韵尚悠扬。',34,'元曲/yuanqu.json','["玉管轻吹引凤凰，余韵尚悠扬。", "他将那〔阿那忽〕腔儿合唱，越感起我悲伤。"]'),
('yuanqu-813','四丞相高会丽春堂・相公爱','王实甫','元','元曲','yuanqu','','[]','泪滴千行与万行，那一日不登楼长望。',42,'元曲/yuanqu.json','["泪滴千行与万行，那一日不登楼长望。", "我平也波常，何曾道离故乡，那一日离的我这心儿上？。"]'),
('yuanqu-814','四丞相高会丽春堂・醉娘子','王实甫','元','元曲','yuanqu','','[]','刚道不思量，教人越凄惶。',38,'元曲/yuanqu.json','["刚道不思量，教人越凄惶。", "我家里撇下一个红妆，守着一间空房，如何教我不思量？。"]'),
('yuanqu-815','四丞相高会丽春堂・金字经','王实甫','元','元曲','yuanqu','','[]','早是人寂寞，更那堪更漏长？点点声声被他滴断肠，到晓光。',53,'元曲/yuanqu.json','["早是人寂寞，更那堪更漏长？点点声声被他滴断肠，到晓光。", "到晓光，便道他不断肠，又被这家私上，横枝儿有一万桩。"]'),
('yuanqu-816','四丞相高会丽春堂・山石榴','王实甫','元','元曲','yuanqu','','[]','夫人也，我则道你一身亡，全家丧，三百口老小添悲怆。',81,'元曲/yuanqu.json','["夫人也，我则道你一身亡，全家丧，三百口老小添悲怆。", "我怕你断送了别头项。", "(夫人云)老相公，当初一日，是你的不是也。", "谢圣恩可怜，还取你来家，实是万千之喜。", "(正末唱)。"]'),
('yuanqu-817','四丞相高会丽春堂・幺篇','王实甫','元','元曲','yuanqu','','[]','平白地这一场，从天降。',151,'元曲/yuanqu.json','["平白地这一场，从天降。", "想也不想。", "谁承望，大人也，谁承望又到俺这前厅上。", "(众官云)老夫人，去取的新衣服与老丞相换了者。", "(夫人云)下次孩儿每，将那相公旧日穿的衣服来。", "(杂当云)衣服在此。", "(夫人云)请老相公换了者。", "(正末云)夫人，这是几时做的衣服？(夫人云)老相公，是你旧时穿的衣服。", "(正末云)是呵。", "(唱)。"]'),
('yuanqu-818','四丞相高会丽春堂・雁儿落','王实甫','元','元曲','yuanqu','','[]','你与我拂绰了白象床，整顿了销金帐，高擎着鹦鹉杯，满捧着羊羔酿。',31,'元曲/yuanqu.json','["你与我拂绰了白象床，整顿了销金帐，高擎着鹦鹉杯，满捧着羊羔酿。"]'),
('yuanqu-819','四丞相高会丽春堂・得胜令','王实甫','元','元曲','yuanqu','','[]','准备着翠袖舞《霓裳》，却又早丹诏下茅堂。',206,'元曲/yuanqu.json','["准备着翠袖舞《霓裳》，却又早丹诏下茅堂。", "未见真龙画，先闻宝篆香。", "托赖着君王，高力士休拦挡，我若不斟量，又只怕李太白贬夜郎。", "(使命上，云)听圣人的命，因你有功在前，将你的罪尽皆饶免。", "如今取你回朝，本要差你破除草寇，不想革寇听的你回，都来投降了。", "圣人大喜，教你依旧统军，复你右丞相之职，赐你黄金千两，香酒百瓶，就在丽春堂大吹大擂，做一个庆喜的筵席。", "望阙谢恩者。", "(正末叩谢科)(左相同众官云)老丞相，贺喜。", "(正末昌)。"]'),
('yuanqu-820','四丞相高会丽春堂・风流体','王实甫','元','元曲','yuanqu','','[]','我则道官封做、官封做一字王，位不过、位不过头厅相。',80,'元曲/yuanqu.json','["我则道官封做、官封做一字王，位不过、位不过头厅相。", "想着老无知，老无知焉敢当？(左相云)老丞相你受了官职者，何必太谦？(正末唱)哎，怎比的你左承相，左丞相洪福量。"]'),
('yuanqu-821','四丞相高会丽春堂・古都白','王实甫','元','元曲','yuanqu','','[]','愿陛下圣寿无疆，顿首诚惶。',52,'元曲/yuanqu.json','["愿陛下圣寿无疆，顿首诚惶。", "唬的我手儿脚儿忙也波忙。", "俺如今托赖着君王，可怜我疏狂，直来到宅上，死生应难忘。"]'),
('yuanqu-822','四丞相高会丽春堂・唐兀歹','王实甫','元','元曲','yuanqu','','[]','端的是万万载千秋圣主昌，地久天长。',33,'元曲/yuanqu.json','["端的是万万载千秋圣主昌，地久天长。", "老臣怎敢道不谦让？可是当也波当。"]'),
('yuanqu-823','四丞相高会丽春堂・搅筝琶','王实甫','元','元曲','yuanqu','','[]','他背着些粗荆杖，(众官云)请老丞相责罚他几下。',170,'元曲/yuanqu.json','["他背着些粗荆杖，(众官云)请老丞相责罚他几下。", "(正末唱)谁敢道先打后商量。", "(李圭云)都因那一日与老丞相射柳时的冤仇。", "(正末唱)且休说百步穿杨，我和你九打-盘无梁。", "从今后你也要安详，我也不夸强。", "(李圭云)老丞相打我几下倒等我放下心者。", "(正末唱)休慌，我若是手梢儿在你身上荡，(李圭云)老丞相打几下怕怎么？(正末云)不中。", "(唱)义只怕惹起风霜。"]'),
('yuanqu-824','四丞相高会丽春堂・沽美酒','王实甫','元','元曲','yuanqu','','[]','舞蹁跹翠袖长，击鼍鼓奏笙簧。',37,'元曲/yuanqu.json','["舞蹁跹翠袖长，击鼍鼓奏笙簧。", "高髻云鬟宫样妆，金钗列数行。", "欢声动一座丽春堂。"]'),
('yuanqu-825','四丞相高会丽春堂・太平令','王实甫','元','元曲','yuanqu','','[]','歌〔金缕〕清音嘹亮，品鸾箫余韵悠扬。',55,'元曲/yuanqu.json','["歌〔金缕〕清音嘹亮，品鸾箫余韵悠扬。", "大筵会公卿宰相，早先声把烟尘扫荡。", "从今后四方，八荒，万邦，齐仰贺当今皇上。"]'),
('yuanqu-826','般涉调・耍孩儿庄家不识构阑','杜仁杰','元','元曲','yuanqu','','[]','风调雨顺民安乐，都不似俺庄家快活。',75,'元曲/yuanqu.json','["风调雨顺民安乐，都不似俺庄家快活。", "桑蚕五谷十分收，官司无甚差科。", "当村许下还心愿，来到城中买些纸火。", "正打街头过，见吊个花碌碌纸榜，不似那答儿闹穰穰人多。"]'),
('yuanqu-827','六煞・见一个人手撑着椽做的门，高声的叫“请、请”，道迟来的满了无','杜仁杰','元','元曲','yuanqu','','[]','处停坐。',45,'元曲/yuanqu.json','["处停坐。", "说道：前截儿院本《调风月》，背后幺末敷演《刘耍和》。", "高声叫：赶散易得，难得的妆哈。"]'),
('yuanqu-828','五・要了二百钱放过咱，入得门上个木坡，见层层叠叠团坐。抬头觑是','杜仁杰','元','元曲','yuanqu','','[]','个钟楼模样，往下觑却是人旋窝。',42,'元曲/yuanqu.json','["个钟楼模样，往下觑却是人旋窝。", "见几个妇女向台儿上坐，又不是迎神赛社，不住的擂鼓筛锣。"]'),
('yuanqu-829','四・一个女孩儿转了几遭，不多时引出一伙，中间里一个央人货，裹着枚','杜仁杰','元','元曲','yuanqu','','[]','皂头巾顶门上插一管笔，满脸石灰更着些黑道儿抹。',44,'元曲/yuanqu.json','["皂头巾顶门上插一管笔，满脸石灰更着些黑道儿抹。", "知他待是如何过？浑身上下，则穿领花布直裰。"]'),
('yuanqu-830','三・念了会诗共词，说了会赋与歌，无差错。唇天口地无高下，巧语花言','杜仁杰','元','元曲','yuanqu','','[]','记许多。',21,'元曲/yuanqu.json','["记许多。", "临绝末，道了低头撮脚，爨罢将幺拨。"]'),
('yuanqu-831','二・一个妆做张太公，他改做小二哥，行、行、行，说向城中过。见个年','杜仁杰','元','元曲','yuanqu','','[]','少的妇女向帘儿下立，那老子用意铺谋待取做老婆。',46,'元曲/yuanqu.json','["少的妇女向帘儿下立，那老子用意铺谋待取做老婆。", "教小二哥相说合，但要的豆谷米麦，问甚布绢纱罗。"]'),
('yuanqu-832','尾・则被一胞尿，爆的我没奈何。刚捱刚忍更待看些儿个，枉被这驴颓笑','杜仁杰','元','元曲','yuanqu','','[]','杀我。',88,'元曲/yuanqu.json','["杀我。", "喻情我当初不合鬼擘口和你言盟誓，惹得你鬼病厌厌挂体。", "鬼相扑不曾使甚养家钱，鬼厮赴刁蹬的心灰。", "若是携得歌妓家中去，便是袖得春风马上归。", "司狱司蹬弩劳神力，望梅止渴，画饼充饥。"]'),
('yuanqu-833','哨遍・铁球儿漾在江心内，实指望团圆到底。失群孤雁往南飞，比目鱼永','杜仁杰','元','元曲','yuanqu','','[]','不分离。',47,'元曲/yuanqu.json','["不分离。", "王屠倒脏牵肠肚，毛宝心毒不放龟。", "老母狗跳墙做得个扌央势，把我做扑灯蛾相戏，掠水燕双飞。"]'),
('yuanqu-834','五煞・腊月里桑采甚的，肚脐里爆豆实心儿退。木猫儿守窟瞧他甚，泥狗','杜仁杰','元','元曲','yuanqu','','[]','儿看家守甚黑。',28,'元曲/yuanqu.json','["儿看家守甚黑。", "天长观里看水庵相识，济元庙里口愿把我抛持。"]'),
('yuanqu-835','四・唐三藏立墓铭空费了碑，闲槽枋里躲酒无巴避。悲田院里下象无钱递，','杜仁杰','元','元曲','yuanqu','','[]','左右司蒸糕省做媒。',37,'元曲/yuanqu.json','["左右司蒸糕省做媒。", "蓼儿洼里太庙干不济，郑元和在曲江边担土，闲话儿把咱支持。"]'),
('yuanqu-836','三・泥捏的山不信是石，相扑汉卖药干陪了擂。镜台前照面你是你，警巡','杜仁杰','元','元曲','yuanqu','','[]','院倒了墙贼见贼。',28,'元曲/yuanqu.json','["院倒了墙贼见贼。", "大虫窝里蒿草无人刈，看山瞎汉，不辨高低。"]'),
('yuanqu-837','一・秦始皇鞋无道履，绵带子拴腿无绳系。开花仙藏ㄓ过瞒得你，街道司','杜仁杰','元','元曲','yuanqu','','[]','衙门唬得过谁。',28,'元曲/yuanqu.json','["衙门唬得过谁。", "尉迟恭捣米胡支对，蜂窝儿呵欠，口口是虚脾。"]'),
('yuanqu-838','尾・楮树下梯要摘梨，葬瓶中灰骨是个不自由的鬼，谷地里瓜儿单单的记','杜仁杰','元','元曲','yuanqu','','[]','着你。',3,'元曲/yuanqu.json','["着你。"]'),
('yuanqu-839','集贤宾南・今宵两星相会期，正乞巧投机。沉李浮瓜肴馔美，把几个摩诃','杜仁杰','元','元曲','yuanqu','','[]','罗儿摆起。',18,'元曲/yuanqu.json','["罗儿摆起。", "齐拜礼，端的是塑得来可嬉。"]'),
('yuanqu-840','凤鸾吟北・月色辉，夜将阑银汉低，斗穿针逞艳质。喜蛛儿奇，一丝丝往','杜仁杰','元','元曲','yuanqu','','[]','下垂，结罗成巧样势。',53,'元曲/yuanqu.json','["下垂，结罗成巧样势。", "酒斟着绿蚁，香焚着麝脐，引杯觞大家沉醉。", "樱桃妒水底红，葱指剖冰瓜脆，更胜似爱月夜眠迟。"]'),
('yuanqu-841','斗双鸡南・金钗坠、金钗坠玳瑁整齐，蟠桃宴、蟠桃宴众仙聚会。彩衣、','杜仁杰','元','元曲','yuanqu','','[]','彩衣轻纱织翠，禁步摇绣带垂，但愿得同欢宴团圆到底。',25,'元曲/yuanqu.json','["彩衣轻纱织翠，禁步摇绣带垂，但愿得同欢宴团圆到底。"]'),
('yuanqu-842','节节高北・玉葱纤细，粉腮娇腻。争妍斗巧，笑声举，欢天喜地。我则见','杜仁杰','元','元曲','yuanqu','','[]','管弦齐动，商音夷则。',25,'元曲/yuanqu.json','["管弦齐动，商音夷则。", "遥天外斗渐移，喜阴晴今宵七夕。"]'),
('yuanqu-843','耍鲍老南・团圈笑令心尽喜，食品愈稀奇。新摘的葡萄紫，旋剥的鸡头美，','杜仁杰','元','元曲','yuanqu','','[]','珍珠般嫩实。',59,'元曲/yuanqu.json','["珍珠般嫩实。", "欢坐间，夜凉人静已，笑声接青霄内。", "风淅淅，雨霏霏，露湿了弓鞋底。", "纱笼罩仕女随，灯影下人扶起，尚留恋懒心回。"]'),
('yuanqu-844','四门子北・画堂深，寂寂重门闭，照金荷红蜡辉。斗柄又横，月色又西，','杜仁杰','元','元曲','yuanqu','','[]','醉乡中不知更漏迟。',25,'元曲/yuanqu.json','["醉乡中不知更漏迟。", "士庶每安，烽燧又息，愿吾皇万岁。"]'),
('yuanqu-846','双调・蝶恋花','杜仁杰','元','元曲','yuanqu','','[]','鸥鹭同盟曾自许，怕见山英，怪我来何暮？风度修然林下去，琴书共作烟霞侣。',35,'元曲/yuanqu.json','["鸥鹭同盟曾自许，怕见山英，怪我来何暮？风度修然林下去，琴书共作烟霞侣。"]'),
('yuanqu-848','金娥神曲・世俗，看取，花样巧番机杼。乾坤腐儒，天地逆旅，自叹难合','杜仁杰','元','元曲','yuanqu','','[]','时务！。',4,'元曲/yuanqu.json','["时务！。"]'),
('yuanqu-849','四・至如，有些官禄，辨甚么贤共愚。更那，有些金玉，识甚么亲共疏？','杜仁杰','元','元曲','yuanqu','','[]','命福，有些乘除，问甚么有共无！。',16,'元曲/yuanqu.json','["命福，有些乘除，问甚么有共无！。"]'),
('yuanqu-850','瘸李岳诗酒玩江亭・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','则我这宝篆氤氲，麝兰香喷，家滋润。',31,'元曲/yuanqu.json','["则我这宝篆氤氲，麝兰香喷，家滋润。", "瑞气迎门，端的是人物偏丰韵。"]'),
('yuanqu-851','瘸李岳诗酒玩江亭・金盏儿','无名氏','元','元曲','yuanqu','','[]','你则是怕当军，倦为民，两桩儿曾与高人论。',70,'元曲/yuanqu.json','["你则是怕当军，倦为民，两桩儿曾与高人论。", "你有则得半仙之分，你更不全真。", "速离了八仙洞，飞下那九天门。", "你则是个逍遥云外客，特地来点化俺这世间人。"]'),
('yuanqu-852','瘸李岳诗酒玩江亭・尾声','无名氏','元','元曲','yuanqu','','[]','俺这梅他粉包了心，檀黄嫩，插在那银瓶里宜得水温，如麝如兰香喷喷，端的有欺霜傲雪的精神。',102,'元曲/yuanqu.json','["俺这梅他粉包了心，檀黄嫩，插在那银瓶里宜得水温，如麝如兰香喷喷，端的有欺霜傲雪的精神。", "哎，你个许真人，白日飞升，比不的岳阳楼下枯干了的柳树神。", "他也无那神仙的福分，则有些江梅丰韵，冷清清今夜待黄昏。", "(下)。"]'),
('yuanqu-853','瘸李岳诗酒玩江亭・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','良辰晓雾浓，美景韶光丽。',64,'元曲/yuanqu.json','["良辰晓雾浓，美景韶光丽。", "草茵轻荏苒，则他这桃李任芳菲。", "春日迟迟，槛外黄莺呖，帘前紫燕飞。", "幸开怀宴乐欢娱，俺可便宜赏玩，情甘意美。"]'),
('yuanqu-854','瘸李岳诗酒玩江亭・十二月','无名氏','元','元曲','yuanqu','','[]','穿的是麻袍和这草履，(云)呸！是草鞋，错唱了草履。',212,'元曲/yuanqu.json','["穿的是麻袍和这草履，(云)呸！是草鞋，错唱了草履。", "便也罢，则是难为我唱了，从头都改过哩。", "也罢，也罢，一言既出，驷马追而不及。", "我若不改了，显的我就无才学了。", "(唱)穿的是麻袍和这草鞋，更强似着绿穿白。", "我伴的是鲇鱼和这鲤鱼，铺的是杆草茅柴。", "采的是不老长生的药材，俺可便每日家厮捱，(云)你不知道怎么捱，俺师父有两个徒弟，一递一日打柴。", "他打柴，我学道。", "我打柴，他学道。", "该我我便去，该他他便去。", "他不去，我肯去。", "(唱)俺可便每日家厮捱。"]'),
('yuanqu-855','瘸李岳诗酒玩江亭・尧民歌','无名氏','元','元曲','yuanqu','','[]','我则待要引着狗骑着猫逍遥散澹乘兴歌曲过南台，(云)我是出家人，我心里待要往南台，就往南台，要往北闸口去，谁敢当拦住我？(唱)我则待靠着水偎着山小小低低急留圪刺椽',168,'元曲/yuanqu.json','["我则待要引着狗骑着猫逍遥散澹乘兴歌曲过南台，(云)我是出家人，我心里待要往南台，就往南台，要往北闸口去，谁敢当拦住我？(唱)我则待靠着水偎着山小小低低急留圪刺椽儿捧儿拴拴抓抓盖一座茅庐那幽哉。", "一似那乱纷纷急穰穰蜂衙蚁阵受禁害，稽首，则不如跟贫道打简子掴渔鼓抢着吃挝着吃抹油嘴无扰无虑那开怀。", "伤也波哉，寻着李太白，我着你便一个人生一身疥。"]'),
('yuanqu-856','瘸李岳诗酒玩江亭・锦上花','无名氏','元','元曲','yuanqu','','[]','则不如我展放开愁眉，休争闲气。',94,'元曲/yuanqu.json','["则不如我展放开愁眉，休争闲气。", "今日容颜，老似昨日。", "古往今来，我须尽知。", "贤的愚的。", "贫的共富的，到头这一场，难逃那一日。", "则不如快活了一日，一日便宜。", "百岁光阴，七十又早稀。", "咸的酸的，香的共臭的。"]'),
('yuanqu-857','瘸李岳诗酒玩江亭・隔尾','无名氏','元','元曲','yuanqu','','[]','你挟着这半截家竹桶闲行立，你可甚么一部笙歌出入随。',70,'元曲/yuanqu.json','["你挟着这半截家竹桶闲行立，你可甚么一部笙歌出入随。", "几曾见子弟舍里新添了个八仙队。", "不争你在这里，俺门前立地，着人道出落着你个先生少可有二十嘴。"]'),
('yuanqu-858','瘸李岳诗酒玩江亭・红芍药','无名氏','元','元曲','yuanqu','','[]','你和他每日炼修持，可待要说是谈非。',168,'元曲/yuanqu.json','["你和他每日炼修持，可待要说是谈非。", "(牛员外云)俺师徒二人，这一向在山中修炼。", "师父也离不的我，我也离不的师父，吃饭的工夫也没了。", "(正旦唱)你与他每日不曾离，直这般废寝忘食。", "(牛员外云)我与你做个师父，你与我做个徒弟，我把手捏腕，传与你金丹大道，可是如何？(正旦唱)我则道因个甚的。", "我这里便谢吾师说破玄机。", "厮抹着肩胛手相携，说您那弄盏传杯。"]'),
('yuanqu-859','瘸李岳诗酒玩江亭・菩萨梁州','无名氏','元','元曲','yuanqu','','[]','你道是先生，与你回席，灌的你十分沉醉。',170,'元曲/yuanqu.json','["你道是先生，与你回席，灌的你十分沉醉。", "长留做共薄醅，真乃是水酒三杯。", "(先生上，云)牛郎说与赵江梅。", "(牛员外做吃惊科，云)道可道，非常道；名可名，非常名。", "(笑科)(正旦唱)你道是牛郎说与赵江梅，(云)可也怪不着也。", "(唱)你可甚么一枝泄漏春消息。", "他别人铜斗儿般好家计，指空划空信着你，你搬调的他弃子抛妻。", "(先生云)他不合说与外人知。", "(正旦唱)。"]'),
('yuanqu-860','瘸李岳诗酒玩江亭・贺新郎','无名氏','元','元曲','yuanqu','','[]','你道是他不合说与外人知，(先生云)打这厮口发虚言。',188,'元曲/yuanqu.json','["你道是他不合说与外人知，(先生云)打这厮口发虚言。", "(正旦唱)你打他口发虚言，你大古里脚踏着实地。", "(先生云)我踏罡步斗驱邪祟，仗着剑书符咒水。", "(正旦唱)则你那踏罡步斗驱邪祟，你杖剑书符也那咒水，休阿则你那不济事谎话儿休题。", "(先生云)跟我出家去呵，我着你全身无病疾，远害免灾危。", "(正旦唱)你着俺全身无病疾，远害免灾危，见如今拄着一条粗拐瘸着一条腿。", "那些个满川缚虎意，犹自说兵机！。"]'),
('yuanqu-861','瘸李岳诗酒玩江亭・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','今日个横饮金瓯。',79,'元曲/yuanqu.json','["今日个横饮金瓯。", "吃的来醉醺醺不知一个前后，(云)若见俺牛员外呵，(唱)我和他话不相投。", "我可便见他呵，相逢处，这一场迤逗。", "将他那衣快忙揪。", "拽起运绿罗裙揎拳裸袖。"]'),
('yuanqu-862','瘸李岳诗酒玩江亭・石榴花','无名氏','元','元曲','yuanqu','','[]','你道是将恩爱变为仇。',173,'元曲/yuanqu.json','["你道是将恩爱变为仇。", "(牛员外云)我随缘过的便合休。", "(正旦唱)你道是随缘过的便合休，(牛员外云)我与你做个师父。", "(正旦唱)打一个稽首，(牛员外云)兀的不是也。", "(正旦唱)便要回头。", "(牛员外云)我清风明月为知友。", "(正旦唱)倚仗着你清风明月为知友，那的是阆苑神洲。", "(牛员外云)我每日家麻绦草履垂袍袖。", "(正旦唱)你道你那麻绦草履垂袍袖，这的是你拄杖恰过头。"]'),
('yuanqu-863','瘸李岳诗酒玩江亭・十二月','无名氏','元','元曲','yuanqu','','[]','你可便坚心儿强口，他可便不害那惭羞。',94,'元曲/yuanqu.json','["你可便坚心儿强口，他可便不害那惭羞。", "(牛员外云)我这般躬身叉手。", "曲脊低头，背着你，街上人都捻舌，排说我哩。", "(正旦唱)长街上躬身叉手，我见他便曲脊低头。", "长街上惹的人家嘴口，不争你厌背着娇羞。"]'),
('yuanqu-864','瘸李岳诗酒玩江亭・尧民歌','无名氏','元','元曲','yuanqu','','[]','呀，着人道牧童归去倒骑牛，呀，敢抵多少一千个刘盼盼闹衡州。',114,'元曲/yuanqu.json','["呀，着人道牧童归去倒骑牛，呀，敢抵多少一千个刘盼盼闹衡州。", "这的是前街后巷滴滴蹬蹬马和牛，这的是恋酒迷花风风魔魔下场头。", "(牛员外云)我如今去见了师父说知，着你跟我也做神仙去。", "(正旦唱)休也波诌，待学马半州，去也我可也做不的刘行首。"]'),
('yuanqu-865','瘸李岳诗酒玩江亭・耍孩儿','无名氏','元','元曲','yuanqu','','[]','我身将跨凤乘鸾友，都做了参辰卯酉。',123,'元曲/yuanqu.json','["我身将跨凤乘鸾友，都做了参辰卯酉。", "(牛员外云)我如今等闲恩爱等闲休。", "(正旦唱)你道是等闲恩爱等闲休，空着咱一任难酬。", "(牛员外云)我如今饱谙世事慵开口。", "(正旦唱)你如今饱谙世事慵开口，会尽人间只点头。", "把浮生梦都参透，撇了这酒色财气，真个是谭马丘刘。"]'),
('yuanqu-866','瘸李岳诗酒玩江亭・二煞','无名氏','元','元曲','yuanqu','','[]','我为甚先打你这头？(牛员外云)你为何赠我这一击。',137,'元曲/yuanqu.json','["我为甚先打你这头？(牛员外云)你为何赠我这一击。", "怎么说？(正旦唱)我则是到来年吃贱牛，则你那一天和气恩情厚。", "你行处春日风动，你过处春山春水流，你模佯忒出丑。", "(牛员外云)我模样忒出丑？哦，他也则是嗓磕我这牛哩。", "你再有何比并？(正旦唱)你抛了这朝云暮雨，则恐怕误了你那春种秋收。"]'),
('yuanqu-867','瘸李岳诗酒玩江亭・尾声','无名氏','元','元曲','yuanqu','','[]','准备着硬绳去你那鼻窍里穿，(牛员外云)你怎生则嗓磕我这牛？(正旦唱)粗鞭杖把你那胯骨上丢。',76,'元曲/yuanqu.json','["准备着硬绳去你那鼻窍里穿，(牛员外云)你怎生则嗓磕我这牛？(正旦唱)粗鞭杖把你那胯骨上丢。", "则你那偷寒送暖村皮肉，我教你绰见我这庞儿望风儿似走。", "(同下)。"]'),
('yuanqu-868','瘸李岳诗酒玩江亭・双调/新水令','无名氏','元','元曲','yuanqu','','[]','则您这出家儿受用似比那富家郎，哎，你个鼓盆歌老先生休强。',70,'元曲/yuanqu.json','["则您这出家儿受用似比那富家郎，哎，你个鼓盆歌老先生休强。", "吃了些无是非的稀解粥，忍了些受饥饿瘦皮囊。", "空着我腹热肠慌，则不如葫芦提吃的来粉红样。"]'),
('yuanqu-869','瘸李岳诗酒玩江亭・川拨棹','无名氏','元','元曲','yuanqu','','[]','这厮狠心肠，没道理别势样。',95,'元曲/yuanqu.json','["这厮狠心肠，没道理别势样。", "好教我急急忙忙，腹热肠慌。", "(牛员外云)阿，罢了，歪了船，淹上水来了。", "踏着这边晃一晃，看他怕也不怕。", "(正旦唱)这晰他撑的个小船儿摇摇晃晃，我心中慌上慌，我心中忙上忙。"]'),
('yuanqu-870','瘸李岳诗酒玩江亭・七兄弟','无名氏','元','元曲','yuanqu','','[]','这厮便指望，大纲要成双，(牛员外云)你走的那里去？(正旦唱)百般的不肯将咱放。',58,'元曲/yuanqu.json','["这厮便指望，大纲要成双，(牛员外云)你走的那里去？(正旦唱)百般的不肯将咱放。", "身躯儿左右怎遮拦，手脚儿怎生难遮当？。"]'),
('yuanqu-871','瘸李岳诗酒玩江亭・梅花酒','无名氏','元','元曲','yuanqu','','[]','呀，谁承望这一场，我恰才身命在长江。',100,'元曲/yuanqu.json','["呀，谁承望这一场，我恰才身命在长江。", "面对看沙滩。", "空腹热肠慌。", "不见卷云涛波浩浩，翻滚滚水茫茫。", "谁承望这一场，(先生上，云)赵江梅，你省也么？(正旦云)师父，弟子省也。", "(唱)我则道是画眉郎，睡梦里厮魔障。"]'),
('yuanqu-872','瘸李岳诗酒玩江亭・喜江南','无名氏','元','元曲','yuanqu','','[]','呀，今日个刘行首省悟也波马丹阳，不求白日赴仙乡，落花深处水茫茫。',50,'元曲/yuanqu.json','["呀，今日个刘行首省悟也波马丹阳，不求白日赴仙乡，落花深处水茫茫。", "俺可便玩赏，今日个拜三清同赴上天堂。"]'),
('yuanqu-873','沙门岛张生煮海・仙吕/点绛唇','李好古','元','元曲','yuanqu','','[]','海水汹汹，晚风微送，兼天涌。',27,'元曲/yuanqu.json','["海水汹汹，晚风微送，兼天涌。", "不辨四东，把凌波步轻那动。"]'),
('yuanqu-874','沙门岛张生煮海・混江龙','李好古','元','元曲','yuanqu','','[]','清宵无梦，引着这小精灵，闲伴我游踪。',136,'元曲/yuanqu.json','["清宵无梦，引着这小精灵，闲伴我游踪。", "恰离了澄澄碧海，遥望那耿耿长空。", "你看那万朵彩云生海上，一轮皓月映波中。", "(侍女云)海中景物，与人间敢不同么？(正旦唱)觑了那人间风阙，怎比我水国龙宫？清湛湛、洞天福地任逍遥，碧悠悠、那愁他浴凫飞雁争喧哄。", "似俺这闺情深远，直恁般好信难通！。"]'),
('yuanqu-875','沙门岛张生煮海・油葫芦','李好古','元','元曲','yuanqu','','[]','海上神仙年寿永，这蓬莱在眼界中。',104,'元曲/yuanqu.json','["海上神仙年寿永，这蓬莱在眼界中。", "风飘仙袂绛绡红，则我这云鬟高挽金钗重，蛾眉轻展花钿动。", "袖儿笼，指十葱，裙儿簌，鞋半弓。", "只待学吹箫同跨丹山凤，那其间，登碧落，趁天风。", "(侍女云)想天上人间，自然难比。", "(正旦唱)。"]'),
('yuanqu-876','沙门岛张生煮海・天下乐','李好古','元','元曲','yuanqu','','[]','不比那人世繁华扫地空，尘中，似转蓬，则他这春过夏来秋又冬。',54,'元曲/yuanqu.json','["不比那人世繁华扫地空，尘中，似转蓬，则他这春过夏来秋又冬。", "听一声报晓鸡，听一声定夜钟，断送的他世间人犹未懂。"]'),
('yuanqu-877','沙门岛张生煮海・那吒令','李好古','元','元曲','yuanqu','','[]','听疏剌剌晚风，风声落万松；明朗朗月容，容光照半空；响潺潺水冲，冲流绝涧中。',68,'元曲/yuanqu.json','["听疏剌剌晚风，风声落万松；明朗朗月容，容光照半空；响潺潺水冲，冲流绝涧中。", "又不是采莲女拨棹声，又不是捕鱼叟鸣榔动，惊的那夜眠人睡眼朦胧。"]'),
('yuanqu-878','沙门岛张生煮海・寄生草','李好古','元','元曲','yuanqu','','[]','他一字字情无限，一声声曲未终。',74,'元曲/yuanqu.json','["他一字字情无限，一声声曲未终。", "恰便似颤巍巍金菊秋风动，香馥馥丹桂秋风送，响珊珊翠竹秋风弄。", "咿呀呀，偏似那织金梭撺断锦机声；滴溜溜，舒春纤乱撒珍珠进。"]'),
('yuanqu-879','沙门岛张生煮海・六幺序','李好古','元','元曲','yuanqu','','[]','表诉那弦中语，出落着指下功，胜檀槽慢掇轻拢。',92,'元曲/yuanqu.json','["表诉那弦中语，出落着指下功，胜檀槽慢掇轻拢。", "则见他正色端容，道貌仙丰。", "莫不是汉相如作客临邛，也待要动文君，曲奏求凰风；不由咱不引起情浓。", "你听这清风明月琴三弄，端的个金徽汹涌，玉轸玲珑。"]'),
('yuanqu-880','沙门岛张生煮海・幺篇','李好古','元','元曲','yuanqu','','[]','端的心聪，那更神工，悲若鸣鸿，切若寒蛩，娇比花容，雄似雷轰，真乃是消磨了闲愁万种。',100,'元曲/yuanqu.json','["端的心聪，那更神工，悲若鸣鸿，切若寒蛩，娇比花容，雄似雷轰，真乃是消磨了闲愁万种。", "这秀才一事精，百事通。", "我蹑足潜踪，他换羽移宫。", "抵多少盼盼女词媚涪翁。", "似良宵一枕游仙梦。", "因此上偷窥方丈，非是我不守房栊。"]'),
('yuanqu-881','沙门岛张生煮海・金盏儿','李好古','元','元曲','yuanqu','','[]','家住在碧云空，绿波中，有披鳞带角相随从，深居富贵水晶宫。',488,'元曲/yuanqu.json','["家住在碧云空，绿波中，有披鳞带角相随从，深居富贵水晶宫。", "我便是海中龙氏女，胜似那天上许飞琼。", "岂不知众星皆拱北，无水不朝东？(张生云)小娘子姓龙氏，我记得何承天《姓苑》上有这个姓来。", "难道小娘子既然有姓，岂可无名？因甚至此？(正旦云)妾身龙氏三娘，小字琼莲。", "见秀才弹琴，因听琴至此。", "(张生云)小娘子既为听琴而至，这等，是赏音的了。", "何不到书房中坐下，待小生细弹一曲，何如？(正旦云)愿往。", "(做到书房科，正旦云)敢问先生高姓？(张生云)小生姓张名羽，字伯腾，潮州人氏。", "早年父母双亡，也曾饱学诗书，争奈功名未遂，游学至此，并无妻室。", "(侍女云)这秀才好没来头，谁问你有妻无妻哩！(家童云)不则是相公，我也无妻。", "(张生云)小娘子不弃小生贫寒，肯与小生为妻么？(正旦云)我见秀才聪明智慧，丰标俊雅，一心愿与你为妻。", "则是有父母在堂，等我问了时，你到八月十五日中秋节届，前来我家，招你为婿。", "(张生云)既蒙小娘子俯允，只不如今夜便成就了，何等有趣，着小生几时等到八月十五日也！(家童云)正是，我也等不得。", "(侍女云)你等不得，且是容易哩。", "(正旦云)常言道：\"有情何怕隔年期\"，这有甚等不得那？(唱)。"]'),
('yuanqu-882','沙门岛张生煮海・后庭花','李好古','元','元曲','yuanqu','','[]','那里也阳台云雨踪，不比那秦楼风月丛。',190,'元曲/yuanqu.json','["那里也阳台云雨踪，不比那秦楼风月丛。", "(张生云)敢问小娘子家在何处？(正旦唱)只在这沧海三千丈，险似那巫山十二峰。", "(张生云)小生做贵宅女婿，就做了富贵之郎，不知可有人服侍么？(正旦唱)俺可更有门风：无非足蛟虬参从，还有那鼋将军、鳖相公、鱼大人、虾爱宠、鼍先锋、龟老翁。", "能浮波，惯弄风；隔云山，千万重；要相逢，指顾中。", "(张生云)只要小娘子言而有信，俺小生是一个志诚老实的。", "(正旦唱)。"]'),
('yuanqu-883','沙门岛张生煮海・梁州第七','李好古','元','元曲','yuanqu','','[]','你看那缥缈间十洲三岛，微茫处阆苑蓬莱，望黄河一股儿浑流派。',161,'元曲/yuanqu.json','["你看那缥缈间十洲三岛，微茫处阆苑蓬莱，望黄河一股儿浑流派。", "高冲九曜，远映三台，上连银汉，下接黄埃。", "势汪洋无岸无涯，出许多异宝奇哉。", "看、看、看，波涛涌，光隐隐无价珠玑；是、是、是，草木氏，香喷喷长生药材；有、有、有，蛟龙偃，郁沉沉精怪灵胎。", "常则是云昏气霭，碧油油隔断红尘界，恍疑在九天外。", "平吞了八九区云梦泽，问甚么翠岛苍崖。"]'),
('yuanqu-884','沙门岛张生煮海・牧羊关','李好古','元','元曲','yuanqu','','[]','猛地里难回避，可教人怎离摘？则见他叉手前来，多管是迷了路的行人，多管是失了船的过客。',130,'元曲/yuanqu.json','["猛地里难回避，可教人怎离摘？则见他叉手前来，多管是迷了路的行人，多管是失了船的过客。", "(张生云)道姑，敢问这搭儿是何处也？(仙姑唱)比及你来相问，先对俺说明白。", "(张生云)我到此，只为那可意人儿，不知在那里？(仙姑唱)且将个采芝女，权休怪，只问那可意人，安在哉？。"]'),
('yuanqu-885','沙门岛张生煮海・骂玉郎','李好古','元','元曲','yuanqu','','[]','可知道龙宫美女多娇态，想当时因有约，则今日独寻来，拚的个舍残生，做下风流债。',81,'元曲/yuanqu.json','["可知道龙宫美女多娇态，想当时因有约，则今日独寻来，拚的个舍残生，做下风流债。", "那龙也青脸儿长左猜，恶性儿无可解，狠势儿将人害。", "(张生云)可怎生恁般利害？(仙姑唱)。"]'),
('yuanqu-886','沙门岛张生煮海・感皇恩','李好古','元','元曲','yuanqu','','[]','呀！他把那牙爪张开，头角轻抬。',71,'元曲/yuanqu.json','["呀！他把那牙爪张开，头角轻抬。", "一会儿起波涛，一会儿摧山岳，一会儿卷江淮。", "变大呵，乾坤中较窄；变小呵，芥子里藏埋。", "他可便能英勇，显神通，放狂乖。"]'),
('yuanqu-887','沙门岛张生煮海・采茶歌','李好古','元','元曲','yuanqu','','[]','他兴云雾，片时来，动风雨，满尘埃，则怕惊急烈一命丧尸骸。',51,'元曲/yuanqu.json','["他兴云雾，片时来，动风雨，满尘埃，则怕惊急烈一命丧尸骸。", "休为那约雨期云龙氏女，送了你个攀蟾折桂俊多才。"]'),
('yuanqu-888','沙门岛张生煮海・黄钟煞尾','李好古','元','元曲','yuanqu','','[]','这宝呵。',115,'元曲/yuanqu.json','["这宝呵。", "出八那瑶台紫府清虚界，碧落苍空天上来。", "任熬煎，任布划，可从心，可称怀，不求亲，不纳财，做行媒，做娇客，连理枝，并蒂开，凤鸾交，鱼水谐，休将他，觑小哉，信神仙，妙手策。", "也是那前生福有安排，直着你沸汤般煎干了这大洋海。", "(下)。"]'),
('yuanqu-889','沙门岛张生煮海・正宫/端正好','李好古','元','元曲','yuanqu','','[]','一地里受煎熬，遍寰宇空劳攘，兀的不慌杀了海上龙王。',47,'元曲/yuanqu.json','["一地里受煎熬，遍寰宇空劳攘，兀的不慌杀了海上龙王。", "我则见水晶宫血气从空撞，闻不得鼻口内干烟炝。"]'),
('yuanqu-890','沙门岛张生煮海・滚绣球','李好古','元','元曲','yuanqu','','[]','那秀才谁承望，急煎煎做这场，不知他挟着的甚般伎俩，只待要卖弄杀手段高强。',246,'元曲/yuanqu.json','["那秀才谁承望，急煎煎做这场，不知他挟着的甚般伎俩，只待要卖弄杀手段高强。", "莫不是放火光，逼太阳，烧的来焰腾腾滚波翻浪。", "纵有那雷和雨，也救不得惊惶。", "则见锦鳞鱼活泼刺波心跳，银脚蟹乱扒沙在岸上藏，但着一点儿，就是一个燎浆。", "(做到科，云)来到此间，正是沙门岛海岸了。", "兀那秀才，你在此煮着些甚么哩？(张生云)我煮海也。", "(正末云)你煮他那海做甚么？(张生云)老师父不知，小生前夜在于寺中操琴，有一女子前来窃听，他说是龙氏三娘，小字琼莲，亲许我中秋会约。", "不见他来，因此在这里煮海，定要煎他出来。", "(正末唱)。"]'),
('yuanqu-891','沙门岛张生煮海・滚绣球','李好古','元','元曲','yuanqu','','[]','俺也不是化道粮，也不是要供养，我则是特来相访。',310,'元曲/yuanqu.json','["俺也不是化道粮，也不是要供养，我则是特来相访。", "(张生云)我是个穷秀才，相访我有甚么化与你。", "(正末唱)俺本是出家人，便乞化何妨。", "(张生云)若得见那小娘子，肯招我做女婿，便有布施。", "(正末唱)则为那窈窕娘，不招你个俊俏郎，弄出这一番祸从天降。", "你穷则穷道与他门户辉光，你那里得熬煎铅汞山头火？你那里觅医治相思海上方？此物非常。", "(张生云)老师父，我老实对你说，若那夜女子不出来呵，我则管煮哩。", "(正末云)秀才，你听者：东海龙神着老僧来做媒，招你为东床娇客，你意下如何？(张生云)老师父你不要耍我，这海中一望是白茫茫的水，小生是个凡人，怎生去的？(家僮云)相公，这个不妨事，你只跟着长老去，若是他不淹死，难道独独淹死了你？(正末唱)。"]'),
('yuanqu-892','沙门岛张生煮海・脱布衫','李好古','元','元曲','yuanqu','','[]','俺实丕丕要问行藏，你慢腾腾好去商量。',37,'元曲/yuanqu.json','["俺实丕丕要问行藏，你慢腾腾好去商量。", "将这水指一指翻为土壤，分一分步行坦荡。"]'),
('yuanqu-893','沙门岛张生煮海・小梁州','李好古','元','元曲','yuanqu','','[]','直着你如履平原草径荒，(张生云)到那海底去，莫不昏暗么？(正末唱)却正是日出扶桑。',100,'元曲/yuanqu.json','["直着你如履平原草径荒，(张生云)到那海底去，莫不昏暗么？(正末唱)却正是日出扶桑。", "(张生云)小生终是个凡人，怎敢就到海中去？(正末唱)虽然人海号东洋，休谦让，(带云)去来波！(唱)他则待招选你做东床。"]'),
('yuanqu-894','沙门岛张生煮海・幺篇','李好古','元','元曲','yuanqu','','[]','便休提弥漫弱水三千丈，端的是锦模糊水国鱼邦。',93,'元曲/yuanqu.json','["便休提弥漫弱水三千丈，端的是锦模糊水国鱼邦。", "(张生做望科，云)我看这海有偌般宽阔，无边无岸，想是连着天的，好怕人也！(正末唱)你道是白茫茫，如天祥，越显得他宽洪海量，我劝你早准备帽儿光。"]'),
('yuanqu-895','沙门岛张生煮海・笑和尚','李好古','元','元曲','yuanqu','','[]','去、去、去，向兰阁，到画堂，俺、俺、俺，这言语，无虚诳，(张生云)是真个么？(正末唱)你、你、你，终有个酸寒相。',92,'元曲/yuanqu.json','["去、去、去，向兰阁，到画堂，俺、俺、俺，这言语，无虚诳，(张生云)是真个么？(正末唱)你、你、你，终有个酸寒相。", "他、他、他，女艳妆，早、早、早，得成双，来、来、来，似鸳鸯并宿在销金帐。"]'),
('yuanqu-896','沙门岛张生煮海・尾声','李好古','元','元曲','yuanqu','','[]','则为你佳人才子多情况，唬得他椿室萱堂着意忙。',107,'元曲/yuanqu.json','["则为你佳人才子多情况，唬得他椿室萱堂着意忙。", "你貌又轩昂才又良，他玉有温柔花有香。", "意相投，姻缘可配当；心厮爱，夫妻谁比方。", "似他这百媚韦娘，共你个风流张敞，(带云)去来波！(唱)须将俺撮合山的媒人重重赏。", "(同张生下)。"]'),
('yuanqu-897','沙门岛张生煮海・双调/新水令','李好古','元','元曲','yuanqu','','[]','则为这波涛相间的故人疏，我则怕黑漫漫各寻别路。',49,'元曲/yuanqu.json','["则为这波涛相间的故人疏，我则怕黑漫漫各寻别路。", "受了些活地狱，下了些死工夫。", "海角天隅，须有日再完聚。"]'),
('yuanqu-898','沙门岛张生煮海・驻马听','李好古','元','元曲','yuanqu','','[]','摆列着水里兵卒，都是些鼋将军、鼍先锋、鳖大夫。',97,'元曲/yuanqu.json','["摆列着水里兵卒，都是些鼋将军、鼍先锋、鳖大夫。", "看了这海中使数，无过是赤须虾、银脚蟹、锦鳞鱼。", "绣帘十二列珍珠，家财千万堆金正。", "(张生云)是好富贵也！(正旦唱)你自暗付，则俺这水晶宫是一搭儿奢华处。"]'),
('yuanqu-899','沙门岛张生煮海・滴滴金','李好古','元','元曲','yuanqu','','[]','趁着那绿水清波，良辰美景，轻云薄雾，霜气浸冰壶。',54,'元曲/yuanqu.json','["趁着那绿水清波，良辰美景，轻云薄雾，霜气浸冰壶。", "可则是玉露泠泠。", "金风淅淅，中秋节序，正值着冷清清，人静更初。"]'),
('yuanqu-900','沙门岛张生煮海・折桂令','李好古','元','元曲','yuanqu','','[]','俺去他那月明中信步阶除，听三弄瑶琴音韵非俗。',86,'元曲/yuanqu.json','["俺去他那月明中信步阶除，听三弄瑶琴音韵非俗。", "恰便似云外鸣鹤，天边语雁，枝上啼乌。", "他待觅莺俦燕侣，我正愁凤只鸾孤，因此上，要识贤愚，别辨亲疏。", "端的个和意同心，早遂了似水如鱼。"]'),
('yuanqu-901','沙门岛张生煮海・雁儿落','李好古','元','元曲','yuanqu','','[]','不想这火中生比目鱼，石内长荆山玉。',31,'元曲/yuanqu.json','["不想这火中生比目鱼，石内长荆山玉。", "天边有比翼鸟，地上出连枝树。"]'),
('yuanqu-902','沙门岛张生煮海・得胜令','李好古','元','元曲','yuanqu','','[]','你待将铅汞燎干枯，早难道水火不同炉。',50,'元曲/yuanqu.json','["你待将铅汞燎干枯，早难道水火不同炉。", "将大海扬尘度，把东洋烈焰煮。", "神术煅化的为夫妇，儿子熬煎杀俺眷属。"]'),
('yuanqu-903','沙门岛张生煮海・沽美酒','李好古','元','元曲','yuanqu','','[]','待着俺辞龙宫，离水府，上碧落，赴云衢，我和你同会西池见圣母。',50,'元曲/yuanqu.json','["待着俺辞龙宫，离水府，上碧落，赴云衢，我和你同会西池见圣母。", "秀才也，抵多少跳龙门应举，攀仙桂步蟾蜍。"]'),
('yuanqu-904','沙门岛张生煮海・收尾','李好古','元','元曲','yuanqu','','[]','则今日双双携手登仙去，也不枉鲛绡帕留为信物。',44,'元曲/yuanqu.json','["则今日双双携手登仙去，也不枉鲛绡帕留为信物。", "闲看他蟠桃灼灼树头红，撇罢了尘世茫茫海中苦。"]'),
('yuanqu-905','半夜雷轰荐福碑・仙吕/点绛唇','马致远','元','元曲','yuanqu','','[]','我本是那一介寒懦，半生埋没红尘路。',36,'元曲/yuanqu.json','["我本是那一介寒懦，半生埋没红尘路。", "则我这七尺身躯，可怎生无一个安身处？。"]'),
('yuanqu-906','半夜雷轰荐福碑・后庭花','马致远','元','元曲','yuanqu','','[]','哥哥也，咱可便相识了数载余。',119,'元曲/yuanqu.json','["哥哥也，咱可便相识了数载余。", "哎，你个故人音信疏；远阻隔三千里。", "你可便近新来安乐无？(云)比及哥哥来，我早知道了也。", "(范仲淹云)兄弟，我又不曾有书信来，你如何知道？(正末唱)我昨夜看文书，猛抬头，疑怪他这灯花儿结聚，今日个果门迎你个长者车。"]'),
('yuanqu-907','半夜雷轰荐福碑・油葫芦','马致远','元','元曲','yuanqu','','[]','则这断简残编孔圣书，常则是养蠹鱼。',110,'元曲/yuanqu.json','["则这断简残编孔圣书，常则是养蠹鱼。", "我去这六经中枉下了死工夫。", "冻杀我也《论语》篇、《孟子》解、《毛诗》注，饿杀我也《尚书》云、《周易》传、《春秋》疏。", "比及道河出图、洛出书，怎禁那水牛背上乔男女，端的可便定害杀这个汉相如！。"]'),
('yuanqu-908','半夜雷轰荐福碑・天下乐','马致远','元','元曲','yuanqu','','[]','这世里难乘驷马车，想贤也波愚，不并居。',151,'元曲/yuanqu.json','["这世里难乘驷马车，想贤也波愚，不并居。", "我干受了漏星堂半世活地狱。", "(范仲淹云)你积攒下些甚么囊箧？(正末唱)我浑攒下不到六七斤家麻，五四斗家粟，几时能够播清风一万古？(范仲淹云)贤弟受窘。", "你肯谒托一两个朋友呵，必有济惠。", "得些盘费，进取功名，可不好那！(正末云)哥哥，如今难投托人，今人与古人不同。", "(唱)。"]'),
('yuanqu-909','半夜雷轰荐福碑・那吒令','马致远','元','元曲','yuanqu','','[]','当日个结交有周瑜鲁肃，当日个量宽有王阳贡禹，今日个义让无管仲鲍叔。',49,'元曲/yuanqu.json','["当日个结交有周瑜鲁肃，当日个量宽有王阳贡禹，今日个义让无管仲鲍叔。", "则我这运未通、时难遇，枉了狂图。"]'),
('yuanqu-910','半夜雷轰荐福碑・鹊踏枝','马致远','元','元曲','yuanqu','','[]','我如今带儒冠，着儒服，知他我那命里有公侯也伯子男乎？我左右来无一个去处，天也，则索阁落里韫椟藏诸！。',50,'元曲/yuanqu.json','["我如今带儒冠，着儒服，知他我那命里有公侯也伯子男乎？我左右来无一个去处，天也，则索阁落里韫椟藏诸！。"]'),
('yuanqu-911','半夜雷轰荐福碑・寄生草','马致远','元','元曲','yuanqu','','[]','想前贤语，总是虚。',73,'元曲/yuanqu.json','["想前贤语，总是虚。", "可不道\"书中车马多如簇\"，可不道\"书中自有千钟粟\"，可不道\"书中有女颜如玉\"；则见他白衣便得一个状元郎，那里是绿袍儿赚了书生处。"]'),
('yuanqu-912','半夜雷轰荐福碑・幺篇','马致远','元','元曲','yuanqu','','[]','这壁拦住贤路，那壁又挡住仕途。',66,'元曲/yuanqu.json','["这壁拦住贤路，那壁又挡住仕途。", "如今这越聪明越受聪明苦，越痴呆越享痴呆福，越糊突越有了糊突富！则这有银的陶令不休官，无钱的子张学干禄。"]'),
('yuanqu-913','半夜雷轰荐福碑・六幺序','马致远','元','元曲','yuanqu','','[]','我想那今世里真男子，更和那大丈夫，我战钦钦拨尽寒炉。',85,'元曲/yuanqu.json','["我想那今世里真男子，更和那大丈夫，我战钦钦拨尽寒炉。", "则这失志鸿鹄，久困鳌鱼，倒不如那等落落之徒。", "枉短檠三尺挑寒雨，消磨尽这暮景桑榆。", "我少年已被儒冠误，羞归故里，懒睹乡闾。"]'),
('yuanqu-914','半夜雷轰荐福碑・幺篇','马致远','元','元曲','yuanqu','','[]','则这寒儒，则索村居，教伴哥读书，牛表描朱。',103,'元曲/yuanqu.json','["则这寒儒，则索村居，教伴哥读书，牛表描朱。", "为甚么怕去长安应举？我伴着伙士大夫，穿着些百衲衣服，半露皮肤。", "天公与小子何辜，问黄金谁买《长门赋》？好不直钱也者也之乎！我平生正直无私曲，一任着小儿簸弄，山鬼揶揄。"]'),
('yuanqu-915','半夜雷轰荐福碑・醉扶归','马致远','元','元曲','yuanqu','','[]','这厮蠢则蠢家豪富，富则富腹中虚。',68,'元曲/yuanqu.json','["这厮蠢则蠢家豪富，富则富腹中虚。", "(带云)哥哥，(唱)便道东道和门馆德不孤，他纯经义不词赋，他识字呵不抵死十分看书；他则是个中选的锄田户。"]'),
('yuanqu-916','半夜雷轰荐福碑・赚煞','马致远','元','元曲','yuanqu','','[]','您兄弟先谒信安君，后记扬州牧，看小子今番命福。',130,'元曲/yuanqu.json','["您兄弟先谒信安君，后记扬州牧，看小子今番命福。", "你兄弟一片功名心更速，岂不闻光阴如过隙白驹。", "我将这护身符，你着我变几贯青蚨。", "(带云)长者。", "(唱)我投人须投大丈夫。", "则这新丰一旅，将着马周来不遇。", "(带云)哥哥，你可放心也。", "(唱)你看我专等常何的那一纸荐贤书。", "(下)。"]'),
('yuanqu-917','半夜雷轰荐福碑・仙吕/赏花时','马致远','元','元曲','yuanqu','','[]','我恰做访戴山阴王子猷，身似飘飘没缆舟，为活计拙如鸠。',40,'元曲/yuanqu.json','["我恰做访戴山阴王子猷，身似飘飘没缆舟，为活计拙如鸠。", "则这客僧投寺宿，措大谒儒流。"]'),
('yuanqu-918','半夜雷轰荐福碑・幺篇','马致远','元','元曲','yuanqu','','[]','投至得千里书回碧树秋，则怕这一夜霜天白发愁。',50,'元曲/yuanqu.json','["投至得千里书回碧树秋，则怕这一夜霜天白发愁。", "王粲谒荆州，我想那朝中故友，休教我空倚定仲宣楼！(下)。"]'),
('yuanqu-919','半夜雷轰荐福碑・滚绣球','马致远','元','元曲','yuanqu','','[]','这一遭，下不着，孔融好等你那弥衡一鹗。',97,'元曲/yuanqu.json','["这一遭，下不着，孔融好等你那弥衡一鹗。", "哥也，我便似望鹏抟万里青霄。", "你搬的我撒了学，置下袍，去这布衣中莽跳。", "空着我绕朱门，恰便似燕子寻巢。", "比及见这四方豪士频插手，我争如学五柳先生懒折腰，枉了徒劳。"]'),
('yuanqu-920','半夜雷轰荐福碑・滚绣球','马致远','元','元曲','yuanqu','','[]','虽然我住破窑使破瓢，我犹自不改其乐，后来便为官也富而无骄。',174,'元曲/yuanqu.json','["虽然我住破窑使破瓢，我犹自不改其乐，后来便为官也富而无骄。", "洛阳书坐化了，黄州书自窨约。", "比及那时节有一个秀才来投托，这世里谁似晏平仲善与人交？(云)到那财主门首，报复将去，有个秀才下书。", "那财主便道：着他门首等者。", "(唱)他腆着胸脯，眼见的昂昂傲。", "(带云)要他那赍发呵，(唱)将我这羞脸儿怀揣着慢慢的熬。", "(带云)投至得他那几贯钱呵！(唱)轻可等半月十朝。"]'),
('yuanqu-921','半夜雷轰荐福碑・倘秀才','马致远','元','元曲','yuanqu','','[]','敢问你个禅师长老。',192,'元曲/yuanqu.json','["敢问你个禅师长老。", "(行者云)问甚么？(正末唱)这条路去黄州也不错？(行者云)正是黄州大路。", "(正末唱)长老也，则他这钟不宜时，为甚敲？(行者云)是无常钟，死了人便撞这钟。", "(正末唱)我道死了人的不是个锄田汉。", "(行者云)不是。", "(正末唱)必然是个富官僚。", "(行者云)可知哩。", "(正末云)这官人姓甚名谁？(行者云)我说与你，死了的官人是黄州团练使刘仕林。", "(正末唱)我听的他道了。", "(做叹气科)(唱)。"]'),
('yuanqu-922','半夜雷轰荐福碑・醉太平','马致远','元','元曲','yuanqu','','[]','争些儿把我撞着，可着我心痒难揉。',208,'元曲/yuanqu.json','["争些儿把我撞着，可着我心痒难揉。", "扬州太守听消耗，你这其间莫不害倒？第一封书已自无着落，第二封书打发谁行要？我将这第三封扯做纸题条。", "(带云)张镐，(唱)则好去深村做教学。", "(行者云)吓我这一跳。", "秀才，你闲也是忙？忙便罢，闲便来寺里吃酸馅来。", "(正末云)长老恕罪。", "张镐也，怎生如此般命蹇？哥哥与了三封书，妨杀了两个人。", "第三封书谒托扬州剌史，罢、罢、罢，我不往扬州去，我则加那潞州长子县张家村上，等哥哥消耗，可不好那。", "(下)。"]'),
('yuanqu-923','半夜雷轰荐福碑・倘秀才','马致远','元','元曲','yuanqu','','[]','则他这香火冷，把他庄家赛倒。',52,'元曲/yuanqu.json','["则他这香火冷，把他庄家赛倒。", "莫不是雨雪少，把这黎民来瘦却？古庙荒凉饿鬼嚎，我权捻土做香烧，怨书生的命薄。"]'),
('yuanqu-924','半夜雷轰荐福碑・倘秀才','马致远','元','元曲','yuanqu','','[]','我则为他三封书把我这前程来误却，万言策被人赖了。',57,'元曲/yuanqu.json','["我则为他三封书把我这前程来误却，万言策被人赖了。", "大道上肯分的轴头儿厮抹着，他请我在庄儿上教村学，也曾看成的我至好。"]'),
('yuanqu-925','半夜雷轰荐福碑・滚绣球','马致远','元','元曲','yuanqu','','[]','我是金字边着个高。',145,'元曲/yuanqu.json','["我是金字边着个高。", "(曳剌云)可他呢？(正末唱)他是点水边着个告，因此上一般名号。", "(曳剌云)那加官的管着甚么来？(正末唱)谁想这送宣的再也不辨个根苗。", "他道是盖世豪，我道是儿女曹，咱两个非同管鲍，哥也，则你那十两枣穰金是鞘里藏刀。", "俺两个一时本是知心友，不想道半路里翻为刎颈交。", "他怎肯将我耽饶？。"]'),
('yuanqu-926','半夜雷轰荐福碑・煞尾','马致远','元','元曲','yuanqu','','[]','你是必兴心儿再认下这搭沙和草，哥也，你可休不挂意揩抹了这把带血刀。',210,'元曲/yuanqu.json','["你是必兴心儿再认下这搭沙和草，哥也，你可休不挂意揩抹了这把带血刀。", "(带云)张浩，(唱)休想天公把你饶！鞭牛汉平白的赖了官爵，采桑妇没来由受了郡诰。", "我空向他乡走一遭，千里投人怕的是到。", "若不是吾兄义气高，若不是哥哥怎生了？山海也似恩临决然报！异日峥嵘厮撞着，请一个传神巧待诏，一幅丹青写容貌。", "堂上铺陈挂幔幕，罗列杯盘置椅桌，百味珍羞不教少。", "一炷明香旦暮烧，将你那救我命的恩人，(带云)你是赵实哥哥，(唱)直供养到老！(下)。"]'),
('yuanqu-927','半夜雷轰荐福碑・中吕/粉蝶儿','马致远','元','元曲','yuanqu','','[]','千里而来，早则不兴阑了子猷访戴，干赔了对践红尘踏路的芒鞋。',69,'元曲/yuanqu.json','["千里而来，早则不兴阑了子猷访戴，干赔了对践红尘踏路的芒鞋。", "则俺那守饶州、范学士，故人安在？哥也，不争你日转千阶，我便是第三番又劫着个空寨。"]'),
('yuanqu-928','半夜雷轰荐福碑・醉春风','马致远','元','元曲','yuanqu','','[]','行杀我也客路远如天，闪杀我也侯门深似海。',65,'元曲/yuanqu.json','["行杀我也客路远如天，闪杀我也侯门深似海。", "趁着这木鱼声，每日上堂斋；秀才也，更做甚么客、客？谢长老慈悲，为小生贫困，将我做上宾看待。"]'),
('yuanqu-929','半夜雷轰荐福碑・石榴花','马致远','元','元曲','yuanqu','','[]','小生可便等三年一度选场开，守村院看书斋。',153,'元曲/yuanqu.json','["小生可便等三年一度选场开，守村院看书斋。", "(长老云)当初范学士可怎生相访来？(正末唱)不想俺那月明千里故人来，他见我便困在、万丈尘埃。", "(长老云)说道了与你三封书，去投奔人如何？(正末唱)倚仗着他三封书，还了我这饥寒债。", "(带云)好处托生也。", "(唱)先妨杀一个洛阳的员外，奔黄州早则无方碍，半路里先引的一个旋风来。"]'),
('yuanqu-930','半夜雷轰荐福碑・斗鹌鹑','马致远','元','元曲','yuanqu','','[]','只为他财散人离，闪的我天宽地窄。',68,'元曲/yuanqu.json','["只为他财散人离，闪的我天宽地窄。", "抵死待要屈脊低腰，又不会巧言令色，况兼今日十谒朱门九不开。", "休道有七步才，他每道十二金钗，强似养三千剑客。"]'),
('yuanqu-931','半夜雷轰荐福碑・普天乐','马致远','元','元曲','yuanqu','','[]','谢吾师，倾心爱，有田文义气、赵胜的胸怀。',77,'元曲/yuanqu.json','["谢吾师，倾心爱，有田文义气、赵胜的胸怀。", "打一统法帖碑，去向京师卖。", "到处里书生都相待，谁肯学有朋自远方来？那里取鸣时的凤麟，则别些个喧檐的燕雀，当路的狼豺。"]'),
('yuanqu-932','半夜雷轰荐福碑・红绣鞋','马致远','元','元曲','yuanqu','','[]','本待看金色清凉境界，霎时间都做了黄公水墨楼台。',74,'元曲/yuanqu.json','["本待看金色清凉境界，霎时间都做了黄公水墨楼台。", "多管是角木蛟当直圣亲差，把黄河移得至，和东海取将来，抵多少长江风送客。", "(带云)这雨越下的大也。", "(唱)。"]'),
('yuanqu-933','半夜雷轰荐福碑・上小楼','马致远','元','元曲','yuanqu','','[]','这雨水平常有来，不似今番特煞。',68,'元曲/yuanqu.json','["这雨水平常有来，不似今番特煞。", "这场大雨非为秋霖，不是甘泽，遮莫是箭杆雨、过云雨，可更淋漓辰霭。", "(带云)我今夜不读书。", "(唱)看你怎生飘麦。"]'),
('yuanqu-934','半夜雷轰荐福碑・幺篇','马致远','元','元曲','yuanqu','','[]','振乾坤雷鼓鸣，走金蛇电影开。',57,'元曲/yuanqu.json','["振乾坤雷鼓鸣，走金蛇电影开。", "他那里撼岭巴山，搅海翻江，倒树摧崖。", "这孽畜，更做你这般神通广大，也不合佛顶上大惊小怪。"]'),
('yuanqu-935','半夜雷轰荐福碑・满庭芳','马致远','元','元曲','yuanqu','','[]','粉碎了阎浮世界，今年是九龙治水，少不少珠露成灾。',103,'元曲/yuanqu.json','["粉碎了阎浮世界，今年是九龙治水，少不少珠露成灾。", "将一统家丈三碑，霹雳做了石头块，这的则好与妇女捶帛。", "把似你便逞头角欺俺这秀才，把似你便有牙爪近取那澹石，周处也曾除三害。", "我若得那魏征剑来，我可也敢驱上斩龙台。"]'),
('yuanqu-936','半夜雷轰荐福碑・快活三','马致远','元','元曲','yuanqu','','[]','你不去五台山里且逃乖，干把个梵王宫密云埋。',44,'元曲/yuanqu.json','["你不去五台山里且逃乖，干把个梵王宫密云埋。", "则待要倒天河淹没了讲经台，那里取日月光琉璃界。"]'),
('yuanqu-937','半夜雷轰荐福碑・鲍老儿','马致远','元','元曲','yuanqu','','[]','当日个七个女思凡，养着俺这秀才，那其间可不好霹碎了天灵盖。',162,'元曲/yuanqu.json','["当日个七个女思凡，养着俺这秀才，那其间可不好霹碎了天灵盖。", "古庙里题诗，是我骂来。", "我不曾学了煮海张生怪。", "我腹怀锦绣，剑挥星斗，胸卷江淮，饶你冲开海狱，磨昏日月，崩塌山崖。", "(云)长老，小生命运如此，是天不容小生也。", "这殿角边有株槐树，要我这性命做甚么？倒不如撞槐身死。", "(范仲淹冲上拖末，云)蝼蚁尚且贪生，为人何不惜命？(正末唱)。"]'),
('yuanqu-938','半夜雷轰荐福碑・尧民歌','马致远','元','元曲','yuanqu','','[]','做了场蒺藜沙上野花开。',89,'元曲/yuanqu.json','["做了场蒺藜沙上野花开。", "(范仲淹云)指望你金榜标名。", "(正末唱)但占着龙虎榜，谁思量这远乡牌？那里是扬州车马五侯宅，今日个洛阳花酒一时来？哀也波哉，西风动客杯，空着我流落在天涯外！。"]'),
('yuanqu-939','半夜雷轰荐福碑・耍孩儿','马致远','元','元曲','yuanqu','','[]','更怕我东南倦上红尘陌，空惹的行人赛色。',88,'元曲/yuanqu.json','["更怕我东南倦上红尘陌，空惹的行人赛色。", "可不骑鹤人枉沉埋，把着个颜回瓢也叫化的回来。", "未曾结庐山长老白莲社，正遇着东海龙王大会垓。", "他共我冤仇大，将这座药师佛海会，都变作赵太祖凶宅。"]'),
('yuanqu-940','半夜雷轰荐福碑・二煞','马致远','元','元曲','yuanqu','','[]','若不是八金刚护着寺门，险些儿四天王值着水灾。',69,'元曲/yuanqu.json','["若不是八金刚护着寺门，险些儿四天王值着水灾。", "偏这条龙不受佛家戒。", "恰才禅灯老衲开青眼，可又早荐福碑文卧绿苔。", "空悲慨！他风云已遂，我日月难捱。"]'),
('yuanqu-941','半夜雷轰荐福碑・一煞','马致远','元','元曲','yuanqu','','[]','虽然相公回百姓安，则怕小生行雨又来，也是我曾经着蛇咬自惊怪。',75,'元曲/yuanqu.json','["虽然相公回百姓安，则怕小生行雨又来，也是我曾经着蛇咬自惊怪。", "我则见一株松影横僧舍，错认做个千尺苍龙卧殿阶，真无奈。", "今日贵神迎见喜，我问甚么青龙洞求财。"]'),
('yuanqu-942','半夜雷轰荐福碑・煞尾','马致远','元','元曲','yuanqu','','[]','相公文章欺董仲舒，诗才过李白。',50,'元曲/yuanqu.json','["相公文章欺董仲舒，诗才过李白。", "则为这三封书赍发我做十年客，你则休教八辅相葫芦提了那万言策。", "(同下)。"]'),
('yuanqu-943','半夜雷轰荐福碑・驻马听','马致远','元','元曲','yuanqu','','[]','当日个废寝忘食，铸铁砚长分磨剑的水；到今日攀蟾折桂，步金阶才觅着上天梯。',66,'元曲/yuanqu.json','["当日个废寝忘食，铸铁砚长分磨剑的水；到今日攀蟾折桂，步金阶才觅着上天梯。", "得青春割断管宁席，险白头掷却班超笔。", "谢罢礼，君恩敕赐平身立。"]'),
('yuanqu-944','半夜雷轰荐福碑・雁儿落','马致远','元','元曲','yuanqu','','[]','都则为范张鸡黍期，今日得龙虎风云会。',32,'元曲/yuanqu.json','["都则为范张鸡黍期，今日得龙虎风云会。", "你休夸举荐心，我非得文章力。"]'),
('yuanqu-945','半夜雷轰荐福碑・得胜令','马致远','元','元曲','yuanqu','','[]','都则为那平地一声雷，今日对文武两班齐。',65,'元曲/yuanqu.json','["都则为那平地一声雷，今日对文武两班齐。", "想当初在古庙里题诗句，谁承望老龙王劈破面皮。", "其实、驱逼的我无存济；谁知、可元来运通也有发迹。"]'),
('yuanqu-946','半夜雷轰荐福碑・落梅风','马致远','元','元曲','yuanqu','','[]','当日个荐福碑，多谢你老禅师倒陪了纸墨。',43,'元曲/yuanqu.json','["当日个荐福碑，多谢你老禅师倒陪了纸墨。", "不想那避乖龙肯分的去碑上起，可早霹雳做粉零麻碎。"]'),
('yuanqu-947','半夜雷轰荐福碑・水仙子','马致远','元','元曲','yuanqu','','[]','枉自有三封书札袖中携，我则索拨尽寒炉一夜灰。',104,'元曲/yuanqu.json','["枉自有三封书札袖中携，我则索拨尽寒炉一夜灰。", "眼睁睁现放着傍州例，我则去那菜馒头处拖狗皮。", "早两桩儿送的来路绝人稀。", "(范仲淹云)兄弟，那死的死了，扬州为何不去？(正末唱)便道你扬州牧能义气，我则怕又做了死病难医。"]'),
('yuanqu-948','半夜雷轰荐福碑・川拨棹','马致远','元','元曲','yuanqu','','[]','你道你便老实，你不知为不知，你只会拽耙扶犁，抱瓮浇畦。',54,'元曲/yuanqu.json','["你道你便老实，你不知为不知，你只会拽耙扶犁，抱瓮浇畦。", "万言策谁人做的？你待要狐假虎威。", "哎，你个贾长沙省气力。"]'),
('yuanqu-949','半夜雷轰荐福碑・七弟兄','马致远','元','元曲','yuanqu','','[]','就里、端的，现放着试金石。',45,'元曲/yuanqu.json','["就里、端的，现放着试金石。", "这是万邦取则鱼龙地，对金銮壮志吐虹霓，不比你那看青山满眼骑驴背。"]'),
('yuanqu-950','半夜雷轰荐福碑・梅花酒','马致远','元','元曲','yuanqu','','[]','呀，张仲泽你忒下得，说小生当日，正波迸流移，无处可也依栖。',138,'元曲/yuanqu.json','["呀，张仲泽你忒下得，说小生当日，正波迸流移，无处可也依栖。", "他倚恃着黄金浮世在，我险些儿白发故人稀。", "当日在，村庄里、村庄里，教学的；教学的，谢天地；谢天地，遂风雷；遂风雷，脱白衣；脱白衣，上丹墀；上丹墀，帝王知；帝王知，我身亏；我身亏，那一日；那一日，便心坦克；便心里，得便宜。"]'),
('yuanqu-951','半夜雷轰荐福碑・收江南','马致远','元','元曲','yuanqu','','[]','呀，你今日讨便宜翻做了落便宜。',328,'元曲/yuanqu.json','["呀，你今日讨便宜翻做了落便宜。", "你待将沤麻坑，索换我那凤凰池。", "(净云)可怜见我父亲年纪高大，又有疾病哩。", "(正末唱)你道你父亲年老更残疾，他也不是个好的。", "常言道\"老而不死是为贼。", "\"(云)只不见我那大恩人在那里？(曳剌云)相公认的洒家吗？只我便是赵实。", "(末云)哥哥，受张镐两拜。", "(曳剌云)洒家不敢，相公请起。", "(范仲淹云)兄弟，你为甚么拜他？(正末云)哥哥不知，我当此一日，若不是他饶了我性命呵，岂有今日！(范仲淹云)原来有这等事。", "你一行人听我下断：假张浩暗赖了万言长策，诈图官爵，杀坏平人，市曹中明正典刑；赵实见义当为，不行邪径，就加你为吉阳县令；荐福寺长老加为紫衣太师；宋公序选吉日良辰，就招女婿张镐过门。", "老夫杀羊造酒，做一个喜庆的筵席。", "(众谢科)(正旦唱)。"]'),
('yuanqu-952','半夜雷轰荐福碑・鸳鸯煞','马致远','元','元曲','yuanqu','','[]','则这远公休结白莲会，谢安却被苍生起，谁知也有这日。',102,'元曲/yuanqu.json','["则这远公休结白莲会，谢安却被苍生起，谁知也有这日。", "成就了宰相荐贤心，才趁了男儿仗义胆，白破了贼汉拖刀计。", "倒招了个女娇娃结眷姻，和你这老禅师为交契。", "大都来是书生命里，不争将黄阁玉堂臣，几乎的做了违宣抗敕鬼。"]'),
('yuanqu-953','摩利支飞刀对箭・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','万里青霄，四方明照，行仁道。',37,'元曲/yuanqu.json','["万里青霄，四方明照，行仁道。", "俺父亲他则着我耕种锄刨，似恁的几时上凌烟阁？。"]'),
('yuanqu-954','摩利支飞刀对箭・混江龙','无名氏','元','元曲','yuanqu','','[]','我如今五陵年少，不能够夺旗扯鼓显英豪，恰便似天边老雁，更和那云外孤鹤。',200,'元曲/yuanqu.json','["我如今五陵年少，不能够夺旗扯鼓显英豪，恰便似天边老雁，更和那云外孤鹤。", "我不能够边塞上统军居帅府，丹墀内束带立于朝，我干受了半生苦志，十载劬劳。", "姜太公渭河边垂钓，伍员在丹阳县吹箫。", "待进来眼前有八荒荆棘，待退来脑后有万丈波涛。", "我如今修不成活计，垒不就窝巢。", "每日家苦淹淹守定这座大黄庄，空着我便眼巴巴盼不到长安道。", "我不能够奋青云雕鹗，我倒不如那傲夏日鹪鹩！(云)薛仁贵也，几时是你那发达的时节也呵！(唱)。"]'),
('yuanqu-955','摩利支飞刀对箭・天下乐','无名氏','元','元曲','yuanqu','','[]','几时能够宫殿风微燕雀高？我这里便量也波度，不由我心内焦，则我那上天梯若还寻觅着。',64,'元曲/yuanqu.json','["几时能够宫殿风微燕雀高？我这里便量也波度，不由我心内焦，则我那上天梯若还寻觅着。", "龙能够致雨风，虎能够奋牙爪，将我这严生志须应了。"]'),
('yuanqu-956','摩利支飞刀对箭・那吒令','无名氏','元','元曲','yuanqu','','[]','我这里见父亲，烦烦恼恼；(卜儿云)老的，休打孩儿，且饶过这一遭者。',196,'元曲/yuanqu.json','["我这里见父亲，烦烦恼恼；(卜儿云)老的，休打孩儿，且饶过这一遭者。", "(正末唱)母亲那里劝着，俺父亲他忄敝忄敝噪噪；(旦儿云)哎约！这个父亲，今日也说打，明日也说打，不付能寻将来，父亲可又不打他。", "(正末云)噤声！(唱)他那里嘴不剌的，他也聒聒噪噪！(孛老儿云)我说着他，他倒寻媳妇儿的不是。", "孩儿也，你也似不的那闵子贤，曾参孝。", "(正末唱)我似不的那闵子般贤，我学不的曾参般孝，和你一个鼓瞍把我闲瞧。"]'),
('yuanqu-957','摩利支飞刀对箭・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','动不动黄桑棒拷折腰，是不是坐囚牢。',192,'元曲/yuanqu.json','["动不动黄桑棒拷折腰，是不是坐囚牢。", "我可甚恭俭温良，你可甚善与人交？(孛老儿云)你不做庄农生活，每日则是刺枪弄棒，你怎么能够长进？(正末唱)有一日长全我这六梢，(孛老儿云)你可待往那里去？(正末唱)我可敢飞腾过万里青霄。", "(孛老儿云)俺庄农人家，欲要富，土里做；欲要牢，土里刨。", "你说你会武艺，你就在这草堂上敷演一遍，我试看者。", "(正末云)我在这草堂上敷演一遍，父亲、母亲，你试看者。", "(唱)。"]'),
('yuanqu-958','摩利支飞刀对箭・寄生草','无名氏','元','元曲','yuanqu','','[]','我若是临军阵，恶战讨。',71,'元曲/yuanqu.json','["我若是临军阵，恶战讨。", "遮莫他扑碌碌队伍在这杀场上闹，乱纷纷土雨在空中落，慢腾腾杀气头直上罩。", "遮莫便骨刺刺杂彩绣旗摇，遮莫便扑冬冬画鼓征鼙噪！。"]'),
('yuanqu-959','摩利支飞刀对箭・后庭花','无名氏','元','元曲','yuanqu','','[]','休将你这歹孩儿留恋着，枉把我这功名来耽误了。',219,'元曲/yuanqu.json','["休将你这歹孩儿留恋着，枉把我这功名来耽误了。", "(孛老儿云)你这一去，凭着你甚么武艺那？(正末唱)凭着我这四海五湖量，(孛老见云)孩儿也，则做庄农罢。", "(正末唱)我怎肯深村里穷到老？(孛老儿云)两阵之间，你怎生与他拒敌？(正末唱)你看我便显英豪，听您这歹孩儿言道，马头前若撞着，仗英雄显荣耀！(卜儿云)孩儿也，便好道父母在堂，不可远游也。", "(正末唱)见母亲留恋着，老家尊心内焦。", "(孛老儿云)好共歹不要你去。", "(正末云)父亲，您孩儿若不去呵，(唱)。"]'),
('yuanqu-960','摩利支飞刀对箭・青哥儿','无名氏','元','元曲','yuanqu','','[]','休阿！枉惹的乡人、乡人耻笑，(云)父亲，您孩儿尽忠，不能尽孝也。',442,'元曲/yuanqu.json','["休阿！枉惹的乡人、乡人耻笑，(云)父亲，您孩儿尽忠，不能尽孝也。", "(唱)我报不的哀哀父母劬劳，(孛老儿云)孩儿也，你伴着那沙三、伴哥、王留，饮酒耍子，可不好？(正末唱)我可甚么人伴贤良智转高。", "(孛老儿云)你听的谁说来？(正末唱)则听的绛州人道，黄榜上名标。", "我将这义军来投了，骨刺刺摆开旗号。", "二马相交，王吉玎的箭对了飞刀。", "轻舒猿猱，磕答的扌昝住征袍，滴溜扑摔下鞍鞒，将背唐朝高丽一只手扌昝住头梢，把那厮扌蚩扌蚩的拖来到。", "(孛老儿云)孩儿也，便好道心去意难留，留下结冤仇。", "去则去，得官不得官，你则早些儿回来，休着老汉忧心也。", "(正末云)则今日好日辰，辞别了父亲、母亲，便索长行也。", "(卜儿云)孩儿也，你这一去，得官不得官，则要你早些儿回来，休着我忧心也。", "(正末云)大嫂，你在家中，好生看觑一双父母。", "我若为了官呵，你便是夫人县君也。", "(旦儿云)住、住、住！薛仁贵，父亲在上，依着妾身说呵，可以待时守分，耕种为活，堪可度日，侍奉一双父母，不强似名利奔波？你坚心要去，我未知你的主意如何也？(正末唱)。"]'),
('yuanqu-961','摩利支飞刀对箭・尾声','无名氏','元','元曲','yuanqu','','[]','我则要身到凤凰池，有心待标写在凌烟阁。',184,'元曲/yuanqu.json','["我则要身到凤凰池，有心待标写在凌烟阁。", "与敌兵相持战讨，下寨安营边塞遥。", "我胸中虎略龙韬，看杀气阵云高，荡征尘土雨潇潇，则我这马到处贼兵都退了。", "(孛老儿云)你这一去，凭着你些什么手策也？(正末唱)倚仗我拨天关手爪，凭着我这撼乾坤勇跃，舍着我这一腔鲜血立唐朝！(下)(孛老儿云)孩儿去了也。", "这一去，他必然为官也。", "老汉无甚事，回我那家中去也。", "眼观旌捷旗，耳听好消息。", "(同下)。"]'),
('yuanqu-962','摩利支飞刀对箭・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','看别人云滚滚省台登，看别人云滚滚省台登，几时能够闹穰穰公侯做。',63,'元曲/yuanqu.json','["看别人云滚滚省台登，看别人云滚滚省台登，几时能够闹穰穰公侯做。", "则他那谒朱门缘木求鱼，则这书中自有他这黄金屋，将我久困在红尘路。"]'),
('yuanqu-963','摩利支飞刀对箭・滚绣球','无名氏','元','元曲','yuanqu','','[]','每日家听钟声山寺里斋，赶宿头古庙里居，有那等财主每，听笙簧则在那画堂深处，如今那有学的酩子里韫椟藏诸。',112,'元曲/yuanqu.json','["每日家听钟声山寺里斋，赶宿头古庙里居，有那等财主每，听笙簧则在那画堂深处，如今那有学的酩子里韫椟藏诸。", "我看了这今世图，这时务，杠了我交语，赤紧的满眼卫不辨贤愚。", "存的我这胸中三卷黄公略，我愁甚么架上三封天子书，恰便似饿虎当途。"]'),
('yuanqu-964','摩利支飞刀对箭・快活三','无名氏','元','元曲','yuanqu','','[]','小人在龙门镇是我祖居，(张士贵云)你可在那里居住？(正末唱)大黄庄有我的家属。',106,'元曲/yuanqu.json','["小人在龙门镇是我祖居，(张士贵云)你可在那里居住？(正末唱)大黄庄有我的家属。", "(张士贵云)你从小里习学甚么武艺来？(正末唱)自小里习文演武用工夫。", "(张士贵云)你可来俺这元帅府做什么？(正末唱)特地来夺富贵争名目。"]'),
('yuanqu-965','摩利支飞刀对箭・朝天子','无名氏','元','元曲','yuanqu','','[]','遮莫待开弓也那蹬弩，(张士贵云)你敢扬威耀武么？(正末唱)扬威也那耀武。',270,'元曲/yuanqu.json','["遮莫待开弓也那蹬弩，(张士贵云)你敢扬威耀武么？(正末唱)扬威也那耀武。", "(张士贵云)你敢阵面上相持去么？(正末唱)我情愿阵面上相持去，(张士贵云)我就用你在我军阵中，做个小卒，你意下如何？(正末唱)但能够军阵里做一个小卒，(张士贵云)我着你合后当先，你敢去么？(正末唱)遮莫便合后等当先去，(张士贵云)兀那厮，你是军健汉，逢山开路，遇水叠桥，你敢去么？(正末唱)遮莫待遇水叠桥，逢山开路，(张士贵云)你敢施威、敢射虎么？(正末唱)我可便敢施威、敢射虎。", "(张士贵云)就用了这厮。", "(正末唱)大人若是用度、用度了这勇夫，我马到处写满了您那功劳簿。"]'),
('yuanqu-966','摩利支飞刀对箭・齐天乐','无名氏','元','元曲','yuanqu','','[]','当街里马头来拦住，听小人从头细说当初。',114,'元曲/yuanqu.json','["当街里马头来拦住，听小人从头细说当初。", "(徐懋功云)你那里人氏？姓甚名谁？(正末唱)小人是农夫，大黄庄有我的家属。", "来时节欢娱，到的这龙门镇揭黄榜过去。", "正犯着大人名讳，他道是不用俺这村夫。", "磕答的弓拽折，急恼的元帅怒，他道我该斩该徒。"]'),
('yuanqu-967','摩利支飞刀对箭・红衫儿','无名氏','元','元曲','yuanqu','','[]','军兵牢拿住，绑在长街去，好教我气长吁，气长吁，仰面嚎啕哭。',44,'元曲/yuanqu.json','["军兵牢拿住，绑在长街去，好教我气长吁，气长吁，仰面嚎啕哭。", "大人也，薛仁贵委实的衔冤负屈。"]'),
('yuanqu-968','摩利支飞刀对箭・尾声','无名氏','元','元曲','yuanqu','','[]','愿吾皇慑夷狄，降边国，千千年九五飞龙齐天福。',118,'元曲/yuanqu.json','["愿吾皇慑夷狄，降边国，千千年九五飞龙齐天福。", "愿吾皇永坐着宗庙旧，家邦老，万万载百二山河壮帝居。", "到来日看排兵，列士卒；荡征尘，腾土雨，旱路上亡，水面上浮；成不的功，变不的虎。", "我直杀的他呐不的喊，摇不的旗，放心也，我着他便擂不的鼓！(下)。"]'),
('yuanqu-969','摩利支飞刀对箭・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','那厮便耀武扬威说大言，怎敢今番夺众权？(摩利支云)我飞刀起！(正末云)箭对了！(摩利支云)飞刀起！(正末云)箭对了！(摩利支云)飞刀起！(正末云)箭对了！(摩利',164,'元曲/yuanqu.json','["那厮便耀武扬威说大言，怎敢今番夺众权？(摩利支云)我飞刀起！(正末云)箭对了！(摩利支云)飞刀起！(正末云)箭对了！(摩利支云)飞刀起！(正末云)箭对了！(摩利支云)五口飞刀，对了我三口，留着两口防身。", "不中，我也近不的他，拨回马，我与你走、走、走！(下)(正末唱)他那里飞刀起，我这里箭离弦。", "杀的他身躯倒偃，我见他拨回马走当先。"]'),
('yuanqu-970','摩利支飞刀对箭・幺篇','无名氏','元','元曲','yuanqu','','[]','你可甚为看青山懒赠鞭，看的俺唐十宰公卿如芥藓。',89,'元曲/yuanqu.json','["你可甚为看青山懒赠鞭，看的俺唐十宰公卿如芥藓。", "遮莫他变做神鬼化做飞仙？(云)待走往那里去？(唱)离不了天涯和那海边！(云)众军校跟我去来。", "(唱)我与你直赶到他这个焰魔天！(下)。"]'),
('yuanqu-971','摩利支飞刀对箭・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','走的我汗似汤浇，浑身上水洗。',74,'元曲/yuanqu.json','["走的我汗似汤浇，浑身上水洗。", "恰离了乱撺军营，急煎煎盼不到元帅府里。", "两只脚飞腾，一声儿踹起。", "苦亡家，倾败国，恶战敌。", "人着箭踉跄身歪，马中枪惊急里脚失。"]'),
('yuanqu-972','摩利支飞刀对箭・紫花儿序','无名氏','元','元曲','yuanqu','','[]','焰腾腾火烧了寨栅，浪滔滔水淹了营垒，不剌剌马踏碎丁城池。',68,'元曲/yuanqu.json','["焰腾腾火烧了寨栅，浪滔滔水淹了营垒，不剌剌马踏碎丁城池。", "英雄虎将，世上无敌，难及。", "一个个擐甲披袍那气势，耀武扬威，擂鼓筛锣，呐喊摇旗！。"]'),
('yuanqu-973','摩利支飞刀对箭・寨儿令','无名氏','元','元曲','yuanqu','','[]','鼓震的山岳摧，喊一声鬼神悲，荡征尘翻滚滚火门辉。',136,'元曲/yuanqu.json','["鼓震的山岳摧，喊一声鬼神悲，荡征尘翻滚滚火门辉。", "领雄兵迎敌，厮杀相持，(云)出马来，出马来！(唱)则听的高叫一声似春雷。", "(高丽将云)这壁厢是俺摩利支出马。", "好将军也，顶盔擐甲，挂剑悬鞭，弯弓插箭。", "张士贵见了俺摩利支，可是怕也不怕？探子，你喘息定，慢慢的再说一遍。", "(正末唱)。"]'),
('yuanqu-974','摩利支飞刀对箭・幺篇','无名氏','元','元曲','yuanqu','','[]','垓心里耀武扬威，阵面上扯鼓夺旗。',43,'元曲/yuanqu.json','["垓心里耀武扬威，阵面上扯鼓夺旗。", "摩利支冠簪着金獬豸，甲挂着锦唐猊，坐下马浑一似赤狻猊。"]'),
('yuanqu-975','摩利支飞刀对箭・秃厮儿','无名氏','元','元曲','yuanqu','','[]','两员将各施武艺，两员将比并高低。',38,'元曲/yuanqu.json','["两员将各施武艺，两员将比并高低。", "他两个棋逢对手难摘离，两员将费心机，好跷蹊。"]'),
('yuanqu-976','摩利支飞刀对箭・尾声','无名氏','元','元曲','yuanqu','','[]','高丽家休占那中原地，年年进金珠宝贝。',99,'元曲/yuanqu.json','["高丽家休占那中原地，年年进金珠宝贝。", "十万里锦绣江山，愿陛下永坐定蟠龙元金椅！(下)(高丽将云)摩利支输了也，白袍小将赢了也。", "俺收拾方物，与大唐进奉，走一遭去。", "饶你深山共深处，到头都属帝王家。", "(下)。"]'),
('yuanqu-977','摩利支飞刀对箭・甜水令','无名氏','元','元曲','yuanqu','','[]','我在这班部丛中，秉笏披袍，抽身忙褪，我这里独步出辕门。',144,'元曲/yuanqu.json','["我在这班部丛中，秉笏披袍，抽身忙褪，我这里独步出辕门。", "(孛老儿云)一个大人来了也。", "(正末唱)我则见他便老弱虺羸，腰屈头低，霜髯雪鬓，(孛老儿云)兀的唬杀老汉也。", "(正末云)兀的不是我父亲母亲也！(唱)年迈个也堂上双亲。", "(孛老儿云)媳妇儿，扶着你母亲靠后些。", "(正末云)休道俺父母不老。", "(唱)。"]'),
('yuanqu-978','摩利支飞刀对箭・折桂令','无名氏','元','元曲','yuanqu','','[]','和我那赛杨香憔悴了精神，(孛老儿云)大人，你是谁？(正末云)父亲、母亲，你认的你孩儿薛驴哥么？(孛老儿云)谁是薛驴哥？(正末)则您孩儿，便是薛驴哥。',270,'元曲/yuanqu.json','["和我那赛杨香憔悴了精神，(孛老儿云)大人，你是谁？(正末云)父亲、母亲，你认的你孩儿薛驴哥么？(孛老儿云)谁是薛驴哥？(正末)则您孩儿，便是薛驴哥。", "(孛老儿云)孩儿，你做了官也？兀的不欢喜杀老汉也。", "(正末唱)我这里便展脚舒腰，安乐者波堂上双亲？(卜儿云)大人请起。", "兀的不唬杀老身也。", "(正末唱)我如今状貌堂堂，威风赳赳，志气凌云。", "(孛老儿云)孩儿也，你如今得了个甚么官也？(正末唱)我如今下马为朝中宰臣，上马为阃外将军。", "(孛老儿云)孩儿，你多受了些辛苦也。", "(正末唱)我受了些热血相喷，万苦干辛，恰便似翻滚滚的雪浪里逃生，您儿今日个便跳过龙门。"]'),
('yuanqu-979','摩利支飞刀对箭・乔牌儿','无名氏','元','元曲','yuanqu','','[]','酩子里添笑忻，十载受劳困。',106,'元曲/yuanqu.json','["酩子里添笑忻，十载受劳困。", "老来也又得官一品，(云)父亲，您孩儿不道来？(孛老儿云)你道甚么来？(正末唱)你儿道是改家门有定准。", "(孛老儿云)孩儿也，大人赏我黄金千两，香酒百瓶，玉柱杖一条，喜欢杀老汉也。", "(正末唱)。"]'),
('yuanqu-980','摩利支飞刀对箭・挂玉钩','无名氏','元','元曲','yuanqu','','[]','索强如段段田苗，可便接远村；(孛老儿云)这个原来是玉柱杖。',220,'元曲/yuanqu.json','["索强如段段田苗，可便接远村；(孛老儿云)这个原来是玉柱杖。", "(正末云)这玉柱杖，(唱)索强似您打麒麟的黄桑棍，(孛老儿云)又与俺香酒百瓶也。", "(正末云)父亲，您休吃了，留者。", "(孛老儿云)留者做甚么？(正末唱)咱可索答荷天公雨露恩。", "(孛老儿云)孩儿也，休题旧话。", "(正末唱)我将这勇烈施逞尽。", "(孛老儿云)我老汉老了也，拂绰了土满身，梳掠起白髭鬓。", "这的是一日为官，强似千载为民也。", "(正末唱)拂绰了土满身，梳掠起白髭鬓。", "这的是一日为官，索强如千载为民。"]'),
('yuanqu-981','中吕・粉蝶儿怨别','陈克明','元','元曲','yuanqu','','[]','画阁萧疏，那里也玉堂人物，间别来音信全无。',51,'元曲/yuanqu.json','["画阁萧疏，那里也玉堂人物，间别来音信全无。", "拆鸾凰，分莺燕，生离开比目。", "闷恹恹瘦损肌肤，粉慵施朱唇懒注。"]'),
('yuanqu-982','醉春风・这些时缕带尽了三分，罗裙掩过半幅。临行时曾说几时回，我与','陈克明','元','元曲','yuanqu','','[]','你数，数。',31,'元曲/yuanqu.json','["你数，数。", "去时节正遇着春分，回来时必然夏至，到如今又过了秋暮。"]'),
('yuanqu-983','醉高歌・更阑香冷金炉，夜静灯残画烛。今宵有梦归何处，那里也吹萧伴','陈克明','元','元曲','yuanqu','','[]','侣？。',3,'元曲/yuanqu.json','["侣？。"]'),
('yuanqu-984','红绣鞋・愁寂莫萦牵肠肚，病恹恹瘦损了身躯，则我这鬓云松意懒甚时梳。','陈克明','元','元曲','yuanqu','','[]','茶饭上无些滋味，针指上减了些工夫，尘蒙了七弦琴冷了雁足。',28,'元曲/yuanqu.json','["茶饭上无些滋味，针指上减了些工夫，尘蒙了七弦琴冷了雁足。"]'),
('yuanqu-985','普天乐・意绯徊，心忧虑。知他在科场应举，翰院迁除？峥嵘在画阁中，','陈克明','元','元曲','yuanqu','','[]','显耀在兰堂处。',50,'元曲/yuanqu.json','["显耀在兰堂处。", "闪的人冷冷清清捱朝暮，想薄情负我何辜？扑簌簌两行泪珠，闷恹恹九分病苦，气丝丝一口长吁。"]'),
('yuanqu-986','上小楼・也是我今生分福，多管是前生合注。那里也画眉张敞，掷果潘安，','陈克明','元','元曲','yuanqu','','[]','傅粉平叔？不弱如待月张生，偷香韩寿，谒浆崔护？则我这孤辰运命该天数。',34,'元曲/yuanqu.json','["傅粉平叔？不弱如待月张生，偷香韩寿，谒浆崔护？则我这孤辰运命该天数。"]'),
('yuanqu-987','幺篇・愁和闷眼倦开，闷和愁眉怎舒？愁的是情思昏昏，神魂飘荡，鬼病','陈克明','元','元曲','yuanqu','','[]','揶揄。',32,'元曲/yuanqu.json','["揶揄。", "闷连着华狱三峰，巫山十二，黄河九曲，则我这骨捱捱命归泉路。"]'),
('yuanqu-988','十二月・四时景光阴迅速，更和这秋景萧疏。疏剌剌风摇翠竹，淅零零雨','陈克明','元','元曲','yuanqu','','[]','洒苍梧。',24,'元曲/yuanqu.json','["洒苍梧。", "画檐间玎玎当当铁马，戍楼中滴滴点点铜壶。"]'),
('yuanqu-989','尧民歌・呀，我恰才望夫山上问个实虚，他可在竹林寺里寄情书？多管在','陈克明','元','元曲','yuanqu','','[]','秦楼谢馆笑欢娱，柳陌花街恋娇姝。',35,'元曲/yuanqu.json','["秦楼谢馆笑欢娱，柳陌花街恋娇姝。", "踌蹰，薄情忒狠毒，因此上扯碎了姻缘簿。"]'),
('yuanqu-990','耍孩儿・赶苏卿何处双通叔？到做了三不归离魂倩女。想当日碧桃花下凤','陈克明','元','元曲','yuanqu','','[]','鸾雏，山和水阻隔着万里程途。',61,'元曲/yuanqu.json','["鸾雏，山和水阻隔着万里程途。", "山隐隐绕天涯怎觅青鸾信？水茫茫淹海角难寻锦鲤书，两般儿无归路。", "桃源洞墨云荏苒，武陵溪烟水模糊。"]'),
('yuanqu-991','一煞・身似水上萍，命如风内烛，月初圆又被阴云布。蓝桥下水波涛万丈','陈克明','元','元曲','yuanqu','','[]','浸了海峤，ビ庙火烈焰千层接着太虚，两桩儿本是无情物。',43,'元曲/yuanqu.json','["浸了海峤，ビ庙火烈焰千层接着太虚，两桩儿本是无情物。", "玉簪折何时再接，冰弦断甚日重续？。"]'),
('yuanqu-992','尾声・汉相如有朝归故乡，卓文君多曾亲见睹？一星星自把衷肠诉，将我','陈克明','元','元曲','yuanqu','','[]','这受过的凄凉慢慢的数。',11,'元曲/yuanqu.json','["这受过的凄凉慢慢的数。"]'),
('yuanqu-993','张公艺九世同居・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','九世同居，故家乔木，传今古。',31,'元曲/yuanqu.json','["九世同居，故家乔木，传今古。", "则俺这远近宗族，端的是上下皆和睦。"]'),
('yuanqu-994','张公艺九世同居・混江龙','无名氏','元','元曲','yuanqu','','[]','尊卑有序，俺一团和气霭门闾。',144,'元曲/yuanqu.json','["尊卑有序，俺一团和气霭门闾。", "立身的有士农工贾，传家的有礼乐诗书。", "想着那累代功名天下有，似俺家满门忠孝世间无。", "为男的孝于父母，做女的善侍公姑。", "人力众数百家眷，田宅广无限仓庾。", "亲戚同高楼大厦，朋友共肥马轻车。", "乐天年幽居田野。", "播芳声喧满江湖。", "但存忠孝以齐家，不求荣显学干录。", "常能如此，更待何如。"]'),
('yuanqu-995','张公艺九世同居・油葫芦','无名氏','元','元曲','yuanqu','','[]','似俺般富贵荣华天付与，俺端的心自足。',101,'元曲/yuanqu.json','["似俺般富贵荣华天付与，俺端的心自足。", "(大末云)喜遇明君治世。", "(正末昌)时遇着舜天尧日乐安居，堪叹的是西山日迫桑榆暮。", "喜的是高堂月旦芝兰聚，自北齐千乘君，大隋仁圣主，省差徭免赋税加优恤，见如今旋表耀门闾。"]'),
('yuanqu-996','张公艺九世同居・天下乐','无名氏','元','元曲','yuanqu','','[]','两度天书出帝都，家也波声，传父祖，一家儿孝慈成化俗。',48,'元曲/yuanqu.json','["两度天书出帝都，家也波声，传父祖，一家儿孝慈成化俗。", "士民俱赞扬，乡闾皆敬伏，俺端的播清风一万古。"]'),
('yuanqu-997','张公艺九世同居・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','左右行列昭穆，定亲疏，追思这祖考音容，洋洋乎在生规模。',44,'元曲/yuanqu.json','["左右行列昭穆，定亲疏，追思这祖考音容，洋洋乎在生规模。", "再拜虔诚告祝，保护一家儿上下无虞。"]'),
('yuanqu-998','张公艺九世同居・寄生草','无名氏','元','元曲','yuanqu','','[]','你做须做文章伯，学则学君子儒，可不道书中自有千钟粟。',90,'元曲/yuanqu.json','["你做须做文章伯，学则学君子儒，可不道书中自有千钟粟。", "你为人要比连城玉，济时须作擎天柱。", "(带云)孟子云：穷则独善其身，达则兼善天下。", "(唱)你达时腰金佩紫掌丝纶，不达时沦黄数黑寻章句。"]'),
('yuanqu-999','张公艺九世同居・幺篇','无名氏','元','元曲','yuanqu','','[]','你学济世安邦策，按六韬三略书。',69,'元曲/yuanqu.json','["你学济世安邦策，按六韬三略书。", "则要你识安危动变驱兵旅，察虚实攻守安营戍，分奇正左右依行伍，但能够雄赳赳虎豹帐中居，煞强如冷清清鹦鹉洲边住。"]'),
('yuanqu-1000','张公艺九世同居・六幺序','无名氏','元','元曲','yuanqu','','[]','我这里频嘱付，孩儿每自喑伏。',135,'元曲/yuanqu.json','["我这里频嘱付，孩儿每自喑伏。", "休得恣荒淫酒色欢娱，为儒的早趁三余，笃志诗书休得闲遥遥惰却身躯。", "少年莫道儒冠误，索将他经史熟读。", "圣人言不贰过不迁怒，修其天爵，人爵从诸。", "(云)孩儿也。", "你两个学的文武全才，即今便上朝应举去，则要你着志者。", "(二末云)您孩儿即今便行也。", "(正末唱)。"]'),
('yuanqu-1001','张公艺九世同居・幺篇','无名氏','元','元曲','yuanqu','','[]','想为官的要辨贤愚，休要弄权术。',99,'元曲/yuanqu.json','["想为官的要辨贤愚，休要弄权术。", "爱恤民庶，教化风俗，一片心常思报主。", "想民瘼不易除，为农的竭力耕锄，休教他田野荒芜。", "到头来勤苦是亨衢。", "饱衣暖食供朝暮。", "不勤时仓禀空虚，礼义廉耻为先务。", "毋忝尔祖，以保身躯。"]'),
('yuanqu-1002','张公艺九世同居・赚煞尾','无名氏','元','元曲','yuanqu','','[]','便好道养育受亲恩。',108,'元曲/yuanqu.json','["便好道养育受亲恩。", "仁宦食天禄，这的是父生汝君子食汝。", "自古君亲两不殊，不忠孝天理何如！慎其独，似十目视十手指严乎。", "(带云)则要你上合天心下协民望，(唱)天网恢恢本不疏。", "你索温恭自虚，制竹谨度，行藏须鉴圣贤书。", "(同下)。"]'),
('yuanqu-1003','张公艺九世同居・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','镜添白发新，人对黄花瘦。',58,'元曲/yuanqu.json','["镜添白发新，人对黄花瘦。", "光阴驹过隙，世事水浮沤。", "寒暑相逐，乌免搬昏昼。", "昨日春今日秋，过中年万事俱休，空枉了堆金北斗。"]'),
('yuanqu-1004','张公艺九世同居・隔尾','无名氏','元','元曲','yuanqu','','[]','逐朝春镜容颜瘦，一枕黄粮梦境熟。',42,'元曲/yuanqu.json','["逐朝春镜容颜瘦，一枕黄粮梦境熟。", "往事回头尽参透，吾心已休，甘心退守，老却当年钓鳌手。"]'),
('yuanqu-1005','张公艺九世同居・幺篇','无名氏','元','元曲','yuanqu','','[]','庄田与我亲标拨，钱粮与我别项收，恐有那一等受贫穷朋友干求。',434,'元曲/yuanqu.json','["庄田与我亲标拨，钱粮与我别项收，恐有那一等受贫穷朋友干求。", "倘有那连丧不举的人家，久定难成的配偶。", "(大末云)丧不举呵，怎的？(正末唱)丧不举呵，我与他斋僧道营坟墓，(大末云)婚不了呵，如何？(正末唱)女不嫁呵，我与他办首饰置衾绸。", "须教他嫁娶心无憾，免得他居丧礼不周。", "(云)下次小的每门首看着，有甚么人来？(大末云)理会的。", "(王伯清上云)小生王伯清是也。", "因父丧不举，到此张公艺家，借些小钱物，埋殡父亲。", "可早来到也。", "兀那门公报复去，道有王原举之子来见老员外。", "(行钱云)理会的。", "(做报科，云)报的员外得知，有王原举之子来见员外。", "(正末云)行钱，当初王原举，与老夫有一面之交，请他过来。", "(行钱云)理会的。", "有请。", "(王伯清做见施礼科)(正末云)孩儿也。", "你有甚么事，来到此处也。", "(王伯清云)不瞒长者说，我父亲曾与长者有一面之交。", "我父不辛，身亡三载，停柩在堂，无线殡葬。", "止有老母在堂，并无亲故。", "想长者有疏财仗义之心，全望长者可怜，借些钱物，以葬我父亲。", "若蒙俯允，此恩不忘也。", "(正末唱)。"]'),
('yuanqu-1006','张公艺九世同居・红芍药','无名氏','元','元曲','yuanqu','','[]','他从头至尾说因由，和我也雨泪交流。',259,'元曲/yuanqu.json','["他从头至尾说因由，和我也雨泪交流。", "他道父亡三载久停留，并无-个亲识追求。", "则你那文齐来福未酬，则要你显男儿得志之秋。", "(正末做悲科)老夫一一记在心头，我必有个主意相周。", "(正末取银子鞍马衣服科，云)这拾两银子，与你埋殡父亲。", "你埋殡了父亲，你上朝求官应举去。", "这拾两银子，与你做盘缠，这鞍马权与你代步。", "孩儿，你则着志者。", "(王伯清做谢科，云)多谢了长者也。", "(正末云)路远不及吊问，休怪也。", "(王伯清云)不敢不敢。", "(行钱云)我倒好笑，拿着细丝银子儿，鞍马衣服，白与了别人去了。", "我整日家与他做买卖，倒不与我，真乃是夹脑风也。", "(正末唱)。"]'),
('yuanqu-1007','张公艺九世同居・菩萨梁州','无名氏','元','元曲','yuanqu','','[]','你与我疾便登舟，休辞生受。',66,'元曲/yuanqu.json','["你与我疾便登舟，休辞生受。", "显文章魁首，免你那倚门尊母忧愁。", "蟾宫独步占鳌头，门庭改换传家后。", "此言语不虚谬，不枉了灯窗学业修，万古名留。"]'),
('yuanqu-1008','张公艺九世同居・骂玉郎','无名氏','元','元曲','yuanqu','','[]','声名不落他人后，心已遂更何求。',44,'元曲/yuanqu.json','["声名不落他人后，心已遂更何求。", "人情世事皆虚谬，想如今故友稀，叹鬓边白发新，喜榻上青毡旧。"]'),
('yuanqu-1009','张公艺九世同居・感皇恩','无名氏','元','元曲','yuanqu','','[]','呀，爱的是山水清幽，喜的是菊松芳秀。',67,'元曲/yuanqu.json','["呀，爱的是山水清幽，喜的是菊松芳秀。", "伴风月两闲人，渺乾坤双醉眼，乐诗酒一儒流。", "闲散心青山故友，暂忘机沧海盟鸥，梦义皇，谢尘世，卧糟丘。"]'),
('yuanqu-1010','张公艺九世同居・采茶歌','无名氏','元','元曲','yuanqu','','[]','做一个醉乡侯，老风流，得优游处且优游。',68,'元曲/yuanqu.json','["做一个醉乡侯，老风流，得优游处且优游。", "对酒当歌开笑口，一杯消尽古今愁。", "(云)分付你的言语，你牢记着。", "(大末云)您孩儿理会的。", "(正末唱)。"]'),
('yuanqu-1011','张公艺九世同居・煞尾','无名氏','元','元曲','yuanqu','','[]','把我那西园池馆从新构，北院山亭即便修。',53,'元曲/yuanqu.json','["把我那西园池馆从新构，北院山亭即便修。", "留得闲身漫迤逗，栽花种柳，携琴载洒，我和那松竹梅花做心友。", "(众下)。"]'),
('yuanqu-1012','张公艺九世同居・双调清江引','无名氏','元','元曲','yuanqu','','[]','别人做了状元喜满腮，咱两个如之奈？他两个都为三品官，齐向金阶拜。',53,'元曲/yuanqu.json','["别人做了状元喜满腮，咱两个如之奈？他两个都为三品官，齐向金阶拜。", "咱两个躲在那背巷里悄悄的家去来。", "(同下)。"]'),
('yuanqu-1013','张公艺九世同居・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','人事尚炎凉，世态轻忠信，似这般不义富于我如浮云。',39,'元曲/yuanqu.json','["人事尚炎凉，世态轻忠信，似这般不义富于我如浮云。", "小人若得十年运，早忘了贫时分。"]'),
('yuanqu-1014','张公艺九世同居・滚绣球','无名氏','元','元曲','yuanqu','','[]','向人前敢自尊，胡议论，出言语无半星儿谦逊，气昂昂傍若无人。',94,'元曲/yuanqu.json','["向人前敢自尊，胡议论，出言语无半星儿谦逊，气昂昂傍若无人。", "倚仗着千两金，万两银，见一等穷相识并不亻秋问，若见他富豪人便和气若雷陈。", "他亲的是朱楼翠阁风流子，他敬的是白马红缨衫色新。", "何足云云。"]'),
('yuanqu-1015','张公艺九世同居・倘秀才','无名氏','元','元曲','yuanqu','','[]','传圣旨火臣到门，忙惊讶心中自忖，有甚事传言达至尊，抬香案，引儿孙，向前接引。',64,'元曲/yuanqu.json','["传圣旨火臣到门，忙惊讶心中自忖，有甚事传言达至尊，抬香案，引儿孙，向前接引。", "(使命云)圣命至此，张公艺你焚香接待也。", "(正末唱)。"]'),
('yuanqu-1016','张公艺九世同居・脱布衫','无名氏','元','元曲','yuanqu','','[]','炷余炉宅篆氤氲，遥瞻拜玉阙丹宸。',32,'元曲/yuanqu.json','["炷余炉宅篆氤氲，遥瞻拜玉阙丹宸。", "顿首诚惶谢恩，有何事感蒙君问？。"]'),
('yuanqu-1017','张公艺九世同居・小梁州','无名氏','元','元曲','yuanqu','','[]','止不过草芥微躯一庶民，隐迹山村。',69,'元曲/yuanqu.json','["止不过草芥微躯一庶民，隐迹山村。", "(使命云)圣人的命，问你九世不分居，有何齐家之道？(正末唱)圣人问齐家之道何因，为甚么家和顺，九世不曾分。"]'),
('yuanqu-1018','张公艺九世同居・幺','无名氏','元','元曲','yuanqu','','[]','老夫自小蒙家训，止不过慈爱宽仁。',88,'元曲/yuanqu.json','["老夫自小蒙家训，止不过慈爱宽仁。", "非老夫能，家无他论，则我这齐家之本，诚意与修身。", "(使命云)你有何言语，我与你上达也。", "(正末云)将纸墨笔砚过来者。", "(行钱云)纸笔在此。", "(正末唱)。"]'),
('yuanqu-1019','张公艺九世同居・醉太平','无名氏','元','元曲','yuanqu','','[]','纸光如素粉，墨浓似春云，抵多少蘸霜毫笔阵扫千军。',80,'元曲/yuanqu.json','["纸光如素粉，墨浓似春云，抵多少蘸霜毫笔阵扫千军。", "(做沉吟科)口无言门哂，待对这万言长策无高论，待答那表章无学问。", "(做写忍字科)写到百十个忍字对天臣，望传达至尊。"]'),
('yuanqu-1020','张公艺九世同居・叨叨令','无名氏','元','元曲','yuanqu','','[]','假如道饭食不周衣服不备为下的道心偏逊，恭敬不至礼节不到为上的道他生忿。',203,'元曲/yuanqu.json','["假如道饭食不周衣服不备为下的道心偏逊，恭敬不至礼节不到为上的道他生忿。", "上责下下怨上即渐的生嗔恨，上不慈下不孝必定相争论。", "(带云)我家不分呵为何？(唱)彼各都忍了也波哥，彼各都忍了也波哥，因此上父为子隐上下家和顺。", "(使命云)原来是如此，我怎知道也。", "(正末云)天使，不则齐家之法，有此忍字，上至宰臣，下及庶民，皆有此忍。", "能忍者全身保命，不忍者丧家取祸，天使，听我说一遍。", "(使命云)你说，小官试听者。", "(正末唱)。"]'),
('yuanqu-1021','张公艺九世同居・随煞尾','无名氏','元','元曲','yuanqu','','[]','这忍字向不平心上安刀刃，呵，心地清能忍清凉绝斗纷。',112,'元曲/yuanqu.json','["这忍字向不平心上安刀刃，呵，心地清能忍清凉绝斗纷。", "守口如瓶要安分，防意如城主忠信。", "能忍呵怨恨成欢仇变恩，不能忍呵恩爱为仇喜作嗔。", "能忍呵谁是谁非尽休问，他弱他强莫争论。", "能忍呵宽裕温柔保六亲，你若要远害全身止不过在于忍。", "(下)。"]'),
('yuanqu-1022','张公艺九世同居・双调/新水令','无名氏','元','元曲','yuanqu','','[]','揭清天一派动箫韶，聚春风玉骢争道。',42,'元曲/yuanqu.json','["揭清天一派动箫韶，聚春风玉骢争道。", "锦斓斑仙仗拥，花烂熳彩楼高。", "县宰官僚，头踏尽来到。"]'),
('yuanqu-1023','张公艺九世同居・殿前欢','无名氏','元','元曲','yuanqu','','[]','天使索劬劳，事君王束带立于朝。',116,'元曲/yuanqu.json','["天使索劬劳，事君王束带立于朝。", "承宣走马长安道，胸卷江涛。", "(王伯清云)长者请坐受礼也。", "(正末唱)偶迎逢一面交，惹议论诸公笑，则道是没见识村夫傲。", "(王伯清云)长者有德，小官年幼也。", "(正末唱)俺年高呵则是个山林潦倒。", "您年幼呵则当代的英豪。"]'),
('yuanqu-1024','张公艺九世同居・川拨棹','无名氏','元','元曲','yuanqu','','[]','仿佛记旧丰标。',49,'元曲/yuanqu.json','["仿佛记旧丰标。", "偶相逢恐认错。", "老人多病年高，老景萧条，僻处荒郊，多因是间别久时间忘了。", "隔关河途路杳。"]'),
('yuanqu-1025','张公艺九世同居・七兄弟','无名氏','元','元曲','yuanqu','','[]','天臣道了，老夫记着。',103,'元曲/yuanqu.json','["天臣道了，老夫记着。", "那一朝，为父丧足下亲来到。", "(云)多蒙厚赐也。", "(唱)谢君不责礼轻薄，(王伯清做递银子与正末科，云)长者当时所赐银两，今在此奉还也。", "多蒙长者厚赠，葬我父亲之恩也。", "(正末唱)暂用急怎敢思君报。"]'),
('yuanqu-1026','张公艺九世同居・梅花酒','无名氏','元','元曲','yuanqu','','[]','今日个事已了，乃朋友之交。',101,'元曲/yuanqu.json','["今日个事已了，乃朋友之交。", "我投以木桃，君报以琼瑶。", "感足下情分好，并不受半分毫。", "(行钱云)这些银子你不要，我拿去买酒吃哩。", "(正末唱)谢天臣敬重老，对县宰众官僚，他举金杯劝香醪，谈今古恣酬酢，喜欢会在今朝。"]'),
('yuanqu-1027','张公艺九世同居・鸳鸯煞','无名氏','元','元曲','yuanqu','','[]','感君王亲赐皇宣诏，谢大臣远践红尘道。',63,'元曲/yuanqu.json','["感君王亲赐皇宣诏，谢大臣远践红尘道。", "送别临歧，走马还朝。", "唱道顿首诚惶，瞻天拜表。", "感谢深蒙雨露恩难报。", "华胄遥遥，千古清风播皇阁。"]'),
('yuanqu-1028','商调・金络索挂梧桐咏别','高明','元','元曲','yuanqu','','[]','羞看镜里花，憔悴难禁架，耽阁眉儿淡了教谁画？最苦魂梦飞绕天涯，须信流年鬓有华。',174,'元曲/yuanqu.json','["羞看镜里花，憔悴难禁架，耽阁眉儿淡了教谁画？最苦魂梦飞绕天涯，须信流年鬓有华。", "红颜自古多薄命，莫怨东风当自嗟。", "无人处，盈盈珠泪偷弹洒琵琶。", "恨那时错认冤家，说尽了痴心话。", "一杯别酒阑，三唱阳关罢，万里云山两下相牵畦。", "念奴半点情与伊家，分付些儿莫记差：不如收拾闲风月，再休惹朱雀桥边野草化。", "无人把，萋萋芳草随君到天涯。", "准备着夜雨梧桐，和泪点常飘洒。", "套数。"]'),
('yuanqu-1029','前腔・风流，恩情怎比墙花路柳？记待月西厢和你携素手。争奈话别匆匆，','高明','元','元曲','yuanqu','','[]','雨散云收？一种相思分做两处愁，雁来是音书未有。',26,'元曲/yuanqu.json','["雨散云收？一种相思分做两处愁，雁来是音书未有。", "合前。"]'),
('yuanqu-1030','集贤宾・西风桂子香韵幽，奈虚度中秋。明月无情穿户牖，听寒蛩声满床','高明','元','元曲','yuanqu','','[]','空房自守，暗数尽谯楼上更漏。',30,'元曲/yuanqu.json','["空房自守，暗数尽谯楼上更漏。", "合如病酒，这滋味那人知否？合前。"]'),
('yuanqu-1031','前腔・功名未遂姻缘未偶，共一个眉头。恼乱春心卒未休，怕朱颜去也难','高明','元','元曲','yuanqu','','[]','把明珠暗投，不如意十常八九。',17,'元曲/yuanqu.json','["把明珠暗投，不如意十常八九。", "合前。"]'),
('yuanqu-1032','黄莺儿・霜降水痕收，迅池塘犹暮秋。满城风雨还重九。白衣人送酒，乌','高明','元','元曲','yuanqu','','[]','纱帽恋头，思那人应似黄花瘦。',31,'元曲/yuanqu.json','["纱帽恋头，思那人应似黄花瘦。", "合怕登楼，云山万叠，遮不得许多愁。"]'),
('yuanqu-1033','猫儿坠・绿荷萧索无可盖眠鸥，碧粼粼露远洲。羁人无力冷飕飕，合愁，','高明','元','元曲','yuanqu','','[]','早知道宋玉当时顿觉伤秋。',12,'元曲/yuanqu.json','["早知道宋玉当时顿觉伤秋。"]'),
('yuanqu-1037','中吕・迎仙客','云龛子','元','元曲','yuanqu','','[]','混元珠，无价宝，赤水溪边收拾了。',421,'元曲/yuanqu.json','["混元珠，无价宝，赤水溪边收拾了。", "色浑浑，光皎皎，手中握定，占断人间俏。", "没机关，没做作，日月任催催不老。", "逆行船，翻拨棹，谁知这个，清净家风好。", "水深清，山色好，天下是非全不到。", "竹窗幽，茅屋小，个中真乐，莫向人间道。", "竹风轻，花影重，酩酊一瓯琴三弄。", "露玄机，藏妙用，槐坛将相，看破浮生梦。", "柳阴边，松影下，竖起脊梁诸缘罢。", "锁心猿，擒意马，明月清风，共谁说长生话。", "汉钟离，官极品，南柯梦断抛金印。", "草鞋轻，藜杖稳，笑携日月，独步长生境。", "吕洞宾，超物外，神光照破三千界。", "弃功名，同草芥，龟毛柱杖，一击乾坤坏。", "混元初，张果老，白驴踏着虚空倒。", "紫云生，红雾绕，夜来一口，吞却蓬莱岛。", "蓝采和，离世俗，手中拍板敲寒玉。", "摆天关，摇地轴，清风明月，独唱长生曲。", "刘海蟾，燕宰相，梦回看破空花放。", "别人间，离海上，红炉片雪，打就黄金像。", "广成子，千二百，崆峒高卧寒云白。", "帝王师，天地宅，纵横自在，物外无名客。", "范蠡翁，曾佐越，五湖独泛扁舟月。", "是非忘，名利绝，一声短笛，受用芦花雪。"]'),
('yuanqu-1038','须贾大夫谇范叔・仙吕/端正好','高文秀','元','元曲','yuanqu','','[]','凭著俺仲尼书，苍颉字，周公礼，子产文辞。',40,'元曲/yuanqu.json','["凭著俺仲尼书，苍颉字，周公礼，子产文辞。", "奈家贫不遇人驱使，怎肯道是无用也于才思。"]'),
('yuanqu-1039','须贾大夫谇范叔・幺篇','高文秀','元','元曲','yuanqu','','[]','常则是半生忙，不遂我平生志，居陋巷甘分随时。',99,'元曲/yuanqu.json','["常则是半生忙，不遂我平生志，居陋巷甘分随时。", "今日个和使臣冠盖相随次，离魏国，到临淄；凭喉舌，决雄雌；休战阵，免兴师，(带云)大人放心，凭范雎三寸之舌，包请俺公子归国便了。", "(唱)管成就这公事。", "(下)。"]'),
('yuanqu-1040','须贾大夫谇范叔・仙吕/点绛唇','高文秀','元','元曲','yuanqu','','[]','日月煎熬，利名牵扰，人空老。',28,'元曲/yuanqu.json','["日月煎熬，利名牵扰，人空老。", "今日明朝，则俺这愁思知多少。"]'),
('yuanqu-1041','须贾大夫谇范叔・混江龙','高文秀','元','元曲','yuanqu','','[]','若依着先王典教，贫而无谄富无骄，俺可甚一身流落，半世辛劳？常只是白首相知犹按剑，枉了也朱门先达有同袍。',81,'元曲/yuanqu.json','["若依着先王典教，贫而无谄富无骄，俺可甚一身流落，半世辛劳？常只是白首相知犹按剑，枉了也朱门先达有同袍。", "猛回头则落的纥地微微笑，倒不如痴呆懵懂，甘守着陋巷的这箪瓢。"]'),
('yuanqu-1042','须贾大夫谇范叔・天下乐','高文秀','元','元曲','yuanqu','','[]','他每只是些躲避当差影身草，自古来文章，可便将人都误了。',114,'元曲/yuanqu.json','["他每只是些躲避当差影身草，自古来文章，可便将人都误了。", "(邹衍云)我想古人都是靠着文章出身的，怎见得就误了人来？(正末唱)劝今人休将前辈学。", "(邹衍云)学便如何？(正末唱)学卞庄斩虎的入虎穴，学吕望钓鱼的近池沼，学太康放鹰鹘拿燕雀。"]'),
('yuanqu-1043','须贾大夫谇范叔・那吒令','高文秀','元','元曲','yuanqu','','[]','我论着那斩虎的，则不如去斩蛟；(邹衍云)这钓鱼的，可是如何？(正末唱)钓于的，则不如去钓鳌；(邹衍云)这放鹰的，可是如何？(正末唱)放鹰的，则不如去放雕。',99,'元曲/yuanqu.json','["我论着那斩虎的，则不如去斩蛟；(邹衍云)这钓鱼的，可是如何？(正末唱)钓于的，则不如去钓鳌；(邹衍云)这放鹰的，可是如何？(正末唱)放鹰的，则不如去放雕。", "调大谎往上趱，抱粗腿向前跳，倒能够禄重官高。"]'),
('yuanqu-1044','须贾大夫谇范叔・鹊踏枝','高文秀','元','元曲','yuanqu','','[]','但有些个好穿着，好靴脚，出来的苫眼铺眉，一个个纳胯挪腰。',54,'元曲/yuanqu.json','["但有些个好穿着，好靴脚，出来的苫眼铺眉，一个个纳胯挪腰。", "说谎的今时可便使着，天那，则俺这诚实的管老死蓬蒿！。"]'),
('yuanqu-1045','须贾大夫谇范叔・寄生草','高文秀','元','元曲','yuanqu','','[]','本待要寻知契、谒故交，见十家九家门关了。',311,'元曲/yuanqu.json','["本待要寻知契、谒故交，见十家九家门关了。", "起三阵五阵檐风哨，有千片万片梨花落。", "但得个一顷半顷洛阳田，谁待想七月八月长安道？(邹衍云)张千，将酒来。", "(张千云)酒到。", "(邹衍云)贤士，小官奉命将着那牛酒管待贤士，请满饮此杯者。", "(做递酒科，正末云)大人请。", "(邹衍云)贤士请。", "(正末云)恭敬不如从命，小生饮这杯酒咱。", "(做饮酒科)(邹衍云)小官奉主公的命，在此驿亭中管待贤士，须要尽醉方归。", "张千，唤将那歌儿舞女来者，着他席间伏侍贤士。", "(张千云)歌儿舞女走动。", "(二旦上，动乐科)(邹衍云)贤士，如今暮冬天道，纷纷扬扬下的是国家祥瑞，更接着这歌儿舞女，娇喉细细，红袖翩翩。", "贤士请放开怀抱，满饮一杯者。", "(正末云)大人，委的是好受用也！(唱)。"]'),
('yuanqu-1046','须贾大夫谇范叔・醉扶归','高文秀','元','元曲','yuanqu','','[]','俺则待手把着严陵钓，耳洗着许由瓢。',102,'元曲/yuanqu.json','["俺则待手把着严陵钓，耳洗着许由瓢。", "不图他顶冠束带立于朝，但得个身安乐。", "(邹衍云)贤士，你怎么说这等没志气的话？人生功名富贵，皆由自取，也不专是天数。", "(正末唱)则这的便是俺一斟一酌，再休题富贵也有个轮来到。"]'),
('yuanqu-1047','须贾大夫谇范叔・梁州第七','高文秀','元','元曲','yuanqu','','[]','但只问魏公子因何释放，全仗着那一个游说齐邦？怎生这功劳不在咱头上？几曾沾一丝儿赏赐，壮半米儿行装？可着俺越多伎俩，越受凄凉。',186,'元曲/yuanqu.json','["但只问魏公子因何释放，全仗着那一个游说齐邦？怎生这功劳不在咱头上？几曾沾一丝儿赏赐，壮半米儿行装？可着俺越多伎俩，越受凄凉。", "枉误了十载文章，干捱了半世风霜。", "他、他、他，谁肯念陋巷间一瓢的书生，是、是、是，我愿则愿那都堂中八府的宰相，来、来、来，他每都不着我见那深宫内万岁的君王。", "这天气，怎当？白茫茫冰连江海三千丈。", "徒步去，将何往？早则是冒雪冰寒冻欲僵，这便是咱衣锦还乡！。"]'),
('yuanqu-1048','须贾大夫谇范叔・隔尾','高文秀','元','元曲','yuanqu','','[]','你那里葡萄酒设销金帐，罗绮筵开白玉堂。',101,'元曲/yuanqu.json','["你那里葡萄酒设销金帐，罗绮筵开白玉堂。", "闻知道魏相国亲身到宅上。", "(做徘徊科，云)既是请丞相赴宴，怎又请我？(唱)故意把寒儒厮奖，显的他宽洪海量。", "(云)哦，我知道了也。", "(唱)多应是须贾高情，将我这范雎来讲。"]'),
('yuanqu-1049','须贾大夫谇范叔・隔尾','高文秀','元','元曲','yuanqu','','[]','正是那耕牛为主遭鞭杖，哑妇倾杯反受殃，灾祸临身自天降。',51,'元曲/yuanqu.json','["正是那耕牛为主遭鞭杖，哑妇倾杯反受殃，灾祸临身自天降。", "我吃了这一场棍棒，天那！这的是为国于家落来的赏。"]'),
('yuanqu-1050','须贾大夫谇范叔・牧羊关','高文秀','元','元曲','yuanqu','','[]','泪雹子腮边落，血冬凌满脊梁，冻剥剥雪上加霜。',69,'元曲/yuanqu.json','["泪雹子腮边落，血冬凌满脊梁，冻剥剥雪上加霜。", "则被你饿掉了三魂，敲翻了五脏。", "带肉连皮颤，彻髓透心凉。", "似这等勘范叔森罗殿，抵多少冻苏秦冰雪堂。"]'),
('yuanqu-1051','须贾大夫谇范叔・菩萨梁州','高文秀','元','元曲','yuanqu','','[]','则我这绵囤也似衣裳，坐不的红炉也那土坑。',100,'元曲/yuanqu.json','["则我这绵囤也似衣裳，坐不的红炉也那土坑。", "吃黄齑的肚肠，(带云)抬了者。", "(唱)我吃不的这法酒肥羊。", "则我这三般地狱怎生当？无情风雪无情棒。", "似吃着无心草，死熬这掩情况。", "打得我肉绽皮开内外伤，眼见的不久身亡。"]'),
('yuanqu-1052','须贾大夫谇范叔・隔尾','高文秀','元','元曲','yuanqu','','[]','哎呀，我几曾醉眠绣被流苏帐，莫不是梦断茅庐映雪窗？长叹罢刚将眼睁放，我看了这厢，我又觑了那厢。',65,'元曲/yuanqu.json','["哎呀，我几曾醉眠绣被流苏帐，莫不是梦断茅庐映雪窗？长叹罢刚将眼睁放，我看了这厢，我又觑了那厢。", "天也，原来我这七尺身躯在那厕坑里躺。"]'),
('yuanqu-1053','须贾大夫谇范叔・牧羊关','高文秀','元','元曲','yuanqu','','[]','待走来如何走？待藏来怎地藏？没揣的偏和他打个头撞。',592,'元曲/yuanqu.json','["待走来如何走？待藏来怎地藏？没揣的偏和他打个头撞。", "(院公云)我举起这灯来试看咱。", "我道是谁，原来是范雎。", "你看一身秽污，你也少吃一钟波。", "(正末唱)我几曾吃美酒羊羔，刚刚是吃了会胡枷乱棒。", "(院公云)你既不醉呵，怎生浑身都是秽污？(正末唱)则被这粪沾湿我两鬓角，尿浸透我一胸膛。", "(院公云)你站开些，这臭气当不得。", "(正末唱)你闻不的我这秽气浑身臭，院公也，我几吃那开埕十里香。", "(院公云)你原来不曾吃酒，可怎生这个模样？(正末做跪科，云)院公可怜见，你救我咱。", "我同大夫入齐为使，见了齐王，一席话间，齐王大喜，便将公子魏申释放还国。", "齐王命中大夫邹衍在驿亭中赐牛酒管待小生，又赐黄金千两，我并不曾受，这是大夫亲见的。", "今归本国，安排筵宴请魏齐丞相饮酒，说我以阴事告齐，将我三推六问，吊拷绷扒，打死了我，丢在这粪坑中，倒亏这秽气熏活了。", "望院公怎生救我出去，此恩异日必当重报。", "(院公云)嗨，好可怜人也。", "这里也无人，你跟我将来，打些水淋的你身上干净，脱了你那秽污衣服。", "这寒冷天道，不冻杀了你来。", "我有穿的旧绵衣服，待我取来与你穿。", "(做取砌末科上，云)你穿了这衣服，还有五两碎银子，与你将息去。", "我如今开了后角门，放你出去。", "你休在这里，不问他州外府，逃你的性命。", "你久已后若得志呵，只休忘了我的恩念。", "(正末做拜科，云)院公，你是我重生的父母，再养的爷娘。", "小生也不往他处，唯有秦国最强，可以报仇，就此告辞去也。", "(唱)。"]'),
('yuanqu-1054','须贾大夫谇范叔・黄钟尾','高文秀','元','元曲','yuanqu','','[]','我便似伍员去楚心犹壮，孙膑投齐气怎降？谢恩人肯主张，放咱去入咸阳。',106,'元曲/yuanqu.json','["我便似伍员去楚心犹壮，孙膑投齐气怎降？谢恩人肯主张，放咱去入咸阳。", "仗英雄显志量，见秦君说勾当。", "管穰侯立辞相，不荒唐有承望，(云)院公，不是我范雎说口，想报冤之期，可也不远。", "(唱)你则待的到蛰龙一声雷震响。", "(下)。"]'),
('yuanqu-1055','须贾大夫谇范叔・正宫/端正好','高文秀','元','元曲','yuanqu','','[]','未亨通，遭穷困，身居在白屋寒门。',31,'元曲/yuanqu.json','["未亨通，遭穷困，身居在白屋寒门。", "两轮日月消磨尽，不觉的添霜鬓。"]'),
('yuanqu-1056','须贾大夫谇范叔・滚绣球','高文秀','元','元曲','yuanqu','','[]','人道是文章好济贫，偏我被儒冠误此身，到今日越无求进，我本待学儒人倒不如人。',227,'元曲/yuanqu.json','["人道是文章好济贫，偏我被儒冠误此身，到今日越无求进，我本待学儒人倒不如人。", "昨日周，今日秦，(带云)似这般途路难逢呵，(唱)可着我有家难奔，恰便似断蓬般移转无根。", "道不得个地无松柏非为贵，腹隐诗书未是贫，则着我何处飘沦？(正末做窥望)(须贾见科，云)奇怪，大雪中走将来这个人，好似范雎也。", "待道是呵，我当初打杀他了，再怎生得个范雎来？待道不是呵，你看那身分儿好生相似。", "且休问他是不是，待我唤一声：范雎，范雎，近前来，我和你说话咱。", "(正末云)谁唤范雎哩？(唱)。"]'),
('yuanqu-1057','须贾大夫谇范叔・叨叨令','高文秀','元','元曲','yuanqu','','[]','我听的他两三番叫咱往前进，猛可便扭回身行至车儿近。',178,'元曲/yuanqu.json','["我听的他两三番叫咱往前进，猛可便扭回身行至车儿近。", "我这里忙掠开泪眼将他认，(须贾云)是我唤你哩。", "(正末唱)我这里觑绝时倒把身躯褪。", "(正末做怕科)(须贾云)范雎，你见了小官，这般慌做甚么那？(正末唱)大夫也，你莫不又待打我也波哥，你莫不又待打我也波哥，唬的我兢兢战战忙逃奔。", "(须贾云)范雎少待，一别许久，正要和你讲话，何故如此惊恐？先生固无恙乎？(正末唱)。"]'),
('yuanqu-1058','须贾大夫谇范叔・滚绣球','高文秀','元','元曲','yuanqu','','[]','大夫也，想着你折磨我那一场，我吃了你那一顿，你打到我有二三百棍。',216,'元曲/yuanqu.json','["大夫也，想着你折磨我那一场，我吃了你那一顿，你打到我有二三百棍。", "(须贾云)你且休题旧话，则问先生何以到此？(正末唱)自从我逃灾出魏国夷门，(须贾云)原来先生西入秦邦，有几时了？(正末唱)到今日经两冬，过一春，睡梦里不曾得个安稳。", "(须贾云)你也曾思量小官么？(正末唱)想着你那雪堆儿里将我棍棒临身，(须贾云)你这般慌做甚么？(正末唱)但题着你名姓先惊了胆。", "梦见你仪容，(带云)兀的是须贾大夫来也。", "(唱)哎呀，可又早唬了魂，有甚精神？。"]'),
('yuanqu-1059','须贾大夫谇范叔・倘秀才','高文秀','元','元曲','yuanqu','','[]','你看我这巾帻旧、雪冰透我脑门，衣衫破、遮不着我这项筋，甚的是白马戏缨衫色新？自叹气，自伤神，只落的微微暗哂。',54,'元曲/yuanqu.json','["你看我这巾帻旧、雪冰透我脑门，衣衫破、遮不着我这项筋，甚的是白马戏缨衫色新？自叹气，自伤神，只落的微微暗哂。"]'),
('yuanqu-1060','须贾大夫谇范叔・伴读书','高文秀','元','元曲','yuanqu','','[]','谢大夫多情分，赐绨袍无悭吝。',66,'元曲/yuanqu.json','["谢大夫多情分，赐绨袍无悭吝。", "我可便接将来怎敢虚谦逊，觉的软设设身上如绵囤。", "不由不喜孜孜顿解心头闷，我、我、我，怎报的你这救济之恩？。"]'),
('yuanqu-1061','须贾大夫谇范叔・笑和尚','高文秀','元','元曲','yuanqu','','[]','比我旧腰身宽二分，比我旧衣襟长三寸，正遮了这破单裤精臁刃。',366,'元曲/yuanqu.json','["比我旧腰身宽二分，比我旧衣襟长三寸，正遮了这破单裤精臁刃。", "冻剥剥正暮冬，如今暖溶溶便开春，来、来、来，谢绨袍妆点了我腌身分。", "(背云)此人绨袍恋恋，尚有故人之心也。", "(须贾云)先生，与小官同到邸舍，共一饭叙旧如何？(正末云)敢问大夫为何至此？(须贾云)先生不知，小官特来庆贺张禄丞相。", "先生在秦已久，可曾闻的张禄丞相与谁人最善也？(正末云)原来大夫因贺张禄丞相到此。", "小生别无闻见，但张禄丞相与小生亦有一面之交。", "(须贾云)哦，先生原来与张君有善。", "(做背科，云)我这绨袍送的着了也。", "(回云)先生，吾闻秦国大小之事，一决于相君。", "今吾等在此，去留皆出其口。", "先生如肯与小官少进片言，慨放小官回还，也见得先生不忘故旧。", "岂有意乎？(正末云)这个当得，但恐人微言轻，不足为重。", "(须贾云)我想先生在魏国时，小官也不曾轻视先生。", "(正末云)多感！多感！(唱)。"]'),
('yuanqu-1062','须贾大夫谇范叔・滚绣球','高文秀','元','元曲','yuanqu','','[]','想着你那日辰，那时分，我胡吃了三推六问，着我似拽车的驴马同尘。',123,'元曲/yuanqu.json','["想着你那日辰，那时分，我胡吃了三推六问，着我似拽车的驴马同尘。", "想着你喂惜的情，草料的恩，我怎肯背槽抛粪。", "(须贾云)君子不念旧恶，这也不必提起了。", "(正末唱)请你个老哥哥远害全身。", "则咱这义的到底终须义，大夫也，你那亲的原来则是亲，我怎做的有喜无嗔？。"]'),
('yuanqu-1063','须贾大夫谇范叔・呆骨朵','高文秀','元','元曲','yuanqu','','[]','休则管巧言令色闲评论，到如今比并甚往古忠臣。',78,'元曲/yuanqu.json','["休则管巧言令色闲评论，到如今比并甚往古忠臣。", "我可也不似灵辄，你可也难学赵盾。", "大夫也，假若你赵盾身危困，我待学灵辄臂扶轮。", "则不要槽中拌和草，便是那桑间一饭恩。"]'),
('yuanqu-1064','须贾大夫谇范叔・滚绣球','高文秀','元','元曲','yuanqu','','[]','他见我尘满衣，垢满身，更和这蓬松两鬓，才出的相府仪门。',116,'元曲/yuanqu.json','["他见我尘满衣，垢满身，更和这蓬松两鬓，才出的相府仪门。", "他骂我做叫化头，乞俭身，都佯呆着不瞅不问，(须贾云)他如今为何惧怕先生也？(正末唱)猛见这素绨袍在我身上全新。", "为甚的那厮每趋前退后都皆怕？大夫也，可知道只敬衣衫不敬人，自古常闻。"]'),
('yuanqu-1065','须贾大夫谇范叔・三煞','高文秀','元','元曲','yuanqu','','[]','他论机谋减灶压着齐孙膑，他论战策不弱如鞭尸楚伍员。',89,'元曲/yuanqu.json','["他论机谋减灶压着齐孙膑，他论战策不弱如鞭尸楚伍员。", "则他那智量似穰苴，文学似子夏，德行似颜渊，舌辩似苏秦。", "端的个能安其国，能治其家，能正其身。", "请大夫把衣冠整顿，我与你同作伴谒张君。"]'),
('yuanqu-1066','须贾大夫谇范叔・二煞','高文秀','元','元曲','yuanqu','','[]','你略消停且待穷交信，便入去须防丞相嗔。',79,'元曲/yuanqu.json','["你略消停且待穷交信，便入去须防丞相嗔。", "我着你早出潼关，早归汴水，早到东京，早离西秦。", "引你去亲登相府，完却公差，直着他开放贤门。", "这归期有准，管着你荡飞骑疾如云。"]'),
('yuanqu-1067','须贾大夫谇范叔・煞尾','高文秀','元','元曲','yuanqu','','[]','我与你分开片片梨花粉，拂散纷纷柳絮尘。',43,'元曲/yuanqu.json','["我与你分开片片梨花粉，拂散纷纷柳絮尘。", "金马门中往前进，我将你个纳士招贤路儿引。", "(下)。"]'),
('yuanqu-1068','须贾大夫谇范叔・双调/新水令','高文秀','元','元曲','yuanqu','','[]','白身一跳到关西，坐都堂便登八位。',40,'元曲/yuanqu.json','["白身一跳到关西，坐都堂便登八位。", "入朝争相印，当殿脱儒衣。", "口吐虹霓，三千丈五陵气。"]'),
('yuanqu-1069','须贾大夫谇范叔・步步娇','高文秀','元','元曲','yuanqu','','[]','这的是楚赵秦韩齐燕魏，今日个七国冠裳会。',117,'元曲/yuanqu.json','["这的是楚赵秦韩齐燕魏，今日个七国冠裳会。", "把干戈从此息，我有甚不欢欣不肯拚沉醉？(邹衍云)丞相请满饮此杯。", "(正末云)住者，(唱)且按住这凤凰杯，(邹衍云)丞相因何不肯饮酒？(正末云)张千。", "(张千云)小人有。", "(正末唱)你只问须贾来也是未。"]'),
('yuanqu-1070','须贾大夫谇范叔・沽美酒','高文秀','元','元曲','yuanqu','','[]','去年时我记的，今日是你生日，天教我便还报你。',49,'元曲/yuanqu.json','["去年时我记的，今日是你生日，天教我便还报你。", "(云)张千，(唱)我这里唤公吏，快疾波请先生去了衣袂。"]'),
('yuanqu-1071','须贾大夫谇范叔・太平令','高文秀','元','元曲','yuanqu','','[]','哎，你个须贾也哥哥休罪，(云)张千，将问事来。',91,'元曲/yuanqu.json','["哎，你个须贾也哥哥休罪，(云)张千，将问事来。", "(张千云)理会的。", "(做丢下问事科)(正末唱)早准备拶子麻槌，下着的国家祥瑞，拣一塔干净田地。", "将这厮跪只，按只，与我仗只，直打的皮开肉碎。"]'),
('yuanqu-1072','须贾大夫谇范叔・川拨棹','高文秀','元','元曲','yuanqu','','[]','这东西，去年时你备的。',42,'元曲/yuanqu.json','["这东西，去年时你备的。", "我与你揣在怀里，放在跟底。", "请先生服毒自吃，俺这里别无甚好饭食。"]'),
('yuanqu-1073','须贾大夫谇范叔・七弟兄','高文秀','元','元曲','yuanqu','','[]','这的，与你，做生日，一根草满寿你一千岁。',70,'元曲/yuanqu.json','["这的，与你，做生日，一根草满寿你一千岁。", "去年将小子痛凌迟，今日教你也知滋味。", "(邹衍云)丞相，各国大夫都在此庆贺，须要尽醉方休也。", "(正末唱)。"]'),
('yuanqu-1074','须贾大夫谇范叔・梅花酒','高文秀','元','元曲','yuanqu','','[]','俺只见众公卿摆列齐，在紫阁黄扉，捧玉液金杯，一周遭绣履珠衣。',66,'元曲/yuanqu.json','["俺只见众公卿摆列齐，在紫阁黄扉，捧玉液金杯，一周遭绣履珠衣。", "从早起至晚夕，食又饱酒又醉。", "他在那大雪里冻一会、问一会，问一会、打一会。"]'),
('yuanqu-1075','须贾大夫谇范叔・收江南','高文秀','元','元曲','yuanqu','','[]','呀，你道我坐儿不觉立儿饥，今朝轮到我还席。',51,'元曲/yuanqu.json','["呀，你道我坐儿不觉立儿饥，今朝轮到我还席。", "则为你损人利己使心机，图着个甚的？可正是得便宜翻做了落便宜。"]'),
('yuanqu-1076','须贾大夫谇范叔・清江引','高文秀','元','元曲','yuanqu','','[]','老院公肯分的来到这里，左右难回避。',90,'元曲/yuanqu.json','["老院公肯分的来到这里，左右难回避。", "他怎敢轻撩虎狼须，快与我搬住猿猱臂。", "(带云)须贾，(唱)你饶过了这老院公，我也饶过了你。", "(院公云)望丞相爷看老院公薄面，饶过俺主人罢。", "(正末唱)。"]'),
('yuanqu-1077','须贾大夫谇范叔・雁儿落','高文秀','元','元曲','yuanqu','','[]','虽然是为恩人有面皮，我与你这贼子无情意。',65,'元曲/yuanqu.json','["虽然是为恩人有面皮，我与你这贼子无情意。", "你若要生辞函谷关，只除非梦返夷门地。", "(须贾云)丞相，这都是旧话，不提他也罢了。", "(正末唱)。"]'),
('yuanqu-1078','须贾大夫谇范叔・得胜令','高文秀','元','元曲','yuanqu','','[]','呀，你道是旧话再休题，我可不干吃你一场亏？(邹衍同众大夫跪科，云)丞相在上，须贾罪过虽重，但他绨袍恋恋，也还有故人之情，望丞相姑恕。',127,'元曲/yuanqu.json','["呀，你道是旧话再休题，我可不干吃你一场亏？(邹衍同众大夫跪科，云)丞相在上，须贾罪过虽重，但他绨袍恋恋，也还有故人之情，望丞相姑恕。", "(正末云)众大夫请起，(唱)也则为尚有绨袍恋，因此上权停棍棒威。", "待饶伊，我也要将今日思前日；待不饶伊，又道我只报仇不报德。"]'),
('yuanqu-1079','须贾大夫谇范叔・收尾','高文秀','元','元曲','yuanqu','','[]','我如今且将须贾驴头寄，疾回去，报与梁王得知。',244,'元曲/yuanqu.json','["我如今且将须贾驴头寄，疾回去，报与梁王得知。", "着他早早的解过魏齐来，(带云)那时节再约大众大夫同临敝国，(唱)慢慢的再贺俺范雎喜。", "(须贾换冠带，同众大夫拜谢科，云)谢丞相宽恩，敢不唯命！(院公云)这一件倒不好承认。", "那魏齐手下心腹人极多，只怕也有似俺院公的，私下放他溜了，教俺主人那里去抓他？(邹衍云)小官等再奉丞相一杯。", "(正末云)酒也深了，一面撤过宴者。", "(词云)因须贾不识忠臣，用谗言闭塞贤门，施侥幸将人陷害，怎知他天道无亲。", "大雪中绨袍恋恋，才得个免祸全身。", "快献取魏齐首级，罢刀兵永灭征尘。"]'),
('yuanqu-1080','杜蕊娘智赏金线池・仙吕/端正好','关汉卿','元','元曲','yuanqu','','[]','郑六遇妖狐，崔韬逢雌虎，那大曲内尽是寒儒。',40,'元曲/yuanqu.json','["郑六遇妖狐，崔韬逢雌虎，那大曲内尽是寒儒。", "想知今晓古人家女，都待与秀才每为夫妇。"]'),
('yuanqu-1081','杜蕊娘智赏金线池・幺篇','关汉卿','元','元曲','yuanqu','','[]','既不呵，那一片俏心肠，那里每堪分付？那苏小卿不辨贤愚，比如我五十年不见双通叔；休道是苏妈妈，也不是醉驴驴。',104,'元曲/yuanqu.json','["既不呵，那一片俏心肠，那里每堪分付？那苏小卿不辨贤愚，比如我五十年不见双通叔；休道是苏妈妈，也不是醉驴驴。", "我是他亲生的女，又不是买来的奴，遮莫拷的我皮肉烂，炼的我骨髓枯，我怎肯跟将那贩茶的冯魁去！（同韩下）。"]'),
('yuanqu-1082','杜蕊娘智赏金线池・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','则俺这不义之门，那里有买卖营运？无资本，全凭着五个字迭办金银。',61,'元曲/yuanqu.json','["则俺这不义之门，那里有买卖营运？无资本，全凭着五个字迭办金银。", "（带云）可是那五个字？(唱)无过是\"恶、劣、乖、毒、狠\"！。"]'),
('yuanqu-1083','杜蕊娘智赏金线池・混江龙','关汉卿','元','元曲','yuanqu','','[]','无钱的可要亲近，则除是驴生戟瓮生根。',170,'元曲/yuanqu.json','["无钱的可要亲近，则除是驴生戟瓮生根。", "佛留下四百八门衣饭，俺占着七十二位凶神。", "才定脚谢馆接迎新子弟，转回头霸陵谁识旧将军？投奔我的都是那矜爷害娘、冻妻饿子、折屋卖田、提瓦罐爻槌运；那些个慈悲为本，多则是板障为门。", "（云）梅香，你看奶奶做甚么哩？（梅香云）奶奶看经哩！（正旦云）俺娘口业作罪，你这般心肠，多少经文忏的过来？枉作的业深了也！（唱）。"]'),
('yuanqu-1084','杜蕊娘智赏金线池・天下乐','关汉卿','元','元曲','yuanqu','','[]','他只待夜夜留人夜夜新，殷勤，顾甚的恩！不依随又道是我女孩儿不孝顺。',55,'元曲/yuanqu.json','["他只待夜夜留人夜夜新，殷勤，顾甚的恩！不依随又道是我女孩儿不孝顺。", "今日个漾人头厮摔，含热血厮喷，定夺俺心上人。"]'),
('yuanqu-1085','杜蕊娘智赏金线池・醉扶归','关汉卿','元','元曲','yuanqu','','[]','有句话多多的苦告你老年尊，累累的嘱托近比邻，"一片花飞减却春"，我如今不老也非为嫩，年纪小呵须是有气分，年纪老无人问。',165,'元曲/yuanqu.json','["有句话多多的苦告你老年尊，累累的嘱托近比邻，\"一片花飞减却春\"，我如今不老也非为嫩，年纪小呵须是有气分，年纪老无人问。", "（云）母亲，嫁了您孩儿罢，孩儿年纪大了也！（卜儿云）丫头，拿镊子来，镊了鬓边的白发，还着你觅钱哩！（正旦云）母亲，你只管与孩儿撇性怎的？（卜儿云）我老人家如今性子淳善了，若发起村来，怕不筋都敲断你的！（正旦唱）。"]'),
('yuanqu-1086','杜蕊娘智赏金线池・金盏儿','关汉卿','元','元曲','yuanqu','','[]','你道是性儿淳，我道你意儿村，提起那人情来往佯装钝。',97,'元曲/yuanqu.json','["你道是性儿淳，我道你意儿村，提起那人情来往佯装钝。", "（带云）有几个打踅客旅辈，丢下些刷牙掠头，问奶奶要盘缠家去。", "（唱）你可早耳朵闭、眼睛昏；前门里统镘客，后门里一个使钱勤；揉开汪泪眼，打拍老精神。"]'),
('yuanqu-1087','杜蕊娘智赏金线池・醉中天','关汉卿','元','元曲','yuanqu','','[]','非是我偏生忿，还是你不关亲，只着俺淡抹浓妆倚市门，积趱下金银囤。',99,'元曲/yuanqu.json','["非是我偏生忿，还是你不关亲，只着俺淡抹浓妆倚市门，积趱下金银囤。", "（卜儿做怒科，云）你这小贱人，你今年才过二十岁，不与我觅钱，教那个觅钱？（正旦唱）你道俺才过二旬，有一日粉消香褪，可不道老死在风尘？。"]'),
('yuanqu-1088','杜蕊娘智赏金线池・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','东洋海洗不尽脸上羞，西华山遮不了身边丑，大力鬼顿不开眉上锁，巨灵神劈不断腹中愁。',83,'元曲/yuanqu.json','["东洋海洗不尽脸上羞，西华山遮不了身边丑，大力鬼顿不开眉上锁，巨灵神劈不断腹中愁。", "闪的我有国难投，抵多少南浦伤离后。", "爱你个杀才没去就，明知道雨歇云收，还指望待天长地久。"]'),
('yuanqu-1089','杜蕊娘智赏金线池・牧羊关','关汉卿','元','元曲','yuanqu','','[]','不见他思量旧，倒有些两意儿投。',114,'元曲/yuanqu.json','["不见他思量旧，倒有些两意儿投。", "－我见了他扑邓邓火上浇油，恰便似钩搭住鱼腮，箭穿了雁口。", "（韩辅臣云）元来你那旧性儿不改，还弹唱哩！（正旦做起拜科）（唱）你怪我依旧拈音乐，则许你交错劝觥筹？你不肯冷落了杯中物，我怎肯生疏了弦上手？。"]'),
('yuanqu-1090','杜蕊娘智赏金线池・骂玉郎','关汉卿','元','元曲','yuanqu','','[]','这的是母亲故折鸳鸯偶，须不是咱设下恶机谋，怎将咱平空抛落他人后？今日个何劳你贵脚儿又到咱家走？。',48,'元曲/yuanqu.json','["这的是母亲故折鸳鸯偶，须不是咱设下恶机谋，怎将咱平空抛落他人后？今日个何劳你贵脚儿又到咱家走？。"]'),
('yuanqu-1091','杜蕊娘智赏金线池・感皇恩','关汉卿','元','元曲','yuanqu','','[]','咱本是泼贱娼优，怎嫁得你俊俏儒流？（韩辅臣云）这是有盟约在前的。',167,'元曲/yuanqu.json','["咱本是泼贱娼优，怎嫁得你俊俏儒流？（韩辅臣云）这是有盟约在前的。", "（正旦唱）把枕畔盟、花下约、成虚谬。", "（韩辅臣云）我出你家门也只得半个多月，怎便见得虚谬了那？（正旦唱）你道是别匆匆无多半月，我觉的冷清清胜似三秋。", "（韩辅臣跪科，云）大姐，我韩辅臣不是了，我跪着你请罪罢！（正旦不睬科，云）那个要你跪！（唱）越显的你嘴儿甜、膝儿软、情儿厚。"]'),
('yuanqu-1092','杜蕊娘智赏金线池・二煞','关汉卿','元','元曲','yuanqu','','[]','有耨处散诞松宽着耨，有偷处宽行大步偷，何须把一家苦苦死淹留？也不管设誓拈香，到处里停眠整宿，说着他瞒心的谎、昧心的咒。',76,'元曲/yuanqu.json','["有耨处散诞松宽着耨，有偷处宽行大步偷，何须把一家苦苦死淹留？也不管设誓拈香，到处里停眠整宿，说着他瞒心的谎、昧心的咒。", "你那手怎掩旁人是非口？说的困须休。"]'),
('yuanqu-1093','杜蕊娘智赏金线池・尾煞','关汉卿','元','元曲','yuanqu','','[]','高如我三板儿的人物也出不得手，强如我十倍儿的声名道着处有。',89,'元曲/yuanqu.json','["高如我三板儿的人物也出不得手，强如我十倍儿的声名道着处有。", "寻些虚脾，使些机彀，用些工夫，再去趁逐。", "你与我高揎起春衫酒淹袖，舒你那攀蟾折桂的指头，请先生别挽一枝章台路旁柳。", "（下）。"]'),
('yuanqu-1094','杜蕊娘智赏金线池・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','明知道书生教门儿负心短命，尽教他海角飘零。',52,'元曲/yuanqu.json','["明知道书生教门儿负心短命，尽教他海角飘零。", "没来由强风情，刚可喜男婚女聘。", "往常我千战千赢，透风处使心作幸。"]'),
('yuanqu-1095','杜蕊娘智赏金线池・醉春风','关汉卿','元','元曲','yuanqu','','[]','能照顾眼前坑，不提防脑后井。',51,'元曲/yuanqu.json','["能照顾眼前坑，不提防脑后井。", "人跟前不恁的吃场扑腾，呆贱人几时能够醒、醒？虽是今番，系干宿世，事关前定。"]'),
('yuanqu-1096','杜蕊娘智赏金线池・石榴花','关汉卿','元','元曲','yuanqu','','[]','－恰便似藕丝儿分破镜花明，我则见一派碧澄澄，东关里犹自不曾经，到如今整整半载其程。',83,'元曲/yuanqu.json','["－恰便似藕丝儿分破镜花明，我则见一派碧澄澄，东关里犹自不曾经，到如今整整半载其程。", "眼前面兜率神仙境，有他呵怎肯道蓦出门庭？那时节眼札毛和他厮拴定，矮房里相扑着闷怀萦。"]'),
('yuanqu-1097','杜蕊娘智赏金线池・斗鹌鹑','关汉卿','元','元曲','yuanqu','','[]','虚度了丽日和风，枉误了良辰美景。',66,'元曲/yuanqu.json','["虚度了丽日和风，枉误了良辰美景。", "往常俺动脚是熬煎，回头是撞挺。", "拘束的刚刚转过双眼睛，到如今各自托生：我依旧安业着家，他依旧离乡背井。"]'),
('yuanqu-1098','杜蕊娘智赏金线池・普天乐','关汉卿','元','元曲','yuanqu','','[]','小妹子是爱莲儿，你都将我相钦敬；茶儿是妹子，你与我好好的看承；小妹子是玉伴哥，从来有些独强性。',135,'元曲/yuanqu.json','["小妹子是爱莲儿，你都将我相钦敬；茶儿是妹子，你与我好好的看承；小妹子是玉伴哥，从来有些独强性。", "（众旦云）姨姨，你为何嗟声叹气的？今日这样好天气，又对着这样好景致，务要开怀畅饮，做一个欢庆会才是。", "（正旦唱）说甚么人欢庆，引得些鸳鸯儿交颈和鸣，忽的见了，愠的面赤，兜的心疼。"]'),
('yuanqu-1099','杜蕊娘智赏金线池・醉高歌','关汉卿','元','元曲','yuanqu','','[]','或是曲儿中唱几个花名。',75,'元曲/yuanqu.json','["或是曲儿中唱几个花名。", "(众旦云)我不省得。", "（正旦唱）诗句里包笼着尾声，（众旦云）我不省得。", "（正旦唱）续麻道字针针顶，（众旦云）我不省的。", "（正旦唱）正。"]'),
('yuanqu-1100','杜蕊娘智赏金线池・十二月','关汉卿','元','元曲','yuanqu','','[]','想那厮着人赞称，天生的济楚才能；只除了心不志诚，诸余的所事儿聪明。',49,'元曲/yuanqu.json','["想那厮着人赞称，天生的济楚才能；只除了心不志诚，诸余的所事儿聪明。", "本分的从来老成，聪俊的到底杂情。"]'),
('yuanqu-1101','杜蕊娘智赏金线池・尧民歌','关汉卿','元','元曲','yuanqu','','[]','丽春园则说一个俏苏卿，明知道不能勾嫁双生，向金山壁上去留名，画船儿赶到豫章城。',117,'元曲/yuanqu.json','["丽春园则说一个俏苏卿，明知道不能勾嫁双生，向金山壁上去留名，画船儿赶到豫章城。", "撇甚么清！投至得你秀才每忒寡情，先接了冯魁定。", "（正旦做叹气科，云）我不合道着\"韩辅臣\"，被罚酒也。", "（众旦云）姨姨，又犯令了！再罚一大觥。", "（正旦做饮科，唱）。"]'),
('yuanqu-1102','杜蕊娘智赏金线池・上小楼','关汉卿','元','元曲','yuanqu','','[]','闪的我孤孤另另，说的话涎涎邓邓；俺也曾轻轻唤着，躬躬前来，喏喏连声。',57,'元曲/yuanqu.json','["闪的我孤孤另另，说的话涎涎邓邓；俺也曾轻轻唤着，躬躬前来，喏喏连声。", "但酒醒硬打挣，强词夺正，则除是醉时节酒淘真性。"]'),
('yuanqu-1103','杜蕊娘智赏金线池・幺篇','关汉卿','元','元曲','yuanqu','','[]','不死心想着旧情，他将我厮看厮待，厮知厮重，厮钦厮敬。',53,'元曲/yuanqu.json','["不死心想着旧情，他将我厮看厮待，厮知厮重，厮钦厮敬。", "不是我把定、无记性，言多伤行。", "扶咱的小哥每是何名姓？。"]'),
('yuanqu-1104','杜蕊娘智赏金线池・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','我为你逼绰了当官令，（带云）谢你那大尹相公呵！（唱）烟花簿上除抹了姓名，交绝了怪友和狂朋，打并的户净门清。',107,'元曲/yuanqu.json','["我为你逼绰了当官令，（带云）谢你那大尹相公呵！（唱）烟花簿上除抹了姓名，交绝了怪友和狂朋，打并的户净门清。", "试金石上把你这子弟每从头儿画，分两等上把郎君子细秤。", "我立的其身正，倚仗着我花枝般模样，愁甚么锦片也似前程！。"]'),
('yuanqu-1105','杜蕊娘智赏金线池・二煞','关汉卿','元','元曲','yuanqu','','[]','我比那□墙贼蝎螫索自忍，我比那俏郎君掏摸须噤声，那里也恶茶白赖寻争竞？最不爱打揉人七八道猫煞爪，掐扭的三十驮鬼捏青。',81,'元曲/yuanqu.json','["我比那□墙贼蝎螫索自忍，我比那俏郎君掏摸须噤声，那里也恶茶白赖寻争竞？最不爱打揉人七八道猫煞爪，掐扭的三十驮鬼捏青。", "看破你传槽病，掴着手分开云雨，腾的似线断风筝。"]'),
('yuanqu-1106','杜蕊娘智赏金线池・尾煞','关汉卿','元','元曲','yuanqu','','[]','我和你半年多衾枕恩，一片家缱绻情，交明春岁数三十整（带云）我老了也，你要我怎的？（唱）你且把这不志诚的心肠与我慢慢等！（做摔开科，下）。',68,'元曲/yuanqu.json','["我和你半年多衾枕恩，一片家缱绻情，交明春岁数三十整（带云）我老了也，你要我怎的？（唱）你且把这不志诚的心肠与我慢慢等！（做摔开科，下）。"]'),
('yuanqu-1107','杜蕊娘智赏金线池・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','忽传台旨到咱丽春园测道是除抹了舞裙歌扇。',46,'元曲/yuanqu.json','["忽传台旨到咱丽春园测道是除抹了舞裙歌扇。", "逢个节朔，遇个冬年，拿着这一盏儿茶钱，告哥哥可怜见。"]'),
('yuanqu-1108','杜蕊娘智赏金线池・沉醉东风','关汉卿','元','元曲','yuanqu','','[]','则道是喜孜孜设席肆筵，为甚的怒哄哄列杖擎鞭？好教我足未移心先战，一步步似毛里拖毡。',64,'元曲/yuanqu.json','["则道是喜孜孜设席肆筵，为甚的怒哄哄列杖擎鞭？好教我足未移心先战，一步步似毛里拖毡。", "本待要大着胆、挺着身、行靠前，百忙里仓惶倒偃。"]'),
('yuanqu-1109','杜蕊娘智赏金线池・沽美酒','关汉卿','元','元曲','yuanqu','','[]','使不着撒腼腆，仗那个替方便，俺只得忍耻耽羞求放免。',131,'元曲/yuanqu.json','["使不着撒腼腆，仗那个替方便，俺只得忍耻耽羞求放免。", "（云）韩辅臣，你与我告一告儿！(韩辅臣云)谁着你失误官身，相公恼的很哩！（正旦唱）你与我搜寻出些巧言，去那官人行劝一劝。", "（韩辅臣云）你今日也有用着我时节？只要你肯嫁我，方才与你告去。", "（正旦云）我嫁你便了！（唱）。"]'),
('yuanqu-1110','杜蕊娘智赏金线池・太平令','关汉卿','元','元曲','yuanqu','','[]','从今后我情愿实为姻眷，你只要早些儿替我周全。',102,'元曲/yuanqu.json','["从今后我情愿实为姻眷，你只要早些儿替我周全。", "（韩辅臣云）我替你告便告去，倘相公不肯饶你，如何？（正旦唱）想当初罗帐里般般逞遍，今日个纸褙子又将咱欺骗，受了你万千作贱，那些儿体面？呀，谁似您浪短命随机应变。"]'),
('yuanqu-1111','杜蕊娘智赏金线池・川拨棹','关汉卿','元','元曲','yuanqu','','[]','似这等好姻缘，人都道全在天。',44,'元曲/yuanqu.json','["似这等好姻缘，人都道全在天。", "若是俺福过灾缠，空意惹情牵；间阻的山长水远，几时得人月圆？。"]'),
('yuanqu-1112','杜蕊娘智赏金线池・七兄弟','关汉卿','元','元曲','yuanqu','','[]','早则是对面、并肩、绿窗前，从今后称了平生愿。',44,'元曲/yuanqu.json','["早则是对面、并肩、绿窗前，从今后称了平生愿。", "一个向青灯黄卷赋诗篇，一个剪红绢翠锦学针线。"]'),
('yuanqu-1113','杜蕊娘智赏金线池・梅花酒','关汉卿','元','元曲','yuanqu','','[]','忆分离自去年，争些儿打散文鸳，折破芳莲，咽断顽涎。',53,'元曲/yuanqu.json','["忆分离自去年，争些儿打散文鸳，折破芳莲，咽断顽涎。", "为老母相间阻，使夫妻死缠绵，两下里正熬煎，谢公相肯矜怜。"]'),
('yuanqu-1114','杜蕊娘智赏金线池・收江南','关汉卿','元','元曲','yuanqu','','[]','呀，不枉了"一春常费买花钱"，也免得佳人才子只孤眠。',55,'元曲/yuanqu.json','["呀，不枉了\"一春常费买花钱\"，也免得佳人才子只孤眠。", "得官呵，相守赴临川，随着俺解元，再不索哭啼啼扶上贩茶船！。"]'),
('yuanqu-1115','尉迟恭单鞭夺槊・仙吕/端正好','关汉卿','元','元曲','yuanqu','','[]','他服孝整三年，事急也权做那三日。',73,'元曲/yuanqu.json','["他服孝整三年，事急也权做那三日。", "此事着后代人知：则这英雄能尽君臣礼。", "待他投降后，凯歌回，卸兵甲，载旗旗，还紫禁，到丹墀，做个龙虎风云会。", "（同下）。"]'),
('yuanqu-1116','尉迟恭单鞭夺槊・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','天数合该，虎臣囚在迷魂寨；请的他来，似兄弟相看待。',25,'元曲/yuanqu.json','["天数合该，虎臣囚在迷魂寨；请的他来，似兄弟相看待。"]'),
('yuanqu-1117','尉迟恭单鞭夺槊・混江龙','关汉卿','元','元曲','yuanqu','','[]','因窥关隘，自从那美良川引至介休来。',118,'元曲/yuanqu.json','["因窥关隘，自从那美良川引至介休来。", "俺想着先王有道，后辈贤才。", "若不是周西伯能求飞虎将，谁把一个姜太公请下钓鱼台？他可也几曾见忽的旗展、豁的门开、冬的鼓响、当的锣筛？投至得这个千战千赢尉迟恭，好险也万生万死唐元帅！到今日回忧作喜，降福除灾。"]'),
('yuanqu-1118','尉迟恭单鞭夺槊・油葫芦','关汉卿','元','元曲','yuanqu','','[]','传将令疾教军布摆，休觑的如小哉，则他这七重围子两边排。',117,'元曲/yuanqu.json','["传将令疾教军布摆，休觑的如小哉，则他这七重围子两边排。", "（徐茂公云）元帅，量敬德一人，兵器袍党鞍马俱无，怕做甚么！（正末唱）虽然他那身边不挂犭唐猊铠，腰间不系狮蛮带，跨下又无骏马宛，手中又无器械；你觑那岩前虎瘦雄心在，休想他便肯纳降牌。"]'),
('yuanqu-1119','尉迟恭单鞭夺槊・天下乐','关汉卿','元','元曲','yuanqu','','[]','纵使有铁壁银山也撞开！哎，你个英也波才，休浪猜，你既肯面缚归降，我也须降阶接待。',130,'元曲/yuanqu.json','["纵使有铁壁银山也撞开！哎，你个英也波才，休浪猜，你既肯面缚归降，我也须降阶接待。", "请将军去了服，罢了哀，俺今日与将军庆贺来。", "（尉迟云）元帅请坐，受尉迟恭几拜！（做拜科）（正未云）将军清起。", "（尉迟云）量尉迟恭有何德能，蒙元帅这般宽恕！敢不终身愿随鞭镫？（正末唱）。"]'),
('yuanqu-1120','尉迟恭单鞭夺槊・那吒令','关汉卿','元','元曲','yuanqu','','[]','看尉迟人生的威风也那气概，腹隐着兵书也那战策，可知道名震着乾坤也那世界。',64,'元曲/yuanqu.json','["看尉迟人生的威风也那气概，腹隐着兵书也那战策，可知道名震着乾坤也那世界。", "俺这里虽然是有纪纲，知兴败，那里讨尉迟这般样一个身材！。"]'),
('yuanqu-1121','尉迟恭单鞭夺槊・鹊踏枝','关汉卿','元','元曲','yuanqu','','[]','说话处掉书袋，施礼数傲吾济。',55,'元曲/yuanqu.json','["说话处掉书袋，施礼数傲吾济。", "据着你斩虎英雄，不弱如那子路、澹台。", "则怕俺弟兄每心不改，可不道\"有朋自远方来\"？。"]'),
('yuanqu-1122','尉迟恭单鞭夺槊・寄生草','关汉卿','元','元曲','yuanqu','','[]','你道是赤瓜峪与咱家曾会垓，马蹄儿撞破连环寨，鞭梢儿早抹着天灵盖，也则为主人各占边疆界。',68,'元曲/yuanqu.json','["你道是赤瓜峪与咱家曾会垓，马蹄儿撞破连环寨，鞭梢儿早抹着天灵盖，也则为主人各占边疆界。", "这的是桀之犬吠了帝尧来，便三将军怎好把你尉迟怪？。"]'),
('yuanqu-1123','尉迟恭单鞭夺槊・后庭花','关汉卿','元','元曲','yuanqu','','[]','你是个领貔貅天下材，画麒麟阁上客。',71,'元曲/yuanqu.json','["你是个领貔貅天下材，画麒麟阁上客。", "想当日汉高祖知人杰，俺准备着韩淮阴拜将台。", "把筵宴快安排，俺将你真心儿酬待。", "则要你立唐朝显手策，立唐朝显手策。"]'),
('yuanqu-1124','尉迟恭单鞭夺槊・青哥儿','关汉卿','元','元曲','yuanqu','','[]','呀，据着你英雄、英雄慷慨，堪定那社稷、社稷兴衰。',74,'元曲/yuanqu.json','["呀，据着你英雄、英雄慷慨，堪定那社稷、社稷兴衰。", "凭着你文武双全将相才，则要你扫荡云霾，肃靖尘埃。", "将勇兵乖，那其间挂印悬牌，便将你一日转千阶，非优待。"]'),
('yuanqu-1125','尉迟恭单鞭夺槊・赚煞','关汉卿','元','元曲','yuanqu','','[]','则今日赴皇都、离边塞，把从前冤仇事解，直至君王御案上拆，一件件禀奏的明白。',100,'元曲/yuanqu.json','["则今日赴皇都、离边塞，把从前冤仇事解，直至君王御案上拆，一件件禀奏的明白。", "便道不应该，未有甚汗马差排，且权做行军副元帅。", "（云）军师，（唱）你与我整三军器械，紧看着营寨；则我这手儿里将的印牌来。", "（下）。"]'),
('yuanqu-1126','尉迟恭单鞭夺槊・正宫/端正好','关汉卿','元','元曲','yuanqu','','[]','是他新，咱须旧，没揣的结下冤仇。',39,'元曲/yuanqu.json','["是他新，咱须旧，没揣的结下冤仇。", "你道他尉迟恭又往那沙陀走，咱可也慢慢的相穷究。"]'),
('yuanqu-1127','尉迟恭单鞭夺槊・脱布衫','关汉卿','元','元曲','yuanqu','','[]','他厮知重不敢抬头，我再相逢争忍凝眸？君子人不念旧恶，小人儿自来悔后。',72,'元曲/yuanqu.json','["他厮知重不敢抬头，我再相逢争忍凝眸？君子人不念旧恶，小人儿自来悔后。", "（云）左右，将酒来。", "我与敬德递一杯送行。", "（把酒科，云）将军满饮一杯。", "（唱）。"]'),
('yuanqu-1128','尉迟恭单鞭夺槊・小梁州','关汉卿','元','元曲','yuanqu','','[]','我这里亲送辕门捧玉瓯，将军你莫记冤仇。',92,'元曲/yuanqu.json','["我这里亲送辕门捧玉瓯，将军你莫记冤仇。", "（云）左右，将一饼金来。", "（卒子云）金在此。", "（尉迟云）元帅要这金做甚么？（正末云）将军，(唱)这金权为路费酒消愁。", "指望待常相守，谁承望心去意难留！。"]'),
('yuanqu-1129','尉迟恭单鞭夺槊・幺篇','关汉卿','元','元曲','yuanqu','','[]','我和你如今便往朝中奏。',218,'元曲/yuanqu.json','["我和你如今便往朝中奏。", "（尉迟云）则是三将军记那一鞭之仇。", "（正末唱）将从前事一笔都匀。", "（元吉云）我也不和他一般见识。", "（正末唱）将军你莫愁，从今后体辞生受，则要你分破帝王忧。", "（卒子慌上报科，云）喏，报的元帅得知：有王世充手下前部先锋单雄信特来索战。", "（尉迟云）元帅，那单雄信只消差三将军去拿他，也不用多拨人马，只一人一骑包拿来了。", "（元吉云）何如？我道你也服了我老三的手段。", "（正末云）是。", "就拨五千人马，着兄弟做先锋，与我擒拿单雄信去来。", "（唱）。"]'),
('yuanqu-1130','尉迟恭单鞭夺槊・上小楼','关汉卿','元','元曲','yuanqu','','[]','你道是精神抖擞，又道是机谋通透；雄信兵来，索要相持，你合承头。',57,'元曲/yuanqu.json','["你道是精神抖擞，又道是机谋通透；雄信兵来，索要相持，你合承头。", "想着你单鞭的拿敬德，这般夸口，又何况那区区洛阳草寇。"]'),
('yuanqu-1131','尉迟恭单鞭夺槊・幺篇','关汉卿','元','元曲','yuanqu','','[]','我正待看洛城、窥战守，因此上息却征鼙，偃却旗幡，减却戈矛。',125,'元曲/yuanqu.json','["我正待看洛城、窥战守，因此上息却征鼙，偃却旗幡，减却戈矛。", "（尉迟云）元帅休小觑了单雄信。", "他人又强，马又肥，使一条狼牙枣木槊，有万夫不当之勇。", "若只是这等，恐怕有关。", "（正末云）不妨事。", "（唱）虽然他人又强，马又肥，也拚的和他歹斗，难道我李世民便落入机彀？。"]'),
('yuanqu-1132','尉迟恭单鞭夺槊・随煞尾','关汉卿','元','元曲','yuanqu','','[]','则这割鸡焉用牛刀手，小将那消大帅收？管教六十四处征尘一扫休，十八处改年号的出尽了丑。',502,'元曲/yuanqu.json','["则这割鸡焉用牛刀手，小将那消大帅收？管教六十四处征尘一扫休，十八处改年号的出尽了丑。", "（徐茂公云）元帅，这一去则愿你鞭敲金镫也。", "（正末唱）那时节将军容再修，将凯歌齐奏，你可也早些儿准备安排着这个庆功的酒。", "（下）（段志贤云）虽然如此，还要与三将军一别。", "三将军安在？（元吉上，云）我适才到营帐里打的一个吨，这肚就不疼了。", "正待要去厮杀，我哥哥便等不得，自家去了。", "（段志贤云）三将军、军师勿罪，我同元帅先去也。", "（元吉云）老段，则要你小心在意者。", "（段志贤下）（徐茂公云）三将军，你领兵合后，我与敬德先接应元帅去来。", "（元吉云）军师先行，我在后领兵再来接应你。", "敬德，据理来饶你不得；看俺哥哥面上，你且寄头在项。", "此一去若有疏失呵，我不道的饶了你哩！（尉迟云）三将军，别人不知，你可知我那水磨鞭来。", "我这一去遇着那单雄信呵，只着他鞭稍一指，头颅早粉碎也。", "（诗云）舍生容易立功难，谁似吾家力拔山？则这水磨钢鞭一骑马，不杀无徒誓不还。", "（徐同下）（元吉云）我要杀了这匹夫来，不想俺哥哥回来救了。", "也罢，我这一去好歹要害了他。", "若杀了敬德呵，才报的我这一鞭之仇！军师着我做合后，我只是慢慢的去，等他救应不到，必有疏失，岂不是一计？（下）。"]'),
('yuanqu-1133','尉迟恭单鞭夺槊・越调/斗鹌鹑','关汉卿','元','元曲','yuanqu','','[]','人一似北极天蓬，马一似南方火龙；他那里纵马横枪，将咱来紧攻。',70,'元曲/yuanqu.json','["人一似北极天蓬，马一似南方火龙；他那里纵马横枪，将咱来紧攻。", "他急似雷霆，我疾如火风；我这里走的慌，他可也赶的凶。", "似这般耀武扬威，争强奋勇！。"]'),
('yuanqu-1134','尉迟恭单鞭夺槊・紫花儿序','关汉卿','元','元曲','yuanqu','','[]','我恨不的胁生双翅，项长三头；他道甚么"体走唐童"。',111,'元曲/yuanqu.json','["我恨不的胁生双翅，项长三头；他道甚么\"体走唐童\"。", "恰便似鱼钻入丝网，鸟扑入樊笼，匆匆。", "马也，少不的上你凌烟第一功，则要得四蹄那动！只听的喊杀声声，更催着战鼓逢逢。", "（单雄信云）赶入这榆科国来了也。", "你待走的那里去？（正末唱）。"]'),
('yuanqu-1135','尉迟恭单鞭夺槊・耍三台','关汉卿','元','元曲','yuanqu','','[]','待把我征马宛纵，残生送。',278,'元曲/yuanqu.json','["待把我征马宛纵，残生送。", "（徐茂公珊马慌上，云）兀的不是元帅！（做揪雄信科）（徐茂公云）将军且暂住一住！（单雄信云）我道是谁，元来是徐茂公。", "你放手！（正末唱）呀，元来是军师茂公！（徐茂公云）元帅，你快逃命走！（单雄信云）徐茂公，你放手！（正末唱）他道我已得命好从容，且看他如何作用。", "则要你拿云手紧将袍袖封，谈天口说转他心意从。", "你便是骗英布的隋何，说韩信的蒯通！（单雄信云）徐茂公，你放手！往日咱两个是朋友，今日各为其主也。", "（徐茂公云）将军，看俺旧交之情。", "（单雄信云）你两次三番则管里扯住我。", "罢！我拔出剑来，你见么？我割袍断义，你若再赶将来，我一剑挥之两段！。"]'),
('yuanqu-1136','尉迟恭单鞭夺槊・调笑令','关汉卿','元','元曲','yuanqu','','[]','见那厮不从，支楞楞扯出霜锋，呀，我见他尽在嘻嘻冷笑中；我见他割袍断袖绝了朋情重，越恼的他忿气冲冲。',73,'元曲/yuanqu.json','["见那厮不从，支楞楞扯出霜锋，呀，我见他尽在嘻嘻冷笑中；我见他割袍断袖绝了朋情重，越恼的他忿气冲冲。", "不争这单雄信推开徐茂公，天也，谁搭救我这微躬？。"]'),
('yuanqu-1137','尉迟恭单鞭夺槊・小桃红','关汉卿','元','元曲','yuanqu','','[]','手中无箭慢张弓，频把这虚弦控。',121,'元曲/yuanqu.json','["手中无箭慢张弓，频把这虚弦控。", "元来徐茂公临阵不中用！（敬德跚马上，叫云）单雄信慢走！（正末唱）则听的语如钟，喝一声响亮春雷动。", "纵然他有些耳聋，乍闻来也须怕恐！（尉迟云）单雄信勿伤吾主！（正末云）元来是敬德救我哩！（唱）高叫道\"休伤俺主人公\"。"]'),
('yuanqu-1138','尉迟恭单鞭夺槊・收尾','关汉卿','元','元曲','yuanqu','','[]','我则见忽的战马交，出的枣槊起，飕的钢鞭重，把一个生硬汉打的来浑身尽肿。',67,'元曲/yuanqu.json','["我则见忽的战马交，出的枣槊起，飕的钢鞭重，把一个生硬汉打的来浑身尽肿。", "哎，则你个打单雄信的尉迟恭，不弱似喝娄烦他这个霸王勇！（同下）。"]'),
('yuanqu-1139','尉迟恭单鞭夺槊・黄钟/醉花阴','关汉卿','元','元曲','yuanqu','','[]','大路上难行落荒里践，两只脚蓦岭登山快捻。',93,'元曲/yuanqu.json','["大路上难行落荒里践，两只脚蓦岭登山快捻。", "走的我一口气似撺椽。", "若见俺军师，一一的都分辨。", "（见科，云）报、报、报！（徐茂公云）好探子，他从那阵上来。", "你只看他喜气旺色，那输赢胜败早可知了也！。"]'),
('yuanqu-1140','尉迟恭单鞭夺槊・喜迁莺','关汉卿','元','元曲','yuanqu','','[]','早来到北邙前面，猛听的锣鼓喧天；那军不到三千，拥出个将一员。',193,'元曲/yuanqu.json','["早来到北邙前面，猛听的锣鼓喧天；那军不到三千，拥出个将一员。", "雄纠纠威风武艺显，是段志贤立阵前。", "一个待功标汗简，一个待名上凌烟。", "（徐茂公云）元来是单雄信与某家段志贤交马。", "两员将扑入垓心，不打话来回便战。", "三军发喊，二将争功。", "阵上数声鼙鼓擂，军前两骑马相交。", "马盘马折，千寻浪里竭波龙；人撞人冲，万丈山前争食虎。", "一个似摔碎雷车霹雳鬼，一个似擘开华岳巨灵神。", "端的是谁输谁赢？再说一遍。", "（探子唱）。"]'),
('yuanqu-1141','尉迟恭单鞭夺槊・出队子','关汉卿','元','元曲','yuanqu','','[]','两员将刀回马转，迎头儿先输了段志贤。',52,'元曲/yuanqu.json','["两员将刀回马转，迎头儿先输了段志贤。", "唐元帅败走恰便似箭离弦，单雄信追赶似风送船，尉迟恭傍观恰便似虎视犬。"]'),
('yuanqu-1142','尉迟恭单鞭夺槊・四门子','关汉卿','元','元曲','yuanqu','','[]','俺元帅勒马亲回转，展虎躯，骤骏马宛。',72,'元曲/yuanqu.json','["俺元帅勒马亲回转，展虎躯，骤骏马宛。", "看他一来一往相交战，是谁人敢占先？那一个奔，这一个赶，将和军躲的偌近远。", "刚崦里藏，休浪里潜。", "马儿上前合后偃。"]'),
('yuanqu-1143','尉迟恭单鞭夺槊・古水仙子','关汉卿','元','元曲','yuanqu','','[]','呀、呀、呀猛望见，便、便、便铁石人见了也可怜。',165,'元曲/yuanqu.json','["呀、呀、呀猛望见，便、便、便铁石人见了也可怜。", "他、他、他袋内有弯弓，壶中无只箭；待、待、待要布展怎地展？挣、锋、挣两三番迸断了弓弦。", "走、走、走一骑马逃入榆科园。", "来、来、来两员将绕定榆科转，见、见、见更狠似美良川！（徐茂公云）单雄信大败于输，俺尉迟恭赢了也！探子，无甚事，赏你一只羊、两坛酒，一个月不打差，你回营中去罢。", "（探子唱）。"]'),
('yuanqu-1144','双调・得胜令宴罢恰初更，摆列著玉娉婷。锦衣搭白马，纱笼照道行。齐','张子坚','元','元曲','yuanqu','','[]','声，唱的是《阿纳忽》时行令。',27,'元曲/yuanqu.json','["声，唱的是《阿纳忽》时行令。", "酒且休斟，俺待银鞍马上听。"]'),
('yuanqu-1145','梁山泊李逵负荆・仙吕/点绛唇','康进之','元','元曲','yuanqu','','[]','饮兴难酬，醉魂依旧。',96,'元曲/yuanqu.json','["饮兴难酬，醉魂依旧。", "寻村酒，恰问罢王留。", "(云)俺问王留道，那里有酒？那厮不说便走。", "俺喝道：走那里去？被俺赶上一把揪住张口毛，恰待要打。", "那王留道：休打，休打，爹爹，有。", "(唱)王留道兀那里人家有。"]'),
('yuanqu-1146','梁山泊李逵负荆・混江龙','康进之','元','元曲','yuanqu','','[]','可正是清明时候，却言风雨替花愁。',68,'元曲/yuanqu.json','["可正是清明时候，却言风雨替花愁。", "和风渐起，暮雨初收。", "俺则见杨柳半藏沽酒市，桃花深映钓鱼舟。", "更和这碧粼粼春水波纹绉，有往来社燕，远近沙鸥。"]'),
('yuanqu-1147','梁山泊李逵负荆・油葫芦','康进之','元','元曲','yuanqu','','[]','往常时酒债寻常行处有，十欠着九。',100,'元曲/yuanqu.json','["往常时酒债寻常行处有，十欠着九。", "(带云)老王也，(唱)则你这杏花庄压尽他谢家楼。", "你与我便熟油般造下春醅酒，你与我花羔般煮下肥羊肉。", "一壁厢肉又熟，一壁厢酒正等。", "抵多少锦封未拆香先透，我则待乘兴饮两三瓯。"]'),
('yuanqu-1148','梁山泊李逵负荆・天下乐','康进之','元','元曲','yuanqu','','[]','可正是一盏能消万种愁，(云)老王也，咱吃了这酒呵，(唱)把烦恼都也波丢，都丢在脑背后，这些时吃一个没了休。',105,'元曲/yuanqu.json','["可正是一盏能消万种愁，(云)老王也，咱吃了这酒呵，(唱)把烦恼都也波丢，都丢在脑背后，这些时吃一个没了休。", "(带云)我醉了呵。", "(唱)遮莫我倒在路边，遮莫我卧在瓮头，(做吐科，云)老王僳，(唱)直醉的来在这搭里呕。"]'),
('yuanqu-1149','梁山泊李逵负荆・赏花时','康进之','元','元曲','yuanqu','','[]','咱两个每日尊前语话投，今日呵，为甚将咱佯不愀。',180,'元曲/yuanqu.json','["咱两个每日尊前语话投，今日呵，为甚将咱佯不愀。", "(王林云)你不知道，我自嫁我的女孩儿，为此着恼。", "(正末唱)哎！你个呆老子畅好是忒掐搜，(云)比似你这般烦恼，休嫁他不的。", "(王林哭科，云)哎哟！我那满堂娇儿也。", "(正末唱)你何不养着他到苍颜皓首？(云)你晓的世上有三不留么？(王林云)哥，是那三不留？(王末云)蚕老不中留，人老不中留，(唱)呆老子，常言道：女大不中留。"]'),
('yuanqu-1150','梁山泊李逵负荆・金盏儿','康进之','元','元曲','yuanqu','','[]','我这里猛睁眸，他那里巧舌头，是非只为多开口。',96,'元曲/yuanqu.json','["我这里猛睁眸，他那里巧舌头，是非只为多开口。", "但半星儿虚谬，恼翻我怎干休！一把火将你那草团瓢烧成为腐炭，盛酒瓮摔成碎瓷瓯。", "(带云)绰起俺两把板斧来，(唱)砍折你那蟠根桑枣树，活杀您那阔角水黄牛。"]'),
('yuanqu-1151','梁山泊李逵负荆・正宫/端正好','康进之','元','元曲','yuanqu','','[]','抖搜着黑精神，扎煞开黄髭髟。',14,'元曲/yuanqu.json','["抖搜着黑精神，扎煞开黄髭髟。"]'),
('yuanqu-1152','梁山泊李逵负荆・滚绣球','康进之','元','元曲','yuanqu','','[]','宋江口来，这是甚所为？甚道理？不知他主着何意？激的我怒气如雷。',90,'元曲/yuanqu.json','["宋江口来，这是甚所为？甚道理？不知他主着何意？激的我怒气如雷。", "可不道他是谁，我是谁，俺两个半生来岂有些嫌隙？到今日，却做了日月交食。", "不争几句闲言语，我则怕恶识多年旧面皮，展转猜疑。"]'),
('yuanqu-1153','梁山泊李逵负荆・倘秀才','康进之','元','元曲','yuanqu','','[]','哎！你个刎颈的知交庆喜，(宋江云)庆甚么喜？(正末唱)则你那压寨的夫人在那里？(指鲁智深科，云)秃驴，你做的好事来。',180,'元曲/yuanqu.json','["哎！你个刎颈的知交庆喜，(宋江云)庆甚么喜？(正末唱)则你那压寨的夫人在那里？(指鲁智深科，云)秃驴，你做的好事来。", "(唱)打干净球儿不道的走了你。", "(宋江云)怎么？智深兄弟，也有你那？(正末唱)强赌当，硬支持，要见个到底。", "(宋江云)山儿，你下山去，有甚么事，何不就明对我说？(正末做恼不言语科)(宋江云)山儿，既然不好和我说，你就对学究哥哥根前说波。", "(正末唱)。"]'),
('yuanqu-1154','梁山泊李逵负荆・倘秀才','康进之','元','元曲','yuanqu','','[]','不争你抢了他花朵般青春艳质，这其间抛闪杀那草桥店白头老的。',83,'元曲/yuanqu.json','["不争你抢了他花朵般青春艳质，这其间抛闪杀那草桥店白头老的。", "(宋江云)这事其中必有暗昧。", "(正末唱)这桩事分明甚暗昧，生割舍，痛悲凄，(带云)宋江口来，(唱)他其实怨你。"]'),
('yuanqu-1155','梁山泊李逵负荆・叨叨令','康进之','元','元曲','yuanqu','','[]','那老儿，一会家便哭啼啼在那茅店里，(带云)觑着山寨，宋江好恨也！(唱)他这般急张拘诸的立。',276,'元曲/yuanqu.json','["那老儿，一会家便哭啼啼在那茅店里，(带云)觑着山寨，宋江好恨也！(唱)他这般急张拘诸的立。", "那老儿，一会家便怒畔畔在那柴门外，(带云)哭道：我那满堂娇儿也！(唱)他这般乞留曲律的气。", "(宋江云)他怎生烦庙那？(正未唱)那老儿，一会家便闷沉沉在那酒瓮边，(带云)那老儿拿起瓢耙，揭开蒲墩，舀一瓢冷酒来，汨汨的咽了。", "(唱)他这般迷留没乱的醉。", "那若儿，托着-片席头便慢腾腾放在土坑上，(带云)他出的门来，看一看，又不见来，哭道：我那满堂娇儿！(唱)他这般壹留兀渌的睡。", "似这般过不的也么哥，似这般过不的也么哥，(宋江云)这厮怎的？(正末唱)他道俺梁山泊不甜人不义。"]'),
('yuanqu-1156','梁山泊李逵负荆・一煞','康进之','元','元曲','yuanqu','','[]','则为尔两头白面搬兴废，转背言词说是非。',98,'元曲/yuanqu.json','["则为尔两头白面搬兴废，转背言词说是非。", "这厮敢狗行狼心，虎头蛇尾。", "不是我节外生枝，囊里盛锥。", "谁着你夺人爱女，逞己风流，被咱都知(宋江云)你看黑牛这村沙样势那。", "(正末唱)休怪我村沙样势，平地上起孤堆。"]'),
('yuanqu-1157','梁山泊李逵负荆・商调/集贤宾','康进之','元','元曲','yuanqu','','[]','过的这翠巍巍-带山崖脚，遥望见滴溜溜的酒旗招。',195,'元曲/yuanqu.json','["过的这翠巍巍-带山崖脚，遥望见滴溜溜的酒旗招。", "想悲欢不同昨夜，论真假只在今朝。", "(云)花和尚，你也小脚儿，这般走不动，多则是做媒的心虚，不敢走哩。", "(鲁智深云)你看这厮！(正末唱)鲁智深似窟里拔蛇，(云)宋公明，你也行动些儿。", "你只是拐了人家女孩儿，害羞也不敢走哩。", "(宋江云)你看他波！(正末唱)宋公明似毡上拖毛。", "则俺那周琼姬，你可甚么上子乔，玉人在何处吹箫？我不合蹬翻了莺燕友，拆散了这凤鸾交。"]'),
('yuanqu-1158','梁山泊李逵负荆・逍遥乐','康进之','元','元曲','yuanqu','','[]','倒做了逢山开道，(鲁智深云)山儿，我还要你遇水搭桥哩。',164,'元曲/yuanqu.json','["倒做了逢山开道，(鲁智深云)山儿，我还要你遇水搭桥哩。", "(正末唱)你休得顺水推船，偏不许我过河拆桥。", "(宋江做前走科)(正末唱)当不的他纳胯扭腰。", "(宋江云)山儿，你不记得上山时，认俺做哥哥，也曾八拜之交哩。", "(正末唱)哥也，你只说在先时，有八拜之交。", "元宋是花木瓜儿外看好，不由咱不回头儿暗笑。", "待和你争甚么头角，辩甚的衷肠，惜甚的皮毛。"]'),
('yuanqu-1159','梁山泊李逵负荆・醋葫芦','康进之','元','元曲','yuanqu','','[]','这老儿外名唤做半槽，就里带着一杓。',125,'元曲/yuanqu.json','["这老儿外名唤做半槽，就里带着一杓。", "是则是去了你那一十八岁这个满堂娇，更做你家年纪老。", "(云)俺叫了两三声不开门，第三声道：送将你那满堂娇女孩儿来了。", "他开开门，搂着俺那黑膊子，叫道：我那满堂娇儿也。", "(唱)老儿也似这般烦恼的无颠无倒，越惹你揉眵抹泪哭嚎啕。"]'),
('yuanqu-1160','梁山泊李逵负荆・幺篇','康进之','元','元曲','yuanqu','','[]','你则合低头就坐来，谁着你睁睛先去瞧？则你个宋公明威势怎生豪，刚一瞅，早将他魂灵吓掉了。',210,'元曲/yuanqu.json','["你则合低头就坐来，谁着你睁睛先去瞧？则你个宋公明威势怎生豪，刚一瞅，早将他魂灵吓掉了。", "这便是你替天行道，则俺那无情板斧肯担饶？(云)老王，你来，兀那秃厮，便是做媒的鲁智深，你再去认咱。", "(鲁智深云)你快认来。", "(王林做再认科，云)不是！不是！那两个一个是青眼儿长子，如今这个是黑矮的。", "那一个是稀头发腊梨，如今这个是剃头发的和尚。", "不是！不是！(鲁智深云)山儿，我可是哩。", "(正末云)你这秃厮，由他自认，你先幺喝一声怎么？(唱)。"]'),
('yuanqu-1161','梁山泊李逵负荆・幺篇','康进之','元','元曲','yuanqu','','[]','谁不知你是镇关西鲁智深，离五台山才落草。',80,'元曲/yuanqu.json','["谁不知你是镇关西鲁智深，离五台山才落草。", "便在黑影中摸索也应着，只被你爆雷似一声先唬倒。", "那呆老子怕不知名号，(带云)适才间他也待认来。", "(唱)只见他摇头侧脑费量度。"]'),
('yuanqu-1162','梁山泊李逵负荆・双雁儿','康进之','元','元曲','yuanqu','','[]','就恨不一把火，刮刮拶拶烧了你这草团瓢。',53,'元曲/yuanqu.json','["就恨不一把火，刮刮拶拶烧了你这草团瓢。", "将人来，险中倒，气得咱，一似那鲫鱼跳。", "可不道家有老敬老，家有小敬小。"]'),
('yuanqu-1163','梁山泊李逵负荆・双调/新水令','康进之','元','元曲','yuanqu','','[]','这一场烦恼可也奔人来，没来由共哥哥赌赛。',73,'元曲/yuanqu.json','["这一场烦恼可也奔人来，没来由共哥哥赌赛。", "袒下我这红内袄，跌绽我这旧皮鞋。", "心下量猜，(带云)到山寨上，哥哥不打，则要头。", "(唱)怎发付脖项上这一块？。"]'),
('yuanqu-1164','梁山泊李逵负荆・驻马听','康进之','元','元曲','yuanqu','','[]','有心待不顾形骸，(带云)这碧湛湛石崖不得底的深涧我待跳下去，休说一个，便是十个黑旋风也不见了。',113,'元曲/yuanqu.json','["有心待不顾形骸，(带云)这碧湛湛石崖不得底的深涧我待跳下去，休说一个，便是十个黑旋风也不见了。", "(唱)两三番自投碧湛崖。", "敬临山寨，行一步如上吓魂台。", "我死后，墓顶上谁定远乡牌？灵位边谁咒生天界？怎擘划，但得个完全尸首，便是十分采。"]'),
('yuanqu-1165','梁山泊李逵负荆・搅筝琶','康进之','元','元曲','yuanqu','','[]','我来到辕门外，见小校雁行排。',130,'元曲/yuanqu.json','["我来到辕门外，见小校雁行排。", "(带云)往常时我来呵，(唱)他这般退后趋前，(带云)怎么今日的。", "（唱）他将我佯呆不睬。", "(做偷瞧科，云)哦！元来是俺宋公明哥哥和众兄弟都升堂了也。", "(唱)他对着那有期会的众英才，一个个稳坐抬颏。", "我说的明白，道莽撞的廉颇请罪来，死也应该。"]'),
('yuanqu-1166','梁山泊李逵负荆・沉醉东风','康进之','元','元曲','yuanqu','','[]','呼保义哥哥见责，我李山儿情愿餐柴。',69,'元曲/yuanqu.json','["呼保义哥哥见责，我李山儿情愿餐柴。", "第一来看着咱兄弟情，第二来少欠他脓血债。", "休道您兄弟不伏烧埋，由你便直打到梨花月上来。", "若不打，这顽皮不改。"]'),
('yuanqu-1167','梁山泊李逵负荆・步步娇','康进之','元','元曲','yuanqu','','[]','则听得宝剑声鸣，使我心惊骇，端的个风团快。',589,'元曲/yuanqu.json','["则听得宝剑声鸣，使我心惊骇，端的个风团快。", "似这般好器械，一柞来铜钱，恰便似砍麻秸。", "(带云)想您兄弟十载相依，那般恩义都也不消说了。", "(唱)还说甚旧情怀，早砍取我半壁天灵盖。", "(王林冲上，叫科，云)刀下留人。", "告太仆，那个贼汉送将我那女孩儿来了。", "我将他两个灌醉在家里，一径的乘报知。", "太仆与老汉做主咱。", "(宋江云)山儿，我如今放你去，若拿得这两个棍徒，将功折罪；若拿不得，二罪俱罚。", "您敢去么？(正末做笑科，云)这是揉着我山儿的痒处。", "管教他瓮中捉鳖，手到拿来。", "(学究云)虽然如此，他有两副鞍马，你一个如何拿的他住？万一被他走了，可不输了我梁山泊上的气概。", "鲁家兄弟，你帮山儿同走一遭。", "(鲁智深云)那山儿开口便骂我秃厮会做媒，两次三番要那王林认我，是甚主意？他如今有本事自去拿那两个，我鲁智深决不帮他。", "(学究云)你只看聚义两个宇，不要因这小忿，坏了大体面。", "(宋江云)这也说的是。", "智深兄弟，你就同他去拿那两个顶名冒姓的贼汉来，(鲁智深云)既是哥哥分付，您兄弟敢不同去？(同下)(宋刚、鲁智恩上，云)好酒，俺们昨夜都醉了也。", "今早日高三丈，还不见太山出来，敢是也醉倒了。", "(正末同鲁智深、王林上，云)贼汉！你太山不在这里？(做见就打科，宋刚云)兀那大汉，你也通个名姓，怎么动手便打？(正末云)你要问俺名姓？若说出来，直唬的你尿流屁滚。", "我就是梁山泊上黑爹爹李逵，这个哥哥是真正花和尚鲁智深。", "(做打科，唱)。"]'),
('yuanqu-1168','梁山泊李逵负荆・乔牌儿','康进之','元','元曲','yuanqu','','[]','你顶着鬼名儿会使乖，到今日当天败。',41,'元曲/yuanqu.json','["你顶着鬼名儿会使乖，到今日当天败。", "谁许这满堂娇压你那莺花寨？也不是我黑爹爹忒性歹。"]'),
('yuanqu-1169','梁山泊李逵负荆・殿前欢','康进之','元','元曲','yuanqu','','[]','我打你这吃敲材，直著你皮残骨断肉都开。',95,'元曲/yuanqu.json','["我打你这吃敲材，直著你皮残骨断肉都开。", "那怕你会飞腾就透出青霄外，早则是手到拿来。", "你、你、你，好一个鲁智深不吃斋，好一个呼保义能贪色。", "如今去亲身对证休嗔怪，须不是我倚强凌弱，还是你自揽祸招灾。"]'),
('yuanqu-1170','梁山泊李逵负荆・离亭宴煞','康进之','元','元曲','yuanqu','','[]','蓼儿洼里开筵待，花标树下肥羊宰，酒尽呵拚当再买。',123,'元曲/yuanqu.json','["蓼儿洼里开筵待，花标树下肥羊宰，酒尽呵拚当再买。", "涎邓邓眼睛剜，滴屑屑手脚卸，碜可可心肝摘。", "饿虎口中将脆骨夺，骊龙颔下把明珠握，生担他一场利害。", "(带云)智深哥哥，(唱)我也则要洗清你这强打挣的执柯人，(带云)公明哥哥，(唱)出脱你这干风情的画眉客。"]'),
('yuanqu-1171','正宫・黑漆弩游金山寺并序','王恽','元','元曲','yuanqu','','[]','邻曲子严伯昌尝以《黑漆弩》侑酒。',325,'元曲/yuanqu.json','["邻曲子严伯昌尝以《黑漆弩》侑酒。", "省郎仲先谓余曰：“词虽佳，曲名似未雅。", "若就以‘江南烟雨’目之，何如？”予曰：“昔东坡作《念奴曲》，后人爱之，易其名曰《酹江月》，其谁曰不然？”仲先因请余效颦，遂追赋《游金山寺》一阕，倚其声而歌之。", "昔汉儒家畜声妓，唐人例有音学。", "而今之乐府，用力多而难为工。", "纵使有成，未免笔墨劝淫为侠耳。", "渠辈年少气锐，渊源正学，不致费日力于此也。", "其词曰：苍波万顷孤岑矗，是一片水面上天竺。", "金鳌头满咽三杯，吸尽江山浓绿。", "蛟龙虚恐下燃犀，风起浪翻如屋。", "任夕阳归棹纵横，待偿我平生不足。", "曲山亦作《言怀》一词，遂继韵戏赠休官彭泽居闲久，纵清苦爱吾子能守。", "幸年来所事消磨，只有苦吟甘酒。", "平生学道在初心，富贵浮云何有？恐此身未许投闲，又待看凤麟飞走。"]'),
('yuanqu-1172','仙吕・后庭花晚眺临武堂','王恽','元','元曲','yuanqu','','[]','绿树连远洲，青山压树头。',39,'元曲/yuanqu.json','["绿树连远洲，青山压树头。", "落日高城望，烟霏翠满楼。", "木兰舟，彼汾一曲，春风佳可游。"]'),
('yuanqu-1173','包龙图智赚合同文字・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','拙妇熬煎，主家方便，相留恋。',30,'元曲/yuanqu.json','["拙妇熬煎，主家方便，相留恋。", "直着俺住到来年，谁想天不从人愿。"]'),
('yuanqu-1174','包龙图智赚合同文字・油葫芦','无名氏','元','元曲','yuanqu','','[]','量小生有甚人情有甚钱，苦痛也波天。',142,'元曲/yuanqu.json','["量小生有甚人情有甚钱，苦痛也波天。", "则为那家私生受了二十年，要领旧席铺停柩无一片，要领好衣服妆裹无一件。", "(张秉彝云)君子，你不须烦恼。", "我这里都已备下了也。", "(正末唱)谢员外厮济惠，谢员外肯见怜。", "(带云)小生若不得员外呵。", "(唱)则俺这人离财散央亲眷，兀良谁赍发与我一根椽。", "(做悲科)(唱)。"]'),
('yuanqu-1175','包龙图智赚合同文字・天下乐','无名氏','元','元曲','yuanqu','','[]','妻也，知他是你命难逃我命蹇，我想从也波前，也是宿世缘，将重孝不披轻孝来穿。',65,'元曲/yuanqu.json','["妻也，知他是你命难逃我命蹇，我想从也波前，也是宿世缘，将重孝不披轻孝来穿。", "想着你恩共情，想着你贞共贤，我甘心儿与你驾灵车，哭少年。"]'),
('yuanqu-1176','包龙图智赚合同文字・那吒令','无名氏','元','元曲','yuanqu','','[]','念不出，消灾的善言；烈不得，买路的纸钱；(张秉彝云)我代你送出去。',97,'元曲/yuanqu.json','["念不出，消灾的善言；烈不得，买路的纸钱；(张秉彝云)我代你送出去。", "(正末云)怎敢劳动员外。", "(唱)我可也放不下，殃人的业冤。", "一片心迷留没乱焦，两条腿滴羞笃速战，恰便似热地上蚰蜒。", "(做走科)(唱)。"]'),
('yuanqu-1177','包龙图智赚合同文字・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','我甫抬身到灵柩边，待亲送出郊原，不觉的肉颤身摇，眼晕头旋。',59,'元曲/yuanqu.json','["我甫抬身到灵柩边，待亲送出郊原，不觉的肉颤身摇，眼晕头旋。", "挪一步早前合后偃，(正末做倒科)(唱)哎哟！叫一声覆地翻天。"]'),
('yuanqu-1178','包龙图智赚合同文字・柳叶儿','无名氏','元','元曲','yuanqu','','[]','则被那官司逼遣，他道是没收成千里无烟，着俺分房减口为供膳。',48,'元曲/yuanqu.json','["则被那官司逼遣，他道是没收成千里无烟，着俺分房减口为供膳。", "因此上携宅眷，撇家缘，图一个苟活偷全。"]'),
('yuanqu-1179','包龙图智赚合同文字・青哥儿','无名氏','元','元曲','yuanqu','','[]','虽则是一张儿合同、合同文券，上写着一家儿庄田宅院，这便我久后归宗的证明显。',103,'元曲/yuanqu.json','["虽则是一张儿合同、合同文券，上写着一家儿庄田宅院，这便我久后归宗的证明显。", "趁如今未丧黄泉，叮咛你大德高贤。", "等孩儿长大时年，交付他收执依然。", "遮莫杀颠沛流连，休迷失水木根源。", "这便是你张员外种下的福无边，天须见。"]'),
('yuanqu-1180','包龙图智赚合同文字・寄生草','无名氏','元','元曲','yuanqu','','[]','他目下交三岁，你若抬举他更数年。',80,'元曲/yuanqu.json','["他目下交三岁，你若抬举他更数年。", "常则是公心教训诚心劝，教的他为人谨慎于人善，不许他初年随顺中年变。", "俺便死也难忘你这天高地厚情，员外你则可怜见，小冤家少母无爹面。"]'),
('yuanqu-1181','包龙图智赚合同文字・赚煞尾','无名氏','元','元曲','yuanqu','','[]','不争我病势正昏沉，更那堪苦事难支遣，忙赶上头里的丧车不远，眼见得客死他乡有谁祭奠？(带云)儿也，你若得长大成人呵。',142,'元曲/yuanqu.json','["不争我病势正昏沉，更那堪苦事难支遣，忙赶上头里的丧车不远，眼见得客死他乡有谁祭奠？(带云)儿也，你若得长大成人呵。", "(唱)你是必休别了父母遗言：将骨殖到梁园，就着俺那祖父的坟前，古树林峰好墓田。", "员外，则你便是我三代祖先，我又无甚六神亲眷。", "可怜见俺两房头这几口儿，都不得个好团圆。", "(下)。"]'),
('yuanqu-1182','包龙图智赚合同文字・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','我将着这一所草堂开，聚几个蒙童训，常则是对青灯黄卷埋身。',48,'元曲/yuanqu.json','["我将着这一所草堂开，聚几个蒙童训，常则是对青灯黄卷埋身。", "苦了我也十年窗下无人问，何日得功名进？。"]'),
('yuanqu-1183','包龙图智赚合同文字・滚绣球','无名氏','元','元曲','yuanqu','','[]','我可也为甚的甘受贫，不厌勤，抵多少策顽磨钝，也只为不如人学做儒人。',87,'元曲/yuanqu.json','["我可也为甚的甘受贫，不厌勤，抵多少策顽磨钝，也只为不如人学做儒人。", "指望待跃锦鳞，过禹门，才是俺男儿发愤，终有日际会风云。", "不枉了严亲教训能酬志，须信道古圣文章可立身，改换家门。"]'),
('yuanqu-1184','包龙图智赚合同文字・倘秀才','无名氏','元','元曲','yuanqu','','[]','俺父亲口快心直怎隐？您孩儿鼻痛心酸怎忍？想着那冻饿死的爷娘，兀的不痛杀人！别了兄嫂，离了家门，养下这个毒害的子孙。',57,'元曲/yuanqu.json','["俺父亲口快心直怎隐？您孩儿鼻痛心酸怎忍？想着那冻饿死的爷娘，兀的不痛杀人！别了兄嫂，离了家门，养下这个毒害的子孙。"]'),
('yuanqu-1185','包龙图智赚合同文字・呆骨朵','无名氏','元','元曲','yuanqu','','[]','想着俺人亡家破，留下这个儿生忿，我直啼哭的地惨天昏。',105,'元曲/yuanqu.json','["想着俺人亡家破，留下这个儿生忿，我直啼哭的地惨天昏。", "不争将先父母思量，又怕俺这老爷娘议论。", "则道把十月怀耽想，可将这数载情肠尽。", "(张秉彝做叹科，云)嗨！他亲的则是亲。", "(正末唱)他道亲的则是亲，我怎肯知恩不报恩？。"]'),
('yuanqu-1186','包龙图智赚合同文字・倘秀才','无名氏','元','元曲','yuanqu','','[]','待奉着俺先人的教训，怎敢道别了家尊的义分，您孩儿两下里爷娘一样的亲。',56,'元曲/yuanqu.json','["待奉着俺先人的教训，怎敢道别了家尊的义分，您孩儿两下里爷娘一样的亲。", "怎敢道分真假，辩清浑，天地也就着俺亡家丧身。"]'),
('yuanqu-1187','包龙图智赚合同文字・滚绣球','无名氏','元','元曲','yuanqu','','[]','想当日盘缠无一文，遗留托二亲，痛杀我也命绝禄尽，谢父亲，将您孩儿抬举成人。',114,'元曲/yuanqu.json','["想当日盘缠无一文，遗留托二亲，痛杀我也命绝禄尽，谢父亲，将您孩儿抬举成人。", "离了这潞州下马村，早来到东京义定门，将俺这骨殖埋殡，认了伯父伯娘呵，您孩儿便索抽身。", "先安定了俺这十五年无主亡魂魄，回来报答你一双的高年养育恩，怎避的艰辛。"]'),
('yuanqu-1188','包龙图智赚合同文字・倘秀才','无名氏','元','元曲','yuanqu','','[]','远远望高山隐隐，近近听黄河滚滚，我则见段段田灯接远村。',44,'元曲/yuanqu.json','["远远望高山隐隐，近近听黄河滚滚，我则见段段田灯接远村。", "到祖宅，造亲坟，尽了我这点儿孝顺。"]'),
('yuanqu-1189','包龙图智赚合同文字・滚绣球','无名氏','元','元曲','yuanqu','','[]','这般担呵我生怕背了母亲，这般提呵又则怕背了父亲，好着俺孝心难尽，做不得郭巨、田真。',97,'元曲/yuanqu.json','["这般担呵我生怕背了母亲，这般提呵又则怕背了父亲，好着俺孝心难尽，做不得郭巨、田真。", "兀的不厌掉魂，唬煞人，原来是至诚的天顺，可又早动鬼惊神。", "曾闻的古来孝子担继母，感得闷林两处分，俺今日也脚底生云。"]'),
('yuanqu-1190','包龙图智赚合同文字・煞尾','无名氏','元','元曲','yuanqu','','[]','披星带月心肠紧，过水登山脚步勤。',92,'元曲/yuanqu.json','["披星带月心肠紧，过水登山脚步勤。", "意急不将昼夜分，心愁岂觉途路稳。", "痛泪零零雨洒尘，怨气腾腾风送云。", "客舍青青柳色新，千里关山劳梦魄。", "归到梁园认老亲，恁时节才把我这十五载流离证了本。", "(下)。"]'),
('yuanqu-1191','包龙图智赚合同文字・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','远赴皇都，急煎煎早行晚住，早难道神鬼皆无。',56,'元曲/yuanqu.json','["远赴皇都，急煎煎早行晚住，早难道神鬼皆无。", "我将饭充饥，茶解渴，纸钱来买路。", "历尽了那一千里程途，几曾道半霎儿停步。"]'),
('yuanqu-1192','包龙图智赚合同文字・醉春风','无名氏','元','元曲','yuanqu','','[]','俺心儿里思想杀老爷娘，则待要墓儿中埋葬俺这先父母。',75,'元曲/yuanqu.json','["俺心儿里思想杀老爷娘，则待要墓儿中埋葬俺这先父母。", "一会家烦恼上眉头，安住到大来是苦，苦！我则道孤影孤身，流落在他州他县，惭愧也，不想还认了这伯娘伯父。"]'),
('yuanqu-1193','包龙图智赚合同文字・红绣鞋','无名氏','元','元曲','yuanqu','','[]','他、他、他，可也为甚么全没那半点儿牵肠割肚？全没那半声儿短叹长吁？莫不您叔嫂妯娌不和睦？(云)伯娘，俺伯伯那里去了？(搽旦云)甚么伯伯？我不知道。',106,'元曲/yuanqu.json','["他、他、他，可也为甚么全没那半点儿牵肠割肚？全没那半声儿短叹长吁？莫不您叔嫂妯娌不和睦？(云)伯娘，俺伯伯那里去了？(搽旦云)甚么伯伯？我不知道。", "(正末唱)伯伯可又无踪影。", "伯娘那里紧支吾，可教我那搭儿葬俺父母？。"]'),
('yuanqu-1194','包龙图智赚合同文字・普天乐','无名氏','元','元曲','yuanqu','','[]','我意慌速，心犹豫，若无显证，怎辩亲疏？(递合同科)(搽旦云)争奈我不识字？如何？(正末唱)伯娘可也不会读，将去着伯父亲身觑。',179,'元曲/yuanqu.json','["我意慌速，心犹豫，若无显证，怎辩亲疏？(递合同科)(搽旦云)争奈我不识字？如何？(正末唱)伯娘可也不会读，将去着伯父亲身觑。", "(云)好一个贤达的伯娘也，我错埋怨了他。", "(唱)他元来是九烈三贞贤达妇，兀的个老人家尚然道出嫁从夫。", "(搽旦入门科)(正末云)呀！伯娘入去了，可怎么这一晌还不见山来？我早猜着了也。", "(唱)一来是收拾祭物，二来是准备孝服，第三来可是报与亲属。"]'),
('yuanqu-1195','包龙图智赚合同文字・迎仙客','无名氏','元','元曲','yuanqu','','[]','因歉年趁熟上，别家乡临外府。',346,'元曲/yuanqu.json','["因歉年趁熟上，别家乡临外府。", "怎知道命儿里百般无是处。", "先亡了俺嫡亲的爷娘，守着这别人家父母。", "整受了十五载孤独，(刘天祥云)你叫做甚么名字？(正末唱)则俺呵，便是您作儿刘安住。", "(刘天祥云)你那里见刘安住来？(正末去)则我便是刘安住。", "(刘天祥做悲科，云)婆婆，你欢喜咱，俺刘安住孩儿回家来了也。", "(搽旦云)甚么刘安住？这里哨子每极多，见咱有些家私，假做刘安住来认俺。", "他爷娘去时，有合同文书，若有便是真的，无便是假的。", "(刘天祥云)婆婆也道的是。", "我出去问他。", "刘安住，你去时节有合同文书，你将的来我看。", "(正末云)有文书来，适才交付与伯娘了也。", "(刘天祥云)婆婆，休斗我耍，我问刘安住来，他道你拿着文书了也。", "(搽旦云)我不曾拿。", "(刘天祥云)刘安住，婆婆道他不曾拿。", "孩儿也，你等我来波，怎么就与了他？(正末唱)。"]'),
('yuanqu-1196','包龙图智赚合同文字・石榴花','无名氏','元','元曲','yuanqu','','[]','俺一生精细一时粗，直恁般不晓事忒糊涂。',86,'元曲/yuanqu.json','["俺一生精细一时粗，直恁般不晓事忒糊涂。", "则他那口如蜜钵说从初，并无间阻，索看文书。", "我则道是亲骨血这搭儿里重完聚，一家儿世不分居。", "我将这合同一纸慌忙付，倒着俺做了扁担脱两头虚。"]'),
('yuanqu-1197','包龙图智赚合同文字・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','我将那百诈的虔婆，错认做三移孟母。',78,'元曲/yuanqu.json','["我将那百诈的虔婆，错认做三移孟母。", "我又不索您钱财，又不分您地土。", "只要把无主的亡灵归墓所，你可也须念兄弟每如手足。", "便做道这张纸为有为无，难道我姓刘的不亲不故。"]'),
('yuanqu-1198','包龙图智赚合同文字・上小楼','无名氏','元','元曲','yuanqu','','[]','想着俺劬劳父母，遇了这饥荒时务。',63,'元曲/yuanqu.json','["想着俺劬劳父母，遇了这饥荒时务。", "辞着兄嫂，引着妻男，趁着丰熟。", "怎知道寿短促，命苦毒，再没个亲人看顾，闪的这两把骨殖儿不着坟墓。"]'),
('yuanqu-1199','包龙图智赚合同文字・幺篇','无名氏','元','元曲','yuanqu','','[]','伯娘你也忒狠酷，怎对付！则待要瞒了侄儿，背了伯伯，下了埋伏。',537,'元曲/yuanqu.json','["伯娘你也忒狠酷，怎对付！则待要瞒了侄儿，背了伯伯，下了埋伏。", "单则是他亲女，和女夫，把家缘收取，可不俺两房头灭门绝户？(刘天祥云)安住孩儿，你那合同文书委实在那里也？(正末云)恰才是伯娘亲手儿拿进去了。", "(搽旦云)这个说谎的小弟子孩儿，我几曾见那文书来？(正末云)伯娘，休斗您孩儿妥。", "你恰才明明的拿进去，怎说不曾见？(搽旦云)我若见你那文书，着我邻舍家害疔疮。", "(刘天祥云)婆婆。", "你若是拿了，将来我看。", "(搽旦云)这老儿也糊突。", "这纸文书，我要他糊窗儿？有甚么用处？这厮故意的来捏舌，待诈骗咱的家私哩。", "(正未)伯伯，您孩儿不要家财，则要傍着祖坟上埋葬了俺父母这两把儿骨殖。", "我便去也。", "(搽旦打破正末头科，云)老的，你只管与他说甚么？咱家去来。", "(关门科)(下)(正末云)认我不队我便罢，怎么将我的头打破了？天那！谁人与我做主咱！(哭科)(李社长上，云)老汉李社长是也。", "打从刘天祥门省经过，看见一个后生，在那里啼哭，不知为何？我问他波。", "这小的，你是甚么人：(正末云)我是十五年前趁熟去的刘天瑞儿子刘安住，(社长认科，云)是谁打破你头天？(正末云)这不干我伯父事，是伯娘不肯认我，拿了我合同文书，抵死的赖了，又打破我的头来。", "(社长云)刘安住，你且省烦恼。", "你是我的女婿，我与你做主。", "(正末唱)。"]'),
('yuanqu-1200','包龙图智赚合同文字・满庭芳','无名氏','元','元曲','yuanqu','','[]','谢得你太山做主，我是他嫡亲骨血，又不比房分的家奴。',115,'元曲/yuanqu.json','["谢得你太山做主，我是他嫡亲骨血，又不比房分的家奴。", "将骨殖儿亲担的还乡，故走了些偌远程途。", "你道俺那亲伯父因何致怒，赤紧的打尧婆先赚了我文书。", "(社长云)难道不认就罢了？(正末唱)我可也难回去，但能勾葬埋了我父母，将安住认不认待何如？。"]'),
('yuanqu-1201','包龙图智赚合同文字・十二月','无名氏','元','元曲','yuanqu','','[]','可怜我时乖命苦，只在张秉彝家暂寓权居。',55,'元曲/yuanqu.json','["可怜我时乖命苦，只在张秉彝家暂寓权居。", "生受了些风餐水宿，巴的到祖贯乡闾。", "我只道认着了伯娘伯父，便欢然复旧如初。"]'),
('yuanqu-1202','包龙图智赚合同文字・尧民歌','无名氏','元','元曲','yuanqu','','[]','怎知俺伯娘啊，他是个不冠不带泼无徒，才说起刘家安住便早嘴卢都。',77,'元曲/yuanqu.json','["怎知俺伯娘啊，他是个不冠不带泼无徒，才说起刘家安住便早嘴卢都。", "他把俺合同文字赚来无，尽场儿揣与俺个闷葫芦。", "似这冤也波屈，教俺那里诉，只落得自吞声，暗啼哭。"]'),
('yuanqu-1203','包龙图智赚合同文字・收尾','无名氏','元','元曲','yuanqu','','[]','他清耿耿水一似，明朗朗镜不如。',50,'元曲/yuanqu.json','["他清耿耿水一似，明朗朗镜不如。", "他将俺一行人都带到南衙去，我拚把个头磕碎金阶，叫道委实的屈。", "(同下)。"]'),
('yuanqu-1204','包龙图智赚合同文字・双调/新水令','无名氏','元','元曲','yuanqu','','[]','只俺这小人不解大人机，把带伤人倒监了十日。',47,'元曲/yuanqu.json','["只俺这小人不解大人机，把带伤人倒监了十日。", "干连人不问及，被论人尽勾提。", "暗暗猜疑，怎参透就中意。"]'),
('yuanqu-1205','包龙图智赚合同文字・乔牌儿','无名氏','元','元曲','yuanqu','','[]','他是个老人家多背悔，大人须有才智。',69,'元曲/yuanqu.json','["他是个老人家多背悔，大人须有才智。", "外人行白打了犹当罪，可不俺关亲人绝分义。", "(包待制云)你只打着他，问一个谁是谁非，便好定罪也。", "(正末唱)。"]'),
('yuanqu-1206','包龙图智赚合同文字・挂玉钩','无名氏','元','元曲','yuanqu','','[]','相公道谁是谁非便得知，(包待制做怒科，云)兀那刘安住，你可怎生不着实打者，(正未唱)俺父亲尚兀是他亲兄弟。',203,'元曲/yuanqu.json','["相公道谁是谁非便得知，(包待制做怒科，云)兀那刘安住，你可怎生不着实打者，(正未唱)俺父亲尚兀是他亲兄弟。", "却教俺乱棒胡敲忍下的，也要想个人心大理终难昧。", "我须是他亲子侄，又不争甚家和计。", "我本为行孝而来，可怎么生忿而归？(包待制诗云)老夫低首自评论，就中曲直岂难分。", "为甚侄儿不将伯父打。", "可知亲者原来则是亲。", "兀那小厮，我着你打这老儿，你左来右去。", "只是不肯打。", "张千，取枷来将那小厮枷了者。", "(做枷正末科)(正末唱)。"]'),
('yuanqu-1207','包龙图智赚合同文字・雁儿落','无名氏','元','元曲','yuanqu','','[]','他荆条棍并不曾汤着皮，我荷叶枷倒替他耽将罪。',42,'元曲/yuanqu.json','["他荆条棍并不曾汤着皮，我荷叶枷倒替他耽将罪。", "稳放着打尧婆在一壁，急的那个社长难支对。"]'),
('yuanqu-1208','包龙图智赚合同文字・得胜令','无名氏','元','元曲','yuanqu','','[]','呀！这是我独自落便宜，好着我半晌似呆痴。',655,'元曲/yuanqu.json','["呀！这是我独自落便宜，好着我半晌似呆痴。", "俺只道正直萧丞相，元来是风魔的党太尉。", "堪悲，屈沉杀刘天瑞，谁知可怎了葫芦提包待制？(包待制云)张千，将刘安住下在死囚牢里去。", "你近前来。", "(打耳喑科)(张千云)理会的。", "(张千做枷正末下)(包待制云)这小厮明明要混赖你这家私，是个假的，(搽旦云，大人见的是。", "他那里是我亲侄儿刘安住？(张千云)禀爷，那刘安住下在牢里发起病来，有八九分重哩。", "(包待制云)天有不测风云，人有旦夕祸福：那小厮恰才无病，怎生下在牢里便有病？张千你再去看来。", "(张千报，云)病重九分了也。", "(包待制云)，你再看云。", "(张千又报，云)刘安住太阳穴被他物所伤，观有青紫痕可验，是个破伤风的病症，死了也。", "(搽旦云)死了，谢天地。", "(包待制云)怎么了这桩事？如今倒做了人命，事越重了也。", "兀那婆子，你与刘安住关亲么？(搽旦云)俺不亲。", "(包待制云)你若是亲呵，你是大他是小，休道死了一个刘安住，便死了十个，则是误杀子孙不偿命，则罚些铜纳赎；若是不亲呵。", "道不的杀人偿命，欠债还钱。", "他是各白世人，你不认他罢了，却拿着甚些仗打破他头，做了破伤风身死。", "律上说：殴打平人，因而致死者抵命。", "张千将枷来，枷了这婆子，替刘安住偿命去。", "(搽旦慌科，云)大人，假若有些关亲，可饶的么？(包待制云)是亲便不偿命。", "(搽旦云)这等，他须是俺亲侄儿哩。", "(包待制云)兀那婆子，刘安住活时你说不是，刘安住死了，可就说是。", "这官府倒由的你那？既说是亲侄儿，有甚么显证？(搽旦云)大人，现有合同文书在此。", "(包待制词云)这小厮本说的丁一确二，这婆子生扭做差三错四。"]'),
('yuanqu-1209','包龙图智赚合同文字・甜水令','无名氏','元','元曲','yuanqu','','[]','我只为认祖归宗，迟眠早起，登山涉水，甫能勾到庭帏。',51,'元曲/yuanqu.json','["我只为认祖归宗，迟眠早起，登山涉水，甫能勾到庭帏。", "又谁知伯母无情，十分猜忌，百般驱逼，直恁的命运低微。"]'),
('yuanqu-1210','包龙图智赚合同文字・折桂令','无名氏','元','元曲','yuanqu','','[]','定道是死别生离，与俺那再养爹娘，永没个相见之期。',101,'元曲/yuanqu.json','["定道是死别生离，与俺那再养爹娘，永没个相见之期。", "幸遇清官，高抬明镜，费尽心机。", "赚出了合同的一张文契，才许我埋葬的这两把儿骨殖。", "今日个父子相依，恩义无亏，早则不迷失了百世宗支，俺可也敢忘味了你这十载提携。"]'),
('yuanqu-1211','包龙图智赚合同文字・水仙子','无名氏','元','元曲','yuanqu','','[]','把白褴衫换了绿罗衣，抵多少一举成名天下知。',77,'元曲/yuanqu.json','["把白褴衫换了绿罗衣，抵多少一举成名天下知。", "为甚么皇恩不弃孤寒辈，似高天雨露垂，生和死共戴荣辉。", "虽然是张秉彝十分仁德，李社长一生信义，也何如俺伯父家有贤妻。"]'),
('yuanqu-1212','南吕・一枝花禄山谋反','孔文卿','元','元曲','yuanqu','','[]','苍烟拥剑门，老树屯云栈。',68,'元曲/yuanqu.json','["苍烟拥剑门，老树屯云栈。", "西风吹渭水，落叶满长安。", "近帝都景物凋残，伤感起人愁叹。", "只合在边寒间，只见那白茫茫莎草连天，甚的是娇滴滴莺花过眼。"]'),
('yuanqu-1213','梁州・不幸遣东归蓟北，更胜如西出阳关，看几时捱彻相思限？怕的是孤','孔文卿','元','元曲','yuanqu','','[]','灯荧暗，残月弓弯，戍楼人静，梅帐更阑。',105,'元曲/yuanqu.json','["灯荧暗，残月弓弯，戍楼人静，梅帐更阑。", "思量玉砌雕阑，消磨尽绿鬓朱颜。", "再几时染浓香翡翠衾温，迷醉魂芙蓉帐暖，解余酲荔枝浆寒？这近间，敢病番，旧时的衣衤肯频频亻替。", "瘦证候何经惯？那的是从来最稀罕，单出落着废寝忘餐。"]'),
('yuanqu-1214','三煞・动无喘息行无汗，坐也昏沉睡不安，两行泪道渍成斑。每日家做伴','孔文卿','元','元曲','yuanqu','','[]','的胡友胡儿，胡舞胡歌，胡吹胡弹，知他是甚风范？偏恁一曲霓裳宠玉环，羯鼓声干。',38,'元曲/yuanqu.json','["的胡友胡儿，胡舞胡歌，胡吹胡弹，知他是甚风范？偏恁一曲霓裳宠玉环，羯鼓声干。"]'),
('yuanqu-1215','二煞・拚了教匆匆行色催征雁，止不过拍拍离愁满战鞍，驱兵早晚到骊山。','孔文卿','元','元曲','yuanqu','','[]','若夺了娘娘，教唐天子登时两分散，休想再能够看一看。',42,'元曲/yuanqu.json','["若夺了娘娘，教唐天子登时两分散，休想再能够看一看。", "四件事分明紧调犯，势到也怎摭拦？。"]'),
('yuanqu-1216','尾声・把六宫心事分明的慢，将半纸音书党闭的悭，教千里途程阻隔的难。','孔文卿','元','元曲','yuanqu','','[]','我因此上一点春心酝酿的反。',13,'元曲/yuanqu.json','["我因此上一点春心酝酿的反。"]'),
('yuanqu-1217','双调・沉醉东风宫词','孙周卿','元','元曲','yuanqu','','[]','双拂黛停分翠羽，一窝云半吐犀梳。',96,'元曲/yuanqu.json','["双拂黛停分翠羽，一窝云半吐犀梳。", "宝靥香，罗襦素，海棠娇睡起谁扶？肠断春风倦绣图，生怕见纱窗唾缕。", "花月下温柔醉人，锦堂中笑语生春。", "眼底情，心间恨，到多如楚雨巫云。", "门掩黄昏月半痕，手抵着牙儿自哂。"]'),
('yuanqu-1218','双调・殿前欢楚云','孙周卿','元','元曲','yuanqu','','[]','楚云高，盈盈泪眼望衡皋，付能盼得春来到。',214,'元曲/yuanqu.json','["楚云高，盈盈泪眼望衡皋，付能盼得春来到。", "玉困香娇，是谁人按六幺？红牙闹，睡未足把人惊觉。", "云偏髻鬟，月淡眉梢。", "楚云纤，玉容清浅自家嫌，离情镇把柔肠占。", "情绪厌厌，见莺花懒揭帘。", "心常欠，怕笑我缃裙掩。", "愁堆眼底，恨压眉尖。", "楚云收，月波冷浸晚妆楼，腰肢到比花枝瘦。", "花瘦无愁，比花枝我自羞。", "花虽瘦，花不会把眉儿皱。", "红消翠减，心上眉头。", "楚云空，绿窗闲数唾窗绒，一春心事和谁共？门掩残红，笑残红与我同。", "成何用，都做了繁华梦。", "香消脸玉，翠减眉峰。"]'),
('yuanqu-1219','南吕・骂玉郎过感皇恩采茶歌闺情','孙周卿','元','元曲','yuanqu','','[]','秋千院宇春将暮，红滴泪绿溶朱，朝云隔断阳台路。',222,'元曲/yuanqu.json','["秋千院宇春将暮，红滴泪绿溶朱，朝云隔断阳台路。", "去凤孤，来燕疏，流莺妒。", "懒步阶除，倦立亭隅。", "草烟铺，梨雪舞，柳风扶。", "花惊我癯，我爱花腴。", "玉奁梳，金翠羽，宝香珠。", "绣罗襦，锦笺书，当时封泪到曾无？屈指归期空自数，倚兰无语慢踌蹰。", "香罗带束春风瘦，金缕袖玉搔头，生红色染胭脂绉。", "柳让柔，莺避讴，花辞秀。", "缓转星眸，细咽歌喉。", "晚云收，秋水溜，远山愁。", "香消自忧，粉淡谁羞。", "燕闲俦，鸳冷绣，凤空游。", "没来由，尽淹留，春来春去几时休。", "锦瑟生疏弦上手，月明闲煞小红楼。"]'),
('yuanqu-1220','双调・蟾宫曲','刘唐卿','元','元曲','yuanqu','','[]','博山铜细袅香风，两行纱笼，烛影摇红。',65,'元曲/yuanqu.json','["博山铜细袅香风，两行纱笼，烛影摇红。", "翠袖殷勤捧金钟，半露春葱。", "畅好是会受用文章巨公，绮罗业醉眼朦胧。", "夜宴将终，十二帘栊，月转梧桐。"]'),
('yuanqu-1221','正宫・甘草子','薛昂夫','元','元曲','yuanqu','','[]','金凤发，飒飒秋香，冷落在阑干下。',61,'元曲/yuanqu.json','["金凤发，飒飒秋香，冷落在阑干下。", "万柳稀，重阳暇，看红叶赏黄花。", "促织儿啾啾添潇洒，陶渊明欢乐煞。", "耐冷迎霜鼎内插，看雁落平沙。"]'),
('yuanqu-1222','中吕・朝天曲','薛昂夫','元','元曲','yuanqu','','[]','沛公，大风，也得文章用。',349,'元曲/yuanqu.json','["沛公，大风，也得文章用。", "却教猛士叹良弓，多了游云梦。", "驾驭英雄，能擒能纵，无人出彀中。", "后宫，外宗，险把炎刘并。", "子牙，鬓华，才上非熊卦。", "争些老死向天涯，只恁垂钩罢。", "满腹天机，天人齐发，武王任不差。", "用他，讨罚，一怒安天下。", "伍员，报亲，多了鞭君忿。", "可怜悬首在东门，不见包胥恨。", "半夜潮声，千年孤愤，钱塘万马奔。", "骇人，怒魂，何似吹箫韵？卞和，抱璞，只合荆山坐。", "三朝不遇待如何，两跣遭祸。", "传国争符，伤身行货，谁教献与他？切磋，琢磨，何似偷敲破？邵平，不平，楚汉争秦鼎。", "将军便去作园丁，软了英雄性。", "瓜苦瓜甜，秦衰秦盛，青门浪得名。", "此生，本轻，不是封侯命。", "假王，气昂，跨下羞都忘。", "提牌不过一中郎，漂母曾相饷。", "蒯彻名言，将军将强。", "良弓不早藏。", "未央，法场，险似坛台上。", "叔孙，讨论，早定君臣分。", "礼成文武两班分，舞蹈扬尘顺。"]'),
('yuanqu-1223','中吕・阳春曲','薛昂夫','元','元曲','yuanqu','','[]','坐听西掖钟声动，睡起东窗日影红，山林朝市两无穷。',210,'元曲/yuanqu.json','["坐听西掖钟声动，睡起东窗日影红，山林朝市两无穷。", "一梦中，樽有酒且从容。", "耐惊耐怕黄齑瓮，长满长干老酒盆，一贫尽可张吾军。", "休忘本，樽有酒且论文。", "胸中太华身难憾，舌底狂澜口且缄，看渠暮四与朝三。", "呆大胆，樽有酒且醺酣。", "周郎赤壁鏖兵后，苏子扁舟载月秋，千年慷慨一时酬。", "今在否？樽有酒且绸缪。", "芸窗月影吟情荡，纸帐梅花醉梦香，觉来身世两相忘。", "休妄想，樽有酒且疏狂。", "岁云暮矣虽无补，时复中之尽有余，老来吾亦爱吾庐。", "清债苦，樽有酒且消除。"]'),
('yuanqu-1224','双调・蟾宫曲叹世','薛昂夫','元','元曲','yuanqu','','[]','鸡羊鹅鸭休争，偶尔相逢，堪炙堪烹。',483,'元曲/yuanqu.json','["鸡羊鹅鸭休争，偶尔相逢，堪炙堪烹。", "天地中间，生老病死，物理常情。", "有一日符到奉行，只图个月朗风清。", "笑杀刘伶，荷插埋尸，犹未忘形。", "人生尔尔堪怜，富贵何时，又待问舍求田？想昨日秦宫，今朝汉阙，呀，可早晋地唐天！能几许长安少年，急回头两鬓皤然。", "谩说求仙，百计千方，都不似樽前。", "雪天仙碧玉琼瑶，点点杨花，片片鹅毛。", "访戴归来，寻梅懒去，独钓无聊。", "一个饮羊羔红炉暖阁，一个冻骑驴野店溪桥。", "你自评跋，那个清高，那个粗豪？题烂柯石桥甚神仙久占岩桥，一局楸枰，满耳松涛。", "引得樵夫，旁观不觉，晋换了唐朝。", "斧柄儿虽云料却，裤腰儿难保坚牢。", "王母蟠桃，三千岁开化，总是虚谣。", "懒朝元石上围棋，问仙子何争？樵叟忘归。", "洞锁青霞，斧柯已烂，局势犹迷。", "恰滚滚桑田浪起，又飘飘沧海尘飞。", "恰待持杯，酒未沾唇，日又平西。", "快阁怀古舣扁舟快阁盘桓，看一道澄江，落木千山。", "自山谷留题，坡仙阁笔，我试凭阑。", "问今古诗人往还，比盟鸥几个能闲？天地中间，物我无干，只除是美酒佳人，意颇相关。", "知音问芳筵歌者何人？便折简相招，恣意开樽。", "细切清风，薄批明月，何必云云。", "是久厌黄齑菜根，要听他白雪阳春。", "翠袖殷勤，雪霁梅开，正好论文。"]'),
('yuanqu-1225','双调・湘妃怨集句','薛昂夫','元','元曲','yuanqu','','[]','几年无事傍江湖，醉倒黄公旧酒垆。',60,'元曲/yuanqu.json','["几年无事傍江湖，醉倒黄公旧酒垆。", "人间纵有伤心处，也不到刘伶坟上土，醉乡中不辨贤愚。", "对风流人物，看江山画图，便醉倒何如？。"]'),
('yuanqu-1226','双调・殿前欢春','薛昂夫','元','元曲','yuanqu','','[]','据危阑，看浮屠双耸倚高寒，鳞鳞万瓦连霄汉。',350,'元曲/yuanqu.json','["据危阑，看浮屠双耸倚高寒，鳞鳞万瓦连霄汉。", "俯视尘寰，望飞来紫翠间。", "云初散，放老眼情无限。", "知他是西山傲我，我傲西山？夏柳扶疏，玻璃万项浸冰壶，流莺声里笙歌度。", "士女相呼，有丹青画不如。", "迷归路，又撑入荷深处。", "知他是西湖恋我，我恋西湖？秋洞箫歌，问当年赤壁乐如何，比西湖画航争些个？一样烟波，有吟人景便多。", "四海诗名播，千载谁酬和？知他是东坡让我，我让东坡？冬捻冰髭，绕孤山枉了费寻思，自逋仙去后无高士。", "冷落幽姿，道梅花不要诗。", "休说推敲字，效杀颦难似。", "知他是西施笑我，我笑西施？浪淘淘，看渔翁举网趁春潮，林间又见樵夫闹。", "伐木声高，比功名客更劳。", "虽然道，他终是心中乐。", "知他是渔樵笑我，我笑渔樵？醉归来，袖春风下马笑腮，笙歌接到朱帘外。", "夜宴重开，十年前一秀才。", "黄齑菜，打熬到文章伯。", "施展出江湖气概，抖擞出风月情怀。"]'),
('yuanqu-1227','双调・楚天遥过清江引','薛昂夫','元','元曲','yuanqu','','[]','花开人正欢，花落春如醉。',254,'元曲/yuanqu.json','["花开人正欢，花落春如醉。", "春醉有时醒，人老欢难会，一江春水流，万点杨花坠。", "谁道是杨花？点点离人泪！回首有情风万里，渺渺天无际。", "愁共海潮来，潮去愁难退，更那堪晚来风又急！屈指数春来，弹指惊春去。", "蛛丝网落花，也要留春住。", "几日喜春睛，几夜愁春雨。", "六曲小山屏，题满伤春句。", "春若有情应解语，问着无凭据。", "江东日暮云，渭北春天树，不知那答儿是春住处？有意送春归，无计留春住。", "明年又着来，何似休归去？桃花也解愁，点点飘红玉。", "目断楚天遥，不见春归路。", "春若有情春更苦，暗里韶光度。", "夕阳山外山，春水渡傍渡，不知那答儿是春住处？套数。"]'),
('yuanqu-1228','正宫・端正好高隐','薛昂夫','元','元曲','yuanqu','','[]','访知音习酬和，也不问名利如何。',30,'元曲/yuanqu.json','["访知音习酬和，也不问名利如何。", "不贪不爱随缘过，把世事都参破。"]'),
('yuanqu-1229','滚绣球・叹光阴疾似梭，想人生能几何，转回头百年已过，急回首两鬓斑','薛昂夫','元','元曲','yuanqu','','[]','花阴转眼那，日光弹指过，送了些干峥嵘且贪呆货，有两句古语您自评跋。',54,'元曲/yuanqu.json','["花阴转眼那，日光弹指过，送了些干峥嵘且贪呆货，有两句古语您自评跋。", "相随故友年年少，郊外新坟岁岁多，一枕南柯。"]'),
('yuanqu-1230','倘秀才・日落西山衔着烈火，月出东云托着玉钵，似这般东去西来怎奈何？','薛昂夫','元','元曲','yuanqu','','[]','金乌疾如箭，玉兔似撺梭，自心中定夺。',18,'元曲/yuanqu.json','["金乌疾如箭，玉兔似撺梭，自心中定夺。"]'),
('yuanqu-1231','滚绣球・则不如山田一二亩，栽桑麻数百棵，驱家人使牛耕播，住几间无','薛昂夫','元','元曲','yuanqu','','[]','忧愁草苫庄坡。',64,'元曲/yuanqu.json','["忧愁草苫庄坡。", "一朝苗稼锄，趁时将黍豆割，养春蚕桑叶忙锉，着山妻上布织梭。", "秃厮姑紧紧的将绵花纺，村伴姐慌将麻线搓，一弄儿农器家活。"]'),
('yuanqu-1232','倘秀才・闲时节疏林外磁瓯瓦钵，盛摘下些生桃硬果，晚趁斜阳景物多。','薛昂夫','元','元曲','yuanqu','','[]','听水声流浪远，观山色岭嵯峨，与俺那庄农每会合。',23,'元曲/yuanqu.json','["听水声流浪远，观山色岭嵯峨，与俺那庄农每会合。"]'),
('yuanqu-1233','赛鸿秋・我若是醉时节笑引着儿孙和，醉时节麦场上闲独磨，醉时节六轴','薛昂夫','元','元曲','yuanqu','','[]','上乔衙坐，醉时节巴棚下和衣儿卧。',41,'元曲/yuanqu.json','["上乔衙坐，醉时节巴棚下和衣儿卧。", "酒醒觉来时，直睡到参儿锉，不听的五更钟人马街前过。"]'),
('yuanqu-1234','耍孩儿・收成黍豆盈仓垛，经年不缺半合。收耕罢织足衣食，将柴门紧紧','薛昂夫','元','元曲','yuanqu','','[]','扃合。',44,'元曲/yuanqu.json','["扃合。", "早晨间豆粥吃三碗，收晚来齑汤做一锅，暖炕上和衣卧。", "守着俺山妻稚子，喂养些牛畜驴骡。"]'),
('yuanqu-1235','四煞・到春来绿依依柳吐烟，红馥馥桃喷火，粉蝶儿来往穿花过。黄莺出','薛昂夫','元','元曲','yuanqu','','[]','谷寻新柳，紫燕归巢觅旧窝。',36,'元曲/yuanqu.json','["谷寻新柳，紫燕归巢觅旧窝。", "时雨降天公贺，庆新春齐敲社鼓，赛牛王共击铜锣。"]'),
('yuanqu-1236','三煞・到夏来玩池塘十里长，赏荷花百步阔，青铺翠盖穿红破。虽无那彩','薛昂夫','元','元曲','yuanqu','','[]','船画舫游池沼，也有那短棹渔舟泛浅波。',40,'元曲/yuanqu.json','["船画舫游池沼，也有那短棹渔舟泛浅波。", "故友来相贺，绕溪边鲜鱼旋买，沿村务沽酒频酌。"]'),
('yuanqu-1237','二煞・来秋来碧天雁几行，黄花儿开数朵，满川红叶似胭脂抹。青山隐隐','薛昂夫','元','元曲','yuanqu','','[]','连巅岭，绿水潺潺泛浅波。',35,'元曲/yuanqu.json','["连巅岭，绿水潺潺泛浅波。", "鲜藕莲根锉，团脐蟹味欺着锦鲤，嫩黄鸡胜似肥鹅。"]'),
('yuanqu-1238','一煞・到冬来朔风遍地刮，彤云密布合，纷纷雪片钱来大。须臾云汉飘白','薛昂夫','元','元曲','yuanqu','','[]','蕊，咫尺空中舞玉蛾。',32,'元曲/yuanqu.json','["蕊，咫尺空中舞玉蛾。", "冬景堪酬和，草庵前寒梅雪压，短窗边瘦影频磨。"]'),
('yuanqu-1239','尾声・四时景物佳，放形骸堪正可。我比你少忧愁省烦恼无灾祸，到大来','薛昂夫','元','元曲','yuanqu','','[]','无是无非快活煞我！闺怨小庭幽，重门静，东风软膏雨初晴。',44,'元曲/yuanqu.json','["无是无非快活煞我！闺怨小庭幽，重门静，东风软膏雨初晴。", "猛听的卖花声过天街应，惊谢芙蓉兴。"]'),
('yuanqu-1241','倘秀才・南浦道送春行，多应是抛弃了欢娱，奔逐利名。千古恨短长亭，','薛昂夫','元','元曲','yuanqu','','[]','欲留恋难能。',20,'元曲/yuanqu.json','["欲留恋难能。", "四眸相顾两心同，信佳人薄命。"]'),
('yuanqu-1242','三错煞・金杯空冷落了樽前兴，锦瑟闲生疏了月下声。欲寄音书，空织回','薛昂夫','元','元曲','yuanqu','','[]','文锦字成。',20,'元曲/yuanqu.json','["文锦字成。", "奈远水遥山隔万层，鱼雁也难凭。"]'),
('yuanqu-1243','二错煞・料忧愁一日加了十等，想茶饭三停里减了二停。白日犹闲，怕到','薛昂夫','元','元曲','yuanqu','','[]','黄昏睡卧不宁。',27,'元曲/yuanqu.json','["黄昏睡卧不宁。", "则我这泪点儿安排下半枯井，也滴不到天明。"]'),
('yuanqu-1244','煞尾・团团黄篆焚金鼎，夜夜浓薰暖翠屏，偏今宵是怎生？乍别离不惯经，','薛昂夫','元','元曲','yuanqu','','[]','睡不安卧不宁，分外春寒被儿冷。',15,'元曲/yuanqu.json','["睡不安卧不宁，分外春寒被儿冷。"]'),
('yuanqu-1245','南吕・一枝花赠小园春','薛昂夫','元','元曲','yuanqu','','[]','些些并蒂红，指指连枝翠。',59,'元曲/yuanqu.json','["些些并蒂红，指指连枝翠。", "悭悭金谷路，窄窄五陵溪。", "一片花飞，泄漏春消息。", "舞盘中歌扇底，刮得尽风月无多，趱得过繁华有几？。"]'),
('yuanqu-1246','梁州第七・一两个莺俦燕侣，五七双蝶使蜂媒。窖来宽也称游人戏。眼孔','薛昂夫','元','元曲','yuanqu','','[]','大刘晨未识，脚步长杜甫先迷。',109,'元曲/yuanqu.json','["大刘晨未识，脚步长杜甫先迷。", "画帧上香销粉滴，镜奁中绿暗红稀。", "唾津儿浸满盆池，手心儿擎得起屏石。", "苔钱儿买不断闲愁，花瓣儿随手着流水，柳丝儿送不够别离。", "锦堆，翠积。", "海棠偷足相思睡，名偏小景偏媚。", "赚得东君不忍归，一撮儿芳菲。"]'),
('yuanqu-1247','余音・楚阳台云雨无三尺，桃源洞光阴减九十。玉拶香挨这窝儿地，堪信','薛昂夫','元','元曲','yuanqu','','[]','道一寸阴可惜。',23,'元曲/yuanqu.json','["道一寸阴可惜。", "千金价总宜，锦步幢何须五十里？。"]'),
('yuanqu-1248','温太真玉镜台・仙吕/点绛唇','关汉卿','元','元曲','yuanqu','','[]','车骑成行，诣门稽颡，来咨访。',31,'元曲/yuanqu.json','["车骑成行，诣门稽颡，来咨访。", "无非那今古兴亡，端的是语出人皆仰。"]'),
('yuanqu-1249','温太真玉镜台・油葫芦','关汉卿','元','元曲','yuanqu','','[]','还有那苦志书生才学广，一年年守选场，早熬的萧萧白发满头霜；几时得出为破虏三军将，入为治国头厅相？只愿的圣主兴，世运昌；把黄金结作漫天网，收俊杰，揽贤良。',76,'元曲/yuanqu.json','["还有那苦志书生才学广，一年年守选场，早熬的萧萧白发满头霜；几时得出为破虏三军将，入为治国头厅相？只愿的圣主兴，世运昌；把黄金结作漫天网，收俊杰，揽贤良。"]'),
('yuanqu-1250','温太真玉镜台・天下乐','关汉卿','元','元曲','yuanqu','','[]','当日个谁家得凤凰？翱也波翔，在那天子堂，争知他朝为田舍郎？傅说呵在版筑处生，伊尹呵从稼穑中长，他两个也不是出胞胎便显扬。',93,'元曲/yuanqu.json','["当日个谁家得凤凰？翱也波翔，在那天子堂，争知他朝为田舍郎？傅说呵在版筑处生，伊尹呵从稼穑中长，他两个也不是出胞胎便显扬。", "（云）虽然如此，那得志不得志的，都也由命不由人，非可勉强。", "（唱）。"]'),
('yuanqu-1251','温太真玉镜台・那吒令','关汉卿','元','元曲','yuanqu','','[]','他每都恃着口强，便仪秦呵怎敢比量？都恃着力强，便贲育呵怎敢赌当？元来都恃着命强。',76,'元曲/yuanqu.json','["他每都恃着口强，便仪秦呵怎敢比量？都恃着力强，便贲育呵怎敢赌当？元来都恃着命强。", "便孔孟呵也没做主张。", "这一个是王者师，这一个是苍生望，到底捱不彻雪案萤窗。"]'),
('yuanqu-1252','温太真玉镜台・鹊踏技','关汉卿','元','元曲','yuanqu','','[]','只落的意彷徨，走四方；昨日燕陈，明日齐梁。',43,'元曲/yuanqu.json','["只落的意彷徨，走四方；昨日燕陈，明日齐梁。", "若不是聚生徒来听讲，怎留得这诗书万古传芳？。"]'),
('yuanqu-1253','温太真玉镜台・寄生草','关汉卿','元','元曲','yuanqu','','[]','我正行功名运，我正在富贵乡。',60,'元曲/yuanqu.json','["我正行功名运，我正在富贵乡。", "俺家声先世无诽谤，俺书香今世无虚诳，俺功名奕世无谦让，遮莫是帽檐相接御楼前，靴踪不离金阶上。"]'),
('yuanqu-1254','温太真玉镜台・幺篇','关汉卿','元','元曲','yuanqu','','[]','不枉了开着金屋，空着画堂。',65,'元曲/yuanqu.json','["不枉了开着金屋，空着画堂。", "酒醒梦觉无情况，好天良夜成虚旷，临风对月空惆怅。", "怎能够可情人消受锦幄凤凰衾，把愁怀都打撇在玉枕鸳鸯帐！。"]'),
('yuanqu-1255','温太真玉镜台・六么序','关汉卿','元','元曲','yuanqu','','[]','兀的不消人魂魄，绰人眼光？说神仙那的是天堂？则见脂粉馨香，环佩丁当，藕丝嫩新织仙裳，但风流都在他身上，添分毫便不停当。',88,'元曲/yuanqu.json','["兀的不消人魂魄，绰人眼光？说神仙那的是天堂？则见脂粉馨香，环佩丁当，藕丝嫩新织仙裳，但风流都在他身上，添分毫便不停当。", "见他的不动情，你便都休强，则除是铁石儿郎，也索恼断柔肠！。"]'),
('yuanqu-1256','温太真玉镜台・幺篇','关汉卿','元','元曲','yuanqu','','[]','我这里端祥他那模样：花比腮庞，花不成妆；玉比肌肪，玉不生光。',133,'元曲/yuanqu.json','["我这里端祥他那模样：花比腮庞，花不成妆；玉比肌肪，玉不生光。", "宋玉襄王，想像高唐，止不过魂梦悠扬，朝朝暮暮阳台上，害的他病在膏盲；若还来此相亲傍，怕不就形消骨化，命丧身亡！（夫人云）梅香，将酒来。", "小姐与哥哥把盏。", "（旦奉酒科，云）哥哥，满饮一杯。", "（做递酒科）（正末唱）。"]'),
('yuanqu-1257','温太真玉镜台・金盏儿','关汉卿','元','元曲','yuanqu','','[]','来日不空亡，没相妨。',149,'元曲/yuanqu.json','["来日不空亡，没相妨。", "天生壬申癸酉全家旺，不比那长星赤口要提防。", "大纲来阴阳偏有准，择日要端详；岂不闻成开皆大吉，闭破莫商量。", "（夫人云）既如此，就是明日，要劳动学士者。", "（正末云）谨依尊命！明日温峤自来。", "但温峤无学，怎生教的小姐？（夫人云）学士休得推辞，只看你下世姑夫的面皮，教训女孩儿则个。", "（正末唱）。"]'),
('yuanqu-1258','温太真玉镜台・醉中天','关汉卿','元','元曲','yuanqu','','[]','白日短，无时晌，兼夜教，正更长，便误了翰林院编修有甚忙？我待做师为学长，拚的个十分应当，再无推让，早收拾幽静书房。',57,'元曲/yuanqu.json','["白日短，无时晌，兼夜教，正更长，便误了翰林院编修有甚忙？我待做师为学长，拚的个十分应当，再无推让，早收拾幽静书房。"]'),
('yuanqu-1259','温太真玉镜台・赚煞尾','关汉卿','元','元曲','yuanqu','','[]','恰才立一朵海棠娇，捧一盏梨花酿，把我双送入愁乡醉乡。',103,'元曲/yuanqu.json','["恰才立一朵海棠娇，捧一盏梨花酿，把我双送入愁乡醉乡。", "我这里下得阶基无个顿放，画堂中别是风光。", "恰才则挂垂杨一抹斜阳，改变了黯黯阴云蔽上苍。", "眼见得人倚绿窗，又则怕灯昏罗帐，天那，休添上画檐间疏雨滴愁肠。", "（下）。"]'),
('yuanqu-1260','温太真玉镜台・南吕/一枝花','关汉卿','元','元曲','yuanqu','','[]','藕丝翡翠裙，玉腻蝤蛴颈；妲己空破国，西子枉倾城。',61,'元曲/yuanqu.json','["藕丝翡翠裙，玉腻蝤蛴颈；妲己空破国，西子枉倾城。", "天上飞琼，散下风流病。", "若是寝正浓，梦乍醒，且休问斜月残灯，直睡到东窗口影。"]'),
('yuanqu-1261','温太真玉镜台・牧羊关','关汉卿','元','元曲','yuanqu','','[]','纵然道肌如雪、腕似冰，虽是一段玉，却是几样磨成：指头是三节儿琼瑶，指甲似十颗水晶。',275,'元曲/yuanqu.json','["纵然道肌如雪、腕似冰，虽是一段玉，却是几样磨成：指头是三节儿琼瑶，指甲似十颗水晶。", "稳坐的有那稳坐堪人敬，但举动有那举动可人憎。", "他兀自未揎起金衫袖，我又早先听的玉钏鸣。", "（夫人云）小姐，弹琴不打紧；须装香来，请哥哥在相公抱角床上坐，着小姐拜哥哥。", "\"一日为师，终身为父。", "\"学士教小姐写字者。", "（旦写字科）（正末云）腕平着，笔直着。", "小姐，不是这等。", "（正末起把笔捻旦手科）（旦云）是何道理，妹子跟前捻手捻腕！（正末云）小生岂有他意？（夫人云）小鬼头，但得哥哥捻手捻腕，你早十分有福也。", "（旦云）\"男女七岁，不可同席。", "\"（夫人笑科，云）哥哥根前掉书袋儿。", "（正未唱）。"]'),
('yuanqu-1262','温太真玉镜台・四块玉','关汉卿','元','元曲','yuanqu','','[]','兀的紫霜毫烧甚香，斑竹管有何幸，倒能勾柔荑般指尖擎。',67,'元曲/yuanqu.json','["兀的紫霜毫烧甚香，斑竹管有何幸，倒能勾柔荑般指尖擎。", "只你那纤纤的手腕儿须索平正。", "我不曾将你玉笋荡，他又早星眼睁，好骂我这泼顽皮没气性。"]'),
('yuanqu-1263','温太真玉镜台・牧羊关','关汉卿','元','元曲','yuanqu','','[]','妇人每鞋袜里多藏着病，灰土儿没面情，除底外四周围并无余剩。',78,'元曲/yuanqu.json','["妇人每鞋袜里多藏着病，灰土儿没面情，除底外四周围并无余剩。", "几般儿窄窄狭狭，几般儿周围正正。", "几时迤逗的独强性，勾引的把人憎。", "几时得使性气由他呲，恶心烦自在蹬。"]'),
('yuanqu-1264','温太真玉镜台・贺新郎','关汉卿','元','元曲','yuanqu','','[]','你便是醉中茶，一啜曛然醒。',109,'元曲/yuanqu.json','["你便是醉中茶，一啜曛然醒。", "都为他皓齿明眸，不由我使心作幸。", "待寻条妙计无踪影，老姑娘手把着头梢自领。", "索甚么嘱咐叮咛，似取水垂辘轳，用酒打猩猩。", "到这里惜甚廉耻，敢倾人命！休、休、休，做一头海来深不本分，使一场天来大昧前程。"]'),
('yuanqu-1265','温太真玉镜台・隔尾','关汉卿','元','元曲','yuanqu','','[]','他藉妆梳颜色花难并，宜环佩腰肢柳笑轻，一对不倒踏窄小金莲尚古自剩。',54,'元曲/yuanqu.json','["他藉妆梳颜色花难并，宜环佩腰肢柳笑轻，一对不倒踏窄小金莲尚古自剩。", "想天公是怎生？这世情，教他独占人间第一等。"]'),
('yuanqu-1266','温太真玉镜台・红芍药','关汉卿','元','元曲','yuanqu','','[]','年纪和温峤不多争，和温峤一样身形；据文学比温峤更聪明，温峤怎及他豪英？保亲的堪信凭，搭配的两下里相应。',66,'元曲/yuanqu.json','["年纪和温峤不多争，和温峤一样身形；据文学比温峤更聪明，温峤怎及他豪英？保亲的堪信凭，搭配的两下里相应。", "不提防对面说才能，远不出门庭。"]'),
('yuanqu-1267','温太真玉镜台・菩萨梁州','关汉卿','元','元曲','yuanqu','','[]','古人亲事，把闺门礼正。',74,'元曲/yuanqu.json','["古人亲事，把闺门礼正。", "但得人心至诚，也不须礼物丰盈。", "点灯吃饭两分明：缑山无梦碧瑶笙，玉台有主菱花镜。", "更有场大厮并，月夜高烧绛蜡灯，只愁那烦扰非轻！。"]'),
('yuanqu-1268','温太真玉镜台・煞尾','关汉卿','元','元曲','yuanqu','','[]','俺待麝兰腮、粉香臂、鸳鸯颈，由你水银渍、朱砂斑、翡翠青。',195,'元曲/yuanqu.json','["俺待麝兰腮、粉香臂、鸳鸯颈，由你水银渍、朱砂斑、翡翠青。", "到春来小重楼策杖登，曲阑边把臂行，闲寻芳、闷选胜。", "到夏来追凉院、近水庭，碧纱厨、绿窗净，针穿珠、扇扑萤。", "到秋来入兰堂、开画屏，看银河、牛女星，伴添香、拜月亭。", "到冬来风加严、雪乍晴，摘疏梅、浸古瓶，欢寻常、乐余剩。", "那时节、趁心性，由他娇痴、尽他怒憎，善也偏宜、恶也相称。", "朝至暮不转我这眼睛，孜孜觑定，端的寒忘热、饥忘饱、冻忘冷。", "（下）。"]'),
('yuanqu-1269','温太真玉镜台・中吕/粉蝶儿','关汉卿','元','元曲','yuanqu','','[]','怕不动的鼓乐声齐，若是女孩儿不谐鱼水，我自拖拽这一场出丑扬疾。',66,'元曲/yuanqu.json','["怕不动的鼓乐声齐，若是女孩儿不谐鱼水，我自拖拽这一场出丑扬疾。", "安排下佯小心，装大胆，丹方一味：他若是皱着双眉，我则索牙床前告他一会。"]'),
('yuanqu-1270','温太真玉镜台・红绣鞋','关汉卿','元','元曲','yuanqu','','[]','则见他无发付氲氲恶气，急节里不能勾步步相随。',80,'元曲/yuanqu.json','["则见他无发付氲氲恶气，急节里不能勾步步相随。", "我那\"五言诗作上天梯\"，首榜上标了名姓，当殿下脱了白衣，今夜管洞房中抓了面皮。", "（云）媒人，待咱大了胆过去来。", "（唱）。"]'),
('yuanqu-1271','温太真玉镜台・迎仙客','关汉卿','元','元曲','yuanqu','','[]','到这里论甚使数，问甚官媒？紧逐定一团儿休厮离。',50,'元曲/yuanqu.json','["到这里论甚使数，问甚官媒？紧逐定一团儿休厮离。", "和他守何亲，等甚喜？一发的走到跟底。", "大家吃一会没滋味。"]'),
('yuanqu-1272','温太真玉镜台・醉高歌','关汉卿','元','元曲','yuanqu','','[]','我见他姿姿媚媚容仪，我几曾稳稳安安坐地？向旁边踢开一把银交椅，我则是靠着个栲栳圈站立。',43,'元曲/yuanqu.json','["我见他姿姿媚媚容仪，我几曾稳稳安安坐地？向旁边踢开一把银交椅，我则是靠着个栲栳圈站立。"]'),
('yuanqu-1273','温太真玉镜台・红绣鞋','关汉卿','元','元曲','yuanqu','','[]','正堂里夫人寝睡，小官在书房中依旧孤忄西。',104,'元曲/yuanqu.json','["正堂里夫人寝睡，小官在书房中依旧孤忄西。", "遮莫待尽世儿不能勾到他这罗帏，人都道刘家女被温峤娶为妻，落得个虚名儿则是美！（云）将酒来，我与小姐把盏咱。", "（正末把酒科）（旦云）我不吃。", "（官媒云）小姐接酒。", "（正末唱）。"]'),
('yuanqu-1274','温太真玉镜台・普天乐','关汉卿','元','元曲','yuanqu','','[]','初相见玉堂中，常想在天宫内，则索向空闲偷觑，怎生敢整顿观窥？得如今服侍他，情愿待为奴婢。',92,'元曲/yuanqu.json','["初相见玉堂中，常想在天宫内，则索向空闲偷觑，怎生敢整顿观窥？得如今服侍他，情愿待为奴婢。", "厨房中水陆烹炮珍羞味，箱柜内无限锦绣珠翠。", "但能勾与你插戴些首饰，执料些饮食，则这的我早福共天齐。"]'),
('yuanqu-1275','温太真玉镜台・上小楼','关汉卿','元','元曲','yuanqu','','[]','休提着违宣抗敕，越逗的他烦天恼地。',111,'元曲/yuanqu.json','["休提着违宣抗敕，越逗的他烦天恼地。", "你则说迟了燕尔，过了新婚，误了时刻；你说领着省事，掌着军权，居着高位；又道会亲处倚官挟势。", "（云）我则索哀告你个媒婆，做个方便者。", "（做跪科）（官媒云）学士，你为何在老身跟前下礼？（正末唱）。"]'),
('yuanqu-1276','温太真玉镜台・幺篇','关汉卿','元','元曲','yuanqu','','[]','我"求灶头不如告灶尾"。',51,'元曲/yuanqu.json','["我\"求灶头不如告灶尾\"。", "为甚我今日媒人跟前做小伏低？教他款慢里劝谏的俺夫妻和会，兀的是罗帏中用人之际。"]'),
('yuanqu-1277','温太真玉镜台・耍孩儿','关汉卿','元','元曲','yuanqu','','[]','你少年心想念着风流配，我老则老争多的几岁？不知我心中常印着个不相宜，索将你百纵千随。',92,'元曲/yuanqu.json','["你少年心想念着风流配，我老则老争多的几岁？不知我心中常印着个不相宜，索将你百纵千随。", "你便不欢欣，我则满面儿相陪笑；你便要打骂，我也浑身儿都是喜。", "我把你看承的、看承的家宅土地，本命神祗。"]'),
('yuanqu-1278','温太真玉镜台・四煞','关汉卿','元','元曲','yuanqu','','[]','论长安富贵家，怕青春子弟稀，有多少千金娇艳为妻室？这厮每黄昏鸾凤成双宿，清晓鸳鸯各自飞，那里有半点儿真实意？把你似粪堆般看待，泥土般抛掷。',69,'元曲/yuanqu.json','["论长安富贵家，怕青春子弟稀，有多少千金娇艳为妻室？这厮每黄昏鸾凤成双宿，清晓鸳鸯各自飞，那里有半点儿真实意？把你似粪堆般看待，泥土般抛掷。"]'),
('yuanqu-1279','温太真玉镜台・三煞','关汉卿','元','元曲','yuanqu','','[]','你攒着眉熬夜阑，侧着耳听马嘶，闷心欲睡何曾睡。',61,'元曲/yuanqu.json','["你攒着眉熬夜阑，侧着耳听马嘶，闷心欲睡何曾睡。", "灯昏锦帐郎何在？香烬金炉人未归，渐渐的成憔悴还不到一年半载，他可早两妇三妻。"]'),
('yuanqu-1280','温太真玉镜台・二煞','关汉卿','元','元曲','yuanqu','','[]','今日咱守定伊，休道近前使唤丫鬟辈，便有瑶池仙子无心觑，月殿嫦娥懒去窥。',63,'元曲/yuanqu.json','["今日咱守定伊，休道近前使唤丫鬟辈，便有瑶池仙子无心觑，月殿嫦娥懒去窥。", "俺可也别无意，你道因甚的千般惧怕？也只为差了这一分年纪。"]'),
('yuanqu-1281','温太真玉镜台・煞尾','关汉卿','元','元曲','yuanqu','','[]','我都得知、都得知，你休执迷、休执迷；你若别寻的个年少轻狂婿，恐不似我这般十分敬重你。',47,'元曲/yuanqu.json','["我都得知、都得知，你休执迷、休执迷；你若别寻的个年少轻狂婿，恐不似我这般十分敬重你。", "（同下）。"]'),
('yuanqu-1282','温太真玉镜台・双调/新水令','关汉卿','元','元曲','yuanqu','','[]','则为凤鸾失配累了苍鹘，今日个玳筵开，专要把鸳鸯完聚。',73,'元曲/yuanqu.json','["则为凤鸾失配累了苍鹘，今日个玳筵开，专要把鸳鸯完聚。", "我前面骑的是五花骢，他背后坐的是七香车；人都道这村里妻夫，直恁般似水如鱼，两口儿不肯离了一步。"]'),
('yuanqu-1283','温太真玉镜台・驻马听','关汉卿','元','元曲','yuanqu','','[]','想当日沽酒当垆，拼了个三不归青春卓氏女；今日膝行肘步，招了个百般嫌皓首汉相如。',81,'元曲/yuanqu.json','["想当日沽酒当垆，拼了个三不归青春卓氏女；今日膝行肘步，招了个百般嫌皓首汉相如。", "偏不肯好头好面到成都，忄敞的我没牙没口题桥柱。", "谁跟前敢告诉，兀的是自招自揽风流苦！。"]'),
('yuanqu-1284','温太真玉镜台・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','自从不应举，何尝对两字句？昨日会宾朋，饮到遥天暮，今日酒渴的我没是处。',35,'元曲/yuanqu.json','["自从不应举，何尝对两字句？昨日会宾朋，饮到遥天暮，今日酒渴的我没是处。"]'),
('yuanqu-1285','温太真玉镜台・挂玉钩','关汉卿','元','元曲','yuanqu','','[]','恨不的巴到咽喉咽下去。',67,'元曲/yuanqu.json','["恨不的巴到咽喉咽下去。", "井坠着朱砂玉，与咱更压瘴气，凉心经，解脏毒。", "大人呵他自有通仙术。", "至如肿了面皮，疮生眉目，也索蘸笔挥毫，咒水书符。"]'),
('yuanqu-1286','温太真玉镜台・川拨棹','关汉卿','元','元曲','yuanqu','','[]','这官人待须臾，休恁般相逼促。',43,'元曲/yuanqu.json','["这官人待须臾，休恁般相逼促。", "你道是傅粉涂朱，妖艳妆梳。", "貌赛过神仙洛浦，怎好把墨来乌？。"]'),
('yuanqu-1287','温太真玉镜台・豆叶黄','关汉卿','元','元曲','yuanqu','','[]','你在黑阁落里欺你男儿，今日呵可不道指斥銮舆，也有禁住你限时，降了你乖处。',113,'元曲/yuanqu.json','["你在黑阁落里欺你男儿，今日呵可不道指斥銮舆，也有禁住你限时，降了你乖处。", "两个月方才唤了我个丈夫，虽不曾彻胆欢娱，荡着皮肤，刚听的这一声娇似莺雏，早着我浑身麻木。", "（旦云）丈夫，你知道么？倘或罚水，乌墨搽面，教我怎了？（正末唱）。"]'),
('yuanqu-1288','温太真玉镜台・乔牌儿','关汉卿','元','元曲','yuanqu','','[]','如今便面上笔落处，也则是浮抹不生住。',57,'元曲/yuanqu.json','["如今便面上笔落处，也则是浮抹不生住。", "咱自有新合来澡豆香芬馥，到家银盆中洗面去。", "（旦云）丈夫，着意吟诗！（正末唱）。"]'),
('yuanqu-1289','温太真玉镜台・挂玉钩','关汉卿','元','元曲','yuanqu','','[]','我从小里文章不大古，年老也还有甚词赋？则道我沉醉黄公旧酒垆，怎知我也有妆幺处。',67,'元曲/yuanqu.json','["我从小里文章不大古，年老也还有甚词赋？则道我沉醉黄公旧酒垆，怎知我也有妆幺处。", "见他害恐惧，我倒身无措。", "且等他急个多时，慢慢的再做支吾。"]'),
('yuanqu-1290','温太真玉镜台・水仙子','关汉卿','元','元曲','yuanqu','','[]','须闻得温峤不尘俗，明知道诗书饱满腹，那里是白头把你青春误？就嫌的我无地缝钻入去。',77,'元曲/yuanqu.json','["须闻得温峤不尘俗，明知道诗书饱满腹，那里是白头把你青春误？就嫌的我无地缝钻入去。", "少甚么年少儿夫？这一个眼灌的自邓邓，那一个脸抹的黑突突，空恁般绿鬓何如？。"]'),
('yuanqu-1291','温太真玉镜台・甜水令','关汉卿','元','元曲','yuanqu','','[]','我如今举起霜毫，舒开茧纸，题成诗句，待费我甚工夫！冷眼偷看这盆凉水，何须忧虑，只当做醒酒之物。',47,'元曲/yuanqu.json','["我如今举起霜毫，舒开茧纸，题成诗句，待费我甚工夫！冷眼偷看这盆凉水，何须忧虑，只当做醒酒之物。"]'),
('yuanqu-1292','温太真玉镜台・折桂令','关汉卿','元','元曲','yuanqu','','[]','想着我气卷江湖，学贯珠玑，又不是年近桑榆，怎把金马玉堂、锦心绣口，都觑的似有如无？则被你欺负得我千足万足，因此上我也还他佯醉佯愚。',324,'元曲/yuanqu.json','["想着我气卷江湖，学贯珠玑，又不是年近桑榆，怎把金马玉堂、锦心绣口，都觑的似有如无？则被你欺负得我千足万足，因此上我也还他佯醉佯愚。", "（旦云）丈夫，着意吟诗！倘罚水，墨乌面皮，教我怎了？（正末唱）他如今做了三谒茅庐，勉强承伏。", "软兀刺走向前来，恶支煞倒褪回去。", "（正末吟诗科，云）不分君恩重，能怜玉镜台。", "花从仙禁出，酒自御厨来。", "设席劳京尹，题诗属上才。", "遂令鱼共水，由此得和谐。", "（府尹云）温学士，不枉了高才大手，吟得好诗！赐金钟饮酒，夫人插凤头钗，搽官定粉。", "（旦喜科，云）学士，这多亏了你也！（正末云）夫人，我温峤何如？（府尹云）夫人，你肯依随学士么？（旦云）妾身愿随学士。", "（府尹云）既然夫人一心依随学士，老夫即当奏过官里，再准备一个庆喜的筵席。", "（正末唱）。"]'),
('yuanqu-1293','温太真玉镜台・鸳鸯煞','关汉卿','元','元曲','yuanqu','','[]','从今后姻缘注定姻缘簿，相思还彻相思苦。',80,'元曲/yuanqu.json','["从今后姻缘注定姻缘簿，相思还彻相思苦。", "剩道连理欢浓，于飞愿足。", "可怜你窈窕巫娥，不负了多情宋玉。", "则这琴曲诗篇吟和处，风流句，须不是我故意亏图，成就了那朝云和暮雨。"]'),
('yuanqu-1294','风雨像生货郎旦・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','你把解库存活，草堂工课，都耽阁。',27,'元曲/yuanqu.json','["你把解库存活，草堂工课，都耽阁。", "终日波波，白日休空过。"]'),
('yuanqu-1295','风雨像生货郎旦・混江龙','无名氏','元','元曲','yuanqu','','[]','到晚来早些来个，直至那玉壶传点二更过。',119,'元曲/yuanqu.json','["到晚来早些来个，直至那玉壶传点二更过。", "(李彦和云)大嫂，你可怜见，我实不相瞒，这妇人他一心待要嫁我哩。", "(正旦唱)你教我可怜见，你待敢是无奈之何。", "你比着东晋谢安才艺浅，比着江州司马泪痕多，也只为婚姻事成抛躲。", "劝不醒痴迷楚子，直要娶薄幸巫娥。"]'),
('yuanqu-1296','风雨像生货郎旦・天下乐','无名氏','元','元曲','yuanqu','','[]','你正是引的狼来屋里窝，娶到家，也不和，我怎肯和他轮车儿伴宿争竞多。',114,'元曲/yuanqu.json','["你正是引的狼来屋里窝，娶到家，也不和，我怎肯和他轮车儿伴宿争竞多。", "你不来我行呵我房儿中作念着，你来我行呵他空窗外咒骂我，(带云)咱两个合口唱叫，(唱)你中间里图甚么？(李彦和云)大嫂，他须不是这等人，我也不是这等人。", "(正旦唱)。"]'),
('yuanqu-1297','风雨像生货郎旦・那吒令','无名氏','元','元曲','yuanqu','','[]','休信那黑心肠的玉娥，他每便乔趋抢取撮，休犯着黄蘖肚小么。',63,'元曲/yuanqu.json','["休信那黑心肠的玉娥，他每便乔趋抢取撮，休犯着黄蘖肚小么。", "数量着哝过，紧忙里做作，似蝎子的老婆。", "你便有洛阳田，平阳果，钞广银多。"]'),
('yuanqu-1298','风雨像生货郎旦・鹊踏枝','无名氏','元','元曲','yuanqu','','[]','有时节典了庄科，准了绫罗；铜斗儿家私，恰做了落叶辞柯。',55,'元曲/yuanqu.json','["有时节典了庄科，准了绫罗；铜斗儿家私，恰做了落叶辞柯。", "那其间便是你郑孔目风流结果，只落得酷寒亭刚留下一个萧娥。"]'),
('yuanqu-1299','风雨像生货郎旦・寄生草','无名氏','元','元曲','yuanqu','','[]','你爱他眼弄秋波色，眉分青黛蛾。',68,'元曲/yuanqu.json','["你爱他眼弄秋波色，眉分青黛蛾。", "怎知道误功名是那额点芙蓉朵，陷家缘唇注樱桃颗，啜人魂舌吐丁香唾。", "只怕你飞花儿支散养家钱，旋风儿推转团圆磨。"]'),
('yuanqu-1300','风雨像生货郎旦・柳叶儿','无名氏','元','元曲','yuanqu','','[]','你道他为甚来眉峰暗锁？则要我庆新亲茶饭张罗。',95,'元曲/yuanqu.json','["你道他为甚来眉峰暗锁？则要我庆新亲茶饭张罗。", "(云)李彦和，他那伙亲眷，我都认的。", "(李彦和云)可是那几个？(正旦唱)都是些胡姑姑假姨姨厅堂上坐。", "待着我供玉馔，饮金波，可不道谁扶侍你姐姐哥哥？。"]'),
('yuanqu-1301','风雨像生货郎旦・赚煞','无名氏','元','元曲','yuanqu','','[]','气勃勃堵住我喉咙，骨噜噜潮上痰涎沫。',650,'元曲/yuanqu.json','["气勃勃堵住我喉咙，骨噜噜潮上痰涎沫。", "气的我死没腾软瘫做一垛，拘不定精神衣怎脱，四肢沉寸步难那。", "若非是小孤撮，叫我一声娘呵，兀的不怨恨冲天气杀我。", "你没事把我救活，可也合自知其过，你守着业尸骸学庄子鼓盆歌。", "(死科，下)(李彦和悲科，云)我那大嫂也！(外旦云)李彦和，你张着口号甚的？有便置，没便弃。", "(李彦和云)这是甚么说话！大嫂亡逝已过，便须高原选地，破木造棺，埋殡他入土。", "大嫂，只被你痛杀我也！(下)(外旦云)这也是我脚迹儿好处，一入门先妨杀了他大老婆，何等自在，何等快活。", "那李彦和虽然娶了我，不知我心下只不喜他。", "想那魏邦彦，这些时也来家了。", "我如今暗地里央着人去，与他说知，这早晚敢待来也。", "(净上，云)自家魏邦彦的便是。", "前月打差便去，叵耐张玉娥无礼，投到我来家，早嫁了别人。", "如今又使人来寻我，不知有甚么事？我见他去，此间就是。", "家里有人么？(外旦出见净科，云)你来家里来。", "(净云)敢不中么？(外旦云)不妨事。", "(净云)你嫁了人唤我怎的？(外旦云)我和你有说的话。", "(净云)有甚么说话？(外旦取砌末付净科，云)我虽是嫁了他，心中只是想着你。", "我如今收拾些金银财宝，悄地交付了你，可便先到洛河边，寻下一只小船。", "等着我在家点起一把火，烧了他房子，俺同他躲到洛河边，你便假做梢公，载俺上船。", "到的河中间，你将李彦和推在河里，把三姑和那小厮，也都勒死了，咱两个长远做夫妻，可不好那？(净云)你那是我老婆，就是我的娘哩。", "我先去在洛河边等你，明日早些儿来。", "(下)(外旦云)魏邦彦去了也。", "我如今不免点火去。", "在这房后边，放起火来。"]'),
('yuanqu-1302','风雨像生货郎旦・步步娇','无名氏','元','元曲','yuanqu','','[]','送的我背井离乡遭灾勾，这贱才敢道辞生受。',148,'元曲/yuanqu.json','["送的我背井离乡遭灾勾，这贱才敢道辞生受。", "断不得哄汉子的口，都是些即世求食鬼狐犹。", "(外旦云)我几曾在黑地行走，教我受这般的苦也。", "(副旦云)你道你不曾黑地里行呵，(唱)咱如今顾不得你脸儿羞，(云)你也曾悬着名姓，靠着房门，你也曾卖嘴料舌，推天抢地，你也曾挟着毡被，挑着灯球。", "(唱)可也曾半夜里当祗候。"]'),
('yuanqu-1303','风雨像生货郎旦・雁儿落','无名氏','元','元曲','yuanqu','','[]','只管里絮叨叨没了收，气扑扑寻敌斗。',32,'元曲/yuanqu.json','["只管里絮叨叨没了收，气扑扑寻敌斗。", "有多少家乔断案，只是骂贼禽兽。"]'),
('yuanqu-1304','风雨像生货郎旦・沽美酒','无名氏','元','元曲','yuanqu','','[]','逞末浪不即留，只管里卖风流，看他这天淡云开雨乍收。',44,'元曲/yuanqu.json','["逞末浪不即留，只管里卖风流，看他这天淡云开雨乍收。", "可便去寻一个宿头，觅一碗浆水饭润咱喉。"]'),
('yuanqu-1305','风雨像生货郎旦・太平令','无名氏','元','元曲','yuanqu','','[]','住了雨也晒甚娘褐袖，只愿的下雹子打你娘驴头。',98,'元曲/yuanqu.json','["住了雨也晒甚娘褐袖，只愿的下雹子打你娘驴头。", "(外旦骂科，云)这泼妇，我打不的你那！(打科)(副旦唱)只见他百忙里眉梢一皱，公然的指尖儿把颊腮剜透。", "似这般左瞅，右瞅，只不如罢手，俺也须是那爷娘皮肉。"]'),
('yuanqu-1306','风雨像生货郎旦・川拨棹','无名氏','元','元曲','yuanqu','','[]','慌走到岸边头，仓卒间怎措手。',54,'元曲/yuanqu.json','["慌走到岸边头，仓卒间怎措手。", "风雨飕飕，地上浇油。", "扭颈回眸，那里寻个梢公搭救？我将他衣领揪，他忙将我腰胯木刍。"]'),
('yuanqu-1307','风雨像生货郎旦・殿前欢','无名氏','元','元曲','yuanqu','','[]','这一片水悠悠，急忙里觅不出钓鱼舟。',370,'元曲/yuanqu.json','["这一片水悠悠，急忙里觅不出钓鱼舟。", "虚飘飘恩爱难成就，怕不的锦鸳鸯立化做轻鸥。", "他、他、他，趁西风卒未休，把你来推落在水中浮，(外旦云)他自吃醉了，这等脚高步低，立也立不住，干我甚么事，说我推他？要你来嚼舌！(副旦唱)抵多少酒淹湿春衫袖。", "(李彦和云)这里水浅，自过去了罢。", "(副旦唱)现淹的眼黄眼黑，你尚兀自东见东流。", "(净扮梢公上，云)官人，娘子，我这里是摆渡的船，你每快上来。", "(外旦和净打手势科)(副旦云)哥哥，你休上船去。", "这婆娘眼脑不好，敢是他约着的汉子哩！(做扯李科)(李彦和云)你放手，不妨事。", "我上的这船来，自有分晓。", "(净推李下河)(副旦扯住净)(净勒杀副旦科)(丑扮梢公上救，喊云)拿住这杀人贼！(副旦揪住丑云)有杀人贼！(净同外旦走斗)(丑云)苦也娘子，不干我事。", "勒杀你的是那个梢公，他走了也。", "我是来救你的，你休认差了也。", "(副旦唱)。"]'),
('yuanqu-1308','风雨像生货郎旦・鸳鸯尾煞','无名氏','元','元曲','yuanqu','','[]','乞与你不痛亲父母行施恩厚，我扶侍义养儿使长多生受。',288,'元曲/yuanqu.json','["乞与你不痛亲父母行施恩厚，我扶侍义养儿使长多生受。", "你途路上驱驰，我村疃里淹留。", "畅道你父亲此地身亡，你是必牢记着这日头。", "大厮八做个周年，分甚么前和后。", "那时节遥望着西楼，与你爷烧一陌儿纸，看一卷儿经，奠一杯儿酒。", "(同孛老下)(孤云)那老儿领着妇人去了。", "老夫也引着这孩儿抱上马，还我私宅中去来。", "(下)(丑哭科，云)好苦恼子也！只一个妇人，领着个小的，几乎被人勒杀。", "恰好撞见我，我救了他性命。", "他又把这个小的卖与那个官人，那个官人又将他那个小的领着去了。", "这等孤孤凄凄，怎教我不要伤感？(做跌倒起科，云)呸！可干我甚么事？(诗云)随他自卖男，随他自认女。", "我只去做梢公，不管风和雨。", "(下)。"]'),
('yuanqu-1309','风雨像生货郎旦・正宫/端正好','无名氏','元','元曲','yuanqu','','[]','口角头饿成疮，脚心里踏成趼，行一步似火燎油煎。',43,'元曲/yuanqu.json','["口角头饿成疮，脚心里踏成趼，行一步似火燎油煎。", "记的那洛河岸一似亡家犬，拿住俺将麻绳缠。"]'),
('yuanqu-1310','风雨像生货郎旦・滚绣球','无名氏','元','元曲','yuanqu','','[]','见一个旋风儿在这榆柳园，古道边，足律律往来打转，刮的些纸钱灰飞到跟前。',92,'元曲/yuanqu.json','["见一个旋风儿在这榆柳园，古道边，足律律往来打转，刮的些纸钱灰飞到跟前。", "是神祗，是圣贤，你也好随时呈变，居庙堂索受香烟。", "可知道今世里令史每都挝钞，和这古庙里泥神也爱钱，怎能勾达道升仙？。"]'),
('yuanqu-1311','风雨像生货郎旦・倘秀才','无名氏','元','元曲','yuanqu','','[]','沿路上身轻体健，这搭儿筋乏力软，到庙儿外不曾撒纸钱。',45,'元曲/yuanqu.json','["沿路上身轻体健，这搭儿筋乏力软，到庙儿外不曾撒纸钱。", "爷爷你厮余闰，厮哀怜，我这老妇人咒愿。"]'),
('yuanqu-1312','风雨像生货郎旦・上小楼','无名氏','元','元曲','yuanqu','','[]','唬的我身心恍然，负急处难生机变。',79,'元曲/yuanqu.json','["唬的我身心恍然，负急处难生机变。", "我只索念会咒语，数会家亲，诵会真言。", "这几年，便着把哥哥追荐，作念的个死魂灵眼前活现。", "(李彦和云)我不是鬼，我是人。", "(副旦唱)。"]'),
('yuanqu-1313','风雨像生货郎旦・幺篇','无名氏','元','元曲','yuanqu','','[]','对着你咒愿，休将我顾恋。',422,'元曲/yuanqu.json','["对着你咒愿，休将我顾恋。", "有一日拿住奸夫，摄到三姑，替你通传。", "非足我不意专，不意坚，搜寻不见，是早起店儿里吃羹汤不曾浇奠。", "(李彦和云)三姑，我不曾死，我是人。", "(副旦云)你是人呵，我叫你，你应的一声高似一声；是鬼呵，一声低似一声。", "(叫科)李彦和哥哥！(李彦和做应科)(三唤)(做低应科)(副旦云)有鬼也！(李彦和云)我斗你耍来。", "(做打悲、认科)(李彦和云)三姑，我的孩儿春郎，那里去了也。", "(副旦云)没的饭食养活他，是我卖了也。", "(李彦和做悲科，云)原来是你卖了，知他如今死的活的？可不痛杀我也！你如今做甚么活计？穿的衣服，这等新鲜，全然不像个没饭吃的，你可对我说。", "(副旦云)我唱货郎儿为生。", "(李彦和做怒科云)兀的不气杀我也！我是甚么人家？我是有名的财主。", "谁不知道李彦和名儿？你如今唱货郎儿，可不辱没杀我也！(做跌倒)(副旦扶起科，云)休烦恼，我便辱没杀你。", "哥哥，你如今做甚么买卖？(李彦和云)我与人家看牛哩，不比你这唱货郎的生涯这等下贱。", "(副旦唱)。"]'),
('yuanqu-1314','风雨像生货郎旦・十二月','无名氏','元','元曲','yuanqu','','[]','你道我生涯下贱，活计萧然。',50,'元曲/yuanqu.json','["你道我生涯下贱，活计萧然。", "这须是衣食所逼，名利相牵。", "你道我唱货郎儿辱没杀你祖先，怎比的你做财主官员。"]'),
('yuanqu-1315','风雨像生货郎旦・尧民歌','无名氏','元','元曲','yuanqu','','[]','与人家耕种洛阳田，早难道笙歌引入画堂前。',202,'元曲/yuanqu.json','["与人家耕种洛阳田，早难道笙歌引入画堂前。", "趁一村桑梓一村田，早难道玉楼人醉杏花天。", "牵，也波牵，牵牛执着鞭，杖敲落桃花片。", "(云)哥哥，你肯跟我回河南府去，凭着我说唱货郎。", "儿，我也养的你到老，何如？(李彦和云)罢、罢、罢，我情愿丢了这般好生意，跟的你去。", "(副旦云)你可辞了你那主人家去。", "(李彦和向古门云)主人家，我认着了一个亲眷，我如今回家去也。", "牛羊都交还与你，并不曾少了一只。", "(副旦云)跟的我去来波。", "(唱)。"]'),
('yuanqu-1316','风雨像生货郎旦・随尾','无名氏','元','元曲','yuanqu','','[]','袄庙火，宿世缘，牵牛织女长生愿。',38,'元曲/yuanqu.json','["袄庙火，宿世缘，牵牛织女长生愿。", "多管为残花几片，误刘晨迷入武陵源。", "(同下)。"]'),
('yuanqu-1317','风雨像生货郎旦・梁州第七','无名氏','元','元曲','yuanqu','','[]','正遇着美遨游融和的天气，更兼着没烦恼丰稔的年时。',167,'元曲/yuanqu.json','["正遇着美遨游融和的天气，更兼着没烦恼丰稔的年时。", "有谁人不想快平生志。", "都只待高张绣幕，都只待烂醉金卮。", "我本是穷乡寡妇，没甚的艳色矫姿。", "又不会卖风流弄粉调脂，又不会按宫商品竹弹丝。", "无过是赶几处沸腾腾热闹场儿，摇几下桑琅琅蛇皮鼓儿，唱几句韵悠悠信口腔儿。", "一诗，一词。", "都是些人间新近希奇事，扭捏来无诠次。", "倒也会动的人心谐的耳，都一般喜笑孜孜。"]'),
('yuanqu-1318','风雨像生货郎旦・转调货郎儿','无名氏','元','元曲','yuanqu','','[]','也不唱韩元帅偷营劫寨，也不唱汉司马陈言献策，也不唱巫娥云雨楚阳台。',77,'元曲/yuanqu.json','["也不唱韩元帅偷营劫寨，也不唱汉司马陈言献策，也不唱巫娥云雨楚阳台。", "也不唱梁山伯，也不唱祝英台。", "(小末云)你可唱甚么那？(副旦唱)只唱那娶小妇的长安李秀才。"]'),
('yuanqu-1319','风雨像生货郎旦・二转','无名氏','元','元曲','yuanqu','','[]','我只见密臻臻的朱楼高厦，碧耸耸青檐细瓦，四季里常开不断花。',186,'元曲/yuanqu.json','["我只见密臻臻的朱楼高厦，碧耸耸青檐细瓦，四季里常开不断花。", "铜驼陌纷纷斗奢华，那王孙士女乘车马，一望绣帘高挂，都则是公侯宰相家。", "(云)话说长安有一秀才，姓李名英，字彦和。", "嫡亲的三口儿家属，浑家刘氏，孩儿春郎，奶母张三姑。", "那李彦和共一娼妓，叫做张玉娥，作伴情熟，次后娶结成亲。", "(叹科，云)嗨！他怎知才子有心联翡翠，佳人无意结婚姻。", "(小末云)是唱的好，你慢慢的唱咱。", "(副旦唱)。"]'),
('yuanqu-1320','风雨像生货郎旦・三转','无名氏','元','元曲','yuanqu','','[]','那李秀才不离了花街柳陌，占场儿贪杯好色，看上那柳眉星眼杏花腮。',90,'元曲/yuanqu.json','["那李秀才不离了花街柳陌，占场儿贪杯好色，看上那柳眉星眼杏花腮。", "对面儿相挑泛，背地里暗差排。", "抛着他浑家不理睬，只教那媒人往来，闲家擘划，诸般绰开，花红布摆。", "早将一个泼贱的烟花娶过来。"]'),
('yuanqu-1321','风雨像生货郎旦・五转','无名氏','元','元曲','yuanqu','','[]','火逼的好人家人离物散，更那堪更深夜阑，是谁将火焰山移向到长安？烧地户，燎天关，单则把凌烟阁留他世上看。',143,'元曲/yuanqu.json','["火逼的好人家人离物散，更那堪更深夜阑，是谁将火焰山移向到长安？烧地户，燎天关，单则把凌烟阁留他世上看。", "恰便似九转飞芒，老君炼丹，恰便似介子推在绵山，恰便似子房烧了连云栈，恰便似赤壁下曹兵涂炭，恰便似布牛阵举火田单，恰便似火龙鏖战锦斑斓。", "将那房檐扯，脊梁扳。", "急救呵可又早连累了官房五六间。"]'),
('yuanqu-1322','风雨像生货郎旦・六转','无名氏','元','元曲','yuanqu','','[]','我只见黑黯黯天涯云布，更那堪湿淋淋倾盆骤雨，早是那窄窄狭狭沟沟堑堑路崎岖。',150,'元曲/yuanqu.json','["我只见黑黯黯天涯云布，更那堪湿淋淋倾盆骤雨，早是那窄窄狭狭沟沟堑堑路崎岖。", "知奔向何方所。", "犹喜的消消洒洒、断断续续、出出律律、忽忽噜噜阴云开处，我只见霍霍闪闪电光星炷。", "怎禁那萧萧瑟瑟风，点点滴滴雨，送的来高高下下、凹凹凸凸一搭模糊，早做了扑扑簌簌、湿湿渌渌疏林人物。", "倒与他妆就了一幅昏昏惨惨潇湘水墨图。"]'),
('yuanqu-1323','风雨像生货郎旦・七转','无名氏','元','元曲','yuanqu','','[]','河岸上和谁讲话，向前去亲身问他，只说道奸夫是船家。',88,'元曲/yuanqu.json','["河岸上和谁讲话，向前去亲身问他，只说道奸夫是船家。", "猛将咱家长喉咙掐，磕搭地揪住头发，我是个婆娘怎生救拔！也是他合亡化，扑冬的命掩黄泉下。", "将李春郎的父亲，只向那翻滚滚波心水淹杀。"]'),
('yuanqu-1324','风雨像生货郎旦・八转','无名氏','元','元曲','yuanqu','','[]','据一表仪容非俗，打扮的诸余里俏簇，绣云胸背雁衔芦。',136,'元曲/yuanqu.json','["据一表仪容非俗，打扮的诸余里俏簇，绣云胸背雁衔芦。", "他系一条兔鹘、兔鹘，海斜皮偏宜衬连珠，都是那无瑕的荆山玉。", "整身躯也么哥，缯髭须也么哥，打着鬓胡。", "走犬飞鹰，驾着鸦鹘，恰围场过去、过去。", "折跑盘旋骤着龙驹，端的个疾似流星度。", "那行朝也么哥，恰浑如也么哥，恰浑如和番的昭君出塞图。"]'),
('yuanqu-1325','风雨像生货郎旦・九转','无名氏','元','元曲','yuanqu','','[]','便写与生时年纪，不曾道差了半米。',322,'元曲/yuanqu.json','["便写与生时年纪，不曾道差了半米。", "未落笔花笺上泪珠垂，长吁气呵软了毛锥，忄西惶泪滴满了端溪。", "(小末云)他去了多少时也？(副旦唱)十三年不知个信息。", "(小末云)那时这小的几岁了？(副旦唱)相别时恰才七岁，(小末云)如今该多少年纪也？(副旦唱)他如今刚二十。", "(小末云)你可晓的他在那里？(副旦唱)恰便似大海内沉石。", "(小末云)你记的在那里与他分别来？(副旦唱)俺在那洛河岸上两分离，知他在江南也塞北？(小末云)你那小的有甚么记认处？(副旦唱)俺孩儿福相貌双耳过肩坠，(小末云)再有甚么记认？(副旦云)有、有、有，(唱)胸前一点朱砂记。", "(小末云)他祖居在何处？(副旦唱)他祖居在长安解库省衙西。", "(小末云)他小名唤做甚么？(副旦唱)那孩儿小名唤做春郎身姓李。"]'),
('yuanqu-1326','风雨像生货郎旦・煞尾','无名氏','元','元曲','yuanqu','','[]','我只道他州他府潜逃匿，今世今生没见期。',454,'元曲/yuanqu.json','["我只道他州他府潜逃匿，今世今生没见期。", "又谁知冤家偏撞着冤家对。", "(净云)原来这就是李春郎，这就是张三姑。", "当日勒他不死，就该有今日的晦气了。", "(做叩头科，云)大人，可怜见，饶了我老头儿罢。", "这都是我少年间不晓事，做这等勾当。", "如今老了，一口长斋，只是念佛。", "不要说杀人，便是苍蝇也不敢拍杀一个。", "况是你一家老小现在，我当真谋杀了那一个来？可怜见，放赦了老头儿罢。", "(外旦云)你这叫化头，讨饶怎的？我和你开着眼做，合着眼受，不如早早死了，生则同衾，死则共穴，在黄泉底下，做一对永远夫妻，有甚么不快活？(副旦唱)你也再没的怨谁，我也断没的饶伊。", "(小末斩净、外旦科，下)(副旦唱)要与那亡过的娘亲现报在我眼儿里。", "(李彦和云)今日个天赐俺父子重完，合当杀羊造酒，做个庆喜的筵席。", "孩儿，你听者。", "(词云)这都是我少年间误作差为，娶匪妓当局者迷。", "一碗饭二匙难并，气死我儿女夫妻。", "泼烟花盗财放火，与奸夫背地偷期。", "扮船家阴图害命，整十载财散人离。", "又谁知苍天有眼，偏争他来早来迟。", "到今日冤冤相报，解愁眉顿作欢眉。", "喜骨肉团圆聚会，理当做庆贺筵席。"]'),
('yuanqu-1327','刘晨阮肇误入桃源・仙吕/点绛唇','王子一','元','元曲','yuanqu','','[]','啸傲烟霞，寸心休把名牵挂。',24,'元曲/yuanqu.json','["啸傲烟霞，寸心休把名牵挂。", "暗里年华，青镜添白发。"]'),
('yuanqu-1328','刘晨阮肇误入桃源・油葫芦','王子一','元','元曲','yuanqu','','[]','一上天台石径滑，践翠霞则见这竹篱茅舍两三家，听得那夕阳杜宇啼声煞，这时节春风桃李花开罢。',83,'元曲/yuanqu.json','["一上天台石径滑，践翠霞则见这竹篱茅舍两三家，听得那夕阳杜宇啼声煞，这时节春风桃李花开罢。", "我虽不伴长沮事耦耕，学严陵理钓槎。", "常则是杖头三百青钱挂，抵多少坐三日县官衙！。"]'),
('yuanqu-1329','刘晨阮肇误入桃源・天下乐','王子一','元','元曲','yuanqu','','[]','也算个闲趁东风数落花，荣华，谁恋他？敢则是瓦盆边几场沉醉杀。',54,'元曲/yuanqu.json','["也算个闲趁东风数落花，荣华，谁恋他？敢则是瓦盆边几场沉醉杀。", "快清风，袍袖宽，倦红尘路径狭，便休题相逢不下马。"]'),
('yuanqu-1330','刘晨阮肇误入桃源・鹊踏枝','王子一','元','元曲','yuanqu','','[]','远奢华，近清佳，火炼丹砂，水煮黄芽。',122,'元曲/yuanqu.json','["远奢华，近清佳，火炼丹砂，水煮黄芽。", "牢拴住心猿意马，急疏开利锁名枷。", "(阮肇云)这几年天下荒荒，干戈并起，不能勾风尘宁静。", "若有英雄生于此时，觑事业如拾芥耳。", "(正末云)贤者避世，其次避地，其次避色，其次避言。", "兄弟，还只是我们的见识高得多哩。", "(唱)。"]'),
('yuanqu-1331','刘晨阮肇误入桃源・寄生草','王子一','元','元曲','yuanqu','','[]','我情愿弃轩冕离人世，傍泉石度岁华。',66,'元曲/yuanqu.json','["我情愿弃轩冕离人世，傍泉石度岁华。", "一任他英雄并起图王霸，烟尘并起兴戈甲，异端并起伤风化。", "我和你韬光晦迹老山中，煞强如齐家治国平天下。"]'),
('yuanqu-1332','刘晨阮肇误入桃源・幺篇','王子一','元','元曲','yuanqu','','[]','去去山无尽，行行路转差。',67,'元曲/yuanqu.json','["去去山无尽，行行路转差。", "则为那白云渐渐迷高下，不由咱寸心悄悄耽惊怕，见-个村翁远远来迎迓。", "我这里为迷山路问樵夫，抵多少因过竹院逢僧话。"]'),
('yuanqu-1333','刘晨阮肇误入桃源・醉中天','王子一','元','元曲','yuanqu','','[]','信脚山之下，洗耳水之涯。',150,'元曲/yuanqu.json','["信脚山之下，洗耳水之涯。", "正失路迷踪没乱煞，(带云)得遇老人呵，(唱)抵多少卖得龟儿卦。", "(太白云)二位可通个姓名，现居何处？(正末唱)我两个本东庄措大。", "(太白云)我看你二位生得齐整，像个出仕的人。", "(正末唱)休认做名题科甲，(太白云)二位可还有甚陪伴的么？(正末云)若问我陪伴的呵，(唱)无非是糜鹿鱼虾。"]'),
('yuanqu-1334','刘晨阮肇误入桃源・后庭花','王子一','元','元曲','yuanqu','','[]','并不想有轩车有驷马，我则愿无根椽无片瓦。',100,'元曲/yuanqu.json','["并不想有轩车有驷马，我则愿无根椽无片瓦。", "出来的一品职千钟禄，那里有六韬书三略法，他都是井中蛙妄称尊大。", "比周公不握发，比陈蕃不下榻。", "空结实花木瓜，费琢磨水晶塔。", "斗筲器不足夸，粪土墙容易塌，儿童见惊讶杀。"]'),
('yuanqu-1335','刘晨阮肇误入桃源・青歌儿','王子一','元','元曲','yuanqu','','[]','空一带江山、江山如画，止不过饭囊、饭囊衣架，塞满长安乱似麻。',120,'元曲/yuanqu.json','["空一带江山、江山如画，止不过饭囊、饭囊衣架，塞满长安乱似麻。", "每日价大纛高牙，冠盖头踏。", "人物不撑达，服色尽奢华，心行更奸猾。", "举止少谦洽。", "纷纷扰扰由他，多多少少欺咱，言言语语参杂。", "是是非非交加。", "因此上不事王侯，不求闻达。", "隐姓埋名做庄家，学耕稼。"]'),
('yuanqu-1336','刘晨阮肇误入桃源・赚煞','王子一','元','元曲','yuanqu','','[]','投至的山上采芝回，早难道江上踏青罢，眼见得路迢遥芒鞋邋遢。',99,'元曲/yuanqu.json','["投至的山上采芝回，早难道江上踏青罢，眼见得路迢遥芒鞋邋遢。", "抵多少古道西风鞭瘦马，叹明朝回首天涯。", "谩嗟呀，那里也出入通达，不觉的枯木寒烟噪晚鸦。", "望青山那搭，红轮直下，兀的是白云深处有人家。", "(同阮下)。"]'),
('yuanqu-1337','刘晨阮肇误入桃源・正宫/端正好','王子一','元','元曲','yuanqu','','[]','风力紧羽衣轻，露华湿乌巾重。',42,'元曲/yuanqu.json','["风力紧羽衣轻，露华湿乌巾重。", "我本为厌红尘跳出樊笼，只待要拨开云雾丘陇，身世外无擒纵。"]'),
('yuanqu-1338','刘晨阮肇误入桃源・倘秀才','王子一','元','元曲','yuanqu','','[]','我待学炼九转丹砂葛洪，上万丈昆仑赤松，因此上思入风云变态中。',130,'元曲/yuanqu.json','["我待学炼九转丹砂葛洪，上万丈昆仑赤松，因此上思入风云变态中。", "(云)兄弟，你看一溪流水，几片落花，这山中必有人家也。", "(唱)则见一溪流水绿，几片落花红，兀的把春光断送。", "(云)兄弟，这般景物，畅是宜人，我且题咏几句咱。", "(阮云)兄长正好题咏几句，小弟拱听。", "(正末唱)。"]'),
('yuanqu-1339','刘晨阮肇误入桃源・滚绣球','王子一','元','元曲','yuanqu','','[]','水呵莫不黄河天上来？花呵莫不碧桃天上种？水呵索强如翠岩前三千丈玉泉飞进，花呵干闪下闹西园一队队课蜜游蜂。',128,'元曲/yuanqu.json','["水呵莫不黄河天上来？花呵莫不碧桃天上种？水呵索强如翠岩前三千丈玉泉飞进，花呵干闪下闹西园一队队课蜜游蜂。", "水呵则是弥漫三月雨，花呵可惜狼藉一夜风。", "水呵近沧波濯尘缨一溪光莹，花呵性轻薄乱飘零枉费春工。", "水呵抵多少长江后浪催前浪，花呵早则一片西飞一片东，岁月匆匆。"]'),
('yuanqu-1340','刘晨阮肇误入桃源・倘秀才','王子一','元','元曲','yuanqu','','[]','我这里长啸时草木振动，怅望处风涛怒涌，不觉的悄然而悲悚然恐。',128,'元曲/yuanqu.json','["我这里长啸时草木振动，怅望处风涛怒涌，不觉的悄然而悲悚然恐。", "(阮肇云)咱两个则傍这一道流水寻去，料的前面必有个渔家可以投宿。", "(正末唱)盼不的渔家春水渡，(阮肇云)这山中敢有个寺儿么？(正末唱)闻不见僧寺夕阳钟，(带去)兄弟呵，(唱)咱两个莫不被樵大调哄？。"]'),
('yuanqu-1341','刘晨阮肇误入桃源・呆骨朵','王子一','元','元曲','yuanqu','','[]','你便铁石人也惹起凡心动，莫不是驾青鸾天上飞琼？似这般花月神仙，晃动了文章巨公。',138,'元曲/yuanqu.json','["你便铁石人也惹起凡心动，莫不是驾青鸾天上飞琼？似这般花月神仙，晃动了文章巨公。", "(做相见科，旦云)刘郎、阮郎，请同到舍下。", "(正末云)他女娘家怎知我们的名姓，便以刘郎、阮郎呼之？兄弟，我和你莫非是梦中么？(唱)没揣的撞到风流阵，引入花胡同。", "摆列着金钗十二行，敢则梦上他巫山十二峰。"]'),
('yuanqu-1342','刘晨阮肇误入桃源・脱布衫','王子一','元','元曲','yuanqu','','[]','光闪闪贝阙珠宫，齐臻臻碧瓦朱甍。',32,'元曲/yuanqu.json','["光闪闪贝阙珠宫，齐臻臻碧瓦朱甍。", "宽绰绰罗帏绣栊，郁巍巍画梁雕栋。"]'),
('yuanqu-1343','刘晨阮肇误入桃源・醉太平','王子一','元','元曲','yuanqu','','[]','注金波碧筒，烧银烛纱笼，笙歌引至画堂中，红遮翠拥。',111,'元曲/yuanqu.json','["注金波碧筒，烧银烛纱笼，笙歌引至画堂中，红遮翠拥。", "人心此会应相重，人情今夜初相共，人生何处不相逢？早忘却更长漏水。", "(二旦做意把盏科，云)草草杯盘，不足以待贤者，惶恐！惶恐！(正末谢云)生等不才，多承错爱，何以克当？(唱)。"]'),
('yuanqu-1344','刘晨阮肇误入桃源・倘秀才','王子一','元','元曲','yuanqu','','[]','则见他喜孜孜幽欢密宠，便一似悄促促私期暗通，怎消得翠袖殷勤捧玉钟？屏开金孔雀，褥隐绣芙蓉，兀的般受用。',51,'元曲/yuanqu.json','["则见他喜孜孜幽欢密宠，便一似悄促促私期暗通，怎消得翠袖殷勤捧玉钟？屏开金孔雀，褥隐绣芙蓉，兀的般受用。"]'),
('yuanqu-1345','刘晨阮肇误入桃源・叨叨令','王子一','元','元曲','yuanqu','','[]','记不的轩辕一枕华胥梦，学不的淳于一枕南柯梦，盼不的文王一枕非熊梦，成不的庄周一枕蝴蝶梦。',73,'元曲/yuanqu.json','["记不的轩辕一枕华胥梦，学不的淳于一枕南柯梦，盼不的文王一枕非熊梦，成不的庄周一枕蝴蝶梦。", "倒大来福分也么哥，倒大来福分也么哥，恰做了襄王一枕高唐梦。"]'),
('yuanqu-1346','刘晨阮肇误入桃源・二煞','王子一','元','元曲','yuanqu','','[]','一杯未尽笙歌送，两意初谐语话同。',80,'元曲/yuanqu.json','["一杯未尽笙歌送，两意初谐语话同。", "效文君私奔相如，比巫娥愿从宋玉，似莺莺暗约张生，学孟光自许梁鸿。", "他年不骑鹤，何日可登鳌？今夜恰乘龙。", "说甚的只鸾单凤，天与配雌雄。"]'),
('yuanqu-1347','刘晨阮肇误入桃源・随煞尾','王子一','元','元曲','yuanqu','','[]','色笼葱光潋滟，山环水绕天台洞。',154,'元曲/yuanqu.json','["色笼葱光潋滟，山环水绕天台洞。", "势周旋，形曲折，虎踞龙盘仙子宫。", "本意闲寻采药翁，谁想桃源一径通。", "谩叹人生似转蓬，犹恐相逢是梦中。", "月满兰房夜未扃，人在珠帘第几重。", "结煞同心心已同，绾就合欢欢正浓。", "焚尽金炉宝篆空，烧罢银台烛影红。", "身在天台花树丛，梦入阳台云雨踪。", "准备着凤枕鸳衾玉人共，成就了年少风流志诚种。", "(同下)。"]'),
('yuanqu-1348','刘晨阮肇误入桃源・仙吕/赏花时','王子一','元','元曲','yuanqu','','[]','我做甚三叠阳关愁不听，也只为一段伤心画怎成。',47,'元曲/yuanqu.json','["我做甚三叠阳关愁不听，也只为一段伤心画怎成。", "则不是人感慨别离轻，听兀那流莺树顶。", "先啼出断肠声。"]'),
('yuanqu-1349','刘晨阮肇误入桃源・幺篇','王子一','元','元曲','yuanqu','','[]','抵多少绿暗红稀出凤城，拚得个倒尽沙头双玉瓶。',56,'元曲/yuanqu.json','["抵多少绿暗红稀出凤城，拚得个倒尽沙头双玉瓶。", "直到这十里短长亭，避不的登山蓦岭，便子索回首问前程。", "(正末同阮下)。"]'),
('yuanqu-1350','刘晨阮肇误入桃源・中吕/粉蝶儿','王子一','元','元曲','yuanqu','','[]','兔走乌飞，搬不尽古今兴废，急回来物换星移。',59,'元曲/yuanqu.json','["兔走乌飞，搬不尽古今兴废，急回来物换星移。", "成就了凤鸾交，莺燕侣，五百年夙缘仙契。", "不多时执手临岐，倒揽下干相思一场憔悴。"]'),
('yuanqu-1351','刘晨阮肇误入桃源・醉春风','王子一','元','元曲','yuanqu','','[]','则被这红灼灼洞中花，碧澄澄溪上水，赚将刘阮入桃源，畅好是美，美。',56,'元曲/yuanqu.json','["则被这红灼灼洞中花，碧澄澄溪上水，赚将刘阮入桃源，畅好是美，美。", "受用他一段繁华，端详了一班人物，别是个一重天地。"]'),
('yuanqu-1352','刘晨阮肇误入桃源・迎仙客','王子一','元','元曲','yuanqu','','[]','下坡如投地阱，蓦岭似上天梯，这的是蝴蝶梦中家万里。',56,'元曲/yuanqu.json','["下坡如投地阱，蓦岭似上天梯，这的是蝴蝶梦中家万里。", "不甫能雨才收，没揣的风又起。", "似这般风雨凄凄，早难道迟日江山丽。"]'),
('yuanqu-1353','刘晨阮肇误入桃源・红绣鞋','王子一','元','元曲','yuanqu','','[]','见了这三五搭人家稀密，过了这百千重山路逶迤，那里也新郎归去马如飞。',63,'元曲/yuanqu.json','["见了这三五搭人家稀密，过了这百千重山路逶迤，那里也新郎归去马如飞。", "愁的是林深禽语碎，怕的是路远客行迟，呀！却原来鹧鸪啼烟树里。"]'),
('yuanqu-1354','刘晨阮肇误入桃源・醉高歌','王子一','元','元曲','yuanqu','','[]','望见那萧萧古寺投西，行过这泛泛危桥转北。',137,'元曲/yuanqu.json','["望见那萧萧古寺投西，行过这泛泛危桥转北。", "早来到三家疃上熟游地，这搭儿分明记得。", "(正末做意惊见科，云)好怪，这两株松树我去时亲手栽下，与兄弟上天台山采药，到今只有一年光景，这两株树怎么就长得偌来大，不由我心中好生疑惑。", "(阮肇云)我也记得，这等大的快，敢则是地肥哩。", "(正末唱)。"]'),
('yuanqu-1355','刘晨阮肇误入桃源・普天乐','王子一','元','元曲','yuanqu','','[]','曾得个几星霜，多年岁，为甚么松杉作洞，花木成蹊？往时节将嫩苗跑土栽，今日呵见老树冲天立。',90,'元曲/yuanqu.json','["曾得个几星霜，多年岁，为甚么松杉作洞，花木成蹊？往时节将嫩苗跑土栽，今日呵见老树冲天立。", "见了这景物翻腾非前日，不由人几般儿心下猜疑。", "修补了颓垣败壁，整顿了明窗净几，改换了茅舍疏篱。"]'),
('yuanqu-1356','刘晨阮肇误入桃源・石榴花','王子一','元','元曲','yuanqu','','[]','则见这野风吹起纸钱灰，咚咚的挝鼓响如雷。',107,'元曲/yuanqu.json','["则见这野风吹起纸钱灰，咚咚的挝鼓响如雷。", "原来是当村父老众相知，赛叶王社日，摆列着尊愚。", "(做叫云)刘弘，开门来，开门来。", "(唱)到的这柴门前便唤咱儿名讳，他那里默无声弄盏传杯。", "一个个紧低头不睬佯妆醉，方信道人面逐高低。"]'),
('yuanqu-1357','刘晨阮肇误入桃源・上小楼','王子一','元','元曲','yuanqu','','[]','则见他一时半刻，使尽了千方百计。',105,'元曲/yuanqu.json','["则见他一时半刻，使尽了千方百计。", "吃紧的理不服人，言不谙典，话不投机。", "看不的乔所为，歹见识，刁天决地，早叹道气昂昂后生叮畏。", "(净云)这等撞席的人，倒敢胡言乱语的。", "牛表、沙三，急忙打出去者。", "(众做打科)(正末唱)。"]'),
('yuanqu-1358','刘晨阮肇误入桃源・幺篇','王子一','元','元曲','yuanqu','','[]','真乃是重色不重贤，度人不度己。',133,'元曲/yuanqu.json','["真乃是重色不重贤，度人不度己。", "使的这牛表、沙三、伴哥、王留，唱叫扬疾。", "走将来手便棰，脚便踢，将咱忤逆，这的是孩儿每孝当竭力。", "(云)我是刘晨，同兄弟阮肇去春上天台山采药，今年归家。", "你是何人，倒来打我？(净云)你这两个面生可疑之人，我那里认的？你快去！快去！(正末唱)。"]'),
('yuanqu-1359','刘晨阮肇误入桃源・满庭芳','王子一','元','元曲','yuanqu','','[]','你道我面生可疑，便待要扬威耀武，也合问姓甚名谁。',142,'元曲/yuanqu.json','["你道我面生可疑，便待要扬威耀武，也合问姓甚名谁。", "那些个吐虹霓三千丈英雄气，全不管长幼尊卑。", "(净云)我父亲刘弘在日，尝说老爷刘晨，上天台山采药不归，到今百余年，知他是狼餐豹食？你还提他则甚？(正末唱)你道我上天台狼餐豹食，谁想我入桃源雨约云期。", "休得要夸强会，瞒神吓鬼，大古里人善得人欺。"]'),
('yuanqu-1360','刘晨阮肇误入桃源・十二月','王子一','元','元曲','yuanqu','','[]','叹急急年光似水，看纷纷世事如棋。',48,'元曲/yuanqu.json','["叹急急年光似水，看纷纷世事如棋。", "回首时今来古往，伤心处物是人非。", "若不游嫦娥月窟，必定到王母瑶池。"]'),
('yuanqu-1361','刘晨阮肇误入桃源・尧民歌','王子一','元','元曲','yuanqu','','[]','呀！生折散碧桃花卜凤鸾栖，端的个人生最苦是别离。',64,'元曲/yuanqu.json','["呀！生折散碧桃花卜凤鸾栖，端的个人生最苦是别离。", "倒做了伯劳飞燕各东西，早叹道有情何怕隔年期。", "伤也波悲，登高怨落晖，添几点青衫汨。"]'),
('yuanqu-1362','刘晨阮肇误入桃源・耍孩儿','王子一','元','元曲','yuanqu','','[]','方信道洞天深处非人世，包藏着云纵雨迹。',95,'元曲/yuanqu.json','["方信道洞天深处非人世，包藏着云纵雨迹。", "(带云)我想临行之时，(唱)怎将断肠诗句赠别离，分明是漏泄与肉眼愚眉。", "他道花当洞口应长在，水到人间定不回。", "参透了其中意，本是个神仙境界，错认做裙带衣食。"]'),
('yuanqu-1363','刘晨阮肇误入桃源・五煞','王子一','元','元曲','yuanqu','','[]','我受用淡氤氲香喷鹊尾炉，光潋滟酒倾蕉叶杯。',77,'元曲/yuanqu.json','["我受用淡氤氲香喷鹊尾炉，光潋滟酒倾蕉叶杯。", "脚趔趄佳人锦瑟傍边立，醉疏狂闲吟夜月诗千首，眼迷希细看春风玉一围。", "到今日归何地？想杀我龙肝凤髓，害杀我螓首蛾眉。"]'),
('yuanqu-1364','刘晨阮肇误入桃源・三煞','王子一','元','元曲','yuanqu','','[]','他那里一壶天地宽，两轮日月迟，不比这彩云易散琉璃脆。',67,'元曲/yuanqu.json','["他那里一壶天地宽，两轮日月迟，不比这彩云易散琉璃脆。", "但不知别来仙子今何在，从今后逢着仙翁莫看棋。", "回首更人世，我只怕泰山石烂，沧海尘飞。"]'),
('yuanqu-1365','刘晨阮肇误入桃源・二煞','王子一','元','元曲','yuanqu','','[]','现如今桃源好结缡，问甚么瓜田不纳履，我和他武陵溪畔曾相识。',91,'元曲/yuanqu.json','["现如今桃源好结缡，问甚么瓜田不纳履，我和他武陵溪畔曾相识。", "寂寞了十二阑瑶台仙子吹箫伴，迢递了五百里芳草王孙去路迷。", "阑珊了三千年王母蟠桃会，生疏了日边蓖翠鸾丹凤，冷落丁云外鸣玉犬金鸡。"]'),
('yuanqu-1366','刘晨阮肇误入桃源・尾煞','王子一','元','元曲','yuanqu','','[]','折末你奔关山千百重，进程途一万里。',61,'元曲/yuanqu.json','["折末你奔关山千百重，进程途一万里。", "我则怕春光去了难寻觅，(云)兄弟，咱和你去来。", "(唱)趁着这几瓣桃花半溪水。", "(同阮肇下)。"]'),
('yuanqu-1367','刘晨阮肇误入桃源・双调/新水令','王子一','元','元曲','yuanqu','','[]','满襟情沿湿青袍，伴离人一竿残照。',52,'元曲/yuanqu.json','["满襟情沿湿青袍，伴离人一竿残照。", "行不上岩峦临涧绝，盼不到宫阙倚天高。", "一弄儿行色萧条，恰便似游仙梦撒然觉。"]'),
('yuanqu-1368','刘晨阮肇误入桃源・驻马厅','王子一','元','元曲','yuanqu','','[]','四顾寂寥，绿树依依云渺渺；一声长啸，青山隐隐水迢迢。',57,'元曲/yuanqu.json','["四顾寂寥，绿树依依云渺渺；一声长啸，青山隐隐水迢迢。", "看花长在洛阳桥，休官不止长安道。", "归路杳，也是我寻真误入蓬莱岛。"]'),
('yuanqu-1369','刘晨阮肇误入桃源・沈醉东风','王子一','元','元曲','yuanqu','','[]','成就了东床婿伏低做小，宴会了西王母接贵攀高。',70,'元曲/yuanqu.json','["成就了东床婿伏低做小，宴会了西王母接贵攀高。", "引动这撩云拨雨心，想起那闭月羞花貌。", "撇的似绕朱门燕子寻巢，没来由北往南来走一遭，眼见的离多会少。"]'),
('yuanqu-1370','刘晨阮肇误入桃源・殿前欢','王子一','元','元曲','yuanqu','','[]','不觉的五魂消，则见这无媒径路草萧萧，急煎煎似上蚰蜒道。',72,'元曲/yuanqu.json','["不觉的五魂消，则见这无媒径路草萧萧，急煎煎似上蚰蜒道。", "一会价心痒难揉，这时节武陵溪怎暗约？桃花片空零落，胡麻饭绝音耗。", "做了个云迷楚岫，水淹蓝桥。"]'),
('yuanqu-1371','刘晨阮肇误入桃源・雁儿落','王子一','元','元曲','yuanqu','','[]','也是我一事差百事错，空惹的千人骂万人笑。',38,'元曲/yuanqu.json','["也是我一事差百事错，空惹的千人骂万人笑。", "本则合暮登天子堂，没来由夜宿袄神庙。"]'),
('yuanqu-1372','刘晨阮肇误入桃源・得胜令','王子一','元','元曲','yuanqu','','[]','这的是人怨语声高，我今日得命也无毛。',184,'元曲/yuanqu.json','["这的是人怨语声高，我今日得命也无毛。", "吉丁当掂碎连环玉，生可擦分开比翼鸟。", "梦断魂劳，身未到心先到；分浅缘薄，有上梢没下梢。", "(二末做投崖科)(太白现像，急喝云)刘晨、阮肇，休胡寻思。", "吾乃上界太白金星。", "为你二人与桃源仙子有夙世姻缘之分，你前日采药迷路，吾曾化为樵夫，指引入洞。", "今复来此，迷其旧路，听吾指引。", "(正末同阮拜科，云)愚民肉眼，不识大仙，只望垂悯，指示前路。", "(唱)。"]'),
('yuanqu-1373','刘晨阮肇误入桃源・沽美酒','王子一','元','元曲','yuanqu','','[]','怎肯学鲲鹏飞杂燕雀，芝兰长混蓬蒿，可正是忙处人多闲处少。',43,'元曲/yuanqu.json','["怎肯学鲲鹏飞杂燕雀，芝兰长混蓬蒿，可正是忙处人多闲处少。", "早着我迷踪失道，无处访旧时樵。"]'),
('yuanqu-1374','刘晨阮肇误入桃源・太平令','王子一','元','元曲','yuanqu','','[]','但得你天公指教，抵多少晏平仲善与人交。',66,'元曲/yuanqu.json','["但得你天公指教，抵多少晏平仲善与人交。", "你若肯扶倾济弱，我可便回嗔作笑。", "一会价记着想着念着，(带云)休道是人呵，(唱)马也有垂缰之报。"]'),
('yuanqu-1375','刘晨阮肇误入桃源・落梅风','王子一','元','元曲','yuanqu','','[]','过了这苍苔径独木桥，路崎岖寂无人到。',34,'元曲/yuanqu.json','["过了这苍苔径独木桥，路崎岖寂无人到。", "刘郎这回归去了，乱山头杜鹃休叫。"]'),
('yuanqu-1376','刘晨阮肇误入桃源・折桂令','王子一','元','元曲','yuanqu','','[]','依然见桃源洞玉软香娇，一队队美貌相迎，一个个笑脸擎着。',93,'元曲/yuanqu.json','["依然见桃源洞玉软香娇，一队队美貌相迎，一个个笑脸擎着。", "今日也鱼水和谐，燕莺成对，琴瑟相调。", "玉炉中焚宝篆沈烟细袅，绛台上照红妆银蜡高烧。", "人立妖娆，乐奏箫韶。", "依旧有翠绕珠围，再成就凤友鸾交。"]'),
('yuanqu-1377','中吕・快活三过朝天子四边静春','马谦斋','元','元曲','yuanqu','','[]','海棠娇，恰睡足，牡丹香，正开初。',380,'元曲/yuanqu.json','["海棠娇，恰睡足，牡丹香，正开初。", "只悉春色在须臾，休教燕子衔春去。", "辇毂，景物，芳草碧重城路。", "五花娇马七香车，帘挂锦珂鸣玉。", "箫鼓声中，园林佳处，翠鬟歌红袖舞。", "近黄公酒垆，诵坡仙乐府，直吃到月转垂杨树。", "明时难遇，百岁光阴过隙驹。", "休教辜负，春来春去。", "榆钱乱舞，难买春光住。", "夏恰帘前社燕忙，正枝头楚梅黄。", "当空畏日炽炎光，杨柳阴迷深巷。", "北堂，草堂，人在羲皇上。", "亭台潇洒近池塘，睡足思新酿。", "竹影横斜，荷香飘荡，一襟满意凉。", "醉乡，艳妆，〔水调〕谁家唱？红尘千丈，岂羡功名纸半张？渔樵闲访，先生豪放，诗狂酒狂，志不在凌烟上。", "秋芰荷衰，翠影稀。", "豆花凉，雨声催。", "谁家砧杵捣寒衣？万物皆秋意。", "燕归，雁飞，霜染芙蓉醉。", "长江万里鲈正肥，谩忆家乡味。", "啸月吟情，凌云豪气，岂当怀宋玉悲！赏风光帝里，贺恩波凤池，喜生在唐虞世。", "香山叠翠，红叶西风衬马蹄。", "重阳佳致，千金曾费。", "黄橙绿醅，烂醉登高会。"]'),
('yuanqu-1378','越调・柳营曲太平即事','马谦斋','元','元曲','yuanqu','','[]','亲凤塔，住龙沙，天下太平无事也。',297,'元曲/yuanqu.json','["亲凤塔，住龙沙，天下太平无事也。", "辞却公衙，别了京华，甘分老农家。", "傲河阳潘岳栽花，郊东门邵平种瓜。", "庄前栽果木，山下种桑麻。", "度岁华，活计老生涯。", "怀古曾窨约，细评薄，将业兵功非小可。", "生死存活，成败消磨，战策属谁多？破西川平定干戈，下南交威镇山河。", "守玉关班定远，标铜柱马伏波。", "那两个，今日待如何？楚汉遗事楚霸王，汉高皇，龙争虎斗几战场。", "争弱争强，天丧天亡，成败岂寻常。", "一个福相催先到咸阳，一个命将衰自刎乌江。", "江山空寂寞，宫殿久荒凉。", "君试详，都一枕梦黄粱。", "叹世手自搓，剑频磨，古来丈夫天下多。", "青镜摩挲，白首蹉跎，失志困衡窝。", "有声名谁识廉颇？广才学不用萧何。", "忙忙的逃海滨，急急的隐山阿。", "今日个，平地起风波。"]'),
('yuanqu-1379','双调・沉醉东风嘲妓好睡','马谦斋','元','元曲','yuanqu','','[]','摇不醒鸾交凤友，搬不回燕侣莺俦。',154,'元曲/yuanqu.json','["摇不醒鸾交凤友，搬不回燕侣莺俦。", "莫不是宰予妻，陈抟友？百忙里蝶梦庄周。", "衲被蒙头万事休，真乃是眠花卧柳。", "自悟恣瓯内潋滟英掩，瓦盆中渐浅重添。", "线鸡肥，新ド酽。", "不须典琴留剑，二顷桑麻足养廉，归去来，长安路险！取富贵青蝇竞血，进功名白蚁争穴。", "虎狼丛甚日休，是非海何时彻？人我场慢争优劣，免使傍人做话说，咫尺韶华去也。"]'),
('yuanqu-1380','晋文公火烧介子推・仙吕)【点绛唇','狄君厚','元','元曲','yuanqu','','[]','我想今日人才，各居朝代，为臣宰。',36,'元曲/yuanqu.json','["我想今日人才，各居朝代，为臣宰。", "怕不都立在舜殿尧阶，一个个将古圣风俗坏。"]'),
('yuanqu-1381','晋文公火烧介子推・油葫芦','狄君厚','元','元曲','yuanqu','','[]','二太子要寻上天梯将云月摘，上青霄可无大才。',129,'元曲/yuanqu.json','["二太子要寻上天梯将云月摘，上青霄可无大才。", "娘娘啊，便怎能够挽蟾宫攀折得桂枝来？(带云)晋朝宫室盖不得。", "(驾云了)(正末云)陛下，不可。", "(唱)枉了乘船用车把砖石载，枉厂梁山选木将园林采。", "石包成千尺台，砖砌就五丈阶。", "为甚咱晋朝中宫殿难修盖？子那深山里摧残栋梁材。"]'),
('yuanqu-1382','晋文公火烧介子推・天下乐','狄君厚','元','元曲','yuanqu','','[]','今日待动土兴工七十利开，但用的民夫，将百姓差，题起来痛伤情老臣心内骇。',64,'元曲/yuanqu.json','["今日待动土兴工七十利开，但用的民夫，将百姓差，题起来痛伤情老臣心内骇。", "不争宫殿上太极宫，不争台修成云月台，臣则怕引得祸从天上来。"]'),
('yuanqu-1383','晋文公火烧介子推・那吒令','狄君厚','元','元曲','yuanqu','','[]','百姓海怒嫉能妒色，损臣僚重宰；力假三市诸侯恨荒淫好色，布八方四海；史官每骂轻贤重色，传千年万载。',70,'元曲/yuanqu.json','["百姓海怒嫉能妒色，损臣僚重宰；力假三市诸侯恨荒淫好色，布八方四海；史官每骂轻贤重色，传千年万载。", "那其间正值着讥岁时，凶年代，普天下并役个差。"]'),
('yuanqu-1384','晋文公火烧介子推・鹊踏枝','狄君厚','元','元曲','yuanqu','','[]','比及垒起基阶，立起梁材，百姓每冻饿死的尸骸，成山握盖。',48,'元曲/yuanqu.json','["比及垒起基阶，立起梁材，百姓每冻饿死的尸骸，成山握盖。", "那座摘早楼兴工了数载，不曾动分毫府库资财。"]'),
('yuanqu-1385','晋文公火烧介子推・寄生草','狄君厚','元','元曲','yuanqu','','[]','百姓每如何敢卖，官司也不敢买。',89,'元曲/yuanqu.json','["百姓每如何敢卖，官司也不敢买。", "(驾云了)(正末唱)拣人家高梁大厦浑成坏，问甚末圣坛佛堂从头儿拆，将他那皇宫内苑从新盖。", "告大王，恁时节龙楼凤阁已成功，待怎么到如今雕栏玉砌今何在？。"]'),
('yuanqu-1386','晋文公火烧介子推・六幺序','狄君厚','元','元曲','yuanqu','','[]','每日将生灵害，每日把筵宴开。',116,'元曲/yuanqu.json','["每日将生灵害，每日把筵宴开。", "微子、箕子、比干这三人谏在金阶。", "谏不从也，微子便走去西伯，箕子在宫苑尘埃，把那比干腹教刀刃分开。", "碜可可活把心肝摘，血濯濯的苦痛伤怀，验三毛七孔真如在。", "妲己早欢娱满面，纣王早喜笑盈腮。", "(驾云了)(正末唱)。"]'),
('yuanqu-1387','晋文公火烧介子推・幺篇','狄君厚','元','元曲','yuanqu','','[]','为那娇态，有些颜色，选入宫来。',175,'元曲/yuanqu.json','["为那娇态，有些颜色，选入宫来。", "把那虿盆深埋，铜柱牢栽，酒池镌开，肉林安排，损害人材，食啖婴孩，引的四海兵来，戈戟无该。", "想着纣王兴衰，我王裁划，则为摘星楼把山河败坏。", "(带云)陛下，(唱)修甚么望月台？(驾云了)(正末唱)戊午日兵来，甲子日成灾。", "皆因那姜太公妙策奇材，临时间血浸朝歌坏，把座摘星楼变做尘埃。", "武王伐纣功劳大，一来是神天保护，一来是天地裁排。"]'),
('yuanqu-1388','晋文公火烧介子推・尾','狄君厚','元','元曲','yuanqu','','[]','跳出那兴废利名场，做一个用舍行藏客。',143,'元曲/yuanqu.json','["跳出那兴废利名场，做一个用舍行藏客。", "孔子道：危行言逊免害，不得中行而与之，必也狂狷进退乎哉！(净旦云了)(正末唱)见如今您晋朝中祸已成胎，少不得惹起场干戈横祸灾。", "(云了)(正末唱)我想这于尺月台，恁时节撇在九霄云外。", "(净云了)(正末唱)我道来，去了这晋朝臣，您可索提备着楚兵来。", "(下)。"]'),
('yuanqu-1389','晋文公火烧介子推・南吕/一枝花','狄君厚','元','元曲','yuanqu','','[]','致令得申生遭罪囚，逼临得重耳私奔走。',83,'元曲/yuanqu.json','["致令得申生遭罪囚，逼临得重耳私奔走。", "虽然是骊皇后生嫉妒，哎，你个晋大子也合问缘由。", "您肯分解个恩仇，赐朝典他甘心受，料东宫一命休。", "则是刎颈交伤身，难不了这短剑白练药酒。"]'),
('yuanqu-1390','晋文公火烧介子推・梁州第七','狄君厚','元','元曲','yuanqu','','[]','前家儿功番成罪累，后尧婆恩变为仇。',138,'元曲/yuanqu.json','["前家儿功番成罪累，后尧婆恩变为仇。", "从古至今，前家后继从来有，似这骊后一计，国舅铺谋，暗存着燕侣莺俦，可持请佃他凤阁龙楼。", "送的个前家儿惹罪遭殃，搬得个亲夫主出乖弄丑，都是后尧婆私事公仇。", "国舅、太后，君王行两三遍题名儿奏，着自家自等候。", "交武士金瓜列在我这脑背后，我如何不敢承头？。"]'),
('yuanqu-1391','晋文公火烧介子推・牧羊关','狄君厚','元','元曲','yuanqu','','[]','将太子待放来如何放？教太子待走来如何走？臣若坏了太子呵，教这泼宫奴万载名留。',110,'元曲/yuanqu.json','["将太子待放来如何放？教太子待走来如何走？臣若坏了太子呵，教这泼宫奴万载名留。", "若不教太子短剑下身亡，微臣便索金瓜下命休。", "太子今日青天上遭罪死，若黄泉下不可结冤仇。", "(太子云了)(正末唱)那壁是圣旨难推怨，微臣这壁官差不自由。"]'),
('yuanqu-1392','晋文公火烧介子推・四块玉','狄君厚','元','元曲','yuanqu','','[]','我从来是个奉善人，那里有杀人的手？竹节也似圣旨催怎敢迟留！至如东宫合死呵，也不合教这明晃晃短剑下亡。',105,'元曲/yuanqu.json','["我从来是个奉善人，那里有杀人的手？竹节也似圣旨催怎敢迟留！至如东宫合死呵，也不合教这明晃晃短剑下亡。", "(觑砌末，云)若要个完全的尸首，(唱)则合教这长挽挽白练休，(觑砌末，云)太子呵。", "(唱)你能可眼睁睁服药酒？。"]'),
('yuanqu-1393','晋文公火烧介子推・骂玉郎','狄君厚','元','元曲','yuanqu','','[]','听太子从头儿说开无虚谬，元来是争社稷结冤仇。',77,'元曲/yuanqu.json','["听太子从头儿说开无虚谬，元来是争社稷结冤仇。", "则是这三人定的计策，臣也都参透。", "是君王传的圣旨，骊后定的见识，是贼子施的机彀。", "(净云了)(正末慌听了)(唱)。"]'),
('yuanqu-1394','晋文公火烧介子推・感皇恩','狄君厚','元','元曲','yuanqu','','[]','呀，唬的我魂魄悠悠，不提防有人随后。',71,'元曲/yuanqu.json','["呀，唬的我魂魄悠悠，不提防有人随后。", "嗨，太子命难逃，微臣也身难躲，那贼汉怒难收。", "(太子云了)(正末唱)都是贼子奏，奏得您继母焦，焦得您父王愁。"]'),
('yuanqu-1395','晋文公火烧介子推・采茶歌','狄君厚','元','元曲','yuanqu','','[]','你道他下场头，怎干休？太子呵，则除你一心分破帝王忧。',43,'元曲/yuanqu.json','["你道他下场头，怎干休？太子呵，则除你一心分破帝王忧。", "古往今来虽是有，冤冤相报何时休！。"]'),
('yuanqu-1396','晋文公火烧介子推・牧羊关','狄君厚','元','元曲','yuanqu','','[]','他父亲牵肠肚，咱两个可费口？他子父母更歹杀呵痛关着骨肉，待将他摘胆剜心，怎做的不伤怀袖？触突着皇后合依平论，冒突着天子何问缘由。',82,'元曲/yuanqu.json','["他父亲牵肠肚，咱两个可费口？他子父母更歹杀呵痛关着骨肉，待将他摘胆剜心，怎做的不伤怀袖？触突着皇后合依平论，冒突着天子何问缘由。", "伤毒着宫婢非为罪。", "药杀神獒直甚狗！。"]'),
('yuanqu-1397','晋文公火烧介子推・尾','狄君厚','元','元曲','yuanqu','','[]','你今日道屠杀他这太子不怕难合，(带云)上天生我，上天死我，君王何不可。',285,'元曲/yuanqu.json','["你今日道屠杀他这太子不怕难合，(带云)上天生我，上天死我，君王何不可。", "(唱)我怕甚伏侍君正不到头。", "哎，众公卿，众宰侯，别人有家私不能勾，有妻男不能守，有功名不能就。", "宰辅臣僚冒支请受，臣道君昏怎生不奏？骊后心毒，献公出丑。", "杀的是玉叶金枝，有好榆柳，将凤子龙孙，不如猪狗。", "你等苍生，真乃禽兽。", "我已过三十不为夭寿，为主忠心，死而甘受。", "我博一个万载青名，煞强如教万民咒。", "(带云)我如今弃了身，弃了命，便死身亡。", "(唱)问甚您钢刀下烂朽！(带云)割舍了讹言课语，抗敕违宣，(唱)怕甚末金瓜下碎首！(带云)既为臣子，怎敢将主所杀。", "我将这行仁慈、有道理、忒忠孝的申生，我委实下不得手！。"]'),
('yuanqu-1398','晋文公火烧介子推・中吕/粉蝶儿','狄君厚','元','元曲','yuanqu','','[]','活计生涯，遣仆男一梨两耙，落得个任逍遥散诞行达。',101,'元曲/yuanqu.json','["活计生涯，遣仆男一梨两耙，落得个任逍遥散诞行达。", "背一张琴，携一壶酒，访友在山间林下。", "今日还家，想着我出朝进那场惊怕。", "(正末云)孔子云：邦有道则知，邦无道则愚。", "其知可及也．其愚不可及也。", "信有之也。", "(唱)。"]'),
('yuanqu-1399','晋文公火烧介子推・醉春风','狄君厚','元','元曲','yuanqu','','[]','我如今耳净胜如聋，眼明浑似瞎。',58,'元曲/yuanqu.json','["我如今耳净胜如聋，眼明浑似瞎。", "我便有那论邦辩国的巧舌头，则不如妆做个哑、哑、哑、哑。", "将书剑收拾，素琴抬起，剑匣高挂。"]'),
('yuanqu-1400','晋文公火烧介子推・喜春来','狄君厚','元','元曲','yuanqu','','[]','你今日修文治国平天下，你如今待演武安邦定杀伐。',73,'元曲/yuanqu.json','["你今日修文治国平天下，你如今待演武安邦定杀伐。", "儿呵，你如今修文演武未通达。", "(带云)罢，罢，至如你便不成呵，(唱)似我也退朝，准肯将你货与帝王家？。"]'),
('yuanqu-1401','晋文公火烧介子推・迎仙客','狄君厚','元','元曲','yuanqu','','[]','他道认得咱，不知是准那？(做见科了)(唱)臣道是淮家个客人，元来却足殿下。',120,'元曲/yuanqu.json','["他道认得咱，不知是准那？(做见科了)(唱)臣道是淮家个客人，元来却足殿下。", "(重耳做见科)(正末唱)小太子若是但躬身，微臣便该万剐。", "(重耳做起了)(正末云)东宫安在。", "(重耳云了)(正末打悲了，唱)东宫元来自刎升遐，晋天子呵，全不怕万载人民骂。"]'),
('yuanqu-1402','晋文公火烧介子推・上小楼','狄君厚','元','元曲','yuanqu','','[]','我则见扯剑出匣，他便揪住头发，吃察刀过处头落地。',87,'元曲/yuanqu.json','["我则见扯剑出匣，他便揪住头发，吃察刀过处头落地。", "苦痛天那！(带云)你好是下得呵，儿呵，(唱)好儿今日个不寻思，就、就死擎王保，(太子云)(正末唱)显得臣也，忠心扶你晋朝天下。"]'),
('yuanqu-1403','晋文公火烧介子推・幺篇','狄君厚','元','元曲','yuanqu','','[]','你没儿待怎生，我绝嗣待怎么？孩儿今日救了储君，替了亲爷，他须是为国于家。',80,'元曲/yuanqu.json','["你没儿待怎生，我绝嗣待怎么？孩儿今日救了储君，替了亲爷，他须是为国于家。", "(旦哭，做住)(正末唱)不争你举哀声，敢把咱全家诛杀。", "君上，小可题起那骊姬，怕那不怕？。"]'),
('yuanqu-1404','晋文公火烧介子推・醉高歌','狄君厚','元','元曲','yuanqu','','[]','行路途劫劫巴巴，耽凄楚消消洒洒。',35,'元曲/yuanqu.json','["行路途劫劫巴巴，耽凄楚消消洒洒。", "头直上风雪纷纷下咱两个冻不煞多应饿杀。"]'),
('yuanqu-1405','晋文公火烧介子推・红绣鞋','狄君厚','元','元曲','yuanqu','','[]','受了他五七日心惊胆怕，不似这两三程行得人力尽身乏，(太子云了)(正末唱)望见兀那野烟起处有人家。',139,'元曲/yuanqu.json','["受了他五七日心惊胆怕，不似这两三程行得人力尽身乏，(太子云了)(正末唱)望见兀那野烟起处有人家。", "(带云)太子共我绝粮三日，我每日割着身上肉，推做山林内拾得野物肉，与太子充饥，他有一日为君呵，(唱)至如他心亏负我，我须是割股劝着他。", "(太子云了)(到山中了)(正末唱)深山里绝饿杀。"]'),
('yuanqu-1406','晋文公火烧介子推・快活三','狄君厚','元','元曲','yuanqu','','[]','想我着适才来涧底一下，割得来与他家。',51,'元曲/yuanqu.json','["想我着适才来涧底一下，割得来与他家。", "烧得来半熟，慌用手来拿，早是我涩奈无收煞。", "(太子云了)(正末唱)。"]'),
('yuanqu-1407','晋文公火烧介子推・朝天子','狄君厚','元','元曲','yuanqu','','[]','百忙里让咱，猛然的见他，不由我吃忒忒心头怕。',143,'元曲/yuanqu.json','["百忙里让咱，猛然的见他，不由我吃忒忒心头怕。", "(太子云了)(正末唱)太子问臣声唤做其那，有几处热疖坏疮发。", "(太子云了)(正末唱)微臣里忍痛难禁，声疼不罢，(太子云了)(正末唱)太子呵，臣这疼痛如刀扎。", "(太子云了)(正末唱)你又待损剐、损剐些肉咱。", "(太子云了)(正末唱)你直待咽咬煞微臣罢。"]'),
('yuanqu-1408','晋文公火烧介子推・耍孩儿','狄君厚','元','元曲','yuanqu','','[]','哭啼啼诉不尽别离话，(太子云了)(正末唱)你与我疾忙上马。',115,'元曲/yuanqu.json','["哭啼啼诉不尽别离话，(太子云了)(正末唱)你与我疾忙上马。", "你一程程乘骑去他邦，我则索慢慢的步石自还家。", "他那里伤心去路何时尽，我这里含恨归程知他几日是家。", "(太子云了)(正末唱)赤紧的您父子无投机活，可知道风云气少，那里问儿女情多！。"]'),
('yuanqu-1409','晋文公火烧介子推・三煞','狄君厚','元','元曲','yuanqu','','[]','今世里父贤子不孝，子孝父不达。',88,'元曲/yuanqu.json','["今世里父贤子不孝，子孝父不达。", "这的是父不父、子不子，伤厂风化。", "我如今有儿无儿皆如此，(太子云了)(正末唱)你今日有爷无爷争甚那！谢楚大夫相提拔，太子为晋唐枝叶，皆是你齐楚根芽。"]'),
('yuanqu-1410','晋文公火烧介子推・二煞','狄君厚','元','元曲','yuanqu','','[]','太子呵，想必那春申君抬举你，(太子云了)(正末唱)你见那孟尝君随顺他。',123,'元曲/yuanqu.json','["太子呵，想必那春申君抬举你，(太子云了)(正末唱)你见那孟尝君随顺他。", "若是君权向那客舍里权安插，俺便似山川困虎生刚巨，(太子云)(正末唱)你便似浅水蛟龙奋爪牙。", "(太子云了)(正末唱)怎肯教骊姬贼子请了天下。", "太子呵，直等的先皇晏驾，那其间便起征伐。"]'),
('yuanqu-1411','晋文公火烧介子推・煞尾','狄君厚','元','元曲','yuanqu','','[]','太子呵，你若是报不得母、雪不得兄，你便空破了国。',94,'元曲/yuanqu.json','["太子呵，你若是报不得母、雪不得兄，你便空破了国。", "我若是借不得母、埋不得儿，我便是白丧了家。", "你若是雪不得冤、报不得恨，则恁地空干罢！太子呵，你便是治不得国，我便是齐不得家，吡，枉教人唾骂杀。"]'),
('yuanqu-1412','晋文公火烧介子推・仙吕/赏花时','狄君厚','元','元曲','yuanqu','','[]','母亲道奉帝临朝一世荣，背母归山博个万代名。',78,'元曲/yuanqu.json','["母亲道奉帝临朝一世荣，背母归山博个万代名。", "家中万事无牵挂，则今日便登程。", "(卜儿云了)(正末唱)遥望着翠巍巍绵山峻岭，(卜儿云)(正末唱)您孩儿鸦背着母亲行。"]'),
('yuanqu-1413','晋文公火烧介子推・越调/斗鹌鹑','狄君厚','元','元曲','yuanqu','','[]','焰腾腾火起红霞，黑洞洞烟飞墨云，闹垓垓火块纵横，急穰穰烟煤乱滚，悄蹙蹙火巷外潜藏，古爽爽烟峡内侧隐。',84,'元曲/yuanqu.json','["焰腾腾火起红霞，黑洞洞烟飞墨云，闹垓垓火块纵横，急穰穰烟煤乱滚，悄蹙蹙火巷外潜藏，古爽爽烟峡内侧隐。", "我则见烦烦的烟气熏，纷纷的火焰喷。", "急煎煎地火燎心焦，密匝匝烟屯峪门。"]'),
('yuanqu-1414','晋文公火烧介子推・紫花儿序','狄君厚','元','元曲','yuanqu','','[]','红红的星飞迸散，腾腾的焰接林梢，烘烘的火闭了山门。',87,'元曲/yuanqu.json','["红红的星飞迸散，腾腾的焰接林梢，烘烘的火闭了山门。", "烟惊了七魄，火唬了三魂。", "不付能这性命得安存，多谢了烟火神灵搭救了人。", "惭愧呵，险些儿有家难奔，尽都是火岭烟岚，望不见水馆山村。"]'),
('yuanqu-1415','晋文公火烧介子推・小桃红','狄君厚','元','元曲','yuanqu','','[]','小人向虎狼丛里过了三旬，每日负力担柴薪，教俺稚子山妻得安遁。',103,'元曲/yuanqu.json','["小人向虎狼丛里过了三旬，每日负力担柴薪，教俺稚子山妻得安遁。", "(驾云了)(正末唱)我不知你笑那深山里玉堂臣，他向那浓烟烈焰里成灰烬。", "(驾云了)(正末唱)为甚俺这樵夫得脱身无事？他皇天有信，从来不负俺这苦辛人。"]'),
('yuanqu-1416','晋文公火烧介子推・调笑令','狄君厚','元','元曲','yuanqu','','[]','柴林下那个宰臣，教火烧了身，兀的不辛苦杀凌烟阁上人。',80,'元曲/yuanqu.json','["柴林下那个宰臣，教火烧了身，兀的不辛苦杀凌烟阁上人。", "(驾云了)(正末唱)我道来呵，道他亲孩儿替死向钢刀下刎，他血沥割股焚身。", "封官时宰相每若议论，则封个完体将军。"]'),
('yuanqu-1417','晋文公火烧介子推・鬼三台','狄君厚','元','元曲','yuanqu','','[]','飕飕的的狂风彻，将密匝匝山围尽，猛一阵煤扑人生烟呛人。',96,'元曲/yuanqu.json','["飕飕的的狂风彻，将密匝匝山围尽，猛一阵煤扑人生烟呛人。", "风卷泄荡起灰尘，火焰红如绛云。", "沤沤烟熏的两轮日月昏，刮刮的火炼的一合天地分。", "补氤氲兔走被烟迷，忒楞楞扑飞禽被那火淋。", "(驾云了)(正末唱)。"]'),
('yuanqu-1418','晋文公火烧介子推・秃厮儿','狄君厚','元','元曲','yuanqu','','[]','您这火林外前后有军，深山里进退无门。',49,'元曲/yuanqu.json','["您这火林外前后有军，深山里进退无门。", "他道是向火坑中自丧身，更休想卧高冢麒麟。", "(驾云了)(正末唱)。"]'),
('yuanqu-1419','晋文公火烧介子推・圣药王','狄君厚','元','元曲','yuanqu','','[]','那老儿过六旬，近七旬，他道是老而不死是何人。',59,'元曲/yuanqu.json','["那老儿过六旬，近七旬，他道是老而不死是何人。", "你道他性子狠，意气嗔，见如今抱黄芦肢体做灰尘，可知、可知有甚吃火不烧身！。"]'),
('yuanqu-1420','晋文公火烧介子推・收尾','狄君厚','元','元曲','yuanqu','','[]','不争你个晋文公烈火把功臣尽，枉惹得万万载朝廷议论。',44,'元曲/yuanqu.json','["不争你个晋文公烈火把功臣尽，枉惹得万万载朝廷议论。", "常想赵盾捧车轮，也不似你个当今帝王狠。"]'),
('yuanqu-1421','李亚仙花酒曲江池・仙吕/赏花时','石君宝','元','元曲','yuanqu','','[]','赴选皇都将俺学业酬，正是男儿得志秋。',54,'元曲/yuanqu.json','["赴选皇都将俺学业酬，正是男儿得志秋。", "题金榜，占鳌头，这万言策须当应口，直着那状元名喧满凤凰楼。", "(同张千下)。"]'),
('yuanqu-1422','李亚仙花酒曲江池・仙吕/点绛唇','石君宝','元','元曲','yuanqu','','[]','朝来个雨过效原，早荡出晴光一片。',31,'元曲/yuanqu.json','["朝来个雨过效原，早荡出晴光一片。", "东风软，万卉争妍，山色青螺浅。"]'),
('yuanqu-1423','李亚仙花酒曲江池・油葫芦','石君宝','元','元曲','yuanqu','','[]','则你那痨病损的身躯难过遣，可怎生添上喘？央及杀粉骷髅也吐不出野狐涎，折倒的额颅破便似间道皮腰线，折倒的胸脯瘦便似减骨芭蕉扇。',115,'元曲/yuanqu.json','["则你那痨病损的身躯难过遣，可怎生添上喘？央及杀粉骷髅也吐不出野狐涎，折倒的额颅破便似间道皮腰线，折倒的胸脯瘦便似减骨芭蕉扇。", "(带云)妹子，(唱)如今那统镘的郎汉又村，谒浆的崔护又蹇，他来到谢家庄，几曾见桃花面？酩子坦揣与些柳青钱。"]'),
('yuanqu-1424','李亚仙花酒曲江池・天下乐','石君宝','元','元曲','yuanqu','','[]','兀的不三月清明艳丽天，(带云)妹子，(唱)咱和你翩也波翩。',387,'元曲/yuanqu.json','["兀的不三月清明艳丽天，(带云)妹子，(唱)咱和你翩也波翩。", "绕着这古墓前，你看那香车宝马迭万千。", "行行里玩一会景致，行行里听一会管弦，(带云)妹子，你觑波，(唱)早离了酒席儿偌近远。", "(末做骑马同张千上，云)自家郑元和，离了父亲，来到都下，举场未开。", "时遇春天明媚，引着张千，且去那曲江池上赏玩一遭。", "可早来到也，你看好景致。", "(诗云)家家无火桃喷火，处处无烟柳吐烟。", "金勒马嘶芳草地，玉楼人醉杏花天。", "张千，你见这两个妇人么？那一个分外生的娇娇媚媚，可可喜喜，添之太长，减之太短，不施脂粉天然态，纵有丹青画不成，是好女子也呵！(做坠鞭科，张千拾云)相公，坠了鞭子也。", "(末云)真个是风风流流，可可喜喜。", "(又坠鞭，张千拾云)相公，又坠了鞭子也。", "(末云)我知道。", "好女子，好女子。", "(又坠鞭，张千拾云)相公，又坠了鞭子也。", "(末云)我知道。", "(正旦云)我看那生裹帽穿衫，撒丝系带，好个俊人物也！(唱)。"]'),
('yuanqu-1425','李亚仙花酒曲江池・那吒令','石君宝','元','元曲','yuanqu','','[]','谁家个少年，一时间撞见；一时间撞见，两下里顾恋；两下里顾恋，三番家坠鞭。',85,'元曲/yuanqu.json','["谁家个少年，一时间撞见；一时间撞见，两下里顾恋；两下里顾恋，三番家坠鞭。", "(带云)妹子也，他还是个子弟，是个雏儿。", "(唱)他管初逢着路柳丝，他管乍见着墙花片，多应被花柳牵缠。"]'),
('yuanqu-1426','李亚仙花酒曲江池・鹊踏枝','石君宝','元','元曲','yuanqu','','[]','墙花也甚芳鲜，路柳也不飞绵。',41,'元曲/yuanqu.json','["墙花也甚芳鲜，路柳也不飞绵。", "忙杀游蜂，恨杀啼鹃，没乱杀鸣珂巷亚仙，兜的又引起顽涎。"]'),
('yuanqu-1427','李亚仙花酒曲江池・寄生草','石君宝','元','元曲','yuanqu','','[]','他将那花阴串，我将这柳径穿。',463,'元曲/yuanqu.json','["他将那花阴串，我将这柳径穿。", "少年人乍识春风面，春风面半掩桃花扇，桃花扇轻拂垂杨线，垂杨线怎系锦鸳鸯，锦鸳鸯不锁黄金殿。", "(云)梅香，你去请赵官儿来。", "(净上，云)姨姨，叫我做甚么？(正旦云)妹夫，那里有个野味儿，请他来同席，惟做甚么？(净云)在那里？(做见科)呀，我道是谁，元来是郑舍。", "(末云)赵牛筋，我问你咱。", "那两个女子，谁氏之家？(净云)那一个生的好些的，是上厅行首李亚仙；这一个是他妹子刘桃花，就是敝表。", "我姨姨着我来请你哩，你过去同吃几杯儿酒。", "(末云)怎好搅扰。", "(净云)姨姨，我请将来了也。", "(末做见科)(正旦云)敢问足下仙乡何处，甚姓何名？(末云)小生姓郑，表德元和，荥阳人氏，因为应试到此。", "敢问小娘子高姓？(旦云)妾身不幸，落在平康，唤做李亚仙的便是。", "(末云)久闻芳名，今得一睹，实乃小生有缘也。", "(旦云)梅香，将酒来。", "(递酒科，云)解元，请满饮此杯。", "(净云)姨姨，这酒是我买的，我也吃一钟儿。", "(旦云)呀，可忘了妹夫也。", "(末云)俺两个曾结义兄弟哩。", "(正旦云)这等，那个是仁兄？(末云)我是仁兄。", "(正旦云)你是仁兄沙！(唱)。"]'),
('yuanqu-1428','李亚仙花酒曲江池・醉中天','石君宝','元','元曲','yuanqu','','[]','莫不是冲倒临川县？(净去)我是爱弟。',249,'元曲/yuanqu.json','["莫不是冲倒临川县？(净去)我是爱弟。", "(正旦云)你是爱弟沙，(唱)莫不是买断了丽春园？(净云)姨姨，俺和刘大姐两口儿，不似牵牛郎织女那！(正旦唱)你真个是牵牛上碧天，枉踏踏这清虚殿。", "我只问曲江里水比那天台较远？今日和刘郎相见，(云)妹子，我索谢你，(外旦云)姐姐谢我做甚么？(正旦唱)不因你个小名儿沙，你怎肯误入桃源。", "(末云)牛筋，你过去，说我要在亚仙姐姐家使一把钞，可容许么？(净云)姨姨，恰才元和秀才要来姨姨家使把钞，姨姨心下如何？(正旦云)妹夫，你说了就是。", "则俺母亲有些利害，不当稳便。", "(唱)。"]'),
('yuanqu-1429','李亚仙花酒曲江池・金盏儿','石君宝','元','元曲','yuanqu','','[]','他见兔儿叵寸鹰颤，口店羊骨不嫌膻。',68,'元曲/yuanqu.json','["他见兔儿叵寸鹰颤，口店羊骨不嫌膻。", "常则是肉吊窗放下遮他面，动不动便抓钱。", "只怕你脑门边着痛箭，胳膊上惹空拳，那其间羞归明月渡，懒上载花船。"]'),
('yuanqu-1430','李亚仙花酒曲江池・青哥儿','石君宝','元','元曲','yuanqu','','[]','俺娘呵外相儿卜分十分慈善，就地里百般百般机变。',94,'元曲/yuanqu.json','["俺娘呵外相儿卜分十分慈善，就地里百般百般机变。", "那怕你堆积黄金到北斗边，他自有锦套儿腾掀，甜唾儿粘连，俏泛儿勾牵，假意儿熬煎，辘轴儿盘旋，钢钻儿钻研，不消得迫欢买笑几多年早下翻了你个穷原宪。"]'),
('yuanqu-1431','李亚仙花酒曲江池・赚煞','石君宝','元','元曲','yuanqu','','[]','往常我回雪态舞按柳腰肢，遏云声歌尽桃花扇，从今后席上尊前腼腆。',227,'元曲/yuanqu.json','["往常我回雪态舞按柳腰肢，遏云声歌尽桃花扇，从今后席上尊前腼腆。", "(末云)就将小生的马，送大姐回去。", "请上马。", "(做递鞭科)(正旦唱)更做道如今颠倒颠，落的女娘每倒接了丝鞭。", "(末云)小生多备些钱，送与妈妈，必然容允。", "(正旦唱)咱既然结姻缘，又何须置酒张筵？虽然那爱钞的虔婆他可也难恕免。", "争奈我心坚石穿，准备着从良弃贱，我则索你个正腔钱，省了你那买闲钱。", "(下)(末梅香张千随下)(净云)你看，郑舍随着姨姨去了也，我和你明日将些酒礼，与他作贺去来。", "(净、外旦同下)。"]'),
('yuanqu-1432','李亚仙花酒曲江池・南吕/一枝花','石君宝','元','元曲','yuanqu','','[]','俺娘眼上带一对乖，心内隐着十分狠；脸上生那歹斗毛，手内有那握刀纹。',79,'元曲/yuanqu.json','["俺娘眼上带一对乖，心内隐着十分狠；脸上生那歹斗毛，手内有那握刀纹。", "狠的来世上绝伦，下死手，无分寸。", "眼又尖，手又紧。", "他拳起处又早着昏，那郎君呵，不带伤必然内损。"]'),
('yuanqu-1433','李亚仙花酒曲江池・梁州第七','石君宝','元','元曲','yuanqu','','[]','俺娘呵，则是个吃人脑的风流太岁，剥人皮的娘子丧门。',156,'元曲/yuanqu.json','["俺娘呵，则是个吃人脑的风流太岁，剥人皮的娘子丧门。", "油头粉面敲人棍，笑里刀剐皮割肉，绵里针剔髓挑筋。", "娘使尽虚心冷气，女着些带耍连真，总饶你便通天彻地的郎君，也不彀三朝五日遭瘟。", "则俺那爱钱娘扮出个凶神，卖笑女伴了些死人，有情郎便是那冤魂。", "俺娘钱亲钞紧，女心里憎恶娘亲近，娘爱的女不顺。", "娘爱的郎君个个村，女爱的却无银。"]'),
('yuanqu-1434','李亚仙花酒曲江池・商调/尚京马','石君宝','元','元曲','yuanqu','','[]','也则俺一时间错被鬼昏迷，是赡表子平生落得的。',136,'元曲/yuanqu.json','["也则俺一时间错被鬼昏迷，是赡表子平生落得的。", "那有见识的哥哥每知了就里，似这等切切悲悲，从今后有金银，多攒下些买粮食。", "(正旦云)这虔婆则道我见元和穷身泼命，必然不睬他。", "他不说呵便罢，他若说呵，着他吃我几嘴好的。", "(卜儿云)孩儿，你看那无钱的子弟，在那里迎丧送殡哩！(正旦唱)。"]'),
('yuanqu-1435','李亚仙花酒曲江池・隔尾','石君宝','元','元曲','yuanqu','','[]','你道是无钱的子弟那里迎丧殡，(云)你兀自戏说哩，(唱)这须是你爱钱的虔婆送了人。',204,'元曲/yuanqu.json','["你道是无钱的子弟那里迎丧殡，(云)你兀自戏说哩，(唱)这须是你爱钱的虔婆送了人。", "(卜儿云)这亡化的，不知是婆娘，是汉子？(正旦唱)那亡化的婆娘不须你问。", "(卜儿云)不知他偌大年纪了？(正旦唱)多管是未及到五旬。", "(卜儿云)为甚的无个亲眷那？(正旦唱)你道为甚的无个六亲。", "(卜儿云)不知害甚么病死了那？(正旦唱)想则为那苦克瞒心钞儿上紧。", "(卜儿云)兀的不就是那郑元和？是谁家死了人，要郑元和在那里啼哭？(正旦唱)。"]'),
('yuanqu-1436','李亚仙花酒曲江池・牧羊关','石君宝','元','元曲','yuanqu','','[]','常言道街死巷不乐。',204,'元曲/yuanqu.json','["常言道街死巷不乐。", "(卜儿云)你只看他穿着那一套衣服。", "(正旦唱)可显他身贫志不贫。", "(卜儿云)他紧靠定那棺函儿哩。", "(正旦云)谁不道他是郑府尹的孩儿！(唱)他正是倚官挟势的郎君。", "(卜儿云)他与人摇铃儿哩！(正旦唱)他摇铃子当世当权。", "(卜儿云)他与人家唱挽歌儿哩！(正旦唱)唱挽歌也是他一遭一运。", "(卜儿云)他举着神楼儿哩！(正旦唱)他面前称大汉，只待背后立高门。", "送殡呵须是仵作风流种，唱挽呵也则歌吟诗赋人。", "(虚下)。"]'),
('yuanqu-1437','李亚仙花酒曲江池・感皇恩','石君宝','元','元曲','yuanqu','','[]','你死的来不着家坟，撇的我那里终身？(做叫科，云)元和，请起波，请起波。',177,'元曲/yuanqu.json','["你死的来不着家坟，撇的我那里终身？(做叫科，云)元和，请起波，请起波。", "(唱)谁着你恋莺花，轻性命，丧风尘。", "(末做醒科，云)哎呀！醒便醒了，怎么捱的这等疼那。", "(正旦唱)他道是元和醒也，这的便子弟还魂。", "(正末做惊复倒科)(正旦云)元和，是我在此。", "(正末做起科，云)姐姐，你不怕旁人耻笑，妈儿嗔怒，俺家爷爷怪恨那？(正旦唱)我也怎怕的旁人笑，劣母嗔，你爹恨！。"]'),
('yuanqu-1438','李亚仙花酒曲江池・采茶歌','石君宝','元','元曲','yuanqu','','[]','我怕你死在逡巡，抛在荆榛，又则怕傍人夺了你个俊郎君。',101,'元曲/yuanqu.json','["我怕你死在逡巡，抛在荆榛，又则怕傍人夺了你个俊郎君。", "(末云)你妈儿利害哩！(正旦云)俺娘便利害呵，(唱)我也则是一度愁来一度忍。", "(末云)俺家爹爹打的我苦也！(正旦唱)你爹打呵，谁教你唱一年春尽一年春！。"]'),
('yuanqu-1439','李亚仙花酒曲江池・黄钟煞','石君宝','元','元曲','yuanqu','','[]','则是个闷番子弟粗桑棍。',354,'元曲/yuanqu.json','["则是个闷番子弟粗桑棍。", "(云)系着这条舞旋旋的裙儿，也不是裙儿，(唱)则是个缠杀郎君湿布袍。", "接郎君分外勤，赶郎君何太狠！常言道娘慈悲，女孝顺；你不仁，我生忿。", "到家里决撒喷，你看我寻个自尽，觅个自刎，官司知，决然问。", "问一番，拷一顿。", "官人行，怎亲近。", "令史每，无投奔。", "我着你哭啼啼带着锁，披着枷，恁时分，(云)走到衙门前，古堆邦坐的。", "有人问，妈妈你为甚么来，送了这孤寒的老身？妈妈道，这都是那生忿的小贱人送了我也！(唱)我直着你梦撒了撩丁，倒折了本。", "(卜儿拖正旦下)(末云)那虔婆好狠也，李亚仙好忍也，我郑元和好苦也，适才亚仙在此，尽有顾盼小生之意，争奈被他虔婆逼勒去了，单留小生一个，又是打伤的人，那里讨碗饭吃？(叹科，诗云)可堪老鸨太无恩，撇下孤贫半死身。", "仔细思量无活计，不如仍还去唱\"一年春尽一年春。", "\"(下)。"]'),
('yuanqu-1440','李亚仙花酒曲江池・中吕/粉蝶儿','石君宝','元','元曲','yuanqu','','[]','月馆风亭，则为这虔婆上梁不正，这些时消疏了燕燕莺莺。',73,'元曲/yuanqu.json','["月馆风亭，则为这虔婆上梁不正，这些时消疏了燕燕莺莺。", "风月所得清白，雨云乡无粘带，烟花寨耳根清净。", "人问道亚仙的今世今生，则俺那郑元和可甚么了身达命。"]'),
('yuanqu-1441','李亚仙花酒曲江池・醉春风','石君宝','元','元曲','yuanqu','','[]','咱这里温水浸琼花，尚兀自冰澌生玉鼎。',197,'元曲/yuanqu.json','["咱这里温水浸琼花，尚兀自冰澌生玉鼎。", "似这等扬风搅雪没休时，他倒大来冷，冷。", "你去那出殡处跟寻，起丧处访问，下棺处打听。", "(梅香云)我去寻便了。", "(末、净上，梅见科，云)俺姐姐正望你哩，咱家去来。", "(末做见科，云)姐姐，好大雪，兀的不冻杀我也！(正旦云)梅香，将酒来，与他两个吃。", "(末、净做寒吃酒科)(正旦云)赵牛筋，你且在这里，若那虔婆来时，你咳嗽为号。", "(净云)我知道。", "(正旦云)元和，好冷也。", "(唱)。"]'),
('yuanqu-1442','李亚仙花酒曲江池・十二月','石君宝','元','元曲','yuanqu','','[]','遍乾坤冬寒暮景，寰宇内糁玉筛琼。',66,'元曲/yuanqu.json','["遍乾坤冬寒暮景，寰宇内糁玉筛琼。", "长街上阴风凛冽，头直上冷气严凝。", "(带云)好凄凉人也。", "(唱)又不曾亏负了萧娘的性命，虽同姓你又不同名。"]'),
('yuanqu-1443','李亚仙花酒曲江池・满庭芳','石君宝','元','元曲','yuanqu','','[]','哎，怎不教你元和猛惊，那里是虔婆到也，分明是子弟灾星。',171,'元曲/yuanqu.json','["哎，怎不教你元和猛惊，那里是虔婆到也，分明是子弟灾星。", "这一场唱叫无干净，死去波好好先生。", "(卜儿做见科，云)呀，那叫化头，你又来怎的？(净再做咳嗽科)(卜儿云)这个是赵牛筋，我家须不是卑田院，怎么将这叫化的都收拾我家来了？(正旦唱)罢波，你实拿住风月所和奸罪名，检着这乐章集依法施行，常拚着枷稍上长钉钉，你只问临川县令，可不道惺惺的自古惜惺惺。"]'),
('yuanqu-1444','李亚仙花酒曲江池・耍孩儿','石君宝','元','元曲','yuanqu','','[]','虽不曾把黄金堆到北斗杓儿柄，也做的过家私叠等，只为你虚心假意会劳承，赚的他囊橐如冰。',143,'元曲/yuanqu.json','["虽不曾把黄金堆到北斗杓儿柄，也做的过家私叠等，只为你虚心假意会劳承，赚的他囊橐如冰。", "(带云)他有钱呵，(唱)一家儿簇捧做胸前肉；(带云)他没钱呵，(唱)半合儿憎嫌做眼内钉，早把倒宅计安排定。", "只为些蝇头微利，蹬脱子我锦片前程。", "(卜儿云)你看这等锦绣帏翡翠屏，是留得叫化子睡的？(正旦唱)。"]'),
('yuanqu-1445','李亚仙花酒曲江池・三煞','石君宝','元','元曲','yuanqu','','[]','卖弄甚锦绣帏翡翠屏，则他这瓦罐儿早打破在你姻脂井。',102,'元曲/yuanqu.json','["卖弄甚锦绣帏翡翠屏，则他这瓦罐儿早打破在你姻脂井。", "他便能飞也飞不出千重网，便会跳也跳不过万丈坑，郑元和亲身证。", "(卜儿云)你这小贱人，还不赶他出去？要讨打哩！(正旦唱)你就将他赶离后院，少不的我也哭倒长城。"]'),
('yuanqu-1446','李亚仙花酒曲江池・二煞','石君宝','元','元曲','yuanqu','','[]','我和他埋时一处埋，生时一处生。',71,'元曲/yuanqu.json','["我和他埋时一处埋，生时一处生。", "任凭你恶叉白赖寻争竞，常拚个同归青冢抛金缕，更休想重上红楼理玉筝。", "非是我夸清正，只为他星前月下，亲曾设海誓山盟。"]'),
('yuanqu-1447','李亚仙花酒曲江池・双调/新水令','石君宝','元','元曲','yuanqu','','[]','散春风和气满鸣珂，燕莺恰便似耳边吹过。',48,'元曲/yuanqu.json','["散春风和气满鸣珂，燕莺恰便似耳边吹过。", "往常我尊前歌婉转，席上舞婆娑，这妙舞清歌，都参透，总识破。"]'),
('yuanqu-1448','李亚仙花酒曲江池・雁儿落','石君宝','元','元曲','yuanqu','','[]','俺如今有过活，你兀自难存坐。',59,'元曲/yuanqu.json','["俺如今有过活，你兀自难存坐。", "哎，你个卑田院老教头，(云)你认的我么？(净云)奶奶你是谁？(正旦唱)我便是鸣珂巷陪钱货。"]'),
('yuanqu-1449','李亚仙花酒曲江池・得胜令','石君宝','元','元曲','yuanqu','','[]','你可认的那旧家计郑元和？(末见科，云)夫人，他是谁那？(正旦唱)他是你同伴的老哥哥。',93,'元曲/yuanqu.json','["你可认的那旧家计郑元和？(末见科，云)夫人，他是谁那？(正旦唱)他是你同伴的老哥哥。", "不争你那地塌下摇铃子，对着这衙厅上教演他唱挽歌。", "这般样村呵，你道是不快俺风尘过，休波倚仗着门前桃李多。"]'),
('yuanqu-1450','李亚仙花酒曲江池・川拨棹','石君宝','元','元曲','yuanqu','','[]','阶垓下闹镬铎，闹火火，为甚么？则见他发似丝窝，眼似胶锅，口似番河。',91,'元曲/yuanqu.json','["阶垓下闹镬铎，闹火火，为甚么？则见他发似丝窝，眼似胶锅，口似番河。", "(带云)我道是谁？(唱)原来是搅肚蛆肠的老虔婆，将瓦罐都打破。", "(左右打科)(卜儿云)你打破了我的瓦罐哩。", "(正旦唱)。"]'),
('yuanqu-1451','李亚仙花酒曲江池・七弟兄','石君宝','元','元曲','yuanqu','','[]','你敢是恨我、怨我，甚存活。',48,'元曲/yuanqu.json','["你敢是恨我、怨我，甚存活。", "想你来迎新送旧多胡做，到今日穷身泼命怎收科？舒着那手掌儿道乞化钱一个。"]'),
('yuanqu-1452','李亚仙花酒曲江池・收江南','石君宝','元','元曲','yuanqu','','[]','呀，草堂中忽地贵人过，急的我忙接待敢蹉跎？(郑府尹云)媳妇儿，我当初在杏园里打上孩儿一顿，也只要他成人。',114,'元曲/yuanqu.json','["呀，草堂中忽地贵人过，急的我忙接待敢蹉跎？(郑府尹云)媳妇儿，我当初在杏园里打上孩儿一顿，也只要他成人。", "今日孩儿得了官，就不肯认我。", "媳妇儿，你与我问他这个是何道理？(正旦唱)你父子们有甚不相和，倒着俺定夺？管教你一家完美笑呵呵。"]'),
('yuanqu-1453','李亚仙花酒曲江池・鸳鸯煞','石君宝','元','元曲','yuanqu','','[]','从今后把并头花蕊甘生锉，同心搂带拚教割。',142,'元曲/yuanqu.json','["从今后把并头花蕊甘生锉，同心搂带拚教割。", "这的是万古纲常，众口评跋。", "畅道罪逆滔天，何时解脱？(做对末拜科，云)相公，妾今日怎么爱惜得一死？人都道郑元和死为辱子，也只由的李亚仙；生为逆子，也只由的李亚仙。", "(唱)都为我泼贱烟花，把你个名儿污。", "不由不奔井投河，便封我到一品夫人，也荣耀不的我。"]'),
('yuanqu-1454','正宫・醉太平','钟嗣成','元','元曲','yuanqu','','[]','绕前街后街，进大院深宅，怕有那慈悲好善小裙钗，请乞儿一顿饱斋。',211,'元曲/yuanqu.json','["绕前街后街，进大院深宅，怕有那慈悲好善小裙钗，请乞儿一顿饱斋。", "与乞儿绣副合欢带，与乞儿换副新铺盖，将乞儿携手上阳台，设贫咱波奶奶！俺是悲田院下司，俺是刘九儿宗枝，郑元和俺当日拜为师，传流下莲花落稿子。", "搠竹杖绕遍莺花市，提灰笔写遍鸳鸯字，打爻槌唱会《鹧鸪词》，穷不了俺风流敬思。", "风流贫最好，村沙富难交，拾灰泥补砌了旧砖窑，开一个教乞儿市学。", "裹一顶半新不旧乌纱帽，穿一领半长不短黄麻罩，系一条半联不断皂环绦，做一个穷风月训导。"]'),
('yuanqu-1455','双调・沉醉东风','钟嗣成','元','元曲','yuanqu','','[]','听不厌鸾笙象板，看不足凤髻蝉鬟。',55,'元曲/yuanqu.json','["听不厌鸾笙象板，看不足凤髻蝉鬟。", "按不住刺史狂，学不得司空惯，常不教粉吝红悭。", "若不把群花恣意看，饱不了平生饿眼。"]'),
('yuanqu-1456','双调・折桂令咏西域吉诚甫','钟嗣成','元','元曲','yuanqu','','[]','是梨园一点文星，西土储英，中夏扬名。',64,'元曲/yuanqu.json','["是梨园一点文星，西土储英，中夏扬名。", "胸次天诚，口角河倾，席上风生。", "吞学海波澜万顷，战词坛甲胄千兵。", "律按玑衡，声应和铃，乐奏英茎。"]'),
('yuanqu-1457','双调・清江引','钟嗣成','元','元曲','yuanqu','','[]','采薇首阳空忍饥，枉了争闲气。',360,'元曲/yuanqu.json','["采薇首阳空忍饥，枉了争闲气。", "试问屈原醒，争似渊明醉？早寻个稳便处闲坐地。", "伯牙去寻钟子期，讲论琴中意。", "高山流水声，谁是知音的？早寻个稳便处闲坐地。", "五湖去来越范蠡，甘作烟波计。", "功成心自闲，名遂心先退，早寻个稳便处闲坐地。", "楚狂接舆歌凤兮，见人忙回避。", "固知势利心，岂识高贤意？早寻个稳便处闲坐地。", "到头那知谁是谁，倏忽人间世。", "百年有限身，三寸元阳气，早寻个稳便处闲坐地。", "秀才饱学一肚皮，要占登科记。", "假饶七步才，未到三公位，早寻个稳便处闲坐地。", "古今尽成闲是非，翻覆兴和废。", "休夸韩信功，谩说陈平智，早寻个稳便处闲坐地。", "凤凰燕雀一处飞，玉石俱同类。", "分甚高共低，辨甚真和伪？早寻个稳便处闲坐地。", "道人淡然心似灰，酒色俱无意。", "绝交鹦鹉杯，退佃鸳鸯被，早寻个稳便处闲坐地。", "利各假饶争到底，争得成何济。", "谁为刎颈交，那是安窠计？早寻个稳便处闲坐地。"]'),
('yuanqu-1458','双调・清江引情','钟嗣成','元','元曲','yuanqu','','[]','夜长四壁人静悄，强把屏山靠。',107,'元曲/yuanqu.json','["夜长四壁人静悄，强把屏山靠。", "囗路楚云深，有梦无著落，俏魂灵险些儿干送了。", "夜长怎生得睡着，万感萦怀抱。", "伴人瘦影儿，惟有孤灯照，长吁气一声吹灭了。", "昨先话儿说到底，今日都翻悔。", "直恁铁心肠，不管人憔悴，下场头送了我都是你。"]'),
('yuanqu-1459','南吕・一枝花自序丑斋','钟嗣成','元','元曲','yuanqu','','[]','生居天地间，禀受阴阳气。',60,'元曲/yuanqu.json','["生居天地间，禀受阴阳气。", "既为男子体，须入世俗机。", "所事堪宜，件件可咱家意。", "子为评跋上惹是非。", "折莫旧友新知，才见了着人笑起。"]'),
('yuanqu-1460','梁州・子为外貌儿不中抬举，因此内才儿不得便宜。半生未得文章力，空','钟嗣成','元','元曲','yuanqu','','[]','自胸藏锦绣，口唾珠玑。',107,'元曲/yuanqu.json','["自胸藏锦绣，口唾珠玑。", "争奈灰容土貌，缺齿重颏，更兼着细眼单眉，人中短髭鬓稀稀。", "那里取陈平般冠玉精神，何晏般风流面皮，那里取潘安般俊俏容仪？自知，就里。", "清晨倦把青鸾对，恨煞爷娘不争气。", "有一日黄榜招收丑陋的，准拟夺魁。"]'),
('yuanqu-1461','隔尾・有时节软乌纱抓扎起钻天髻，干皂靴出落着簌地衣。向晚乘闲后门','钟嗣成','元','元曲','yuanqu','','[]','立，猛可地笑起。',26,'元曲/yuanqu.json','["立，猛可地笑起。", "似一个甚的？恰便似现世钟馗唬不杀鬼。"]'),
('yuanqu-1462','牧羊关・冠不正相知罪，貌不扬怨恨谁？那里也尊瞻视貌重招威！枕上寻','钟嗣成','元','元曲','yuanqu','','[]','思，心头怒起。',36,'元曲/yuanqu.json','["思，心头怒起。", "空长三千岁，暗想九千回。", "恰便似木上节难镑刨，胎中疾没药医。"]'),
('yuanqu-1463','贺新郎・世间能走的不能飞，饶你千件千宜，百伶百俐。闲中解尽其中意，','钟嗣成','元','元曲','yuanqu','','[]','暗地里自恁解释，倦闲游出塞临池。',50,'元曲/yuanqu.json','["暗地里自恁解释，倦闲游出塞临池。", "临池鱼恐坠，出塞雁惊飞，入园林，俗鸟应回避。", "生前难入画，死后不留题。"]'),
('yuanqu-1464','隔尾・写神的要得丹青意，子怕你巧笔难传造化机。不打草两般儿可同类。','钟嗣成','元','元曲','yuanqu','','[]','法刀鞘依着格式，妆鬼的添上嘴鼻，眼巧何须样子比。',24,'元曲/yuanqu.json','["法刀鞘依着格式，妆鬼的添上嘴鼻，眼巧何须样子比。"]'),
('yuanqu-1465','哭皇天・饶你有拿雾艺冲天计，诛龙局段打凤机。近来论世态，世态有高','钟嗣成','元','元曲','yuanqu','','[]','有钱的高贵，无钱的低微。',74,'元曲/yuanqu.json','["有钱的高贵，无钱的低微。", "哪里问风流子弟？折末颜如灌口，貌赛神仙，洞宾出世，宋玉重生，设答了镘的，梦撒了寮丁，他采你也不见得。", "枉自论黄数黑，谈说是非。"]'),
('yuanqu-1466','乌夜啼・一个斩蛟龙秀士为高第，升堂室古今谁及。一个射金钱武士为夫','钟嗣成','元','元曲','yuanqu','','[]','婿，韬略无敌，武艺深知。',54,'元曲/yuanqu.json','["婿，韬略无敌，武艺深知。", "丑和好自有是和非，文和武便是傍州例。", "有鉴识，无嗔讳，自花白寸心不昧，若说谎上帝应知。"]'),
('yuanqu-1467','收尾・常记得半窗夜雨灯初昧，一枕秋风梦未回。见一人，请相会，道咱','钟嗣成','元','元曲','yuanqu','','[]','家，必高贵。',123,'元曲/yuanqu.json','["家，必高贵。", "既通儒，又通吏，既通疏，更精细。", "一时间，失商议，既成形，悔不及。", "子教你，请俸给，子孙多，夫妇宜。", "货财充，仓廪实，禄福增，寿算齐。", "我特来，告你知，暂相别，恕情罪。", "叹息了几声，懊悔了一会。", "觉来时记得，记得他是谁？原来是不做美当年的捏胎鬼。"]'),
('yuanqu-1468','正宫・叨叨令叹世','杨朝英','元','元曲','yuanqu','','[]','想他腰金衣紫青云路，笑俺烧丹炼药修行处。',139,'元曲/yuanqu.json','["想他腰金衣紫青云路，笑俺烧丹炼药修行处。", "俺笑他封妻荫子叨天禄，不如我逍遥散诞茅庵住。", "倒大来快活也末哥，倒大来快活也末哥，那里也龙韬虎略擎天柱。", "昨日苍鹰黄犬齐飞放，今日单鞭羸马江南丧。", "他待学欺君罔上曹丞相，不如俺葛巾漉酒陶元亮。", "倒大来快活也末哥，倒大来快活也末哥，渔翁把盏樵夫唱。"]'),
('yuanqu-1469','中吕・阳春曲','杨朝英','元','元曲','yuanqu','','[]','浮云薄处ㄔ胧日，白鸟明边隐约山。',68,'元曲/yuanqu.json','["浮云薄处ㄔ胧日，白鸟明边隐约山。", "妆楼倚遍泪空弹，凝望眼，君去几时还？沈腰易瘦衣宽褪，潘鬓新皤镜怕看。", "月明千里报平安，音信悭，归梦绕巫山。"]'),
('yuanqu-1470','商调・梧叶儿客中闻雨','杨朝英','元','元曲','yuanqu','','[]','檐头溜，窗外声，直响到天明。',91,'元曲/yuanqu.json','["檐头溜，窗外声，直响到天明。", "滴得人心碎，聒得人梦怎成。", "夜雨好无情，不道我愁人怕听。", "戏贾观音奴庞儿俊，更喜恰，堪咏又堪夸。", "得空便处风流话，没人处再敢么。", "救苦难俏冤家，有吴道子应难画他。"]'),
('yuanqu-1471','越调・小桃红题写韵轩','杨朝英','元','元曲','yuanqu','','[]','当年相遇月明中，一见情缘重。',50,'元曲/yuanqu.json','["当年相遇月明中，一见情缘重。", "谁想仙凡隔春梦，杳无踪，凌风跨虎归仙洞。", "今人不见，天孙标致，依旧笑春风。"]'),
('yuanqu-1472','双调・得胜令','杨朝英','元','元曲','yuanqu','','[]','日日醉红楼，归来五更头。',175,'元曲/yuanqu.json','["日日醉红楼，归来五更头。", "问著诸般讳，揪ㄎ不害羞。", "敲头，敢设个牙疼咒。", "揪揪，揪得来不待揪。", "庭院正无聊，单枕拥鲛绡。", "细雨和愁种，孤灯带梦烧。", "难熬，促织儿窗前叫。", "焦焦，焦得来不待焦。", "花影下重檐，沉烟袅绣帘。", "人去青鸾杳，春娇酒病厌。", "眉尖。", "常锁伤春怨。", "タタ，タ得来不待タ。", "一笑自生娇，春风兰麝飘。", "夜月红牙按，青螺双凤高。", "妖娆，那里有惹多俏。", "嚣嚣，嚣得来不待嚣。"]'),
('yuanqu-1473','双调・清江引','杨朝英','元','元曲','yuanqu','','[]','秋深最好是枫树叶，染透猩猩血。',35,'元曲/yuanqu.json','["秋深最好是枫树叶，染透猩猩血。", "风酿楚天秋，霜浸吴江月，明日落红多去也。"]'),
('yuanqu-1474','双调・殿前欢和阿里西瑛韵','杨朝英','元','元曲','yuanqu','','[]','白云窝，樵童斟酒牧童歌。',261,'元曲/yuanqu.json','["白云窝，樵童斟酒牧童歌。", "醉时林下和衣卧，半世磨陀。", "富和贫争甚么？自有闲功课，共野叟闲吟和。", "呵呵笑我，我笑呵呵。", "白云窝，闲赊村酒杖藜拖。", "乐天知命随缘过，尽自婆娑。", "任风涛万丈波，难著莫，醉里乾坤大。", "呵呵笑我，我笑呵呵。", "白云窝，浮云富贵待如何？闲时膝上横琴坐，半世磨陀。", "待为□□甚么，无著莫，把世事都参破。", "呵呵笑我，我笑呵呵。", "白云窝，天边乌兔似飞梭。", "安贫守己窝中坐，尽自磨陀。", "教顽童做过活，到大来无灾祸。", "园中瓜里，门外田禾。", "白云窝，守著个知音知律俏奴哥。", "醉时鸳帐同衾卧，两意谐和。", "尽今生我共他，有句话闲提破。", "花前对饮，月下高歌。"]'),
('yuanqu-1475','双调・雁儿落过得胜令落花','杨朝英','元','元曲','yuanqu','','[]','惜残红惜嫩红，如晓梦如春梦。',71,'元曲/yuanqu.json','["惜残红惜嫩红，如晓梦如春梦。", "寂寞了金谷园，冷落了桃源洞。", "错怨五更风，蜂蝶去无踪。", "一径胭脂重，千机锦绣空。", "西东，魂返丹山凤。", "娇容，马嵬坡尘土中。"]'),
('yuanqu-1476','冤报冤赵氏孤儿・仙吕/赏花时','纪君祥','元','元曲','yuanqu','','[]','枉了我报主的忠良一旦休，只他那蠹国的奸臣权在手；他平白地使机谋，将俺云阳市斩首，兀的是出气力的下场头。',51,'元曲/yuanqu.json','["枉了我报主的忠良一旦休，只他那蠹国的奸臣权在手；他平白地使机谋，将俺云阳市斩首，兀的是出气力的下场头。"]'),
('yuanqu-1477','冤报冤赵氏孤儿・幺篇','纪君祥','元','元曲','yuanqu','','[]','落不的身埋在故丘。',184,'元曲/yuanqu.json','["落不的身埋在故丘。", "(云)公主，我嘱咐你的说话，你牢记者！(旦儿云)妾身知道了也！(赵朔唱)分付了腮边雨泪流，俺一句一回愁；待孩儿他年长后，着与俺这三百口，可兀的报冤仇。", "(死科，下)(旦儿云)驸马！则被你痛杀我也！(下)(使命云)赵朔用短刀身，亡了也。", "公主已囚在府中，小官须回主公的话去来。", "(诗云)西戎当日进神獒，赵家百口命难逃；可怜公主犹囚禁，赵朔能无决短刀！(下)。"]'),
('yuanqu-1478','冤报冤赵氏孤儿・仙吕/点绛唇','纪君祥','元','元曲','yuanqu','','[]','列国纷纷，莫强于晋。',33,'元曲/yuanqu.json','["列国纷纷，莫强于晋。", "才安稳，怎有这屠岸贾贼臣，他则把忠孝的公卿损。"]'),
('yuanqu-1479','冤报冤赵氏孤儿・昆江龙','纪君祥','元','元曲','yuanqu','','[]','不甫能风调雨顺，太平年宠用着这般人。',103,'元曲/yuanqu.json','["不甫能风调雨顺，太平年宠用着这般人。", "忠孝的在市曹中斩首，奸佞的在帅府内安身。", "现如今全作威来全作福，还说甚半由君也半由臣。", "他他他，把爪和牙布满在朝门，但违拗的早一个个诛夷尽。", "多咱是人间恶煞，可甚么阃外将军！。"]'),
('yuanqu-1480','冤报冤赵氏孤儿・油葫芦','纪君祥','元','元曲','yuanqu','','[]','他待要剪草防芽绝祸根，使着俺把府门。',110,'元曲/yuanqu.json','["他待要剪草防芽绝祸根，使着俺把府门。", "俺也是了家为国旧时臣。", "那一个藏孤儿的便不合将他隐，这一个杀孤儿的你可也心何忍。", "(带云)屠岸贾，你好狠也。", "(唱)有一日怒了亡苍，恼了下民，怎不怕沸腾腾万口争谈沦，天也显着个青脸儿不饶人。"]'),
('yuanqu-1481','冤报冤赵氏孤儿・天下乐','纪君祥','元','元曲','yuanqu','','[]','却不道远在儿孙近在身，哎，你个贼也波臣，和赵盾，岂可二十载同僚没些儿义分。',64,'元曲/yuanqu.json','["却不道远在儿孙近在身，哎，你个贼也波臣，和赵盾，岂可二十载同僚没些儿义分。", "便兴心使歹心，指贤人作歹人。", "他两个细评论，还是那个狠。"]'),
('yuanqu-1482','冤报冤赵氏孤儿・河西后庭花','纪君祥','元','元曲','yuanqu','','[]','你本是赵盾家堂上宾，我须是屠岸贾门下人。',166,'元曲/yuanqu.json','["你本是赵盾家堂上宾，我须是屠岸贾门下人。", "你便藏着那未满月麒麟种，(带云)程婴你见么？(唱)怎出的这不通风虎豹屯。", "我不是下将军，也不将你来盘问。", "(云)程婴，我想你多曾受赵家恩来！(程婴云)是。", "知恩报恩，何必要说。", "(正末唱)你道是既知恩合报恩，只怕你要脱身难脱身。", "前和后把住门，地和天那处奔？若拿回审个真，将孤儿往报闻，生不能，死有准。"]'),
('yuanqu-1483','冤报冤赵氏孤儿・金盏儿','纪君祥','元','元曲','yuanqu','','[]','见孤儿额颅上汗律津，口角头乳食喷，骨碌碌睁一双小眼儿将咱认，悄促促箱儿里似把声吞，紧绑绑难展足，窄狭狭怎翻身。',70,'元曲/yuanqu.json','["见孤儿额颅上汗律津，口角头乳食喷，骨碌碌睁一双小眼儿将咱认，悄促促箱儿里似把声吞，紧绑绑难展足，窄狭狭怎翻身。", "他正是成人不自在，自在不成人。"]'),
('yuanqu-1484','冤报冤赵氏孤儿・醉中天','纪君祥','元','元曲','yuanqu','','[]','我若是献出去图荣进，却不道利自己损别人。',205,'元曲/yuanqu.json','["我若是献出去图荣进，却不道利自己损别人。", "可怜他三百口亲丁尽不存，着谁来雪这终天恨？(带云)那屠岸贾若见这孤儿呵，(唱)怕不就连皮带筋，捻成齑粉。", "我可也没来由立这样没眼的功勋。", "(云)程婴，你抱的这孤儿出去。", "若屠岸贾问呵，我自与你回话。", "(程婴云)索谢了将军。", "(做抱箱儿走出，又回，跪科)(正末云)程婴，我说放你去，难道耍你？可快出去！(程婴云)索谢了将军。", "(做走，又回，跪科)(正末云)程婴，你怎生又回来？(唱)。"]'),
('yuanqu-1485','冤报冤赵氏孤儿・金盏儿','纪君祥','元','元曲','yuanqu','','[]','敢猜着我调假小为真，那知道蕙叹惜芝焚；去不去我几回家将伊尽，可怎生到门前兜的又回身？(带云)程婴，(唱)你既没包身胆，谁着你强做保孤人？可不道忠臣不怕死，怕死不',188,'元曲/yuanqu.json','["敢猜着我调假小为真，那知道蕙叹惜芝焚；去不去我几回家将伊尽，可怎生到门前兜的又回身？(带云)程婴，(唱)你既没包身胆，谁着你强做保孤人？可不道忠臣不怕死，怕死不忠臣。", "(程婴云)将军，我若出的这府门去，你报与屠岸贾知道，别差将军赶来拿住我程婴，这个孤儿万无活理。", "罢！罢！罢！将军，你拿将程婴去，请功受赏;我与赵氏孤儿，情愿一处身亡便了！(正末云)程婴，你好去的不放心也：(唱)。"]'),
('yuanqu-1486','冤报冤赵氏孤儿・醉扶归','纪君祥','元','元曲','yuanqu','','[]','你为赵氏存遗胤，我于屠贼有何亲？却待要乔做人情遣众军，打一个回风阵。',59,'元曲/yuanqu.json','["你为赵氏存遗胤，我于屠贼有何亲？却待要乔做人情遣众军，打一个回风阵。", "你义忠我可也又信，你若肯舍残生，我也愿把这头来刎。"]'),
('yuanqu-1487','冤报冤赵氏孤儿・青歌儿','纪君祥','元','元曲','yuanqu','','[]','端的是一言一言难尽。',92,'元曲/yuanqu.json','["端的是一言一言难尽。", "(带云)程婴，(唱)你也忒眼内眼内无珍。", "将孤儿好去深山深处隐，那其间教训成人，演武修文；重掌三军，拿住贼臣；碎首分身，报答亡魂，也不负了我和你硬踹着是非门，担危困。"]'),
('yuanqu-1488','冤报冤赵氏孤儿・隔尾','纪君祥','元','元曲','yuanqu','','[]','你道是古来多被奸臣弄，便是圣世何尝没四凶，谁似这万人恨千人赚一人重。',497,'元曲/yuanqu.json','["你道是古来多被奸臣弄，便是圣世何尝没四凶，谁似这万人恨千人赚一人重。", "他不廉不公，不孝不忠，单只会把赵盾全家杀的个绝了种。", "(程婴云)老宰辅，幸得皇天有眼，赵氏还未绝种哩！(正末云)他家满门良贱三百余口，诛尽杀绝，便是驸马也被三般朝典短刀自刎了，公主也将裙带缢死了，还有甚么种在那里？(程婴云)那前项的事，老宰辅都已知道，不必说了。", "近日公主囚禁府中，生下一子，唤做孤儿。", "这不是赵家是那家的种？但恐屠岸贾得知，又要杀坏，若杀了这一个小的，可不将赵家真绝了种也！(正末云)如今这孤儿却在那里？不知可有人救的出来么？(程婴云)老宰辅既有这点见怜之意，在下敢不实说。", "公主临亡时，将这孤儿交付与了程婴，着好生照觑他，待到成人长大，与父母报仇雪恨。", "我程婴抱的这孤儿出门，被韩厥将军要拿的去报与屠岸贾。", "是程婴数说了一场，那韩厥将军放我出了府门，自刎而亡。", "如今将的这孤儿无处掩藏，我特来投奔老宰辅。", "我想宰辅与赵盾元是一殿之臣，必然交厚，怎生可怜见救这个孤儿咱！(正末云)那孤儿今在何处？(程婴云)现在芭棚下哩！(正末云)休惊吓着孤儿，你快抱的来。", "(程婴做取箱开看科，云)谢天地，小舍人还睡着哩。", "(正末接科)(唱)。"]'),
('yuanqu-1489','冤报冤赵氏孤儿・牧羊关','纪君祥','元','元曲','yuanqu','','[]','这孩儿未生时绝了亲戚，怀着时灭了祖宗，便长成人也则是少吉多凶。',126,'元曲/yuanqu.json','["这孩儿未生时绝了亲戚，怀着时灭了祖宗，便长成人也则是少吉多凶。", "他父亲斩首在云阳，他娘呵囚在禁中。", "那里是血腥的白衣相，则是个无恩念的黑头虫。", "(程婴云)赵氏一家，全靠着这小舍人，要他报仇哩。", "(正末唱)你道他是个报父母的真男子；我道来，则是个妨爷娘的小业种。"]'),
('yuanqu-1490','冤报冤赵氏孤儿・红芍药','纪君祥','元','元曲','yuanqu','','[]','须二十年报仇的主人公，恁时节才称心胸。',122,'元曲/yuanqu.json','["须二十年报仇的主人公，恁时节才称心胸。", "只怕我迟疾死后一场空。", "(程婴云)老宰辅，你精神还强健哩。", "(正末唱)我精神比往日难同，闪下这小孩童怎见功？你急切里老不的形容，正好替赵家出力做先锋。", "(带云)程婴，你只依着我便了。", "(唱)我委实的捱不彻暮鼓晨钟。"]'),
('yuanqu-1491','冤报冤赵氏孤儿・三煞','纪君祥','元','元曲','yuanqu','','[]','这两家做下敌头重。',131,'元曲/yuanqu.json','["这两家做下敌头重。", "但要访的孤儿有影踪，必然把太严庄上兵围拥，铁桶般密不通风。", "(云)那屠岸贾拿住了我，高声喝道：老匹夫岂不见三日前出下榜文，偏是你藏下赵氏孤儿。", "与俺作对，请波请波！(唱)则说老匹大清先入瓮，也须知榜揭处天都动；偏你这罢职归田一老农，公然敢剔蝎撩蜂。"]'),
('yuanqu-1492','冤报冤赵氏孤儿・二煞','纪君祥','元','元曲','yuanqu','','[]','他把绷扒吊拷般般用，情节根由细细穷；那其间枯皮朽骨难禁痛，少不得从实攀供，可知道你个程婴怕恐。',91,'元曲/yuanqu.json','["他把绷扒吊拷般般用，情节根由细细穷；那其间枯皮朽骨难禁痛，少不得从实攀供，可知道你个程婴怕恐。", "(带云)程婴，你放心者。", "(唱)我从来一诺似千金重，便将我送上刀山与剑峰，断不做有始无终。"]'),
('yuanqu-1493','冤报冤赵氏孤儿・煞尾','纪君祥','元','元曲','yuanqu','','[]','凭着赵家枝叶千年永，晋国山河百二雄。',236,'元曲/yuanqu.json','["凭着赵家枝叶千年永，晋国山河百二雄。", "显耀英材统军众，威压诸邦尽伏拱；遍拜公卿诉苦衷。", "祸难当初起下宫，可怜三百口亲丁饮剑锋；刚留得孤苦伶仃一小童，巴到今朝袭父封。", "提起冤仇泪如涌，要请甚旗牌下九重，早拿出奸臣帅府中，断首分骸祭祖宗，九族全诛不宽纵，恁时节才不负你冒死存孤报主公，便是我也甘心儿葬近要离路旁冢。", "(下)(程婴云)事势急了，我依旧将这孤儿抱的我家去，将我的孩儿送到太平庄上来。", "(诗云)甘将自己亲生子，偷换他家赵氏孤；这本程婴义分应该得，只可惜遗累公孙老大夫。", "(下)。"]'),
('yuanqu-1494','冤报冤赵氏孤儿・双调/新水令','纪君祥','元','元曲','yuanqu','','[]','我则见荡征尘飞过小溪桥，多管是损忠良贼徒来到。',247,'元曲/yuanqu.json','["我则见荡征尘飞过小溪桥，多管是损忠良贼徒来到。", "齐臻臻摆着士卒，明晃晃列着枪刀。", "眼见的我死在今朝，更避甚痛笞掠。", "(屠岸贾同程婴领卒子上，云)来到这吕吕太平庄上也。", "令人，与我围了太平庄者。", "程婴，那里是公孙杵臼宅院？(程婴云)则这个便是。", "(屠岸贾云)拿过那老匹夫来。", "公孙杵臼，你知罪么？(正末云)我不知罪。", "(屠岸贾云)我知你个老匹夫和赵盾是一殿之臣。", "你怎敢掩藏着赵氏孤儿！(正末云)老元帅，我有熊心豹胆？怎敢掩藏着赵氏孤儿！(屠岸贾云)不打不招。", "令人，与我拣大棒子着实打者。", "(卒子做打科)(正末唱)。"]'),
('yuanqu-1495','冤报冤赵氏孤儿・驻马听','纪君祥','元','元曲','yuanqu','','[]','想着我罢职辞朝，曾与赵盾名为刎颈交。',145,'元曲/yuanqu.json','["想着我罢职辞朝，曾与赵盾名为刎颈交。", "(云)这事是谁见来？(屠岸贾云)观有程婴首告着你哩。", "(正末唱)是那个埋情出告，原来这程婴舌是斩身刀。", "(云)你杀了赵家满门良贱三百余口，则剩下这孩儿，你又要伤他性命。", "(唱)你正是狂风偏纵扑天雕，严霜故打枯根草。", "不争把孤儿又杀坏了。", "可着他三百口冤仇甚人来报。"]'),
('yuanqu-1496','冤报冤赵氏孤儿・雁儿落','纪君祥','元','元曲','yuanqu','','[]','是那一个实丕丕将着粗棍敲？打的来痛杀杀精皮掉。',45,'元曲/yuanqu.json','["是那一个实丕丕将着粗棍敲？打的来痛杀杀精皮掉。", "我和你狠程婴有甚的仇？却教我老公孙受这般虐。"]'),
('yuanqu-1497','冤报冤赵氏孤儿・水仙子','纪君祥','元','元曲','yuanqu','','[]','俺二人商议要救这小儿曹。',259,'元曲/yuanqu.json','["俺二人商议要救这小儿曹。", "(屠岸贾云)可知道指攀下来也。", "你说二人，一个是你了，那一个是谁？你实说将出来，我饶你的性命。", "(正末云)你要我说那一个，我说，我说。", "(唱)哎！一句话来到我舌尖亡却咽了。", "(屠岸贾云)程婴。", "这桩事敢有你么？(程婴云)兀那老头儿，你休妄指平人。", "(正末云)程婴，你慌怎么？(唱)我怎生把你程婴道，似这般有上梢无下梢。", "(屠岸贾云)你头里说两个，你怎生这一会儿可说无了？(正末唱)只被你打的来不知一个颠倒。", "(屠岸贾云)你还不说，我就打死你个老匹夫。", "(正末唱)遮莫便打的我皮都绽，肉尽销，休想我有半个字儿攀着。"]'),
('yuanqu-1498','冤报冤赵氏孤儿・川拨棹','纪君祥','元','元曲','yuanqu','','[]','你当日演神獒，把忠臣来扑咬。',88,'元曲/yuanqu.json','["你当日演神獒，把忠臣来扑咬。", "逼的他走死荒郊，刎死钢刀，缢死裙腰，将三百口全家老小尽行诛剿。", "并没那半个儿剩落，还不厌你心苗。", "(屠岸贾云)我见了这孤儿，就不由我不恼也。", "(正末唱)。"]'),
('yuanqu-1499','冤报冤赵氏孤儿・七弟兄','纪君祥','元','元曲','yuanqu','','[]','我只见他左瞧、左瞧、怒咆哮，火不腾改变了狰狞貌，按狮蛮拽札起锦征袍，把龙泉扯离出沙鱼鞘。',44,'元曲/yuanqu.json','["我只见他左瞧、左瞧、怒咆哮，火不腾改变了狰狞貌，按狮蛮拽札起锦征袍，把龙泉扯离出沙鱼鞘。"]'),
('yuanqu-1500','冤报冤赵氏孤儿・梅花酒','纪君祥','元','元曲','yuanqu','','[]','呀！见孩儿卧血泊。',84,'元曲/yuanqu.json','["呀！见孩儿卧血泊。", "那一个哭哭号号，这一个怨怨焦焦，连我也战战摇摇。", "直恁般歹做作，只除是没天道。", "呀！想孩儿离褥草，到今日恰十朝，刀下处怎耽饶，空生长枉劬劳，还说甚要防老。"]'),
('yuanqu-1501','冤报冤赵氏孤儿・鸳鸯煞','纪君祥','元','元曲','yuanqu','','[]','我七旬死后偏何老，这孩儿一岁死后偏知小。',91,'元曲/yuanqu.json','["我七旬死后偏何老，这孩儿一岁死后偏知小。", "俺两个一处身亡，落的个万代名标。", "我嘱付你个后死的程婴，休别了横亡的赵朔。", "畅道是光阴过去的疾，冤仇报复的早。", "将那厮万剐千刀，切莫要轻轻的素放了。"]'),
('yuanqu-1502','冤报冤赵氏孤儿・中吕/粉蝶儿','纪君祥','元','元曲','yuanqu','','[]','引着些本部下军卒，提起来杀人心半星不惧。',66,'元曲/yuanqu.json','["引着些本部下军卒，提起来杀人心半星不惧。", "每日家习演兵书。", "凭看我，快相持，能对垒，直使的诸邦降伏。", "俺父亲英勇谁如，我拚着个尽心儿扶助。"]'),
('yuanqu-1503','冤报冤赵氏孤儿・迎仙客','纪君祥','元','元曲','yuanqu','','[]','因甚的掩泪珠？(程婴做吁气科)(正末唱)气长吁？我恰才叉定手向前来紧趋伏。',120,'元曲/yuanqu.json','["因甚的掩泪珠？(程婴做吁气科)(正末唱)气长吁？我恰才叉定手向前来紧趋伏。", "(带云)则俺见这壁厢爹爹呵，(唱)忄敞支支恶心烦，勃腾腾生忿怒。", "(带云)是甚么人敢欺负你来？(唱)我这里低首踌躇。", "(带云)既然没的人欺负你呵，(唱)那里是话不投机处。"]'),
('yuanqu-1504','冤报冤赵氏孤儿・红绣鞋','纪君祥','元','元曲','yuanqu','','[]','画着的是青鸦鸦几株桑树，闹炒炒一簇田夫。',70,'元曲/yuanqu.json','["画着的是青鸦鸦几株桑树，闹炒炒一簇田夫。", "这一个可磕擦紧扶定一轮车。", "有-个将瓜捶亲手举，有一个触槐树早身殂，又一个恶犬儿只向着这穿紫的频去扑。"]'),
('yuanqu-1505','冤报冤赵氏孤儿・普天乐','纪君祥','元','元曲','yuanqu','','[]','听的你说从初，才使我知缘故；空长了我这二十年的岁月，生了我这七尺的身躯。',177,'元曲/yuanqu.json','["听的你说从初，才使我知缘故；空长了我这二十年的岁月，生了我这七尺的身躯。", "元来自刎的是父亲，自缢的咱老母。", "说到凄凉伤心处，便是那铁石人也放声啼哭。", "我拚着生擒那个老匹夫，只要他偿还俺一朝的臣宰。", "更和那合宅的家属。", "(云)你不说呵，您孩儿怎生知道。", "爹爹请坐，受您孩儿几拜。", "(正末拜科，程婴云)今日成就了你赵家枝叶，送的俺一家儿剪草除根了也。", "(做哭科)(正末唱)。"]'),
('yuanqu-1506','冤报冤赵氏孤儿・上小楼','纪君祥','元','元曲','yuanqu','','[]','若不是爹爹照觑。',59,'元曲/yuanqu.json','["若不是爹爹照觑。", "把你孩儿抬举，可不的二十年前早撄锋刃，久丧沟渠。", "恨只恨屠岸贾那匹大，寻恨拔树，险送的俺一家儿灭门绝户。"]'),
('yuanqu-1507','冤报冤赵氏孤儿・幺篇','纪君祥','元','元曲','yuanqu','','[]','他他他，把俺一姓戮；我我我，也还他九族屠。',147,'元曲/yuanqu.json','["他他他，把俺一姓戮；我我我，也还他九族屠。", "(程婴云)小主人，你休大惊小怪的，恐怕屠贼知道。", "(正末云)我和他一不做二不休。", "(唱)那怕他牵着神獒，拥着家兵，使着权术。", "你只看这一个那一个都是为谁而卒，岂可我做儿的倒安然如故。", "(云)爹爹放心，到明日我先见过了主公，和那满朝的卿相，亲自杀那贼去。", "(唱)。"]'),
('yuanqu-1508','冤报冤赵氏孤儿・耍孩儿','纪君祥','元','元曲','yuanqu','','[]','到明朝若与仇人遇，我迎头儿把他当住；也不须别用军和卒。',74,'元曲/yuanqu.json','["到明朝若与仇人遇，我迎头儿把他当住；也不须别用军和卒。", "只将咱猿臂轻舒，早提番玉勒雕鞍辔，扯下金花皂盖车，死狗似拖将去。", "我只问他人心安在，天理何如？。"]'),
('yuanqu-1509','冤报冤赵氏孤儿・二煞','纪君祥','元','元曲','yuanqu','','[]','谁着你使英雄忒使过，做冤仇能做毒，少不的一还一报无虚误。',65,'元曲/yuanqu.json','["谁着你使英雄忒使过，做冤仇能做毒，少不的一还一报无虚误。", "你当初屈勘公孙老，今日犹存赵氏孤。", "再休想咱容恕，我将他轻轻掷下，慢慢开除。"]'),
('yuanqu-1510','冤报冤赵氏孤儿・一煞','纪君祥','元','元曲','yuanqu','','[]','摘了他斗来大印一颗，剥了他花来簇几套服；把麻绳背绑在将军柱。',78,'元曲/yuanqu.json','["摘了他斗来大印一颗，剥了他花来簇几套服；把麻绳背绑在将军柱。", "把铁钳拔出他斓斑舌；把锥子生跳他贼眼珠，把尖刀细剐他浑身肉，把钢锤敲残他骨髓，把钢铡切掉他头颅。"]'),
('yuanqu-1511','冤报冤赵氏孤儿・煞尾','纪君祥','元','元曲','yuanqu','','[]','尚兀自勃腾腾怒怎淌，黑沈沈怨未复。',53,'元曲/yuanqu.json','["尚兀自勃腾腾怒怎淌，黑沈沈怨未复。", "也只为二十年的逆子妄认他人父，到今日三百口的冤魂，方才家自有主。", "(下)。"]'),
('yuanqu-1512','冤报冤赵氏孤儿・正宫/端正好','纪君祥','元','元曲','yuanqu','','[]','也不索列兵卒，排军将，动着些阔剑长枪；我今日报仇舍命诛奸党，总是他命尽也合身丧。',40,'元曲/yuanqu.json','["也不索列兵卒，排军将，动着些阔剑长枪；我今日报仇舍命诛奸党，总是他命尽也合身丧。"]'),
('yuanqu-1513','冤报冤赵氏孤儿・滚绣球','纪君祥','元','元曲','yuanqu','','[]','只在这闹街坊，弄一场。',164,'元曲/yuanqu.json','["只在这闹街坊，弄一场。", "我和他决无轻放，恰便似虎扑绵羊。", "我可也不索慌，不索忙，早把手脚儿十分打当，看那厮怎做堤防。", "我将这二十年积下冤仇报，三百口亡来性命偿，我便死也何妨。", "(云)我只在这闹市中等侯着，那老贼敢待来也。", "(屠岸贾领卒子上，云)今日在元帅府回还私宅中去。", "令人，摆开头踏，慢慢的行者。", "(正末云)兀的不是那老贼来了也。", "(唱)。"]'),
('yuanqu-1514','冤报冤赵氏孤儿・倘秀才','纪君祥','元','元曲','yuanqu','','[]','你看那雄赳赳头踏数行，闹攘攘跟随的在两厢。',56,'元曲/yuanqu.json','["你看那雄赳赳头踏数行，闹攘攘跟随的在两厢。", "你看他腆着胸脯，妆些儿势况。", "我这里骤马如流水，掣剑似秋霜，向前来赌当。"]'),
('yuanqu-1515','冤报冤赵氏孤儿・笑和尚','纪君祥','元','元曲','yuanqu','','[]','我、我、我尽威风八面扬，你、你、你怎挣坐怎拦挡？早、早、早吓的他魂飘荡，休、休、休再口强。',70,'元曲/yuanqu.json','["我、我、我尽威风八面扬，你、你、你怎挣坐怎拦挡？早、早、早吓的他魂飘荡，休、休、休再口强。", "是、是、是不商量，来、来、来可匹塔的提离了鞍鞒上。"]'),
('yuanqu-1516','冤报冤赵氏孤儿・脱布衫','纪君祥','元','元曲','yuanqu','','[]','将那厮钉上木驴推上云阳，休便要断首开膛；直剁的他做一埚儿肉酱，也消不得俺满怀惆怅。',41,'元曲/yuanqu.json','["将那厮钉上木驴推上云阳，休便要断首开膛；直剁的他做一埚儿肉酱，也消不得俺满怀惆怅。"]'),
('yuanqu-1517','冤报冤赵氏孤儿・小梁州','纪君祥','元','元曲','yuanqu','','[]','谁肯舍了亲儿把别姓藏？似你这恩德难忘。',45,'元曲/yuanqu.json','["谁肯舍了亲儿把别姓藏？似你这恩德难忘。", "我待请个丹青妙手不寻常，傅着你真容相，侍奉在俺家堂。"]'),
('yuanqu-1518','冤报冤赵氏孤儿・幺篇','纪君祥','元','元曲','yuanqu','','[]','你则那三年乳哺曾无旷，可不胜怀担十月时光；幸今朝出万死身无恙，便日夕里焚香供养，也报不的你养爷娘。',49,'元曲/yuanqu.json','["你则那三年乳哺曾无旷，可不胜怀担十月时光；幸今朝出万死身无恙，便日夕里焚香供养，也报不的你养爷娘。"]'),
('yuanqu-1519','冤报冤赵氏孤儿・黄钟尾','纪君祥','元','元曲','yuanqu','','[]','谢君恩普国多沾降，把奸贼全家尽灭亡。',110,'元曲/yuanqu.json','["谢君恩普国多沾降，把奸贼全家尽灭亡。", "赐孤儿改名望，袭父祖拜卿相；忠义士各褒奖，是军官还职掌，是穷民与收养；已死丧给封葬，现生存受爵赏。", "这恩临似天广，端为谁敢虚让。", "誓捐生在战场，着邻邦并归向。", "落的个史册上标名，留与后人讲。"]'),
('yuanqu-1520','河南府张鼎勘头巾・仙吕/点绛唇','孙仲章','元','元曲','yuanqu','','[]','杜宇伤春，锦莺啼恨。',31,'元曲/yuanqu.json','["杜宇伤春，锦莺啼恨。", "东风顺，则听的叫唤声频，早将我酒力消磨尽。"]'),
('yuanqu-1521','河南府张鼎勘头巾・混江龙','孙仲章','元','元曲','yuanqu','','[]','我把这衣衫整顿，急煎煎行出卧房门。',79,'元曲/yuanqu.json','["我把这衣衫整顿，急煎煎行出卧房门。", "悠悠的惊了七魂，忽忽的唬了三魂。", "脚趔趄难支吾荒冗冗，眼朦胧犹兀自醉醺醺。", "我这里下阶基转影壁亲身问，问一个事从来历，唱叫缘因。"]'),
('yuanqu-1522','河南府张鼎勘头巾・油葫芦','孙仲章','元','元曲','yuanqu','','[]','他是个腰系红裙一妇人，你试议论，有甚事便推天抢地手粘身。',151,'元曲/yuanqu.json','["他是个腰系红裙一妇人，你试议论，有甚事便推天抢地手粘身。", "(王小二云)你家狗咬了我。", "(正末云)你打破我缸，倒说狗咬了你。", "(唱)且休论这两家凭伤损，(带云)常言道：男不和女斗。", "王小二，(唱)你先合该笞四十批头棍。", "(带云)你骂了人，倒说你是。", "(唱)你没事哏，没事村，则你那帮闲钻懒腌身分，到宫中也不索取词因。"]'),
('yuanqu-1523','河南府张鼎勘头巾・天下乐','孙仲章','元','元曲','yuanqu','','[]','敢拖到官中拷断你筋，哎！你个乔人，情性村，则你那泼言语赖人不本分。',195,'元曲/yuanqu.json','["敢拖到官中拷断你筋，哎！你个乔人，情性村，则你那泼言语赖人不本分。", "着我待饶来怎地饶？待忍来怎地忍？恨不的莽拳头嘴缝墩。", "(云)是谁家的狗咬着你来？(王小二云)你家的狗咬着我来。", "(正末云)你道我家狗咬着你，众街坊试看咱：若是我家狗咬他，我便写与你保辜文书。", "若不曾咬着，你便陪我缸来。", "(街坊云)员外说的是。", "俺看他这条腿不曾咬着。", "(王小二云)不是这条腿，是那一条腿。", "(街坊云)也不曾咬。", "(正末唱)。"]'),
('yuanqu-1524','河南府张鼎勘头巾・醉中天','孙仲章','元','元曲','yuanqu','','[]','谁小二哥休心困，觑两条腿辨清浑。',104,'元曲/yuanqu.json','["谁小二哥休心困，觑两条腿辨清浑。", "羞的那厮一柄脸通红似绛云，他慌遮掩忙身褪。", "瞒不过相识街坊众亲，定晴觑认，并无些咬破牙痕。", "(云)原来不曾咬着，这弟子孩儿这等图赖人。", "(王小二云)这等恶狗，你养他怎的？(正末唱)。"]'),
('yuanqu-1525','河南府张鼎勘头巾・金盏儿','孙仲章','元','元曲','yuanqu','','[]','俺这犬吠柴门，和月待黄昏。',287,'元曲/yuanqu.json','["俺这犬吠柴门，和月待黄昏。", "只除是盗贼不敢来相近，(带云)若是闲人呵。", "(唱)无过是摇头摆尾弄精神。", "他可也能熬鞭杖打，不弃主人贫。", "我则理会妻贤先嫁主，这的是恶犬护三村。", "(王小二云)员外，你轻呵轻君子，重呵重小人，怎将狗比我？(正末云)我这富汉打死你这穷汉，则苦了几文钱。", "(王小二云)你说这等大话。", "我大街上撞见你，一无话说。", "僻巷里撞见你，我杀了你。", "(旦云)好也，这厮不只是说出来，一定做出来。", "问他要一纸生死文书，一百日以里，但有头疼脑热，都是你，一百日以外并不干你事。", "(正末云)做甚么哩？(旦云)王小二要杀了你，我问他要保辜文书。", "(正末云)大嫂，他怎敢杀人？王小二你听者。", "(唱)。"]'),
('yuanqu-1526','河南府张鼎勘头巾・赚煞','孙仲章','元','元曲','yuanqu','','[]','你伏低呵自商和，我寻罪责官司问。',136,'元曲/yuanqu.json','["你伏低呵自商和，我寻罪责官司问。", "若不看解劝街坊面分。", "小后生从来火性紧，发狂言信口胡喷。", "自评论，口是祸之门，我劝你言同休记恨。", "减些性粗性蠢，则要你妆痴妆坌，(王小二云)员外，是我的不是了。", "我与你陪礼，取一瓶儿酒，请员外饮一杯罢。", "(正末唱)何须你倒擎着酒盏去求人？(同旦下)。"]'),
('yuanqu-1527','河南府张鼎勘头巾・仙吕/赏花时','孙仲章','元','元曲','yuanqu','','[]','落日西园花正浓，扑面东风酒力涌。',40,'元曲/yuanqu.json','["落日西园花正浓，扑面东风酒力涌。", "全不省上青骢，只记得金钟漫捧，直劝我吃的到喉咙。"]'),
('yuanqu-1528','河南府张鼎勘头巾・幺篇','孙仲章','元','元曲','yuanqu','','[]','你觑那片草浑如蜀锦蒙，残照堪为烛影红，垂柳作帘栊。',258,'元曲/yuanqu.json','["你觑那片草浑如蜀锦蒙，残照堪为烛影红，垂柳作帘栊。", "暂撇下心烦意冗，醉卧绿阴中。", "(做睡科)(净上杀末科，云)我杀了刘员外也。", "拿着这芝麻罗头巾，减银环子。", "回大嫂话去来。", "(下)(街坊上，云)刘员外娘子，不知是甚么人杀了员外也？(旦上。", "云)众街坊，甚么人杀了俺员外？(街坊云)知道是甚么人？(旦云)别无仇人，则是王小二，到他家试问咱。", "早到门首也。", "(唤科)(王小二上，见科)(旦云)好也，你与了我保辜文书，不上十日，就把员外杀了。", "明有王法，我和你见宫去来。", "(王小二云)我门也不曾出，可怎么冤我杀了员外？谁人与我做主咱？(下)。"]'),
('yuanqu-1529','河南府张鼎勘头巾・南吕/一枝花','孙仲章','元','元曲','yuanqu','','[]','虽是个判行的旧状词，合干办新公事。',71,'元曲/yuanqu.json','["虽是个判行的旧状词，合干办新公事。", "出司房忙进步，登涩道下阶址。", "又无甚过犯公私；把文卷依节次，请新官题判时。", "先呈与个押解牒文，后押上今拘头佥字。"]'),
('yuanqu-1530','河南府张鼎勘头巾・牧羊关','孙仲章','元','元曲','yuanqu','','[]','这的是行恶的供成招伏，(府尹云)这一宗呢？(正末唱)这是打家贼责下口词。',248,'元曲/yuanqu.json','["这的是行恶的供成招伏，(府尹云)这一宗呢？(正末唱)这是打家贼责下口词。", "(府尹云)这是甚么文卷？(正末唱)这的是远仓粮犹未关支，(府尹云)这一纸呢？(正末唱)这的是再修理道路桥梁，(府尹云)桥梁道路库狱仓廒，都是合管的，便该修理去。", "又这一宗文卷呢？(正末唱)这的是重盖下仓廒库司。", "(府尹云)这一宗呢？(正末唱)这的是亲兄弟争田土，(府尹云)这个呢？(正末唱)这的是亲女婿赖了家私。", "(府尹云)这一宗呢？(正末唱)这的是相斗争商和状，(府尹云)这宗可是甚么文书？(正末唱)大人，立的是打杀人也未检尸。"]'),
('yuanqu-1531','河南府张鼎勘头巾・贺新郎','孙仲章','元','元曲','yuanqu','','[]','这头巾在菜园坦埋伏许多时，可怎生无半点儿尘丝，一星儿土渍？(令史云)瘸刘家菜园里井口边大石板压着，怎么得泥来？(正末唱)那更这减银上因何不见生涩？则他这一春雨何',220,'元曲/yuanqu.json','["这头巾在菜园坦埋伏许多时，可怎生无半点儿尘丝，一星儿土渍？(令史云)瘸刘家菜园里井口边大石板压着，怎么得泥来？(正末唱)那更这减银上因何不见生涩？则他这一春雨何曾道是住止？(带云)大人寻思波。", "(唱)可怎生黑真真的不动个文字？请先生别勘问，告大人再寻思。", "这厮每其中敢有暗昧跷蹊事。", "(做问科，云)谁是原告？(白云)妾身是原告。", "(正末云)兀那妇人，且一壁去。", "这妇人不是个良人。", "(府尹云)怎生见得他不是良人？(正末唱)这妇人晴天开水路，无事设曹司。"]'),
('yuanqu-1532','河南府张鼎勘头巾・牧羊关','孙仲章','元','元曲','yuanqu','','[]','我跟前休胡讳，那其间必受私，既不沙怎无个放舍悲慈。',104,'元曲/yuanqu.json','["我跟前休胡讳，那其间必受私，既不沙怎无个放舍悲慈。", "常言道：饱食伤心，忠言逆耳。", "且休说受苞苴是穷民血，便那请俸禄也是瘦民脂。", "咱则合分解民冤枉，怎下的将平人去刀下死。", "(云)赵令史，道不的人性命关天关地也。", "(唱)。"]'),
('yuanqu-1533','河南府张鼎勘头巾・商调/集贤宾','孙仲章','元','元曲','yuanqu','','[]','没来山惹这场闲是非，亲自问杀人贼。',91,'元曲/yuanqu.json','["没来山惹这场闲是非，亲自问杀人贼。", "全不论清廉正直，倒不如懵懂愚痴。", "为别人受怕耽惊，没来由废寝忘食。", "则俺那不明白该死的在那里，好教我闷恹恹蹙损双眉。", "则为我一言容易出，今日个驷马却难追。"]'),
('yuanqu-1534','河南府张鼎勘头巾・逍遥乐','孙仲章','元','元曲','yuanqu','','[]','我为你亲身临牢内，审问虚实，端详就里。',169,'元曲/yuanqu.json','["我为你亲身临牢内，审问虚实，端详就里。", "(云)可早来到这牢门首也。", "我拽动这铃索波。", "(张千云)这是孔目来了(做开门见科，云)我开开这门，哥哥请进来。", "(正末入科，云)张千，拿过王小二来。", "(做拿王跪料，末云)兀那厮，你从实说来。", "(唱)若说的半句儿差池，稳情取六问三推。", "休想我等闲间觑面皮，向我行如何支对。", "也无那八棒十枷，万死千生，都不到一时半刻。"]'),
('yuanqu-1535','河南府张鼎勘头巾・醋葫芦','孙仲章','元','元曲','yuanqu','','[]','你道是打的慌胡乱指，不想这头巾在那里，则你那勘时节莫不有甚么外人知？(张千云)哥也，这是狱不通风，谁敢来，并无人知。',468,'元曲/yuanqu.json','["你道是打的慌胡乱指，不想这头巾在那里，则你那勘时节莫不有甚么外人知？(张千云)哥也，这是狱不通风，谁敢来，并无人知。", "(正末唱)取来时不有甚么人见你？(张千云)是我张千取来的，并无人见。", "(正末云)勘时节也无人知，取时节又无人见。", "(唱)这公事深藏着暖昧，好教我左猜右忖没端倪。", "(云)张千，这头巾当初是你去取来？(张千云)是我取来。", "(正末云)你到瘸刘家菜园里，曾叫那地主和房邻眼同一齐取来么？(张千云)不曾叫那地主、房邻，我自家跳过墙去取来了。", "(正末云)张千，你不曾叫那地主、房邻眼同去取，又是越墙而过。", "张千，这头巾环子敢是你放在那里？刘员外敢是你杀了么？(张千云)哥哥，干我甚么事？(正末云)可知不干你事哩，你则与个不应的状子。", "(张千云)怎么把我也问个不应？(正末云)你看这厮不中用。", "休说别的，则说这个问事厅，你来我跟前支了多少钱钞？今日也修理，明日也修理，便无那瓦呵，你也买几个草来苫一苫可也好。", "(张千笑料，云)哦，我想起来了也。", "(正末云)张千，你想起甚么来？这等笑？(张干云)那一日问王小二头巾环子时，有一个卖草的在这里来。", "(正末唱)。"]'),
('yuanqu-1536','河南府张鼎勘头巾・幺篇','孙仲章','元','元曲','yuanqu','','[]','听言绝则我沉默默腹内忧，都做了虚飘飘心上喜，则那的便是图财致命杀人贼。',118,'元曲/yuanqu.json','["听言绝则我沉默默腹内忧，都做了虚飘飘心上喜，则那的便是图财致命杀人贼。", "(带云)张千(唱)你手里要昨日卖草索钱的，(云)快与我拿的那个人来。", "(张千云)我拿去。", "(正末云)回来。", "(唱)你听言仔细，(带云)你若拿不来，(唱)不拿来你身上有灾危。"]'),
('yuanqu-1537','河南府张鼎勘头巾・幺篇','孙仲章','元','元曲','yuanqu','','[]','则他那身材儿长共短？(张千云)我试想着，我记的他是个矮的。',95,'元曲/yuanqu.json','["则他那身材儿长共短？(张千云)我试想着，我记的他是个矮的。", "(正末唱)画皮儿瘦共肥？(张千云)是个黄甘甘瘦脸儿。", "(正末唱)他住居村舍可也近城池？(张千云)他说住在望京店，我记的他有些苫唇髭髟。"]'),
('yuanqu-1538','河南府张鼎勘头巾・挂金索','孙仲章','元','元曲','yuanqu','','[]','省可里后拥前推，着他向书案傍边立。',95,'元曲/yuanqu.json','["省可里后拥前推，着他向书案傍边立。", "祗候人悄语低声。", "休监押休着他跪。", "(带云)孩儿也，(唱)你若说实情呵，我可便买与你个合酪吃。", "(丑云)你孩儿肚里正饥哩。", "(正末唱)我则问你言词，你一句句明支对。"]'),
('yuanqu-1539','河南府张鼎勘头巾・醋葫芦','孙仲章','元','元曲','yuanqu','','[]','听言罢他口内词，不由我心内疑，况兼那婆娘颜色有谁及。',259,'元曲/yuanqu.json','["听言罢他口内词，不由我心内疑，况兼那婆娘颜色有谁及。", "他莫不共先生平口有些不伶俐？只他两个同谋设计，我十猜八九是真实。", "(云)张千，着他吃合酪去。", "(丑下)(正末云)张千，你去拿刘平远浑家来。", "(张千云)理会的。", "(出门科，云)兀那刘员外浑家，衙门里唤你哩。", "(旦做醉上，云)妾身刘员外的浑家。", "俺男儿被王小二杀了，众街坊都来与我解闷，饮了几杯散闷酒。", "有衙门里着人来唤我，不知说甚么？须索走一遭去。", "(见末科)(正末云)这妇人不吃酒来？（旦云)是吃闷解酒来。", "(正末云)敢是解闷酒？(旦云)是众街坊见死了员外，都替我解闷来。", "(正末唱)。"]'),
('yuanqu-1540','河南府张鼎勘头巾・幺篇','孙仲章','元','元曲','yuanqu','','[]','你见这恶哏哏，公吏排，不是我官不威牙爪威，不招承敢粉碎了望夫石。',64,'元曲/yuanqu.json','["你见这恶哏哏，公吏排，不是我官不威牙爪威，不招承敢粉碎了望夫石。", "休则管我跟前声支剌叫唤因甚的，大古里脚踏实地，你从来本性我须知。"]'),
('yuanqu-1541','河南府张鼎勘头巾・后庭花','孙仲章','元','元曲','yuanqu','','[]','待推来怎地推，不招承等甚的？当日个指望待同谐老，今日被意中人连累你。',71,'元曲/yuanqu.json','["待推来怎地推，不招承等甚的？当日个指望待同谐老，今日被意中人连累你。", "你两个待做夫妻，怎当的官司临逼？阻鸾凤两下飞，跪佳人在这里，枷奸夫在那壁。"]'),
('yuanqu-1542','河南府张鼎勘头巾・梧叶儿','孙仲章','元','元曲','yuanqu','','[]','他道你先主意，(旦云)是他先起意来。',370,'元曲/yuanqu.json','["他道你先主意，(旦云)是他先起意来。", "(正末云)是谁先起意来？(丑点头科)(正末云)兀那厮，是你先起意来？(张千云)他说是他来。", "(正末唱)他道都是你的见识。", "(旦云)都是他的见识。", "(正末云)兀那厮，是你的见识么？(丑点头科)(正末唱)他道和你整二载暗偷期，(旦云)那里有二载，才半年也。", "(正未云)兀那厮，是半年么？(丑点头科)(正末唱)他道他三十岁，(旦云)连自己岁数都忘了。", "他三十一岁也。", "(正末云)兀那厮，是三十一岁么？(丑点头科)(正末唱)他道他身姓李。", "(旦云)连他自己姓也忘了，他姓王。", "(正末云)兀那厮，你姓王么？(丑点头科)<正末云)是姓王。", "(唱)他道他曾买与你些东西，(旦云)他身上道袍，还是我买与他的。", "(正末云)你可留他些甚么那？(旦云)初一十五，图他几个馒头吃。", "(正末云)这个也不打紧。", "兀那妇人你听者。", "(唱)他道是家住在三清观里。"]');
